// Check if a schema type string matches LocalBusiness or any of its subtypes
function isLocalBusinessType(typeStr) {
  if (!typeStr || typeof typeStr !== 'string') return false;
  // Direct match
  if (LOCAL_BUSINESS_TYPES.has(typeStr)) return true;
  // Check if the string contains any known LocalBusiness type (for crawled schema strings like "LocalBusiness, ComputerRepairService")
  for (const t of LOCAL_BUSINESS_TYPES) {
    if (typeStr.includes(t)) return true;
  }
  return false;
}

// Check if a page is a service/content page (not utility, not blog, not excluded)
function isServicePage(path, schemas, wordCount, pageExclusions) {
  const clean = (path || '').toLowerCase().replace(/^\/|\/$/g, '');
  if (!clean || clean === '/') return false;
  const slug = clean.split('/').pop() || clean;
  // Skip utility pages
  if (UTILITY_SLUGS.has(clean) || UTILITY_SLUGS.has(slug)) return false;
  // Skip blog/news/category paths
  if (/^(blog|news|category|tag|author|20\d{2})\//.test(clean)) return false;
  // Skip pages with Article/BlogPosting/NewsArticle schema — Yoast adds Article to WP posts (blogs), WebPage to WP pages (services)
  if (schemas && schemas.some(s => typeof s === 'string' && (s === 'Article' || s.includes('BlogPosting') || s.includes('NewsArticle')))) return false;
  // Skip user-excluded pages
  if (pageExclusions && pageExclusions.length > 0) {
    const normalizedPath = '/' + clean;
    if (pageExclusions.some(ex => normalizedPath === ex || clean === ex.replace(/^\//, ''))) return false;
  }
  // Skip thin content
  if (wordCount !== undefined && wordCount < 100) return false;
  return true;
}

