// ==================== 3. AUTH ====================

// Generate JWT token
function generateToken(userId, email, role = 'admin', projectId = null) {
  return jwt.sign({ userId, email, role, projectId }, JWT_SECRET, { expiresIn: '30d' });
}

// Auth middleware
function authMiddleware(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1] || req.query.token;
  if (!token) return res.status(401).json({ error: 'No token provided' });
  try {
    req.auth = jwt.verify(token, JWT_SECRET);
    next();
  } catch (e) {
    res.status(401).json({ error: 'Invalid token' });
  }
}

// Whitelist certain paths from auth requirement
function optionalAuth(req, res, next) {
  const whitelistPaths = ['/api/auth/register', '/api/auth/login', '/api/auth/reset-password', '/api/health', '/api/gsc/callback', '/api/gbp/callback', '/api/debug/serp-test', '/api/debug/maps-test', '/api/debug/dfs-test', '/api/test-gpthuman'];
  // Allow emergency restore without auth
  if (req.path.match(/\/api\/projects\/\d+\/content-queue\/restore-page\/\d+/)) return next();
  // Allow invite routes without auth (client signup flow)
  if (req.path.match(/^\/api\/invite\//)) return next();
  // Allow team-invite routes without auth (team member signup flow)
  if (req.path.match(/^\/api\/team-invite\//)) return next();
  // Allow connector-push routes (they use their own push token auth)
  if (req.path.match(/^\/api\/connector-push\//)) return next();
  // Allow RC grid sync (called by scheduled automation)
  if (req.path.match(/\/api\/projects\/\d+\/rc-grid-sync$/)) return next();
  // Allow RC sync (called by scheduled automation)
  if (req.path.match(/\/api\/projects\/\d+\/rc-sync$/)) return next();
  // Allow plugin-verify (WP plugin uses connection code, not JWT)
  if (req.path.match(/\/api\/projects\/\d+\/plugin-verify/)) return next();
  // Allow plugin endpoints (license check, update check, download — no JWT)
  if (req.path.match(/^\/api\/plugin\//)) return next();
  // Allow internal-links approved pull + confirm (WP plugin pulls/reports without JWT; no sensitive data)
  if (req.path.match(/^\/api\/projects\/\d+\/internal-links\/(approved|confirm)$/)) return next();
  if (whitelistPaths.includes(req.path)) return next();
  // Skip auth for non-API routes (static files, index.html)
  if (!req.path.startsWith('/api/')) return next();
  authMiddleware(req, res, next);
}

// Register
app.post('/api/auth/register', async (req, res) => {
  const { email, password, name } = req.body;
  if (!email || !password) return res.status(400).json({ error: 'Email and password required' });
  try {
    // Open self-registration is disabled. Only the very first (bootstrap) admin may self-register;
    // everyone else must be added via an agency team invitation (/api/team/invite).
    const userCount = parseInt((await pool.query('SELECT COUNT(*)::int AS n FROM users')).rows[0].n);
    if (userCount > 0) return res.status(403).json({ error: 'Self-registration is disabled. Ask an admin to send you a team invitation.' });
    const hash = await bcrypt.hash(password, 10);
    const result = await pool.query(
      'INSERT INTO users (email, password_hash, name) VALUES ($1, $2, $3) RETURNING id, email',
      [email, hash, name || '']
    );
    const user = result.rows[0];
    const token = generateToken(user.id, user.email);
    res.json({ ok: true, user, token });
  } catch (e) {
    if (e.code === '23505') return res.status(409).json({ error: 'Email already registered' });
    res.status(500).json({ error: e.message });
  }
});

// Login
app.post('/api/auth/login', async (req, res) => {
  const { email, password } = req.body;
  if (!email || !password) return res.status(400).json({ error: 'Email and password required' });
  try {
    const result = await pool.query('SELECT id, email, password_hash, name, role, project_id FROM users WHERE email=$1', [email]);
    if (result.rows.length === 0) return res.status(401).json({ error: 'Invalid credentials' });
    const user = result.rows[0];
    const match = await bcrypt.compare(password, user.password_hash);
    if (!match) return res.status(401).json({ error: 'Invalid credentials' });
    const token = generateToken(user.id, user.email, user.role || 'admin', user.project_id);
    res.json({ ok: true, user: { id: user.id, email: user.email, name: user.name, role: user.role || 'admin', project_id: user.project_id }, token });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

