// ── Plugin Connection Verify ────────────────────────────────────────
// Called by WP plugin's Test Connection button — uses CONNECTOR_PUSH_TOKEN env var
app.post('/api/projects/:id/plugin-verify', async (req, res) => {
  try {
    const { code, site_url, plugin_version } = req.body || {};
    const pushToken = process.env.CONNECTOR_PUSH_TOKEN;
    if (!code) return res.status(400).json({ ok: false, error: 'Missing connection code' });
    if (!pushToken) return res.status(500).json({ ok: false, error: 'CONNECTOR_PUSH_TOKEN not set on server' });
    if (code !== pushToken) return res.status(403).json({ ok: false, error: 'Invalid connection code' });
    const result = await pool.query('SELECT domain, business_name FROM projects WHERE id=$1', [req.params.id]);
    if (!result.rows.length) return res.status(404).json({ ok: false, error: 'Project not found' });
    const project = result.rows[0];
    console.log(`[plugin-verify] Project ${req.params.id} verified. site=${site_url}, version=${plugin_version}`);
    res.json({ ok: true, project_name: project.business_name || project.domain || 'Connected' });
  } catch (e) {
    res.status(500).json({ ok: false, error: e.message });
  }
});

// ─── Plugin Proxy: 404s, Redirects, Broken Links ───────────────────
// Helper to call WP plugin REST API
async function callPluginApi(project, path, method = 'GET', body = null) {
  const wpUrl = (project.wordpress_url || project.domain || '').replace(/\/$/, '');
  if (!wpUrl) throw new Error('No WordPress URL configured');
  const authHeaders = getWpAuthHeaders(project);
  if (!authHeaders) throw new Error('No WP Application Password configured');
  const opts = { method, headers: { ...authHeaders }, signal: AbortSignal.timeout(45000) };
  if (body && method !== 'GET') { opts.headers['Content-Type'] = 'application/json'; opts.body = JSON.stringify(body); }
  const resp = await fetch(`${wpUrl}/wp-json/seoroom-opt/v1${path}`, opts);
  if (!resp.ok) {
    const text = await resp.text().catch(() => '');
    throw new Error(`Plugin API ${resp.status}: ${text.substring(0, 200)}`);
  }
  return resp.json();
}

// Helper: filter out garbage/bot 404 URLs (XPath selectors, encoded junk, etc.)
function isValid404Url(url) {
  if (!url || typeof url !== 'string') return false;
  // XPath selectors (e.g. /HTML/BODY/HEADER/*[2][self::NAV])
  if (/\/HTML\//i.test(url)) return false;
  if (/\[self::/i.test(url)) return false;
  // CSS selectors or DOM paths
  if (/\*\[\d+\]/.test(url)) return false;
  // Data URIs
  if (/^data:/i.test(url)) return false;
  // JavaScript URIs
  if (/^javascript:/i.test(url)) return false;
  // Extremely long paths (likely bot junk)
  if (url.length > 500) return false;
  // Encoded binary/null bytes
  if (/%00|%01|%02/.test(url)) return false;
  // Common bot-probing paths (not real pages)
  const path = url.replace(/^https?:\/\/[^/]+/, '').toLowerCase().replace(/\/$/, '');
  const botPaths = [
    '/wp', '/wp-admin', '/wp-login', '/wp-login.php', '/wp-cron', '/wp-config', '/wp-includes',
    '/admin', '/administrator', '/login', '/signin', '/signup',
    '/backup', '/old', '/test', '/debug', '/temp', '/tmp',
    '/api/config', '/api/settings', '/api/health', '/api/v1', '/api/v1/settings',
    '/graphql', '/.env', '/.git', '/.well-known/security.txt',
    '/config', '/env', '/phpinfo', '/server-status', '/actuator',
    '/xmlrpc.php', '/xmlrpc', '/wp-json',
  ];
  if (botPaths.includes(path) || botPaths.some(bp => path.startsWith(bp + '/') || path.startsWith(bp + '?'))) return false;
  // Elementor internal IDs (e.g. /elementor-2561035482)
  if (/\/elementor-\d+/.test(path)) return false;
  // URL.createObjectURL blobs (raw or URL-encoded)
  if (/createobjecturl|blob:/i.test(url)) return false;
  if (/createObjectURL|blob%3A/i.test(decodeURIComponent(url))) return false;
  // tel: links treated as relative paths (e.g. /plumber-hilton/tel:0864005390)
  if (/\/tel:/i.test(path)) return false;
  // Encoded Google Maps URLs leaking into href (e.g. /plumber-X/%26quot%3Bhttps%3A//maps.google.com)
  if (/maps\.google\.com|google\.com\/maps/i.test(decodeURIComponent(url))) return false;
  // /author/ followed by hex hash (bot/spam patterns)
  if (/\/author\/[0-9a-f]{8,}/i.test(path)) return false;
  return true;
}

// GET /api/projects/:id/plugin/404s — fetch 404 log from WP plugin
app.get('/api/projects/:id/plugin/404s', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const data = await callPluginApi(project, '/404s');
    // Filter out garbage/bot URLs
    if (Array.isArray(data)) {
      // Debug: log first 3 raw URLs to see format
      if (data.length > 0) console.log(`[plugin-404s] Sample raw URLs:`, data.slice(0, 3).map(x => x.url || x.url_path || x.request_url || 'NO_URL_FIELD'));
      const filtered = data.filter(item => {
        const u = item.url || item.url_path || '';
        const valid = isValid404Url(u);
        if (!valid) console.log(`[plugin-404s] Filtered: ${u}`);
        return valid;
      });
      const removed = data.length - filtered.length;
      if (removed > 0) console.log(`[plugin-404s] Filtered out ${removed} garbage URLs`);
      return res.json(filtered);
    }
    if (data && Array.isArray(data.items)) {
      data.items = data.items.filter(item => isValid404Url(item.url || item.url_path || ''));
    }
    res.json(data);
  } catch (e) {
    console.error(`[plugin-404s] Error:`, e.message);
    res.status(500).json({ error: e.message });
  }
});

