// POST /api/projects/:id/plugin/404s/suggest-redirects — match 404 URLs to existing pages
app.post('/api/projects/:id/plugin/404s/suggest-redirects', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const { urls } = req.body; // array of 404 URL paths
    if (!urls || !urls.length) return res.status(400).json({ error: 'No URLs to match' });

    const wpUrl = (project.wordpress_url || project.domain || '').replace(/\/$/, '');
    const authHeaders = getWpAuthHeaders(project);
    const baseUrl = `https://${(project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '')}`;

    // Fetch published pages + posts from WP REST API — IN PARALLEL with short timeouts so the
    // whole request never exceeds the gateway limit (the old sequential 15s-per-call loop caused
    // "Request failed" on larger sites). Cap at 3 pages × 100 per type = up to 600 items.
    let allPages = [];
    const fetchWpPage = async (type, page) => {
      try {
        const resp = await fetch(`${wpUrl}/wp-json/wp/v2/${type}?per_page=100&page=${page}&status=publish&_fields=id,slug,title,link,type`, {
          headers: authHeaders, signal: AbortSignal.timeout(8000)
        });
        if (!resp.ok) return [];
        const items = await resp.json();
        if (!Array.isArray(items)) return [];
        return items.map(p => ({
          slug: p.slug,
          title: p.title?.rendered || '',
          url: p.link || `${baseUrl}/${p.slug}/`,
          path: `/${p.slug}/`,
          type: p.type
        }));
      } catch { return []; }
    };
    const jobs = [];
    for (const type of ['pages', 'posts']) for (let page = 1; page <= 3; page++) jobs.push(fetchWpPage(type, page));
    for (const batch of await Promise.all(jobs)) allPages.push(...batch);

    // Fallback: if WP REST returned nothing (auth/blocked), use sitemap discovery so matching still works.
    if (!allPages.length) {
      try {
        const disc = await discoverPages(baseUrl, project.wordpress_url, authHeaders);
        allPages = (disc || []).map(d => ({ slug: (d.slug || '').split('/').pop(), title: d.title || '', url: d.url, path: (() => { try { return new URL(d.url).pathname; } catch { return '/' + (d.slug || ''); } })(), type: d.wpType || 'page' }));
      } catch (e) {}
    }
    console.log(`[suggest-redirects] Found ${allPages.length} published pages/posts`);

    // Helper: extract words from a URL path
    const extractWords = (urlPath) => {
      return (urlPath || '').replace(/^\/|\/$/g, '').split(/[-_\/]/).filter(w => w.length > 2 && !/^\d+$/.test(w));
    };

    // Helper: calculate word overlap score
    const wordOverlap = (words1, words2) => {
      if (!words1.length || !words2.length) return 0;
      const set2 = new Set(words2.map(w => w.toLowerCase()));
      const matches = words1.filter(w => set2.has(w.toLowerCase())).length;
      return matches / Math.max(words1.length, words2.length);
    };

    // Match each 404 URL to best page
    const suggestions = {};
    for (const url404 of urls) {
      const path404 = url404.replace(/^https?:\/\/[^/]+/, '').replace(/\/$/, '');
      const slug404 = path404.split('/').filter(Boolean).pop() || '';
      const words404 = extractWords(path404);

      let bestMatch = null;
      let bestScore = 0;

      for (const page of allPages) {
        let score = 0;
        const pageSlug = page.slug || '';
        const pageWords = extractWords(page.path);

        // Exact slug match = highest score
        if (slug404 === pageSlug) { score = 1.0; }
        // Slug contains or is contained
        else if (slug404.includes(pageSlug) || pageSlug.includes(slug404)) {
          score = 0.7 + (0.2 * Math.min(slug404.length, pageSlug.length) / Math.max(slug404.length, pageSlug.length));
        }
        // Word overlap scoring
        else {
          score = wordOverlap(words404, pageWords) * 0.8;
        }

        // Boost if title words match 404 words
        const titleWords = (page.title || '').toLowerCase().split(/\s+/).filter(w => w.length > 2);
        const titleOverlap = wordOverlap(words404, titleWords);
        score += titleOverlap * 0.2;

        if (score > bestScore && score >= 0.15) {
          bestScore = score;
          bestMatch = { url: page.url, path: page.path, title: page.title, score: Math.round(score * 100), type: page.type };
        }
      }

      suggestions[url404] = bestMatch;
    }

    // Count matches
    const matched = Object.values(suggestions).filter(Boolean).length;
    console.log(`[suggest-redirects] Matched ${matched}/${urls.length} URLs`);

    res.json({ suggestions, total: urls.length, matched });
  } catch (e) {
    console.error(`[suggest-redirects] Error:`, e.message);
    res.status(500).json({ error: e.message });
  }
});

// POST /api/projects/:id/plugin/404s/diagnose — root cause analysis for 404s
app.post('/api/projects/:id/plugin/404s/diagnose', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const { urls, referrers } = req.body;
    if (!urls || !urls.length) return res.status(400).json({ error: 'No URLs to diagnose' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
    const baseUrl = `https://${domain}`;
    const fetchHeaders = { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' };

    // 1. Fetch sitemap and collect all URLs
    const sitemapUrlSet = new Set();
    const sitemapPaths = [`${baseUrl}/sitemap.xml`, `${baseUrl}/sitemap_index.xml`, `${baseUrl}/wp-sitemap.xml`];
    for (const smUrl of sitemapPaths) {
      try {
        const resp = await fetch(smUrl, { headers: fetchHeaders, signal: AbortSignal.timeout(10000), redirect: 'follow' });
        if (!resp.ok) continue;
        const xml = await resp.text();
        if (xml.includes('Cloudflare') && xml.includes('Ray ID')) continue;
        const locMatches = xml.match(/<loc>([^<]+)<\/loc>/g) || [];
        for (const m of locMatches) {
          const url = m.replace(/<\/?loc>/g, '');
          if (url.endsWith('.xml')) {
            // Sub-sitemap — fetch it
            try {
              const subResp = await fetch(url, { headers: fetchHeaders, signal: AbortSignal.timeout(10000) });
              if (subResp.ok) {
                const subXml = await subResp.text();
                const subLocs = subXml.match(/<loc>([^<]+)<\/loc>/g) || [];
                for (const sl of subLocs) {
                  const su = sl.replace(/<\/?loc>/g, '');
                  if (!su.endsWith('.xml')) sitemapUrlSet.add(su.replace(/\/$/, ''));
                }
              }
            } catch {}
          } else {
            sitemapUrlSet.add(url.replace(/\/$/, ''));
          }
        }
        if (sitemapUrlSet.size > 0) break;
      } catch {}
    }
    console.log(`[404-diagnose] Sitemap has ${sitemapUrlSet.size} URLs`);

    // 2. Quick internal link scan — crawl top pages to find broken links
    const wpUrl = project.wordpress_url || null;
    const authHeaders = getWpAuthHeaders(project);
    const allPages = await discoverPages(baseUrl, wpUrl, authHeaders);
    const pagesToScan = allPages.slice(0, 25);

    // Build map: normalized target URL → Set of source page URLs
    const linkSources = new Map();
    const SCAN_BATCH = 5;
    for (let i = 0; i < pagesToScan.length; i += SCAN_BATCH) {
      if (i > 0) await new Promise(r => setTimeout(r, 300));
      const batch = pagesToScan.slice(i, i + SCAN_BATCH);
      await Promise.allSettled(batch.map(async (page) => {
        try {
          const resp = await fetch(page.url, { headers: fetchHeaders, signal: AbortSignal.timeout(15000), redirect: 'follow' });
          if (!resp.ok) return;
          const html = await resp.text();
          const linkMatches = html.match(/<a[^>]*href=["']([^"'#]*?)["'][^>]*>/gi) || [];
          for (const link of linkMatches) {
            const hrefMatch = link.match(/href=["']([^"'#]*?)["']/i);
            if (!hrefMatch) continue;
            let href = hrefMatch[1];
            if (href.startsWith('mailto:') || href.startsWith('tel:') || href.startsWith('javascript:')) continue;
            if (href.startsWith('/')) href = baseUrl + href;
            else if (!href.startsWith('http')) continue;
            if (!href.includes(domain)) continue;
            const normalized = href.replace(/\/$/, '');
            if (!linkSources.has(normalized)) linkSources.set(normalized, new Set());
            linkSources.get(normalized).add(page.url);
          }
        } catch {}
      }));
    }
    console.log(`[404-diagnose] Scanned ${pagesToScan.length} pages, ${linkSources.size} unique link targets`);

    // 3. Diagnose each 404 URL
    const diagnoses = {};
    for (const url of urls) {
      // Normalize: handle both full URLs and paths
      const normalizedUrl = url.startsWith('http')
        ? url.replace(/\/$/, '')
        : `${baseUrl}${url.startsWith('/') ? '' : '/'}${url}`.replace(/\/$/, '');
      const causes = [];
      const details = {};

      // Check sitemap
      if (sitemapUrlSet.has(normalizedUrl)) {
        causes.push('sitemap');
        details.in_sitemap = true;
      }

      // Check internal links (from crawl scan)
      const sources = linkSources.get(normalizedUrl);
      if (sources && sources.size > 0) {
        causes.push('internal_link');
        details.linked_from = Array.from(sources).slice(0, 5);
      }

      // Check referrer (from plugin data) — must check hostname AND referrer must be a real page
      const referrer = referrers ? referrers[url] : null;
      if (referrer) details.referrer = referrer; // capture for tracking, even if external (e.g. Google)
      if (referrer) {
        let referrerHost = '';
        try { referrerHost = new URL(referrer).hostname.replace(/^www\./, ''); } catch {}
        const isDomainReferrer = referrerHost === domain.replace(/^www\./, '');
        // Normalize referrer path for comparison
        const referrerPath = referrer.replace(/^https?:\/\/[^/]+/, '').replace(/\/$/, '').toLowerCase();
        // Skip if the referrer path matches ANY 404 URL path (normalize both sides)
        const allPaths = urls.map(u => {
          if (u.startsWith('http')) return u.replace(/^https?:\/\/[^/]+/, '').replace(/\/$/, '').toLowerCase();
          return u.replace(/\/$/, '').toLowerCase();
        });
        const referrerIsAlso404 = allPaths.some(p => p === referrerPath || p === referrerPath + '/' || referrerPath === p + '/');
        // Skip common bot-probing / non-page paths
        const junkPaths = ['/wp/', '/wp-admin', '/backup', '/old/', '/login', '/admin', '/xmlrpc', '/wp-login', '/wp-cron',
          '/api/', '/api/config', '/api/settings', '/api/health', '/api/v1', '/elementor-', '/graphql', '/config', '/env',
          '/.env', '/.git', '/.well-known', '/debug', '/test', '/phpinfo', '/server-status', '/actuator'];
        const isJunkReferrer = junkPaths.some(jp => referrerPath.toLowerCase().startsWith(jp));
        if (isDomainReferrer && !referrerIsAlso404 && !isJunkReferrer && !causes.includes('internal_link')) {
          // Extra check: verify the referrer was found in the crawl scan (it's a real live page)
          const referrerFull = referrer.replace(/^http:/, 'https:').replace(/\/$/, '');
          const referrerInCrawl = linkSources.size > 0 && [...linkSources.values()].some(srcSet => {
            for (const s of srcSet) { if (s.replace(/\/$/, '') === referrerFull) return true; }
            return false;
          });
          // Only trust referrer as internal link if it was in the crawl scan OR exists in sitemap
          const referrerNorm = referrerFull.replace(/^https?:\/\/www\./, 'https://');
          const referrerInSitemap = sitemapUrlSet.has(referrerFull) || sitemapUrlSet.has(referrerNorm);
          if (referrerInCrawl || referrerInSitemap) {
            causes.push('internal_link');
            details.linked_from = [referrer];
          }
        }
      }

      // If no causes → orphan (old Google index)
      if (causes.length === 0) {
        causes.push('orphan');
      }

      // Fix recommendations per cause — each explains WHY so the problem is trackable
      const fixes = [];
      let reason = '';
      if (causes.includes('sitemap')) {
        reason = 'Listed in your XML sitemap, but the page returns 404.';
        fixes.push('Remove this URL from the sitemap (Yoast SEO → exclude, or your sitemap plugin), then resubmit the sitemap in Google Search Console. If the page just moved, 301-redirect it to the new URL instead.');
      }
      if (causes.includes('internal_link')) {
        const linked = details.linked_from || [];
        const srcList = linked.map(u => (u.replace(baseUrl, '') || '/')).slice(0, 3).join(', ');
        reason = `A live page on your site links to this missing URL (${linked.length} source${linked.length !== 1 ? 's' : ''}).`;
        fixes.push('Update or remove the broken <a> link on: ' + srcList + '. If the target moved, 301-redirect this URL to the correct page so the link still works.');
      }
      if (causes.includes('orphan')) {
        if (details.referrer) {
          let refHost = ''; try { refHost = new URL(details.referrer).hostname.replace(/^www\./, ''); } catch {}
          const external = refHost && refHost !== domain.replace(/^www\./, '');
          reason = `Not linked on your site and not in your sitemap. The last hit came from ${details.referrer}${external ? ' (an external site/search engine still pointing here)' : ''}.`;
          fixes.push(external
            ? 'An external link or old search result still points here. If the page moved, 301-redirect it to the new URL to keep that traffic; if it is gone, return 410 Gone so Google drops it.'
            : 'If this page moved or was renamed, 301-redirect it to the new URL (recovers lost traffic/links); if it is gone for good, return 410 Gone and use the GSC Removal tool.');
        } else {
          reason = 'Not linked anywhere on your site, not in your sitemap, and no referrer was recorded — most likely an old, renamed or deleted URL that Google (or an external site) still has indexed.';
          fixes.push('To find the source, check Google Search Console → Pages (or your server access logs) for where the hits come from. Then: if the page moved/was renamed, 301-redirect it to the closest live page (recovers traffic + link equity); if it is permanently gone, return 410 Gone and use the GSC Removal tool to de-index it faster.');
        }
      }

      // If we still couldn't pin a clear cause, say so plainly instead of leaving a vague message
      if (!reason) {
        reason = 'Cause unclear from the data we have. This URL returns 404 but we found no sitemap entry, internal link, or referrer.';
        fixes.push('Check Google Search Console → Pages and your server access logs to see how this URL is being requested, then redirect (if it moved) or return 410 Gone (if it is gone).');
      }

      diagnoses[url] = { causes, reason, ...details, fixes };
    }

    res.json({ diagnoses, sitemap_urls: sitemapUrlSet.size, pages_scanned: pagesToScan.length });
  } catch (e) {
    console.error(`[404-diagnose] Error:`, e.message);
    res.status(500).json({ error: e.message });
  }
});

// POST /api/projects/:id/plugin/404s/fix-link — fix a broken internal link on a source page via WP REST API
app.post('/api/projects/:id/plugin/404s/fix-link', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const { source_url, broken_url, replacement_url, action } = req.body;
    // action: 'replace' (swap href) or 'remove' (remove the <a> tag, keep text)
    if (!source_url || !broken_url) return res.status(400).json({ error: 'source_url and broken_url required' });

    const wpUrl = (project.wordpress_url || '').replace(/\/$/, '');
    const authHeaders = getWpAuthHeaders(project);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'WordPress URL and credentials required' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
    const baseUrl = `https://${domain}`;

    // Find the WP page/post by URL — try slug matching
    const sourcePath = source_url.replace(/^https?:\/\/[^/]+/, '').replace(/^\/|\/$/g, '');
    const sourceSlug = sourcePath.split('/').filter(Boolean).pop() || '';

    let wpPageId = null;
    let wpPageContent = null;
    let wpPostType = null;

    // Search pages then posts by slug
    for (const postType of ['pages', 'posts']) {
      try {
        const searchResp = await fetch(`${wpUrl}/wp-json/wp/v2/${postType}?slug=${encodeURIComponent(sourceSlug)}&_fields=id,content,slug,link`, {
          headers: { ...authHeaders, 'User-Agent': 'SEORoom-Dashboard/5.0' },
          signal: AbortSignal.timeout(15000)
        });
        if (searchResp.ok) {
          const items = await searchResp.json();
          if (items.length > 0) {
            wpPageId = items[0].id;
            wpPageContent = items[0].content?.rendered || '';
            wpPostType = postType;
            break;
          }
        }
      } catch {}
    }

    // Build the broken href patterns to search for (handle relative and absolute)
    const brokenPath = broken_url.replace(/^https?:\/\/[^/]+/, '');
    const brokenPatterns = [broken_url, brokenPath];
    if (!brokenPath.endsWith('/')) brokenPatterns.push(brokenPath + '/');
    if (brokenPath.endsWith('/')) brokenPatterns.push(brokenPath.replace(/\/$/, ''));
    if (!broken_url.startsWith('http')) {
      brokenPatterns.push(baseUrl + brokenPath);
      brokenPatterns.push(baseUrl + brokenPath + '/');
    }
    const brokenSet = new Set(brokenPatterns.map(p => p.toLowerCase()));

    let totalFixes = 0;
    const fixDetails = [];

    // ── Strategy 1: Fix in page/post content ──
    if (wpPageId) {
      // Fetch raw content (rendered may differ from raw)
      try {
        const rawResp = await fetch(`${wpUrl}/wp-json/wp/v2/${wpPostType}/${wpPageId}?context=edit&_fields=content`, {
          headers: { ...authHeaders, 'User-Agent': 'SEORoom-Dashboard/5.0' },
          signal: AbortSignal.timeout(15000)
        });
        if (rawResp.ok) {
          const rawData = await rawResp.json();
          wpPageContent = rawData.content?.raw || wpPageContent;
        }
      } catch {}

      if (wpPageContent) {
        let updatedContent = wpPageContent;
        let fixCount = 0;
        if (action === 'remove') {
          for (const pattern of brokenPatterns) {
            const escaped = pattern.replace(/[.*+?^${}()|[\]\\\/]/g, '\\$&');
            const regex = new RegExp(`<a[^>]*href=["']${escaped}["'][^>]*>(.*?)<\\/a>`, 'gi');
            const before = updatedContent;
            updatedContent = updatedContent.replace(regex, '$1');
            if (updatedContent !== before) fixCount++;
          }
        } else {
          for (const pattern of brokenPatterns) {
            const escaped = pattern.replace(/[.*+?^${}()|[\]\\\/]/g, '\\$&');
            const regex = new RegExp(`(href=["'])${escaped}(["'])`, 'gi');
            const before = updatedContent;
            updatedContent = updatedContent.replace(regex, `$1${replacement_url}$2`);
            if (updatedContent !== before) fixCount++;
          }
        }
        if (fixCount > 0) {
          await pool.query(
            `INSERT INTO wp_change_history (project_id, page_id, page_url, page_title, change_type, field_name, original_value, new_value) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`,
            [project.id, wpPageId, source_url, sourceSlug, 'fix_broken_link', 'content', broken_url, action === 'remove' ? '[link removed]' : replacement_url]
          );
          const updateResp = await fetch(`${wpUrl}/wp-json/wp/v2/${wpPostType}/${wpPageId}`, {
            method: 'POST',
            headers: { ...authHeaders, 'Content-Type': 'application/json', 'User-Agent': 'SEORoom-Dashboard/5.0' },
            body: JSON.stringify({ content: updatedContent }),
            signal: AbortSignal.timeout(15000)
          });
          if (updateResp.ok) {
            totalFixes += fixCount;
            fixDetails.push({ location: 'page_content', slug: sourceSlug, fixes: fixCount });
          }
        }
      }
    }

    // ── Strategy 2: Fix in Elementor data (_elementor_data post meta) ──
    if (wpPageId && totalFixes === 0) {
      try {
        // Fetch Elementor JSON from post meta
        const metaResp = await fetch(`${wpUrl}/wp-json/wp/v2/${wpPostType}/${wpPageId}?context=edit&_fields=meta`, {
          headers: { ...authHeaders, 'User-Agent': 'SEORoom-Dashboard/5.0' },
          signal: AbortSignal.timeout(15000)
        });
        if (metaResp.ok) {
          const metaData = await metaResp.json();
          let elementorJson = metaData.meta?._elementor_data || metaData.meta?.['_elementor_data'] || '';
          if (typeof elementorJson === 'string' && elementorJson.length > 10) {
            let changed = false;
            for (const pattern of brokenPatterns) {
              const escaped = pattern.replace(/[.*+?^${}()|[\]\\\/]/g, '\\$&');
              if (action === 'remove') {
                // In Elementor JSON, links are in "url" fields — set to empty
                const regex = new RegExp(escaped.replace(/\//g, '\\\\/'), 'gi');
                const before = elementorJson;
                elementorJson = elementorJson.replace(regex, '');
                if (elementorJson !== before) changed = true;
              } else {
                const regex = new RegExp(escaped.replace(/\//g, '\\\\/'), 'gi');
                const before = elementorJson;
                elementorJson = elementorJson.replace(regex, replacement_url.replace(/\//g, '\\/'));
                if (elementorJson !== before) changed = true;
              }
            }
            if (changed) {
              const elUpdateResp = await fetch(`${wpUrl}/wp-json/wp/v2/${wpPostType}/${wpPageId}`, {
                method: 'POST',
                headers: { ...authHeaders, 'Content-Type': 'application/json', 'User-Agent': 'SEORoom-Dashboard/5.0' },
                body: JSON.stringify({ meta: { _elementor_data: elementorJson } }),
                signal: AbortSignal.timeout(15000)
              });
              if (elUpdateResp.ok) {
                totalFixes++;
                fixDetails.push({ location: 'elementor_data', slug: sourceSlug, fixes: 1 });
                await pool.query(
                  `INSERT INTO wp_change_history (project_id, page_id, page_url, page_title, change_type, field_name, original_value, new_value) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`,
                  [project.id, wpPageId, source_url, sourceSlug, 'fix_broken_link', 'elementor_data', broken_url, action === 'remove' ? '[link removed]' : replacement_url]
                );
              }
            }
          }
        }
      } catch (elErr) { console.log(`[fix-link] Elementor check skipped:`, elErr.message); }
    }

    // ── Strategy 3: Fix in WordPress navigation menus ──
    if (totalFixes === 0) {
      try {
        // WP 5.9+ exposes menu items via REST API
        // Try /wp/v2/menu-items first, fall back to /menus/v1/menus
        const menuResp = await fetch(`${wpUrl}/wp-json/wp/v2/menu-items?per_page=100&_fields=id,url,title,status`, {
          headers: { ...authHeaders, 'User-Agent': 'SEORoom-Dashboard/5.0' },
          signal: AbortSignal.timeout(15000)
        });
        if (menuResp.ok) {
          const menuItems = await menuResp.json();
          for (const mi of menuItems) {
            const miUrl = (mi.url || '').toLowerCase().replace(/\/$/, '');
            if (brokenSet.has(miUrl) || brokenSet.has(miUrl + '/')) {
              const newUrl = action === 'remove' ? '#' : replacement_url;
              const fixResp = await fetch(`${wpUrl}/wp-json/wp/v2/menu-items/${mi.id}`, {
                method: 'POST',
                headers: { ...authHeaders, 'Content-Type': 'application/json', 'User-Agent': 'SEORoom-Dashboard/5.0' },
                body: JSON.stringify({ url: newUrl }),
                signal: AbortSignal.timeout(15000)
              });
              if (fixResp.ok) {
                totalFixes++;
                fixDetails.push({ location: 'nav_menu', menu_item_id: mi.id, old_url: mi.url, fixes: 1 });
                await pool.query(
                  `INSERT INTO wp_change_history (project_id, page_id, page_url, page_title, change_type, field_name, original_value, new_value) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`,
                  [project.id, mi.id, mi.url, 'Menu: ' + (mi.title?.rendered || mi.title || ''), 'fix_broken_link', 'menu_url', broken_url, newUrl]
                );
              }
            }
          }
        }
      } catch (menuErr) { console.log(`[fix-link] Menu check skipped:`, menuErr.message); }
    }

    // ── Strategy 4: Search ALL pages/posts for the broken link ──
    if (totalFixes === 0 && !wpPageId) {
      // Source page not found by slug — try search across all content
      try {
        for (const postType of ['pages', 'posts']) {
          const searchResp = await fetch(`${wpUrl}/wp-json/wp/v2/${postType}?per_page=50&search=${encodeURIComponent(brokenPath)}&context=edit&_fields=id,content,slug,link`, {
            headers: { ...authHeaders, 'User-Agent': 'SEORoom-Dashboard/5.0' },
            signal: AbortSignal.timeout(20000)
          });
          if (!searchResp.ok) continue;
          const items = await searchResp.json();
          for (const item of items) {
            const raw = item.content?.raw || item.content?.rendered || '';
            if (!raw) continue;
            let updated = raw;
            let found = false;
            for (const pattern of brokenPatterns) {
              const escaped = pattern.replace(/[.*+?^${}()|[\]\\\/]/g, '\\$&');
              if (action === 'remove') {
                const regex = new RegExp(`<a[^>]*href=["']${escaped}["'][^>]*>(.*?)<\\/a>`, 'gi');
                const before = updated;
                updated = updated.replace(regex, '$1');
                if (updated !== before) found = true;
              } else {
                const regex = new RegExp(`(href=["'])${escaped}(["'])`, 'gi');
                const before = updated;
                updated = updated.replace(regex, `$1${replacement_url}$2`);
                if (updated !== before) found = true;
              }
            }
            if (found) {
              await pool.query(
                `INSERT INTO wp_change_history (project_id, page_id, page_url, page_title, change_type, field_name, original_value, new_value) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`,
                [project.id, item.id, item.link || source_url, item.slug || '', 'fix_broken_link', 'content', broken_url, action === 'remove' ? '[link removed]' : replacement_url]
              );
              const updateResp = await fetch(`${wpUrl}/wp-json/wp/v2/${postType}/${item.id}`, {
                method: 'POST',
                headers: { ...authHeaders, 'Content-Type': 'application/json', 'User-Agent': 'SEORoom-Dashboard/5.0' },
                body: JSON.stringify({ content: updated }),
                signal: AbortSignal.timeout(15000)
              });
              if (updateResp.ok) {
                totalFixes++;
                fixDetails.push({ location: 'search_' + postType, slug: item.slug, page_id: item.id, fixes: 1 });
              }
            }
          }
        }
      } catch (searchErr) { console.log(`[fix-link] Content search error:`, searchErr.message); }
    }

    if (totalFixes === 0) {
      return res.json({ success: false, message: 'Broken link not found in page content, Elementor data, or navigation menus. It may be in a theme template, widget, or custom shortcode.' });
    }

    console.log(`[fix-link] Fixed ${totalFixes} broken link(s): ${broken_url} → ${action === 'remove' ? 'removed' : replacement_url}`, fixDetails);
    res.json({ success: true, fixes: totalFixes, details: fixDetails });
  } catch (e) {
    console.error(`[fix-link] Error:`, e.message);
    res.status(500).json({ error: e.message });
  }
});

