// Push redirects (standalone — uses migration's own WP creds)
app.post('/api/migrations/:migrationId/push-redirects', async (req, res) => {
  try {
    const migration = (await pool.query(`SELECT * FROM seo_migrations WHERE id=$1`, [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const urlMap = migration.url_map || [];
    if (urlMap.length === 0) return res.status(400).json({ error: 'No URL matches to redirect' });

    // Get WP credentials — from migration itself or from linked project
    let wpUrl = migration.wp_url;
    let authHeaders = null;
    if (wpUrl && migration.wp_username && migration.wp_app_password) {
      const token = Buffer.from(migration.wp_username + ':' + migration.wp_app_password).toString('base64');
      authHeaders = { Authorization: 'Basic ' + token };
    } else if (migration.project_id) {
      const project = (await pool.query(`SELECT * FROM projects WHERE id=$1`, [migration.project_id])).rows[0];
      if (project) { wpUrl = project.wp_url?.replace(/\/$/, ''); authHeaders = getWpAuthHeaders(project); }
    }
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'WordPress credentials not configured. Add WP URL, username and app password to the migration.' });

    const axios = require('axios');
    let pushed = 0;
    const errors = [];
    for (const match of urlMap) {
      if (!match.old_url || !match.new_url) continue;
      if (match.included === false) continue;
      try {
        const oldPath = new URL(match.old_url).pathname;
        const newPath = match.new_url.startsWith('http') ? new URL(match.new_url).pathname : match.new_url;
        await axios.post(`${wpUrl}/wp-json/seoroom/v1/redirects`, { source_url: oldPath, target_url: newPath, redirect_type: 301, notes: `Migration: ${match.reason || 'AI matched'}` }, { headers: authHeaders, timeout: 10000 });
        pushed++;
      } catch (e) { errors.push({ url: match.old_url, error: e.response?.data?.message || e.message }); }
    }
    await pool.query(`UPDATE seo_migrations SET redirects_pushed = $1, phase = 'redirects_pushed', status = 'executing', updated_at = NOW() WHERE id = $2`, [pushed, migration.id]);
    res.json({ pushed, total: urlMap.length, errors });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Transfer meta (standalone)
app.post('/api/migrations/:migrationId/transfer-meta', async (req, res) => {
  try {
    const migration = (await pool.query(`SELECT * FROM seo_migrations WHERE id=$1`, [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    let wpUrl = migration.wp_url;
    let authHeaders = null;
    if (wpUrl && migration.wp_username && migration.wp_app_password) {
      const token = Buffer.from(migration.wp_username + ':' + migration.wp_app_password).toString('base64');
      authHeaders = { Authorization: 'Basic ' + token };
    } else if (migration.project_id) {
      const project = (await pool.query(`SELECT * FROM projects WHERE id=$1`, [migration.project_id])).rows[0];
      if (project) { wpUrl = project.wp_url?.replace(/\/$/, ''); authHeaders = getWpAuthHeaders(project); }
    }
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'WordPress credentials not configured' });
    const urlMap = migration.url_map || [];
    const oldPages = migration.old_crawl || [];
    const axios = require('axios');
    let transferred = 0;
    for (const match of urlMap) {
      if (match.included === false) continue;
      const oldPage = oldPages.find(p => p.url === match.old_url);
      if (!oldPage || (!oldPage.title && !oldPage.meta_desc)) continue;
      try {
        const newPath = match.new_url.startsWith('http') ? new URL(match.new_url).pathname : match.new_url;
        const slug = newPath.replace(/\/$/, '').split('/').pop();
        if (!slug) continue;
        let wpPage = null;
        try { const r = await axios.get(`${wpUrl}/wp-json/wp/v2/pages?slug=${slug}&_fields=id`, { headers: authHeaders, timeout: 10000 }); if (r.data.length > 0) wpPage = { id: r.data[0].id, type: 'pages' }; } catch(e) {}
        if (!wpPage) { try { const r = await axios.get(`${wpUrl}/wp-json/wp/v2/posts?slug=${slug}&_fields=id`, { headers: authHeaders, timeout: 10000 }); if (r.data.length > 0) wpPage = { id: r.data[0].id, type: 'posts' }; } catch(e) {} }
        if (!wpPage) continue;
        const meta = {};
        if (oldPage.title) meta['_yoast_wpseo_title'] = oldPage.title;
        if (oldPage.meta_desc) meta['_yoast_wpseo_metadesc'] = oldPage.meta_desc;
        await axios.post(`${wpUrl}/wp-json/wp/v2/${wpPage.type}/${wpPage.id}`, { meta }, { headers: authHeaders, timeout: 10000 });
        transferred++;
      } catch (e) { console.error('[migration] Transfer meta error for', match.old_url, e.message); }
    }
    res.json({ transferred, total: urlMap.length });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// ==================== MIGRATION PAGE CLONING (old content → new-site Elementor templates) ====================

async function getMigrationWp(migration) {
  let wpUrl = migration.wp_url ? migration.wp_url.replace(/\/$/, '') : null;
  let authHeaders = null;
  if (wpUrl && migration.wp_username && migration.wp_app_password) {
    const token = Buffer.from(migration.wp_username + ':' + migration.wp_app_password).toString('base64');
    authHeaders = { Authorization: 'Basic ' + token };
  } else if (migration.project_id) {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [migration.project_id])).rows[0];
    if (project) { wpUrl = (project.wp_url || project.wordpress_url || '').replace(/\/$/, ''); authHeaders = getWpAuthHeaders(project); }
  }
  return { wpUrl, authHeaders };
}

function detectCloneType(url) {
  try {
    const u = new URL(url);
    const path = u.pathname.replace(/\/+$/, '').toLowerCase();
    if (path === '' || path === '/') return 'home';
    if (/\/blog\/|\/news\/|\/article|\/post\/|\/\d{4}\/\d{2}\//.test(url.toLowerCase())) return 'blog';
    return 'suburb';
  } catch (e) { return 'suburb'; }
}

function escCloneHtml(s) {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// Fetch an old page and pull ordered TEXT blocks. Drops images and links (entire <a> tag + text removed).
async function extractOldPageBlocks(url) {
  const resp = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0 SEORoom-Clone/5.0' }, redirect: 'follow', signal: AbortSignal.timeout(60000) });
  if (!resp.ok) throw new Error(`Old page returned ${resp.status}`);
  const html = await resp.text();
  let title = '';
  const tm = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  if (tm) title = tm[1].replace(/\s*[|\-–—]\s*[^|\-–—]*$/, '').replace(/<[^>]+>/g, '').trim();
  const region = (html.match(/<main[^>]*>([\s\S]*?)<\/main>/i) ||
                  html.match(/<article[^>]*>([\s\S]*?)<\/article>/i) ||
                  html.match(/<div[^>]*class="[^"]*(?:entry-content|elementor)[^"]*"[^>]*>([\s\S]*)<\/div>/i) ||
                  [null, html])[1] || html;
  const body = region
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<form[\s\S]*?<\/form>/gi, '')
    .replace(/<img[^>]*>/gi, '')
    .replace(/<a\b[^>]*>([\s\S]*?)<\/a>/gi, '');
  const decode = (t) => t.replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#8217;|&rsquo;|&#039;|&#39;/g, "'")
    .replace(/&#8220;|&#8221;|&ldquo;|&rdquo;|&quot;/g, '"').replace(/&#8211;|&ndash;/g, '–').replace(/&#8212;|&mdash;/g, '—')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/\s+/g, ' ').trim();
  const blocks = [];
  const re = /<(h1|h2|h3|h4|p|li)\b[^>]*>([\s\S]*?)<\/\1>/gi;
  let m;
  while ((m = re.exec(body)) !== null) {
    const tag = m[1].toLowerCase();
    const text = decode(m[2]);
    if (!text || text.length < 2) continue;
    blocks.push({ tag, text });
  }
  // Dedup consecutive identical texts
  const deduped = [];
  for (const b of blocks) { if (!deduped.length || deduped[deduped.length - 1].text !== b.text) deduped.push(b); }
  // Group consecutive li items into single blocks with pre-formatted HTML
  const out = [];
  let liBuffer = [];
  const flushLi = () => {
    if (!liBuffer.length) return;
    const plainText = liBuffer.join('; ');
    const html = '<ul>' + liBuffer.map(t => `<li>${escCloneHtml(t)}</li>`).join('') + '</ul>';
    out.push({ tag: 'p', text: plainText, html });
    liBuffer = [];
  };
  for (const b of deduped) {
    if (b.tag === 'li') { liBuffer.push(b.text); }
    else { flushLi(); out.push(b); }
  }
  flushLi();
  if (!title && out.length) { const h = out.find(b => b.tag === 'h1'); title = h ? h.text : out[0].text; }
  // Extract meta tags from <head>
  const metaTitle = (html.match(/<meta\s+(?:property="og:title"|name="title")\s+content="([^"]*?)"/i) || [])[1] || title;
  const metaDesc = (html.match(/<meta\s+name="description"\s+content="([^"]*?)"/i) || [])[1] || '';
  const focusKw = (html.match(/<meta\s+name="keywords"\s+content="([^"]*?)"/i) || [])[1] || '';
  return { title: title.slice(0, 180), blocks: out, meta: { metaTitle: metaTitle.slice(0, 180), metaDesc: metaDesc.slice(0, 320), focusKw: focusKw.slice(0, 100) } };
}

// Swap text in styled HTML template content. Replaces heading/paragraph text while preserving HTML structure.
function swapStyledHTML(templateHTML, newBlocks) {
  const newHeadings = newBlocks.filter(b => /^h[1-4]$/.test(b.tag));
  const newTexts = newBlocks.filter(b => b.tag === 'p' || b.tag === 'li');
  let hi = 0, ti = 0;
  // Replace headings (h1-h4) in order
  let result = templateHTML.replace(/<(h[1-4])(\b[^>]*)>([\s\S]*?)<\/\1>/gi, (match, tag, attrs, content) => {
    // Skip headings that look like nav/button items (very short or have specific classes)
    const plainText = content.replace(/<[^>]+>/g, '').trim();
    if (plainText.length < 2) return match; // skip empty
    if (hi < newHeadings.length) {
      const newText = escCloneHtml(newHeadings[hi++].text);
      return `<${tag}${attrs}>${newText}</${tag}>`;
    }
    return match;
  });
  // Replace paragraph/text content in order
  result = result.replace(/<p(\b[^>]*)>([\s\S]*?)<\/p>/gi, (match, attrs, content) => {
    const plainText = content.replace(/<[^>]+>/g, '').trim();
    if (plainText.length < 5) return match; // skip tiny/empty paragraphs
    if (ti < newTexts.length) {
      const block = newTexts[ti++];
      const newContent = block.html || `<p${attrs}>${escCloneHtml(block.text)}</p>`;
      if (block.html) return block.html; // grouped li blocks have their own HTML
      return `<p${attrs}>${escCloneHtml(block.text)}</p>`;
    }
    return match;
  });
  // Replace icon-list text items
  result = result.replace(/(<span[^>]*class="[^"]*elementor-icon-list-text[^"]*"[^>]*>)([\s\S]*?)(<\/span>)/gi, (match, open, content, close) => {
    if (ti < newTexts.length) return `${open}${escCloneHtml(newTexts[ti++].text)}${close}`;
    return match;
  });
  return { html: result, headingsSwapped: hi, textsSwapped: ti };
}

async function resolveNewWpPage(wpUrl, authHeaders, pageUrl) {
  const axios = require('axios');
  let path;
  try { path = pageUrl.startsWith('http') ? new URL(pageUrl).pathname : pageUrl; } catch (e) { path = pageUrl; }
  const slug = path.replace(/\/+$/, '').split('/').filter(Boolean).pop() || '';
  if (slug) {
    for (const type of ['pages', 'posts']) {
      try {
        const r = await axios.get(`${wpUrl}/wp-json/wp/v2/${type}?slug=${encodeURIComponent(slug)}&_fields=id`, { headers: authHeaders, timeout: 15000 });
        if (r.data && r.data.length) return { id: r.data[0].id, post_type: type };
      } catch (e) {}
    }
  } else {
    try { const r = await axios.get(`${wpUrl}/wp-json/wp/v2/pages?per_page=1&orderby=id&order=asc&_fields=id`, { headers: authHeaders, timeout: 15000 }); if (r.data && r.data.length) return { id: r.data[0].id, post_type: 'pages' }; } catch (e) {}
  }
  return null;
}

// Read a new-site page's Elementor data + all _elementor* meta + title/template
async function readElementorTemplate(wpUrl, authHeaders, postType, id) {
  const axios = require('axios');
  const r = await axios.get(`${wpUrl}/wp-json/wp/v2/${postType}/${id}?context=edit&_fields=id,title,meta,template`, { headers: authHeaders, timeout: 20000 });
  const meta = r.data.meta || {};
  let tree = null;
  const raw = meta._elementor_data;
  if (typeof raw === 'string' && raw.length > 5) { try { tree = JSON.parse(raw); } catch (e) { tree = null; } }
  const elMeta = {};
  for (const k of Object.keys(meta)) { if (k.indexOf('_elementor') === 0 && k !== '_elementor_data') elMeta[k] = meta[k]; }
  return { title: (r.data.title && (r.data.title.rendered || r.data.title.raw)) || '', tree, elMeta, template: r.data.template || '' };
}

function elementorReplaceIds(node) {
  if (Array.isArray(node)) { node.forEach(elementorReplaceIds); return; }
  if (node && typeof node === 'object') {
    if (typeof node.id === 'string') node.id = Math.random().toString(16).slice(2, 9);
    if (Array.isArray(node.elements)) node.elements.forEach(elementorReplaceIds);
  }
}

function collectElementorTextSlots(node, slots) {
  if (Array.isArray(node)) { node.forEach(n => collectElementorTextSlots(n, slots)); return; }
  if (!node || typeof node !== 'object') return;
  if (node.elType === 'widget' && node.settings) {
    const s = node.settings, wt = node.widgetType;
    if (wt === 'heading' && typeof s.title === 'string') slots.push({ obj: s, key: 'title', kind: 'heading' });
    else if (wt === 'text-editor' && typeof s.editor === 'string') slots.push({ obj: s, key: 'editor', kind: 'text' });
    else if ((wt === 'icon-box' || wt === 'image-box')) {
      if (typeof s.title_text === 'string') slots.push({ obj: s, key: 'title_text', kind: 'heading' });
      if (typeof s.description_text === 'string') slots.push({ obj: s, key: 'description_text', kind: 'text' });
    }
    // Icon-list widget: each item has a 'text' field — collect as a single text slot (joined)
    else if (wt === 'icon-list' && Array.isArray(s.icon_list)) {
      slots.push({ obj: s, key: 'icon_list', kind: 'icon-list' });
    }
    // Accordion / Toggle widgets: each tab has tab_title + tab_content
    else if ((wt === 'accordion' || wt === 'toggle') && Array.isArray(s.tabs)) {
      slots.push({ obj: s, key: 'tabs', kind: 'accordion' });
    }
  }
  if (Array.isArray(node.elements)) node.elements.forEach(n => collectElementorTextSlots(n, slots));
}

// Duplicate a template tree and pour old text blocks into its text slots. Images/links already excluded upstream.
function swapElementorText(tree, blocks) {
  const clone = JSON.parse(JSON.stringify(tree));
  elementorReplaceIds(clone);
  const slots = [];
  collectElementorTextSlots(clone, slots);
  if (!slots.length) throw new Error('Template has no editable Heading/Text widgets to pour content into. Pick a template page built from standard Elementor text widgets.');
  const headings = blocks.filter(b => /^h[1-4]$/.test(b.tag)).map(b => b.text);
  const textBlocks = blocks.filter(b => b.tag === 'p' || b.tag === 'li');
  const headingSlots = slots.filter(s => s.kind === 'heading');
  const textSlots = slots.filter(s => s.kind === 'text');
  let hi = 0, ti = 0;
  // 1. Fill heading slots
  headingSlots.forEach(sl => { sl.obj[sl.key] = hi < headings.length ? headings[hi++] : ''; });
  // 2. Fill text-editor slots one-to-one (no overflow into last slot)
  const formatTextBlock = (b) => b.html ? b.html : `<p>${escCloneHtml(b.text)}</p>`;
  textSlots.forEach(sl => {
    if (ti >= textBlocks.length) { sl.obj[sl.key] = ''; return; }
    sl.obj[sl.key] = formatTextBlock(textBlocks[ti++]);
  });
  // 3. Remove icon-list items (template defaults don't apply to cloned content)
  const iconListSlots = slots.filter(s => s.kind === 'icon-list');
  iconListSlots.forEach(sl => {
    if (Array.isArray(sl.obj[sl.key])) sl.obj[sl.key] = [];
  });
  // 4. Clear accordion/toggle slots
  const accordionSlots = slots.filter(s => s.kind === 'accordion');
  accordionSlots.forEach(sl => {
    const tabs = sl.obj[sl.key];
    if (Array.isArray(tabs)) tabs.forEach(tab => { tab.tab_title = ''; tab.tab_content = ''; });
  });
  // 5. Overflow: remaining blocks go into a new clean section appended to the tree
  const remainingText = textBlocks.slice(ti);
  const remainingHeadings = headings.slice(hi);
  if (remainingText.length || remainingHeadings.length) {
    let overflowHtml = '';
    // Interleave remaining headings and text in original block order
    const remainingBlocks = blocks.filter(b => {
      if (/^h[1-4]$/.test(b.tag)) return headings.indexOf(b.text) >= hi;
      return (b.tag === 'p' || b.tag === 'li') && textBlocks.indexOf(b) >= ti;
    });
    if (remainingBlocks.length) {
      overflowHtml = remainingBlocks.map(b => {
        if (/^h[1-4]$/.test(b.tag)) return `<h3>${escCloneHtml(b.text)}</h3>`;
        return b.html ? b.html : `<p>${escCloneHtml(b.text)}</p>`;
      }).join('');
    } else {
      // Fallback: just concat remaining
      if (remainingHeadings.length) overflowHtml += remainingHeadings.map(t => `<h3>${escCloneHtml(t)}</h3>`).join('');
      if (remainingText.length) overflowHtml += remainingText.map(formatTextBlock).join('');
    }
    const rId = () => Math.random().toString(16).slice(2, 9);
    const overflowSection = {
      id: rId(), elType: 'section',
      settings: { layout: 'boxed', content_width: { unit: 'px', size: 1140 }, padding: { unit: 'px', top: '40', bottom: '40', left: '0', right: '0', isLinked: false } },
      elements: [{
        id: rId(), elType: 'column',
        settings: { _column_size: 100 },
        elements: [{
          id: rId(), elType: 'widget', widgetType: 'text-editor',
          settings: { editor: overflowHtml },
          elements: []
        }]
      }]
    };
    // Insert before the last section (CTA) to keep CTA at the bottom
    if (Array.isArray(clone) && clone.length > 1) {
      clone.splice(clone.length - 1, 0, overflowSection);
    } else if (Array.isArray(clone)) {
      clone.push(overflowSection);
    }
    ti = textBlocks.length;
    hi = headings.length;
  }
  return { tree: clone, slots: slots.length, headingSlots: headingSlots.length, textSlots: textSlots.length,
    headingsTotal: headings.length, textsTotal: textBlocks.length, headingsUsed: headings.length, textsUsed: textBlocks.length };
}

async function createNewElementorPage(wpUrl, authHeaders, postType, title, tree, elMeta, template, status, overrideSlug) {
  const axios = require('axios');
  const slug = overrideSlug || (title || 'cloned-page').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60) || ('clone-' + Date.now());
  const meta = Object.assign({}, elMeta || {}, {
    _elementor_data: JSON.stringify(tree),
    _elementor_edit_mode: 'builder',
  });
  const payload = { title: title || 'Cloned page', status: status || 'draft', slug, meta };
  if (template) payload.template = template;
  const r = await axios.post(`${wpUrl}/wp-json/wp/v2/${postType}`, payload, { headers: Object.assign({}, authHeaders, { 'Content-Type': 'application/json' }), timeout: 60000 });
  return { id: r.data.id, link: r.data.link, slug: r.data.slug, post_type: postType };
}

// Build an auto-generated Elementor template from a source page's content structure
app.post('/api/migrations/:migrationId/build-template', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT * FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const { wpUrl, authHeaders } = await getMigrationWp(migration);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'New-site WordPress credentials not set.' });
    const { type, source_url } = req.body || {};
    if (!source_url) return res.status(400).json({ error: 'source_url required' });
    const pageType = type || 'suburb';

    // 1. Extract blocks from the source page
    console.log('[build-template] Step 1: extracting blocks from', source_url);
    const { title: srcTitle, blocks } = await extractOldPageBlocks(source_url);
    console.log('[build-template] Extracted', blocks.length, 'blocks from source');

    // 2. Build Elementor JSON — one section per h1/h2 heading group, with matching widgets
    const rid = () => Math.random().toString(16).slice(2, 9);
    const elSections = [];
    // Group blocks into logical sections (h1/h2 starts a new section)
    const groups = [];
    let cur = { headings: [], texts: [] };
    for (const b of blocks) {
      if (/^h[12]$/.test(b.tag) && (cur.headings.length || cur.texts.length)) {
        groups.push(cur);
        cur = { headings: [], texts: [] };
      }
      if (/^h[1-4]$/.test(b.tag)) cur.headings.push(b);
      else cur.texts.push(b);
    }
    if (cur.headings.length || cur.texts.length) groups.push(cur);

    // Build one Elementor section per content group
    for (const grp of groups) {
      const widgets = [];
      // Add heading widgets in order
      for (const h of grp.headings) {
        widgets.push({
          id: rid(), elType: 'widget', widgetType: 'heading',
          settings: { title: 'Heading placeholder', header_size: h.tag, align: 'left',
            title_color: '#1a1a2e', typography_typography: 'custom', typography_font_size: { unit: 'px', size: h.tag === 'h1' ? 36 : h.tag === 'h2' ? 28 : 22 } }
        });
      }
      // Add one text-editor widget for all text blocks in this group
      if (grp.texts.length) {
        widgets.push({
          id: rid(), elType: 'widget', widgetType: 'text-editor',
          settings: { editor: '<p>Content placeholder</p>' }
        });
      }
      if (!widgets.length) continue;
      elSections.push({
        id: rid(), elType: 'section',
        settings: { padding: { unit: 'px', top: '30', bottom: '30', left: '40', right: '40' } },
        elements: [{
          id: rid(), elType: 'column',
          settings: { _column_size: 100 },
          elements: widgets
        }]
      });
    }

    // 3. Create the page on the new site
    const pageTitle = `${pageType} template (auto)`;
    console.log('[build-template] Step 3: creating page with', elSections.length, 'sections on WP');
    const created = await createNewElementorPage(wpUrl, authHeaders, 'pages', pageTitle, elSections, {}, '', 'draft');
    console.log('[build-template] Created page', created.id);

    // 4. Read back to get slot count
    const tpl = await readElementorTemplate(wpUrl, authHeaders, 'pages', created.id);
    const tplSlots = [];
    if (tpl.tree) collectElementorTextSlots(tpl.tree, tplSlots);

    // 5. Update migration clone_templates
    const templates = Object.assign({}, migration.clone_templates || {});
    templates[pageType] = {
      url: created.link, page_id: created.id, post_type: 'pages',
      title: pageTitle, has_elementor: !!tpl.tree, text_slots: tplSlots.length,
      auto_generated: true, source_url
    };
    await pool.query('UPDATE seo_migrations SET clone_templates=$1, updated_at=NOW() WHERE id=$2', [JSON.stringify(templates), migration.id]);

    const headingCount = blocks.filter(b => /^h[1-4]$/.test(b.tag)).length;
    const textCount = blocks.filter(b => b.tag === 'p').length;
    res.json({
      ok: true, page_id: created.id, page_url: created.link, slug: created.slug,
      sections: elSections.length, slots: tplSlots.length,
      source_blocks: { headings: headingCount, texts: textCount, total: blocks.length },
      template_set: pageType
    });
  } catch (e) { console.error('[build-template]', e); res.status(500).json({ error: e.message }); }
});

// Copy the full visual design from an old-site page (rendered HTML + Elementor CSS).
// Creates a styled template on the new site that preserves the original look.
app.post('/api/migrations/:migrationId/copy-design', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT * FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const { wpUrl, authHeaders } = await getMigrationWp(migration);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'WordPress credentials not set.' });
    const { type, source_url } = req.body || {};
    if (!source_url) return res.status(400).json({ error: 'source_url required' });
    const pageType = type || 'suburb';

    // 1. Find the old page ID from the old site's REST API
    const oldDomain = new URL(source_url).origin;
    const slug = source_url.replace(/\/$/, '').split('/').pop();
    console.log('[copy-design] Fetching page data for slug:', slug, 'from', oldDomain);
    const pageResp = await fetch(`${oldDomain}/wp-json/wp/v2/pages?slug=${encodeURIComponent(slug)}&_fields=id,content,title`, { signal: AbortSignal.timeout(20000) });
    if (!pageResp.ok) throw new Error(`Old site REST API returned ${pageResp.status}`);
    const pages = await pageResp.json();
    if (!pages.length) throw new Error(`Page with slug "${slug}" not found on old site`);
    const oldPage = pages[0];
    const oldPageId = oldPage.id;
    const renderedHTML = oldPage.content?.rendered || '';
    const pageTitle = oldPage.title?.rendered || slug;
    console.log('[copy-design] Got page', oldPageId, 'with', renderedHTML.length, 'bytes of HTML');

    // 2. Fetch the page-specific Elementor CSS
    let pageCSS = '';
    try {
      const cssResp = await fetch(`${oldDomain}/wp-content/uploads/elementor/css/post-${oldPageId}.css`, { signal: AbortSignal.timeout(10000) });
      if (cssResp.ok) pageCSS = await cssResp.text();
    } catch (e) { console.log('[copy-design] No page CSS found:', e.message); }
    console.log('[copy-design] Page CSS:', pageCSS.length, 'bytes');

    // 3. Rewrite the CSS: change old page ID references to a generic wrapper class
    // Old CSS uses: .elementor-{oldPageId} .elementor-element.elementor-element-{id}
    // We'll wrap content in a div with class "elementor-{oldPageId}" so CSS still works
    const wrapperClass = `elementor-${oldPageId}`;

    // 4. Rewrite image URLs to be absolute (in case they're relative)
    let finalHTML = renderedHTML.replace(/src="\/wp-content/g, `src="${oldDomain}/wp-content`);
    finalHTML = finalHTML.replace(/url\(\/wp-content/g, `url(${oldDomain}/wp-content`);
    // Also fix CSS background images
    let finalCSS = pageCSS.replace(/url\(\/wp-content/g, `url(${oldDomain}/wp-content`);
    finalCSS = finalCSS.replace(/url\("\/wp-content/g, `url("${oldDomain}/wp-content`);

    // 5. Build the complete page content: CSS + wrapped HTML
    const fullContent = `<style>${finalCSS}</style>\n<div class="${wrapperClass}" data-elementor-type="wp-page">${finalHTML}</div>`;

    // 6. Create the page on the new site (as classic editor page, not Elementor)
    const axios = require('axios');
    const newSlug = `${pageType}-template-styled`;
    const payload = {
      title: `${pageType} template (styled)`,
      status: 'draft',
      slug: newSlug,
      content: fullContent
    };
    console.log('[copy-design] Creating styled page on new site...');
    const wpResp = await axios.post(`${wpUrl}/wp-json/wp/v2/pages`, payload, {
      headers: Object.assign({}, authHeaders, { 'Content-Type': 'application/json' }),
      timeout: 60000
    });
    const created = wpResp.data;
    console.log('[copy-design] Created page', created.id);

    // 7. Update migration clone_templates
    const templates = Object.assign({}, migration.clone_templates || {});
    templates[pageType] = {
      url: created.link, page_id: created.id, post_type: 'pages',
      title: payload.title, has_elementor: false, is_styled_html: true,
      old_page_id: oldPageId, wrapper_class: wrapperClass,
      source_url, css_length: finalCSS.length, html_length: finalHTML.length
    };
    await pool.query('UPDATE seo_migrations SET clone_templates=$1, updated_at=NOW() WHERE id=$2', [JSON.stringify(templates), migration.id]);

    res.json({
      ok: true, page_id: created.id, page_url: created.link, slug: created.slug,
      old_page_id: oldPageId, css_bytes: finalCSS.length, html_bytes: finalHTML.length,
      template_set: pageType
    });
  } catch (e) { console.error('[copy-design]', e); res.status(500).json({ error: e.message }); }
});

// Save the three clone templates (home/suburb/blog) by URL; resolve each on the new site.
app.put('/api/migrations/:migrationId/clone-templates', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT * FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const { wpUrl, authHeaders } = await getMigrationWp(migration);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'New-site WordPress credentials not set on this migration (Settings tab).' });
    const incoming = req.body || {};
    const templates = Object.assign({}, migration.clone_templates || {});
    const results = {};
    for (const type of ['home', 'service', 'suburb', 'blog']) {
      if (!(type in incoming)) continue;
      const url = (incoming[type] || '').trim();
      if (!url) { delete templates[type]; results[type] = { cleared: true }; continue; }
      const resolved = await resolveNewWpPage(wpUrl, authHeaders, url);
      if (!resolved) { results[type] = { error: 'Could not find that page on the new site' }; continue; }
      let tpl = null;
      try { tpl = await readElementorTemplate(wpUrl, authHeaders, resolved.post_type, resolved.id); } catch (e) { results[type] = { error: 'Read failed: ' + e.message }; continue; }
      const slots = [];
      if (tpl.tree) collectElementorTextSlots(tpl.tree, slots);
      templates[type] = { url, page_id: resolved.id, post_type: resolved.post_type, title: tpl.title, has_elementor: !!tpl.tree, text_slots: slots.length };
      results[type] = templates[type];
    }
    await pool.query('UPDATE seo_migrations SET clone_templates=$1, updated_at=NOW() WHERE id=$2', [JSON.stringify(templates), migration.id]);
    res.json({ ok: true, templates, results });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// List clones + current templates
app.get('/api/migrations/:migrationId/clones', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT clone_templates FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const rows = (await pool.query('SELECT * FROM migration_clones WHERE migration_id=$1 ORDER BY created_at ASC', [req.params.migrationId])).rows;
    res.json({ templates: migration.clone_templates || {}, clones: rows });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Add old URLs to clone (bulk). body: { urls: [string], type?: 'home'|'suburb'|'blog' }
app.post('/api/migrations/:migrationId/clones', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT id FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const urls = Array.isArray(req.body.urls) ? req.body.urls : [];
    const forcedType = req.body.type;
    let added = 0, skipped = 0;
    for (const raw of urls) {
      const url = (raw || '').toString().trim();
      if (!url || !/^https?:\/\//i.test(url)) { skipped++; continue; }
      const type = (forcedType === 'home' || forcedType === 'service' || forcedType === 'suburb' || forcedType === 'blog') ? forcedType : detectCloneType(url);
      const r = await pool.query(
        `INSERT INTO migration_clones (migration_id, old_url, page_type, status) VALUES ($1,$2,$3,'pending')
         ON CONFLICT (migration_id, old_url) DO NOTHING RETURNING id`,
        [migration.id, url.replace(/\/+$/, '') || url, type]
      );
      if (r.rows.length) added++; else skipped++;
    }
    const rows = (await pool.query('SELECT * FROM migration_clones WHERE migration_id=$1 ORDER BY created_at ASC', [migration.id])).rows;
    res.json({ ok: true, added, skipped, clones: rows });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

