// Run clone for selected ids (creates drafts on the new site)
app.post('/api/migrations/:migrationId/clones/run', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT * FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const { wpUrl, authHeaders } = await getMigrationWp(migration);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'New-site WordPress credentials not set on this migration (Settings tab).' });
    const templates = migration.clone_templates || {};
    const ids = (req.body.ids || []).map(n => parseInt(n, 10)).filter(Boolean);
    const where = ids.length ? 'AND id = ANY($2)' : '';
    const rows = (await pool.query(`SELECT * FROM migration_clones WHERE migration_id=$1 ${where} ORDER BY created_at ASC`, ids.length ? [migration.id, ids] : [migration.id])).rows;
    const results = [];
    for (const clone of rows) {
      try {
        const tplRef = templates[clone.page_type];
        if (!tplRef || !tplRef.page_id) throw new Error(`No ${clone.page_type} template set — add one in the Templates section.`);
        const { title, blocks, meta: oldMeta } = await extractOldPageBlocks(clone.old_url);
        if (!blocks.length) throw new Error('No readable text found on the old page.');
        const pageTitle = title || clone.old_url;
        let created;

        if (tplRef.is_styled_html) {
          // Styled HTML template: read page content, swap text in HTML, create new page
          const axios = require('axios');
          const tplPage = await axios.get(`${wpUrl}/wp-json/wp/v2/${tplRef.post_type}/${tplRef.page_id}?_fields=content`, { headers: authHeaders, timeout: 30000 });
          const templateHTML = tplPage.data.content?.rendered || tplPage.data.content?.raw || '';
          if (!templateHTML) throw new Error('Template page has no content.');
          const swapped = swapStyledHTML(templateHTML, blocks);
          const oldSlugHTML = clone.old_url ? new URL(clone.old_url).pathname.replace(/^\/|\/$/g, '').split('/').pop() : null;
          const slug = oldSlugHTML || (pageTitle || 'clone').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60);
          const newPage = await axios.post(`${wpUrl}/wp-json/wp/v2/${tplRef.post_type}`, {
            title: pageTitle, status: 'draft', slug, content: swapped.html
          }, { headers: Object.assign({}, authHeaders, { 'Content-Type': 'application/json' }), timeout: 60000 });
          created = { id: newPage.data.id, link: newPage.data.link, post_type: tplRef.post_type };
          await pool.query(
            `UPDATE migration_clones SET status='cloned', title=$1, blocks=$2, new_page_id=$3, new_page_url=$4, new_post_type=$5, error=NULL, updated_at=NOW() WHERE id=$6`,
            [pageTitle, JSON.stringify(blocks), created.id, created.link, created.post_type, clone.id]
          );
          results.push({ id: clone.id, status: 'cloned', new_page_url: created.link, blocks: blocks.length, headings: swapped.headingsSwapped, texts: swapped.textsSwapped });
        } else {
          // Elementor template: swap in Elementor JSON
          const tpl = await readElementorTemplate(wpUrl, authHeaders, tplRef.post_type, tplRef.page_id);
          if (!tpl.tree) throw new Error('Template page has no Elementor data.');
          const swapped = swapElementorText(tpl.tree, blocks);
          // Extract slug from old URL path to preserve URL structure
          const oldSlug = clone.old_url ? new URL(clone.old_url).pathname.replace(/^\/|\/$/g, '').split('/').pop() : null;
          created = await createNewElementorPage(wpUrl, authHeaders, tplRef.post_type, pageTitle, swapped.tree, tpl.elMeta, tpl.template, 'draft', oldSlug);
          await pool.query(
            `UPDATE migration_clones SET status='cloned', title=$1, blocks=$2, new_page_id=$3, new_page_url=$4, new_post_type=$5, error=NULL, updated_at=NOW() WHERE id=$6`,
            [pageTitle, JSON.stringify(blocks), created.id, created.link, created.post_type, clone.id]
          );
          results.push({ id: clone.id, status: 'cloned', new_page_url: created.link, blocks: blocks.length,
            slots: swapped.slots, headingSlots: swapped.headingSlots, textSlots: swapped.textSlots,
            headingsTotal: swapped.headingsTotal, textsTotal: swapped.textsTotal });
        }
        // Write Yoast meta tags from old page to new page
        if (oldMeta && created && (oldMeta.metaTitle || oldMeta.metaDesc)) {
          try {
            const axios = require('axios');
            const yoastMeta = {};
            if (oldMeta.metaTitle) yoastMeta._yoast_wpseo_title = oldMeta.metaTitle;
            if (oldMeta.metaDesc) yoastMeta._yoast_wpseo_metadesc = oldMeta.metaDesc;
            if (oldMeta.focusKw) yoastMeta._yoast_wpseo_focuskw = oldMeta.focusKw;
            await axios.post(`${wpUrl}/wp-json/wp/v2/${created.post_type}/${created.id}`, { meta: yoastMeta },
              { headers: Object.assign({}, authHeaders, { 'Content-Type': 'application/json' }), timeout: 15000 });
          } catch (metaErr) { console.error(`[clone] Yoast meta write failed for page ${created.id}:`, metaErr.message); }
        }
      } catch (e) {
        await pool.query(`UPDATE migration_clones SET status='error', error=$1, updated_at=NOW() WHERE id=$2`, [e.message.slice(0, 400), clone.id]);
        results.push({ id: clone.id, status: 'error', error: e.message });
      }
    }
    res.json({ ok: true, results });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Publish selected cloned drafts on the new site
app.post('/api/migrations/:migrationId/clones/publish', async (req, res) => {
  try {
    const migration = (await pool.query('SELECT * FROM seo_migrations WHERE id=$1', [req.params.migrationId])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });
    const { wpUrl, authHeaders } = await getMigrationWp(migration);
    if (!wpUrl || !authHeaders) return res.status(400).json({ error: 'New-site WordPress credentials not set.' });
    const axios = require('axios');
    const ids = (req.body.ids || []).map(n => parseInt(n, 10)).filter(Boolean);
    const where = ids.length ? 'AND id = ANY($2)' : '';
    const rows = (await pool.query(`SELECT * FROM migration_clones WHERE migration_id=$1 AND status='cloned' AND new_page_id IS NOT NULL ${where}`, ids.length ? [migration.id, ids] : [migration.id])).rows;
    let published = 0; const errors = [];
    for (const clone of rows) {
      try {
        await axios.post(`${wpUrl}/wp-json/wp/v2/${clone.new_post_type || 'pages'}/${clone.new_page_id}`, { status: 'publish' }, { headers: Object.assign({}, authHeaders, { 'Content-Type': 'application/json' }), timeout: 60000 });
        await pool.query(`UPDATE migration_clones SET status='published', updated_at=NOW() WHERE id=$1`, [clone.id]);
        published++;
      } catch (e) { errors.push({ id: clone.id, error: e.response?.data?.message || e.message }); }
    }
    res.json({ ok: true, published, errors });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

