// Shared crawl helper — discovers pages via sitemap, then fetches meta for each
async function crawlSiteForMigration(siteUrl) {
  const axios = require('axios');
  const pages = [];
  const visited = new Set();

  // Try sitemap first
  const sitemapUrls = [`${siteUrl}/sitemap.xml`, `${siteUrl}/sitemap_index.xml`];
  let pageUrls = [];

  const CRAWL_UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36';
  console.log(`[migration-crawl] Starting crawl for ${siteUrl}`);

  for (const smUrl of sitemapUrls) {
    try {
      console.log(`[migration-crawl] Trying sitemap: ${smUrl}`);
      const resp = await axios.get(smUrl, { timeout: 15000, headers: { 'User-Agent': CRAWL_UA } });
      const xml = resp.data;
      console.log(`[migration-crawl] Sitemap response: ${resp.status}, length: ${(typeof xml === 'string' ? xml.length : 0)}`);
      const locMatches = xml.match(/<loc>(.*?)<\/loc>/gi) || [];
      console.log(`[migration-crawl] Found ${locMatches.length} <loc> entries`);
      for (const loc of locMatches) {
        const url = loc.replace(/<\/?loc>/gi, '').trim();
        if (url.includes('sitemap') && url.endsWith('.xml')) {
          try {
            const subResp = await axios.get(url, { timeout: 15000, headers: { 'User-Agent': CRAWL_UA } });
            const subLocs = subResp.data.match(/<loc>(.*?)<\/loc>/gi) || [];
            console.log(`[migration-crawl] Sub-sitemap ${url}: ${subLocs.length} entries`);
            for (const subLoc of subLocs) {
              const subUrl = subLoc.replace(/<\/?loc>/gi, '').trim();
              if (!subUrl.includes('sitemap') && !subUrl.endsWith('.xml')) pageUrls.push(subUrl);
            }
          } catch (e) { console.log(`[migration-crawl] Sub-sitemap error: ${e.message}`); }
        } else {
          pageUrls.push(url);
        }
      }
      if (pageUrls.length > 0) break;
    } catch (e) { console.log(`[migration-crawl] Sitemap ${smUrl} error: ${e.message}`); }
  }

  // Also try WP REST API (paginated) — supplements sitemap, gets titles too
  console.log(`[migration-crawl] Trying WP REST API (paginated)...`);
  const wpTitleMap = {}; // url -> { title, slug }
  async function fetchAllWpType(type) {
    const allLinks = [];
    let page = 1;
    while (true) {
      try {
        const resp = await axios.get(`${siteUrl}/wp-json/wp/v2/${type}?per_page=100&page=${page}&_fields=link,title,slug`, { timeout: 10000, headers: { 'User-Agent': CRAWL_UA } });
        if (!resp.data || resp.data.length === 0) break;
        for (const p of resp.data) {
          allLinks.push(p.link);
          if (p.title?.rendered) wpTitleMap[p.link] = { title: p.title.rendered, slug: p.slug || '' };
        }
        const totalPages = parseInt(resp.headers['x-wp-totalpages'] || '1');
        console.log(`[migration-crawl] WP ${type} page ${page}/${totalPages}: ${resp.data.length} items`);
        if (page >= totalPages) break;
        page++;
      } catch (e) {
        if (page === 1) console.log(`[migration-crawl] WP ${type} error: ${e.message}`);
        break;
      }
    }
    return allLinks;
  }
  try {
    const wpPages = await fetchAllWpType('pages');
    pageUrls.push(...wpPages);
  } catch (e) { /* logged inside */ }
  try {
    const wpPosts = await fetchAllWpType('posts');
    pageUrls.push(...wpPosts);
  } catch (e) { /* logged inside */ }

  // Deduplicate
  pageUrls = [...new Set(pageUrls)];
  console.log(`[migration-crawl] Total unique page URLs: ${pageUrls.length}`);

  // Build pages array — use WP API titles where available, no individual HTML fetching
  for (const url of pageUrls) {
    const slug = new URL(url).pathname.replace(/\/$/, '').split('/').pop() || '/';
    const wpData = wpTitleMap[url];
    pages.push({
      url,
      slug: wpData?.slug || slug,
      title: wpData?.title || '',
      meta_desc: '',
      h1: '',
      canonical: '',
      status: 200
    });
  }
  console.log(`[migration-crawl] Final pages count: ${pages.length}`);

  return pages;
}

// Phase 1: AI URL Matching — match old URLs to new URLs
app.post('/api/projects/:id/migrations/:migrationId/match-urls', async (req, res) => {
  try {
    const migration = (await pool.query(`SELECT * FROM seo_migrations WHERE id=$1 AND project_id=$2`, [req.params.migrationId, req.params.id])).rows[0];
    if (!migration) return res.status(404).json({ error: 'Migration not found' });

    const oldPages = migration.old_crawl || [];
    const newPages = migration.new_crawl || [];
    if (oldPages.length === 0 || newPages.length === 0) return res.status(400).json({ error: 'Crawl both sites first' });

    res.json({ status: 'matching', message: 'AI matching URLs...' });

    (async () => {
      try {
        // Build summaries for AI
        const oldSummary = oldPages.map(p => `${p.url} | ${p.title} | ${p.h1} | ${p.slug}`).join('\n');
        const newSummary = newPages.map(p => `${p.url} | ${p.title} | ${p.h1} | ${p.slug}`).join('\n');

        const prompt = `You are an SEO migration specialist. Match old website URLs to their equivalent new website URLs.

OLD SITE PAGES:
${oldSummary}

NEW SITE PAGES:
${newSummary}

For each old URL, find the best matching new URL based on:
1. Slug similarity (e.g., /plumbing-services → /services/plumbing)
2. Title/H1 similarity
3. Content purpose match

Return ONLY a JSON array of objects:
[{"old_url": "...", "new_url": "...", "confidence": 0.0-1.0, "reason": "brief reason"}]

If no match exists for an old URL, set new_url to null and confidence to 0.
Return valid JSON only, no markdown.`;

        const aiResp = await anthropic.messages.create({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 8000,
          messages: [{ role: 'user', content: prompt }]
        });

        let text = aiResp.content[0].text.trim();
        // Extract JSON from response
        const jsonMatch = text.match(/\[[\s\S]*\]/);
        if (!jsonMatch) throw new Error('AI did not return valid JSON');

        const matches = JSON.parse(jsonMatch[0]);
        const urlMap = matches.filter(m => m.new_url && m.confidence > 0).map(m => ({ ...m, included: true }));
        const unmatched = matches.filter(m => !m.new_url || m.confidence === 0);

        await pool.query(
          `UPDATE seo_migrations SET url_map = $1, unmatched_urls = $2, phase = 'matched', updated_at = NOW() WHERE id = $3`,
          [JSON.stringify(urlMap), JSON.stringify(unmatched), migration.id]
        );
        console.log(`[migration] URL matching done: ${urlMap.length} matched, ${unmatched.length} unmatched`);
      } catch (e) {
        console.error('[migration] URL match error:', e.message);
      }
    })();
  } catch (e) { res.status(500).json({ error: e.message }); }
});

