// List findings for a project — with category + pillar normalization
app.get('/api/projects/:id/audit-findings', async (req, res) => {
  try {
    const result = await pool.query(
      'SELECT * FROM audit_findings WHERE project_id=$1 ORDER BY created_at DESC',
      [req.params.id]
    );

    const PILLAR_MAP = {
      gbp_external: 'gbp_external', gbp: 'gbp_external',
      gbp_internal: 'gbp_internal',
      gsc_agent: 'gsc', gsc: 'gsc',
      website: 'website', technical: 'website',
    };
    const PILLAR_DISPLAY = { gbp_external: 'GBP', gbp_internal: 'GBP_Internal', gsc: 'GSC', gsc_agent: 'GSC', website: 'Website' };
    const VALID_CATS = {
      GBP: ['Profile Completeness', 'NAP Consistency', 'Reviews & Reputation', 'Competitor Analysis', 'Directory & Citations', 'Photos & Media', 'Suburb Coverage'],
      GBP_Internal: ['Relevance > Description', 'Relevance > Categories', 'Relevance > Hours', 'Relevance > Services', 'Relevance > NAP', 'Relevance > Content', 'Relevance > Website', 'Proximity > Service Areas', 'Prominence > Reviews', 'Prominence > Posts', 'Prominence > Photos'],
      GSC: ['Quick Win', 'Low CTR', 'Zero Clicks', 'Cannibalization', 'Underperforming Page', 'Brand Dependency', 'Indexing Issues', 'Mobile Usability', 'Mobile Gap', 'Declining Keyword', 'Growing Keyword', 'Sitemap Coverage', 'Search Appearance'],
      Website: ['Site Health', 'Alt Text', 'Content Quality', 'Schema & Data'],
    };
    const ALIASES = {
      'quick win': 'Quick Win', 'quick wins': 'Quick Win',
      'low ctr': 'Low CTR', 'low ctr page': 'Low CTR', 'low ctr pages': 'Low CTR',
      'zero click': 'Zero Clicks', 'zero clicks': 'Zero Clicks', 'zero-click page': 'Zero Clicks', 'zero-click pages': 'Zero Clicks',
      'underperforming page': 'Underperforming Page', 'underperforming pages': 'Underperforming Page', 'underperforming': 'Underperforming Page',
      'cannibalization': 'Cannibalization', 'keyword cannibalization': 'Cannibalization',
      'mobile gap': 'Mobile Gap', 'declining keyword': 'Declining Keyword', 'growing keyword': 'Growing Keyword',
      'sitemap coverage': 'Sitemap Coverage', 'search appearance': 'Search Appearance',
      'brand dependency': 'Brand Dependency', 'indexing issues': 'Indexing Issues', 'mobile usability': 'Mobile Usability',
      'nap': 'NAP Consistency', 'nap consistency': 'NAP Consistency',
      'profile': 'Profile Completeness', 'profile completeness': 'Profile Completeness',
      'reviews': 'Reviews & Reputation', 'reputation': 'Reviews & Reputation', 'reviews & reputation': 'Reviews & Reputation',
      'competitor': 'Competitor Analysis', 'competitors': 'Competitor Analysis', 'competitor analysis': 'Competitor Analysis',
      'directory': 'Directory & Citations', 'directories': 'Directory & Citations', 'citations': 'Directory & Citations', 'directory & citations': 'Directory & Citations',
      'photos': 'Photos & Media', 'media': 'Photos & Media', 'photos & media': 'Photos & Media',
      'suburb': 'Suburb Coverage', 'suburbs': 'Suburb Coverage', 'suburb coverage': 'Suburb Coverage', 'service area': 'Suburb Coverage', 'service areas': 'Suburb Coverage',
      'schema': 'Schema & Data', 'structured data': 'Schema & Data', 'schema & data': 'Schema & Data',
      'content': 'Content Quality', 'content quality': 'Content Quality', 'thin content': 'Content Quality',
      'cwv': 'Core Web Vitals', 'core web vitals': 'Core Web Vitals', 'performance': 'Core Web Vitals', 'speed': 'Core Web Vitals',
      'crawl': 'Site Health', 'crawlability': 'Site Health', 'robots': 'Site Health', 'sitemap': 'Site Health',
      'site health': 'Site Health', 'broken links': 'Site Health', '404': 'Site Health', 'security': 'Site Health', 'mobile': 'Site Health', 'structure': 'Site Health', 'links': 'Site Health',
      'indexing': 'Site Health',
      'manual': null,
      // GBP internal "Pillar > Sub" mappings
      'proximity > maps ranking': 'Suburb Coverage', 'proximity > geo-targeting': 'Suburb Coverage', 'proximity > service areas': 'Suburb Coverage',
      'prominence > social profiles': 'Profile Completeness', 'prominence > reviews': 'Reviews & Reputation',
      'prominence > citations': 'Directory & Citations', 'prominence > photos': 'Photos & Media',
      'relevance > description': 'Profile Completeness', 'relevance > profile completeness': 'Profile Completeness',
      'relevance > posts & updates': 'Profile Completeness', 'relevance > categories & services': 'Profile Completeness',
    };

    function normCat(rawCat, pillarDisplay) {
      const cat = (rawCat || '').toLowerCase().trim();
      const validCats = VALID_CATS[pillarDisplay] || [];
      if (validCats.find(c => c.toLowerCase() === cat)) return validCats.find(c => c.toLowerCase() === cat);
      if (ALIASES[cat] !== undefined) {
        if (ALIASES[cat] === null) return null; // drop "manual" etc
        if (validCats.includes(ALIASES[cat])) return ALIASES[cat];
        // alias exists but wrong pillar — still return it
        return ALIASES[cat];
      }
      const wordMatch = validCats.find(c => {
        const words = c.toLowerCase().split(/[\s&-]+/).filter(w => w.length > 3);
        return words.some(w => cat.includes(w));
      });
      if (wordMatch) return wordMatch;
      return validCats[0] || rawCat || 'General';
    }

    const findings = result.rows.map(f => {
      const normPillar = PILLAR_MAP[(f.pillar || '').toLowerCase()] || f.pillar;
      const display = PILLAR_DISPLAY[normPillar] || 'Website';
      const normCategory = normCat(f.category, display);
      if (normCategory === null) return null; // drop junk
      return { ...f, pillar: normPillar, category: normCategory };
    }).filter(Boolean);

    res.json({ findings });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Update finding status (approve/reject) — auto-creates action item on approve
app.put('/api/audit-findings/:id', async (req, res) => {
  const { status, copywriter_notes } = req.body;
  // Prevent manually marking as 'fixed' — must go through /verify-fix or /technical-fix
  if (status === 'fixed') {
    return res.status(400).json({ error: 'Cannot manually mark as fixed. Use the Verify Fix button to confirm the fix on the live page.' });
  }
  try {
    const result = await pool.query(
      'UPDATE audit_findings SET status=$1, updated_at=NOW() WHERE id=$2 RETURNING *',
      [status, req.params.id]
    );
    if (result.rows.length === 0) return res.status(404).json({ error: 'Finding not found' });
    const finding = result.rows[0];

    let actionItem = null;
    if (status === 'approved' || status === 'sent_to_writer') {
      // Auto-create action item from this finding
      const existing = await pool.query('SELECT id FROM action_items WHERE finding_id=$1', [finding.id]);
      if (existing.rows.length === 0) {
        const aiRes = await pool.query(
          `INSERT INTO action_items (project_id, finding_id, pillar, type, title, description, current_value, new_value, severity, status, execution_type)
           VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, 'pending', $10) RETURNING *`,
          [finding.project_id, finding.id, finding.pillar, finding.category || 'general',
           finding.title, copywriter_notes || finding.recommendation || finding.description,
           finding.current_value, finding.recommended_value, finding.severity,
           // Auto-detect execution type based on category
           ['Quick Win', 'Low CTR', 'Underperforming Page'].includes(finding.category) ? 'semi_auto' : 'manual']
        );
        actionItem = aiRes.rows[0];
        console.log(`[action] Created action item #${actionItem.id} from finding #${finding.id} (${finding.pillar}/${finding.category})`);
      }
    }

    res.json({ finding, actionItem });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ==================== 7. ACTION PLAN ====================

// Get action items for a project (optional ?pillar= filter)
// ── Control Centre: canonical label normalization (kills mixed-case + duplicate categories) ──
const SEVERITY_CANON = new Set(['critical', 'high', 'medium', 'low']);
function normSeverity(s) {
  const k = (s == null ? '' : s).toString().trim().toLowerCase();
  return SEVERITY_CANON.has(k) ? k : (k ? k : 'medium');
}
// Merge duplicate category labels that different code paths produced into one canonical name.
const CATEGORY_CANON = {
  'quick win': 'Quick Wins', 'quick wins': 'Quick Wins',
  'low ctr': 'Low CTR Pages', 'low ctr pages': 'Low CTR Pages',
  'underperforming page': 'Underperforming Pages', 'underperforming pages': 'Underperforming Pages',
  'zero clicks': 'Zero-Click Pages', 'zero click pages': 'Zero-Click Pages', 'zero-click pages': 'Zero-Click Pages',
};
function normCategory(c) {
  if (c == null || c === '') return c;
  const k = c.toString().trim().toLowerCase();
  return CATEGORY_CANON[k] || c.toString().trim();
}
function normalizeActionRow(r) {
  if (!r) return r;
  if (r.severity !== undefined) r.severity = normSeverity(r.severity);
  if (r.category !== undefined) r.category = normCategory(r.category);
  if (!r.fix_type) r.fix_type = deriveFixType(r);
  return r;
}

// ── Control Centre: ticket code scheme (PRJ-PILLAR-NN) + fix-type routing ──
// Middle of the code = root-cause area. Order matters (first match wins).
const PILLAR_CODE_RULES = [
  [/maps visibility|local pack|grid scan/i, 'MAPS'],
  [/serp visibility|not ranking/i, 'SERP'],
  [/ai search|ai overview/i, 'AISR'],
  [/core web vitals|pagespeed|\bspeed\b|\bcwv\b/i, 'CWV'],
  [/index/i, 'INDX'],
  [/cannibal/i, 'CANB'],
  [/citation|director/i, 'CITE'],
  [/backlink/i, 'BLNK'],
  [/internal link|orphan|\blink\b/i, 'LINK'],
  [/review|reputation/i, 'REVW'],
  [/suburb|content|thin|\bcopy\b/i, 'CONT'],
  [/on-?page|\bmeta\b|\btitle\b|ctr|underperform|zero|quick win/i, 'ONPG'],
  [/security|malware|\bssl\b|hsts|xml-?rpc|firewall/i, 'SEC'],
  [/schema|crawl|site health|technical|robots|sitemap|404|broken/i, 'TECH'],
  [/profile|\bnap\b|photo|hours|categor|\bgbp\b|competitor|proximity|relevance|prominence|strategy|30.?day/i, 'GBP'],
];
function pillarCode(item) {
  const hay = `${item.category || ''} ${item.pillar || ''} ${item.type || ''}`;
  // Citations work is recognisable from the TITLE (e.g. "Claim True Local / Yellow Pages listing")
  // — but never override security checks (e.g. the "Directory Listing" check is SEC, not CITE)
  if (!/security/i.test(hay) && /citation|directory|true local|yellow pages|claim.*listing|listings? with.*nap/i.test(item.title || '')) return 'CITE';
  for (const [re, code] of PILLAR_CODE_RULES) if (re.test(hay)) return code;
  return 'GEN';
}
// Which tool the ticket opens.
function deriveFixType(item) {
  const ex = (item.execution_type || '').toLowerCase();
  const pil = (item.pillar || '').toLowerCase();
  const cat = (item.category || '').toLowerCase();
  if (/copywriter|content|copy/.test(ex) || /content|suburb|thin|low ctr|underperform|zero|quick win|cannibal|serp visibility/.test(cat)) return 'Copywriting';
  if (pil.startsWith('gbp') || /citation|director|profile|\bnap\b|photo|review|hours|categor/.test(cat)) return 'GBP';
  if (/automated|plugin/.test(ex) || /website|technical/.test(pil) || /schema|canonical|noindex|core web vitals|crawl|site health/.test(cat)) return 'Technical';
  return 'Manual';
}
// V3 — ONE TICKET = ONE ISSUE, issued at the source. Each finding's ticket anchors to a stable
// identity (project + pillar + normalized title + page) so audit re-runs re-attach the SAME code.
function findingIdentity(projectId, pCode, item) {
  const crypto = require('crypto');
  const page = (item.ranking_page || ((item.pages_affected || '').split(/[\n,]+/)[0] || '')).toString().trim().toLowerCase();
  const norm = `${(item.title || '').toLowerCase().replace(/\s+/g, ' ').trim()}|${page}`;
  return `item:${projectId}:${pCode}:` + crypto.createHash('md5').update(norm).digest('hex').slice(0, 10);
}

// Issue signature: the finding title with page-specific parts (URLs, paths, numbers) stripped,
// so the SAME issue on different pages groups into one ticket, but DIFFERENT issues never mix.
function issueSignature(item) {
  let t = (item.title || '').toString().toLowerCase();
  t = t.replace(/https?:\/\/[^\s]+/g, ' ')      // full URLs
    .replace(/`[^`]*`/g, ' ')                    // backticked paths/values
    .replace(/\/[a-z0-9][a-z0-9\-_\/]*/g, ' ')   // bare paths
    .replace(/["'""'']/g, ' ')
    .replace(/\b\d+(\.\d+)?\s*(s|ms|kb|mb|px|chars?|words?|%)?\b/g, ' ') // numbers + units
    .replace(/[^a-z\s]/g, ' ')
    .replace(/\s+/g, ' ').trim();
  const words = t.split(' ').filter(w => w.length > 2).slice(0, 6);
  return words.join('-') || normCategory(item.category) || 'general';
}
// Stable de-dupe key: ONE TICKET = ONE ISSUE (project + root-cause area + issue signature).
function rootCauseKey(projectId, item) {
  return `${projectId}:${pillarCode(item)}:${issueSignature(item)}`
    .toLowerCase().replace(/[^a-z0-9:]+/g, '-');
}
// 3-letter project code: stored project_code wins, else derived from the name.
function deriveProjectCode(project) {
  if (project && project.project_code) return project.project_code.toUpperCase();
  const name = (project && (project.name || project.business_name) || '').replace(/[^a-zA-Z ]/g, '').trim();
  if (!name) return 'PRJ';
  const words = name.split(/\s+/).filter(Boolean);
  const code = words.length >= 3 ? words.slice(0, 3).map(w => w[0]).join('')
    : words.length === 2 ? (words[0].slice(0, 2) + words[1][0])
    : words[0].slice(0, 3);
  return code.toUpperCase().slice(0, 3);
}

app.get('/api/projects/:id/action-items', async (req, res) => {
  try {
    const { pillar } = req.query;
    let query = 'SELECT * FROM action_items WHERE project_id=$1';
    const params = [req.params.id];
    if (pillar) {
      query += ' AND pillar=$2';
      params.push(pillar);
    }
    query += ' ORDER BY created_at DESC';
    const result = await pool.query(query, params);
    res.json({ action_items: result.rows.map(normalizeActionRow) });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Create action item directly (from external audit)
app.post('/api/projects/:id/action-items', async (req, res) => {
  const { pillar, type, title, description, severity, current_value, new_value, category, execution_type } = req.body;
  try {
    const result = await pool.query(
      `INSERT INTO action_items (project_id, pillar, type, title, description, severity, current_value, new_value, category, status, execution_type)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, 'pending', $10) RETURNING *`,
      [req.params.id, pillar || 'gbp_external', type || 'external_audit', title, description, normSeverity(severity || 'medium'), current_value || null, new_value || null, normCategory(category || type || 'general'), execution_type || 'manual']
    );
    res.json({ action_item: normalizeActionRow(result.rows[0]) });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Get or assign the permanent ticket code for a root cause (stable across re-runs).
async function ensureTicketCode(projectId, projCode, rcKey, pCode) {
  const existing = await pool.query('SELECT code FROM ticket_codes WHERE project_id=$1 AND root_cause_key=$2', [projectId, rcKey]);
  if (existing.rows.length) return existing.rows[0].code;
  const seqRow = await pool.query('SELECT COALESCE(MAX(seq),0)+1 AS next FROM ticket_codes WHERE project_id=$1 AND pillar_code=$2', [projectId, pCode]);
  const seq = seqRow.rows[0].next;
  const code = `${projCode}-${pCode}-${String(seq).padStart(2, '0')}`;
  try {
    await pool.query('INSERT INTO ticket_codes (project_id, root_cause_key, pillar_code, seq, code) VALUES ($1,$2,$3,$4,$5)', [projectId, rcKey, pCode, seq, code]);
    return code;
  } catch (e) {
    // race: another insert won — read it back
    const r = await pool.query('SELECT code FROM ticket_codes WHERE project_id=$1 AND root_cause_key=$2', [projectId, rcKey]);
    return r.rows.length ? r.rows[0].code : code;
  }
}

// CONTROL CENTRE — grouped tickets (one per root cause), the lean replacement for the raw Action Plan dump.
const SEV_RANK = { critical: 4, high: 3, medium: 2, low: 1 };

// Root-cause playbooks: WHAT to do for each pillar code and WHERE to do it.
const TICKET_PLAYBOOK = {
  CWV:  { where: 'Website Audit → PageSpeed Scores', steps: [
    'Speed is handled by BerqWP — confirm it is active on the site and the cache is warmed.',
    'Re-run PageSpeed Scores to get current numbers (old findings may already be fixed).',
    'For pages still scoring red: compress/resize hero images, remove unused embeds/scripts, lazy-load below-the-fold media.',
    'Re-test the fixed pages and Finish the ticket when scores are amber/green.' ] },
  INDX: { where: 'Website Audit → Indexing Status', steps: [
    'Open Indexing Status and find the not-indexed pages from this ticket.',
    'Fix the blocker: thin content → send to Copywriter; noindex/canonical/robots → use the Fix button.',
    'Use "Request Indexing in Search Console" per page once fixed.',
    'Re-check in 1–2 weeks; Finish when pages show Indexed.' ] },
  CONT: { where: 'Copywriter / Optimise Website Copy', steps: [
    'Open the affected page in the Copywriter editor.',
    'Expand to 800+ words targeting the page\'s focus keyword; keep it locally relevant (suburb, services).',
    'Run the SEO + humanize checks, add 2-3 internal links, publish via preview.' ] },
  ONPG: { where: 'Website Audit → On-Page Audit & Fix', steps: [
    'Select the affected pages and run AI Suggest for meta title / description / focus keyword.',
    'Review the suggestions (current vs suggested) and Apply.',
    'For low-CTR pages: rewrite the title/description as a click-worthy promise of the page content.' ] },
  CANB: { where: 'GSC Audit → Cannibalization', steps: [
    'Two or more pages compete for the same keyword — pick the strongest as the primary.',
    'Re-target the other page (new focus keyword + meta) or 301 it into the primary.',
    'Update internal links so anchors for that keyword all point at the primary page.' ] },
  CITE: { where: 'GBP Audit → Directory & Citations', steps: [
    'Work down the directory list: create or claim each listing.',
    'Use EXACTLY the same name, address, phone (NAP) as the Google profile.',
    'Add the website link and business category; mark each directory done as you go.' ] },
  GBP:  { where: 'GBP Audit', steps: [
    'Open the GBP Audit findings for this ticket.',
    'Complete missing profile fields (description, hours, categories, services, attributes).',
    'Add fresh photos and keep service areas current.' ] },
  REVW: { where: 'GBP Audit → Reviews / RatingCaptain', steps: [
    'Reply to all unreplied reviews (oldest first).',
    'Run a review-request push to close the count gap vs competitors.' ] },
  LINK: { where: 'Website Audit → Internal Linking', steps: [
    'Run "Optimise Links (Auto)" — it cleans anchors, inserts links, builds hubs and links spokes.',
    'Re-run the audit and confirm orphans/no-outbound pages are cleared.' ] },
  BLNK: { where: 'Backlinks', steps: [
    'Review the Toxic Links tab; disavow/ignore genuinely spammy domains.',
    'Work the prospects/gap list: outreach for links competitors have and you don\'t.' ] },
  TECH: { where: 'Website Audit', steps: [
    'Open the Website Audit findings for this ticket.',
    'Auto-fixable items (schema, canonical, noindex, mixed content) → click the green Fix button.',
    'Manual items → follow the steps inside the finding card.' ] },
  SEC:  { where: 'Security Audit', steps: [
    'Open the Security Audit page — each failing check below has its own fix instructions there.',
    'Fix in order of severity (critical first: malware/spam, exposed logins, SSL).',
    'Re-run the Security Audit to confirm each check goes green, then Finish.' ] },
  AISR: { where: 'Rankings → AI Search', steps: [
    'Expand the keyword on the AI Search page and click "Build a plan to get cited" — it writes the answer paragraph, headings and FAQ for you.',
    'Publish that answer at the top of the target page (add the FAQ schema).',
    'Re-scan AI Search to confirm your site appears as a source.' ] },
  SERP: { where: 'Rankings → SERP Rankings', steps: [
    'Work the to-dos in the ticket description — pick/create ONE page for the keyword, optimize meta + H1, add internal links.',
    'Run "Check Rankings" after the next crawl to confirm the keyword enters the top 100.' ] },
  MAPS: { where: 'Rankings → Maps Rankings', steps: [
    'Open the keyword row for this suburb — the expanded view lists exactly what is missing (service area, suburb page, directories, reviews, posts).',
    'Work the to-dos in the ticket description, in order.',
    'Re-run the Grid Scan after fixing to confirm visibility improves.' ] },
  GEN:  { where: 'Source audit page', steps: ['Open the source audit page for this category and work the findings there.'] },
};

// Issue-specific "what to do" steps — generated from the ticket's actual issue, not a generic
// pillar blurb. Falls back to the pillar playbook only when no specific rule matches.
function issueSteps(sig, items) {
  const s = (sig || '').replace(/-/g, ' ');
  const n = items.length;
  const pages = n > 1 ? `each of the ${n} pages in the checklist below` : 'the page in the checklist below';
  const firstTarget = (items.find(i => i.new_value) || {}).new_value;
  const hint = firstTarget ? ' The suggested value is shown in green on each finding.' : '';

  if (/title/.test(s) && /long/.test(s)) return [
    `Shorten the meta title on ${pages} to 50–60 characters.`,
    `Keep the focus keyword near the front; cut taglines and filler.${hint}`,
    `Fastest: click the page's Fix button → AI Suggest → review → Apply.`];
  if (/title/.test(s) && /short/.test(s)) return [
    `Lengthen the meta title on ${pages} to at least 30 characters — say what the page offers and where.`,
    `Fastest: Fix button → AI Suggest → Apply.${hint}`];
  if (/title/.test(s) && /missing|no\b/.test(s)) return [
    `Write a meta title (50–60 chars, keyword first) for ${pages}.`,
    `Fastest: Fix button → AI Suggest → Apply.${hint}`];
  if (/description/.test(s) && /long/.test(s)) return [
    `Trim the meta description on ${pages} to 120–160 characters.${hint}`,
    `Fastest: Fix button → AI Suggest → Apply.`];
  if (/description/.test(s) && /short|missing|no\b/.test(s)) return [
    `Write a 120–160 character meta description for ${pages} — include the keyword and a reason to click.${hint}`,
    `Fastest: Fix button → AI Suggest → Apply.`];
  if (/canonical/.test(s)) return [
    `Fix the canonical tag on ${pages} — it should point to the page's own correct URL (or the primary version).`,
    `Use the green Fix button on the Website Audit finding (it sets the canonical via Yoast), then re-check.`];
  if (/noindex/.test(s)) return [
    `Remove the noindex tag from ${pages} so Google can index it.`,
    `Use the green Fix button on the Website Audit finding, then Request Indexing on the Indexing page.`];
  if (/schema|structured data/.test(s)) return [
    `Add JSON-LD schema to ${pages}.`,
    `Use the green Fix button — it generates LocalBusiness/FAQ schema from your profile data automatically.`];
  if (/mixed content|insecure/.test(s)) return [
    `Replace http:// resource URLs with https:// on ${pages}.`,
    `Use the green Fix button (it search-replaces in content), then reload the page to confirm the padlock.`];
  if (/\bh1\b|heading/.test(s)) return [
    `Add one H1 heading to ${pages} — usually the page title with the focus keyword.`,
    `Use the green Fix button, or edit the page header in WordPress.`];
  if (/thin|too short|word count|\bwords\b|expand content|content could be longer/.test(s)) return [
    `Expand the content on ${pages} to its target word count — the target is shown in green on each finding (current count in red).`,
    `Click "Go there now" — the Copywriter opens with the page loaded. Add real specifics: services, suburbs, FAQs, internal links.`,
    `Run the SEO + humanize checks, publish via preview, then tick the finding off here.`];
  if (/low ctr/.test(s)) return [
    `These pages get impressions but few clicks. Rewrite the meta title + description on ${pages} as a click-worthy promise (number, benefit, locality).`,
    `Fix button → AI Suggest gives a starting point — punch it up before Applying.`];
  if (/quick win|position/.test(s)) return [
    `These keywords sit just off page 1. For ${pages}: strengthen the page for its keyword — add it to the H1/intro, expand the section that answers it, add 2–3 internal links pointing at the page with that anchor.`,
    `Re-check position in SERP Rankings after the next crawl.`];
  if (/cannibal/.test(s)) return [
    `Two+ pages target the same keyword. Decide the PRIMARY page (the one already ranking best).`,
    `Re-target the other page: new focus keyword + meta, or 301 it into the primary.`,
    `Point internal links using that keyword's anchor at the primary only. The Competing Pages tool walks you through it.`];
  if (/orphan|no outbound|internal link/.test(s)) return [
    `Add internal links for ${pages} — Internal Linking → "Optimise Links (Auto)" does it in one click.`,
    `Re-run the audit there to confirm the pages are linked.`];
  if (/not indexed|index/.test(s)) return [
    `Fix what blocks indexing on ${pages} (thin content → Copywriter; noindex/canonical → Fix button).`,
    `Then "Request Indexing in Search Console" per page on the Indexing page. Re-check in 1–2 weeks.`];
  if (/slow|lcp|cls|speed|performance|core web vitals/.test(s)) return [
    `Confirm BerqWP is active and warmed, then re-run PageSpeed Scores — many of these may already be fixed.`,
    `For pages still red: compress/resize the hero image, remove unused embeds, lazy-load below-the-fold media.`,
    `Re-test and use Check Progress here to tick off fixed pages.`];
  return null; // no specific rule — fall back to the pillar playbook
}

// Steps for a ticket group: issue rule → findings-text rule → checklist-driven → pillar playbook.
function stepsForGroup(sig, items, pCode) {
  const direct = issueSteps(sig, items);
  if (direct) return direct;
  // No rule on the signature (e.g. tickets titled by page name): try the findings' own text —
  // their titles/descriptions/values usually name the real issue ("350 words", "missing schema").
  const joined = items.map(i => `${i.title || ''} ${i.description || ''} ${i.current_value || ''} ${i.new_value || ''}`)
    .join(' ').toLowerCase();
  const fromText = issueSteps(joined, items);
  if (fromText) return fromText;
  // Several different fixes bundled together: the checklist IS the instruction list
  if (items.length > 1) {
    return [
      `This ticket is ${items.length} specific fixes — each finding in the checklist below states the exact change (current in red → suggested in green).`,
      'Open the page (link on each finding), make the change described, and tick the finding off.',
      'Click "Check progress" to machine-verify what\'s done, or Finish when everything is ticked.',
    ];
  }
  return (TICKET_PLAYBOOK[pCode] || TICKET_PLAYBOOK.GEN).steps;
}

// "Closed when" — the explicit finish line shown on every ticket. AUTO types are machine-checked
// when the assignee clicks Finish; MANUAL types go to the lead for approval.
const AUTO_VERIFY_PILLARS = ['ONPG', 'TECH', 'LINK', 'INDX'];
const TICKET_DONE_WHEN = {
  ONPG: 'The system re-reads each affected page and its meta passes the checks. Verified automatically when you click Finish.',
  TECH: 'The required tag/fix is live on each affected page. Verified automatically when you click Finish.',
  LINK: 'Each affected page has internal links in its content. Verified automatically when you click Finish.',
  INDX: 'Each affected page shows as Indexed in Google. Verified automatically when you click Finish (allow Google a few days after fixing).',
  CWV:  'Affected pages score 50+ on PageSpeed. Re-run PageSpeed Scores after fixing, then Finish — the lead approves.',
  SEC:  'The failing security checks pass on a fresh Security Audit run. Re-run it, then Finish — the lead approves.',
  CITE: 'The listings are created/corrected with exact NAP. The lead reviews and approves.',
  GBP:  'The profile changes are live on Google. The lead reviews and approves.',
  REVW: 'Reviews are replied to / the campaign is running. The lead reviews and approves.',
  CONT: 'The new/updated content is published. The lead reviews and approves.',
  CANB: 'Only one page targets the keyword (other page re-targeted or redirected). The lead reviews and approves.',
  BLNK: 'The toxic/outreach work is done. The lead reviews and approves.',
  MAPS: 'The to-dos for this suburb are done and a fresh Grid Scan shows improved visibility. The lead reviews and approves.',
  SERP: 'A page targets the keyword and a fresh Check Rankings finds it in the top 100. The lead reviews and approves.',
  AISR: 'A fresh AI Search scan shows your site cited as a source in the AI Overview. Closes automatically on re-scan.',
  MANUAL: 'The lead reviews and approves.',
};

// Build the grouped tickets for one project. Assigns/stamps stable codes, merges stored ticket
// state (assignee/status/due date) from ticket_codes, and applies the project default assignee.
async function buildControlTickets(project) {
  const projectId = project.id;
  const projCode = deriveProjectCode(project);
  // V4 — tickets are created ONLY at their source. The board indexes existing tickets;
  // it never invents them: only findings that already carry a code appear here.
  const items = (await pool.query('SELECT * FROM action_items WHERE project_id=$1 AND code IS NOT NULL', [projectId])).rows.map(normalizeActionRow);

  const stateRows = (await pool.query('SELECT * FROM ticket_codes WHERE project_id=$1', [projectId])).rows;
  const stateByKey = {}; for (const r of stateRows) stateByKey[r.root_cause_key] = r;

  const DONE_STATES = ['done', 'completed', 'fixed', 'applied', 'executed'];
  const tickets = [];
  const ticketByKey = {};

  for (const it of items) {
    const pCode = pillarCode(it);
    const rcKey = it.root_cause_key;
    const done = DONE_STATES.includes((it.status || '').toLowerCase());
    const page = it.ranking_page || ((it.pages_affected || '').split(/[\n,]+/).map(s => s.trim()).filter(Boolean)[0] || null);

    // Duplicate finding rows for the same ticket: attach, don't list twice
    if (ticketByKey[rcKey]) { ticketByKey[rcKey].item_ids.push(it.id); continue; }

    const st = stateByKey[rcKey] || {};
    const code = it.code;

    const effectiveAssignee = st.assignee_id || project.assigned_member || null;
    const status = st.status && st.status !== 'New' ? st.status : (effectiveAssignee ? 'Assigned' : 'New');
    const isLate = st.due_date && status !== 'Done' && new Date(st.due_date) < new Date(new Date().toDateString());

    // The instructions ARE the finding's own data from the source audit — no AI rewriting.
    const steps = [];
    if (it.description) steps.push(it.description);
    if (it.how_to_steps) steps.push(...it.how_to_steps.split(/\n+/).map(s => s.trim()).filter(Boolean));
    if (!steps.length) steps.push(...(TICKET_PLAYBOOK[pCode] || TICKET_PLAYBOOK.GEN).steps);

    const t = {
      ticket_id: st.id || null,
      code,
      project_id: Number(projectId),
      project_name: project.name || project.business_name || '',
      pillar_code: pCode,
      category: normCategory(it.category) || it.pillar,
      fix_type: deriveFixType(it),
      severity: it.severity || 'medium',
      // Some old extractions saved the severity word as the title — use the real text instead
      title: /^(critical|high|medium|low)$/i.test((it.title || '').trim())
        ? ((it.description || '').slice(0, 90) || it.category || 'Untitled')
        : (it.title || it.category || 'Untitled'),
      status,
      late: !!isLate,
      assignee_id: effectiveAssignee,
      assignee_source: st.assignee_id ? 'ticket' : (project.assigned_member ? 'project' : null),
      due_date: st.due_date || null,
      affected_count: 1,
      affected_pages: page ? [page] : [],
      estimated_hours: parseFloat(it.estimated_hours) || 0.5,
      item_ids: [it.id],
      how_to: steps.slice(0, 6),
      how_to_source: 'source',
      where: (TICKET_PLAYBOOK[pCode] || TICKET_PLAYBOOK.GEN).where,
      done_when: TICKET_DONE_WHEN[pCode] || TICKET_DONE_WHEN.MANUAL,
      auto_verified: AUTO_VERIFY_PILLARS.includes(pCode),
      verification: st.verification || null,
      started_at: st.started_at || null,
      finished_at: st.finished_at || null,
      verified_at: st.verified_at || null,
      closed_by: st.closed_by || null,
      progress: done ? 100 : (it.source_progress != null && Number.isFinite(+it.source_progress) ? +it.source_progress : 0),
      findings: [{
        id: it.id,
        done,
        title: it.title || '',
        page,
        keyword: it.keyword || null,
        current: (it.current_value || '').toString().slice(0, 160) || null,
        target: (it.new_value || '').toString().slice(0, 160) || null,
        severity: it.severity,
      }],
    };
    tickets.push(t);
    ticketByKey[rcKey] = t;
  }

  tickets.sort((a, b) => (SEV_RANK[b.severity] - SEV_RANK[a.severity]) || (b.affected_count - a.affected_count));
  return { project_code: projCode, total_findings: items.length, tickets };
}

// SOURCE → TICKET: pages call this with their current issues; each issue gets (or reuses) its
// own permanent code. Idempotent by (title + page), so re-syncs never duplicate.
app.post('/api/projects/:id/tickets/source-sync', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const source = (req.body && req.body.source || 'source').toString().slice(0, 30);
    const issues = Array.isArray(req.body && req.body.issues) ? req.body.issues.slice(0, 300) : [];
    if (!issues.length) return res.json({ ok: true, tickets: [] });

    const projCode = deriveProjectCode(project);
    const existing = (await pool.query(
      `SELECT id, title, ranking_page, code, status, type FROM action_items WHERE project_id=$1 AND type LIKE 'src_%'`,
      [req.params.id])).rows;
    const idKey = (t, p) => `${(t || '').toLowerCase().trim()}|${(p || '').toLowerCase().trim()}`;
    const byKey = new Map(existing.map(r => [idKey(r.title, r.ranking_page), r]));

    const out = [];
    for (const iss of issues) {
      if (!iss || !iss.title) continue;
      const k = idKey(iss.title, iss.page);
      let row = byKey.get(k);
      if (row && iss.description) {
        // keep the ticket's to-do list current (e.g. a page's on-page issues changed since last sync)
        await pool.query('UPDATE action_items SET description=$1, severity=$2 WHERE id=$3 AND description IS DISTINCT FROM $1',
          [iss.description.toString().slice(0, 1000), normSeverity(iss.severity || 'high'), row.id]).catch(() => {});
      }
      if (row && Number.isFinite(+iss.progress)) {
        await pool.query('UPDATE action_items SET source_progress=$1 WHERE id=$2', [Math.max(0, Math.min(100, Math.round(+iss.progress))), row.id]).catch(() => {});
      }
      if (row && row.status === 'done') {
        // the issue is BACK at the source — reopen the ticket
        await pool.query(`UPDATE action_items SET status='pending' WHERE id=$1`, [row.id]).catch(() => {});
        if (row.code) await pool.query(`UPDATE ticket_codes SET status='New', finished_at=NULL, verified_at=NULL, closed_by=NULL WHERE project_id=$1 AND code=$2 AND status='Done'`, [req.params.id, row.code]).catch(() => {});
        row.status = 'pending';
      }
      if (!row) {
        row = (await pool.query(
          `INSERT INTO action_items (project_id, pillar, type, title, description, severity, category, status, execution_type, ranking_page)
           VALUES ($1,$2,$3,$4,$5,$6,$7,'pending','manual',$8) RETURNING id, title, ranking_page, code`,
          [req.params.id, iss.pillar || 'website', 'src_' + source, iss.title.toString().slice(0, 250),
           (iss.description || '').toString().slice(0, 1000), normSeverity(iss.severity || 'high'),
           iss.category || source, iss.page || null])).rows[0];
        byKey.set(k, row);
      }
      if (!row.code) {
        const itemForClass = { title: row.title, category: iss.category || source, pillar: iss.pillar || '', type: 'src_' + source, ranking_page: row.ranking_page, pages_affected: '' };
        const pCode = pillarCode(itemForClass);
        const rcKey = findingIdentity(req.params.id, pCode, itemForClass);
        const code = await ensureTicketCode(req.params.id, projCode, rcKey, pCode);
        await pool.query('UPDATE action_items SET code=$1, root_cause_key=$2 WHERE id=$3', [code, rcKey, row.id]);
        row.code = code;
      }
      out.push({ title: row.title, page: row.ranking_page, code: row.code });
    }

    // RECONCILE — the source sent its COMPLETE current issue list: any ticket from this source
    // whose issue is no longer reported has been fixed → close it (machine-verified by the source).
    if (Array.isArray(req.body.reconcile)) {
      const keep = new Set(req.body.reconcile.map(x => (x || '').toString().toLowerCase()));
      for (const r of existing) {
        if (r.type !== 'src_' + source) continue;
        if (keep.has(idKey(r.title, r.ranking_page))) continue;
        if (r.status === 'done') continue;
        await pool.query(`UPDATE action_items SET status='done', source_progress=100 WHERE id=$1`, [r.id]).catch(() => {});
        if (r.code) await pool.query(
          `UPDATE ticket_codes SET status='Done', finished_at=COALESCE(finished_at, NOW()), verified_at=NOW() WHERE project_id=$1 AND code=$2 AND status IS DISTINCT FROM 'Done'`,
          [req.params.id, r.code]).catch(() => {});
      }
    }
    res.json({ ok: true, tickets: out });
  } catch (e) {
    console.error('[source-sync] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

app.get('/api/projects/:id/control-centre/tickets', async (req, res) => {
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.id])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const r = await buildControlTickets(project);
    res.json({ ...r, total_tickets: r.tickets.length });
  } catch (e) {
    console.error('[control-centre] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Ticket codes per pillar for a project — used to tag audit pages with their Control Centre ticket.
// Also returns a URL → codes map so individual page ROWS can show exactly which ticket covers them.
app.get('/api/projects/:id/control-centre/codes', async (req, res) => {
  try {
    const rows = (await pool.query('SELECT pillar_code, code FROM ticket_codes WHERE project_id=$1 ORDER BY code', [req.params.id])).rows;
    const codes = {};
    for (const r of rows) (codes[r.pillar_code] = codes[r.pillar_code] || []).push(r.code);

    const normPath = (u) => {
      if (!u) return null;
      let s = u.toString().trim();
      try { if (s.startsWith('http')) s = new URL(s).pathname; } catch (e) {}
      s = s.replace(/\/+$/, '').toLowerCase();
      return s || '/';
    };
    const items = (await pool.query(
      'SELECT code, ranking_page, pages_affected, title, description FROM action_items WHERE project_id=$1 AND code IS NOT NULL',
      [req.params.id])).rows;
    // Findings often carry the page only inside the title/description (e.g. `/imac-repairs/`) —
    // extract full URLs and backticked/standalone paths from the text too.
    const extractPaths = (txt) => {
      const out = []; const s = (txt || '').toString();
      const re = /(https?:\/\/[^\s"'`)\]]+)|(?:^|[\s`("'\[])(\/[a-z0-9][a-z0-9\-_\/]*\/?)(?=[\s`)"'\].,:;]|$)/gi;
      let m; while ((m = re.exec(s)) !== null) { const v = m[1] || m[2]; if (v) out.push(v); }
      return out;
    };
    const byUrl = {};
    for (const it of items) {
      const urls = [
        it.ranking_page,
        ...((it.pages_affected || '').split(/[\n,]+/)),
        ...extractPaths(it.title),
        ...extractPaths(it.description),
      ].map(s => s && s.trim()).filter(Boolean);
      for (const u of urls) {
        const k = normPath(u);
        if (!k) continue;
        if (!byUrl[k]) byUrl[k] = [];
        if (!byUrl[k].includes(it.code)) byUrl[k].push(it.code);
      }
    }
    // Meta per code (issue title + category) so the UI can say WHICH ticket is which
    const metaRows = (await pool.query(
      `SELECT code, MIN(category) AS category, MIN(title) AS title, COUNT(*)::int AS n FROM action_items
        WHERE project_id=$1 AND code IS NOT NULL GROUP BY code`, [req.params.id])).rows;
    const meta = {};
    for (const r of metaRows) meta[r.code] = { category: r.category || '', title: (r.title || '').slice(0, 80), count: r.n };
    // SEC tickets have no action_items — derive their label from the registry key
    for (const r of rows) {
      if (!meta[r.code]) {
        const reg = (await pool.query('SELECT root_cause_key FROM ticket_codes WHERE code=$1 AND project_id=$2', [r.code, req.params.id])).rows[0];
        const tail = reg && (reg.root_cause_key || '').split(':').pop() || '';
        meta[r.code] = { category: tail.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()), count: null };
      }
    }
    res.json({ codes, by_url: byUrl, meta });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Lead board — tickets across ALL projects + team members for assignment dropdowns
app.get('/api/control-centre/board', async (req, res) => {
  try {
    const projects = (await pool.query('SELECT * FROM projects ORDER BY name')).rows;
    const members = (await pool.query("SELECT id, email, name, role FROM users WHERE role IS DISTINCT FROM 'client' ORDER BY id")).rows;
    const accessRows = (await pool.query('SELECT user_id, project_id FROM project_access')).rows;
    const accessByUser = {};
    for (const r of accessRows) (accessByUser[r.user_id] = accessByUser[r.user_id] || []).push(Number(r.project_id));
    members.forEach(m => { m.project_ids = m.role === 'member' ? (accessByUser[m.id] || []) : null; }); // null = all (admin)
    const all = [];
    const perProject = [];
    for (const p of projects) {
      try {
        const r = await buildControlTickets(p);
        all.push(...r.tickets);
        perProject.push({ project_id: p.id, name: p.name, code: r.project_code, assigned_member: p.assigned_member || null, tickets: r.tickets.length, findings: r.total_findings });
      } catch (e) { console.log('[board] project', p.id, e.message); }
    }
    res.json({ members, projects: perProject, tickets: all });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// A member can only be handed work on projects they can access (admins can take anything).
async function memberCanAccessProject(memberId, projectId) {
  if (!memberId) return true;
  const u = (await pool.query('SELECT role FROM users WHERE id=$1', [memberId])).rows[0];
  if (!u || u.role !== 'member') return true;
  const r = await pool.query('SELECT 1 FROM project_access WHERE user_id=$1 AND project_id=$2', [memberId, projectId]);
  return r.rows.length > 0;
}

// Assign a WHOLE project to a member (all its tickets inherit)
app.post('/api/projects/:id/control-centre/assign', async (req, res) => {
  try {
    const memberId = req.body && req.body.member_id != null ? parseInt(req.body.member_id) : null;
    if (memberId && !(await memberCanAccessProject(memberId, req.params.id))) {
      return res.status(400).json({ error: 'That member has no access to this project. Grant access in Team Members first.' });
    }
    await pool.query('UPDATE projects SET assigned_member=$1 WHERE id=$2', [memberId, req.params.id]);
    res.json({ ok: true, project_id: Number(req.params.id), member_id: memberId });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Per-ticket assignment override / reassign (by code)
app.post('/api/control-centre/tickets/:code/assign', async (req, res) => {
  try {
    const memberId = req.body && req.body.member_id != null ? parseInt(req.body.member_id) : null;
    if (memberId) {
      const tk = (await pool.query('SELECT project_id FROM ticket_codes WHERE code=$1', [req.params.code])).rows[0];
      if (tk && !(await memberCanAccessProject(memberId, tk.project_id))) {
        return res.status(400).json({ error: 'That member has no access to this project. Grant access in Team Members first.' });
      }
    }
    const r = await pool.query(`UPDATE ticket_codes SET assignee_id=$1, status = CASE WHEN status='New' AND $1 IS NOT NULL THEN 'Assigned' ELSE status END WHERE code=$2 RETURNING *`, [memberId, req.params.code]);
    if (!r.rows.length) return res.status(404).json({ error: 'Ticket not found' });
    res.json({ ok: true, ticket: r.rows[0] });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Auto "In Progress" — fires ONLY when the ticket's assignee opens it. Only flips forward, never back.
app.post('/api/control-centre/tickets/:code/open', async (req, res) => {
  try {
    const tk = (await pool.query(
      'SELECT tc.*, p.assigned_member FROM ticket_codes tc JOIN projects p ON p.id=tc.project_id WHERE tc.code=$1',
      [req.params.code])).rows[0];
    if (!tk) return res.status(404).json({ error: 'Ticket not found' });
    const effective = tk.assignee_id || tk.assigned_member;
    if (!effective || String(effective) !== String(req.auth?.userId)) {
      return res.json({ ok: true, changed: false, reason: 'opener is not the assignee' });
    }
    const r = await pool.query(
      `UPDATE ticket_codes SET status='In Progress', started_at=COALESCE(started_at, NOW())
        WHERE code=$1 AND status IN ('New','Assigned') RETURNING *`, [req.params.code]);
    res.json({ ok: true, changed: r.rows.length > 0, ticket: r.rows[0] || null });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// ── FINISH GATE: clicking Finish runs a real machine check; the ticket only closes if it passes ──
// Collect the affected page URLs for a ticket from its findings (same extraction as the codes map).
function ticketPageUrls(project, items) {
  const base = 'https://' + (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
  const found = new Set();
  const extract = (txt) => {
    const out = []; const s = (txt || '').toString();
    const re = /(https?:\/\/[^\s"'`)\]]+)|(?:^|[\s`("'\[])(\/[a-z0-9][a-z0-9\-_\/]*\/?)(?=[\s`)"'\].,:;]|$)/gi;
    let m; while ((m = re.exec(s)) !== null) { const v = m[1] || m[2]; if (v) out.push(v); }
    return out;
  };
  for (const it of items) {
    const urls = [it.ranking_page, ...((it.pages_affected || '').split(/[\n,]+/)), ...extract(it.title), ...extract(it.description)]
      .map(s => s && s.trim()).filter(Boolean);
    for (let u of urls) {
      if (!u.startsWith('http')) u = base + (u.startsWith('/') ? u : '/' + u);
      try { const x = new URL(u); if (x.hostname.replace(/^www\./, '') === base.replace('https://', '').replace(/^www\./, '')) found.add(x.origin + x.pathname.replace(/\/+$/, '') + '/'); } catch (e) {}
    }
  }
  return [...found];
}

// Rule check for one page's HTML against the ticket's issue signature.
function verifyPageRule(html, sig) {
  const titleM = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  const title = titleM ? titleM[1].trim() : '';
  const descM = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']/i);
  const desc = descM ? descM[1].trim() : '';
  const s = sig || '';
  if (/title/.test(s) && /missing|no\b/.test(s)) return { pass: !!title, rule: 'title present', value: title.slice(0, 60) };
  if (/title/.test(s) && /long/.test(s)) return { pass: title.length > 0 && title.length <= 65, rule: 'title ≤65 chars', value: `${title.length} chars` };
  if (/title/.test(s) && /short/.test(s)) return { pass: title.length >= 30, rule: 'title ≥30 chars', value: `${title.length} chars` };
  if (/description/.test(s) && /missing|no\b/.test(s)) return { pass: !!desc, rule: 'description present', value: desc.slice(0, 60) };
  if (/description/.test(s) && /long/.test(s)) return { pass: desc.length > 0 && desc.length <= 170, rule: 'description ≤170 chars', value: `${desc.length} chars` };
  if (/description/.test(s) && /short/.test(s)) return { pass: desc.length >= 50, rule: 'description ≥50 chars', value: `${desc.length} chars` };
  if (/canonical/.test(s)) return { pass: /<link[^>]*rel=["']canonical["']/i.test(html), rule: 'canonical tag present', value: '' };
  if (/noindex/.test(s)) return { pass: !/<meta[^>]*content=["'][^"']*noindex/i.test(html), rule: 'no noindex tag', value: '' };
  if (/schema|structured/.test(s)) return { pass: /application\/ld\+json/i.test(html), rule: 'JSON-LD schema present', value: '' };
  if (/mixed content|insecure/.test(s)) return { pass: !/src=["']http:\/\//i.test(html), rule: 'no http:// resources', value: '' };
  if (/\bh1\b|heading/.test(s)) return { pass: /<h1[\s>]/i.test(html), rule: 'H1 present', value: '' };
  if (/orphan|outbound|internal link|no links/.test(s)) {
    const body = (html.match(/<body[^>]*>([\s\S]*)<\/body>/i) || [, html])[1]
      .replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
      .replace(/<header[\s\S]*?<\/header>/gi, ' ').replace(/<footer[\s\S]*?<\/footer>/gi, ' ');
    const n = (body.match(/href=["'](\/|https?:\/\/)/gi) || []).length;
    return { pass: n > 0, rule: 'content links present', value: `${n} links` };
  }
  return null; // no machine rule for this issue → manual review
}

// First page URL for ONE finding (used to map a page-check result back to its finding)
function itemPageUrl(project, item) {
  const urls = ticketPageUrls(project, [item]);
  return urls.length ? urls[0] : null;
}

// Run the machine checks for an auto-verifiable ticket. Marks each PASSING finding as done.
// Returns { manual, note } or { checked, progress, total, doneCount }.
async function runTicketVerification(tk, project, items, userId) {
  const pillar = tk.pillar_code;
  const sig = (tk.root_cause_key || '').split(':').pop() || '';
  if (!AUTO_VERIFY_PILLARS.includes(pillar)) return { manual: true, note: 'This ticket type is closed by lead review, not machine check. Tick findings off as you complete them.' };

  // Map each finding to its page; check each unique page once
  const itemsByUrl = {};
  for (const it of items) {
    const u = itemPageUrl(project, it);
    if (u) (itemsByUrl[u] = itemsByUrl[u] || []).push(it);
  }
  const pages = Object.keys(itemsByUrl).slice(0, 12);
  if (!pages.length) return { manual: true, note: 'No page URLs recorded on this ticket to check — tick findings off manually / lead reviews.' };

  const checked = [];
  if (pillar === 'INDX') {
    const accessToken = await getGscAccessToken(userId);
    if (!accessToken) return { manual: true, note: 'GSC not connected — indexing can\'t be machine-checked.' };
    const site = await resolveGscSite(project, accessToken);
    if (!site) return { manual: true, note: 'GSC property not found — set it in Project Settings.' };
    for (const url of pages.slice(0, 5)) {
      try {
        const r = await fetch('https://searchconsole.googleapis.com/v1/urlInspection/index:inspect', {
          method: 'POST', headers: { Authorization: `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ inspectionUrl: url, siteUrl: site }), signal: AbortSignal.timeout(20000),
        });
        const d = r.ok ? await r.json() : null;
        const verdict = d && d.inspectionResult && d.inspectionResult.indexStatusResult && d.inspectionResult.indexStatusResult.verdict;
        checked.push({ url, pass: verdict === 'PASS', reason: verdict || ('HTTP ' + r.status) });
      } catch (e) { checked.push({ url, pass: false, reason: e.message }); }
    }
  } else {
    for (const url of pages) {
      try {
        const bust = (url.includes('?') ? '&' : '?') + 'seoroom_verify=' + Date.now();
        const r = await fetch(url + bust, { headers: { 'User-Agent': 'SEORoomBot/1.0', 'Cache-Control': 'no-cache' }, signal: AbortSignal.timeout(15000) });
        if (!r.ok) { checked.push({ url, pass: false, reason: 'HTTP ' + r.status }); continue; }
        const html = await r.text();
        const result = verifyPageRule(html, sig);
        if (!result) return { manual: true, note: 'This issue has no machine check — tick findings off manually / lead reviews.' };
        checked.push({ url, pass: result.pass, reason: `${result.rule}${result.value ? ' — ' + result.value : ''}` });
      } catch (e) { checked.push({ url, pass: false, reason: e.message }); }
    }
  }

  // Mark passing findings as done (this is what moves the progress bar)
  for (const c of checked) {
    if (!c.pass) continue;
    const ids = (itemsByUrl[c.url] || []).map(i => i.id);
    if (ids.length) await pool.query(`UPDATE action_items SET status='done' WHERE id = ANY($1::int[])`, [ids]).catch(() => {});
  }
  const fresh = (await pool.query(`SELECT status FROM action_items WHERE code=$1`, [tk.code])).rows;
  const doneCount = fresh.filter(r => ['done', 'completed', 'fixed', 'applied', 'executed'].includes((r.status || '').toLowerCase())).length;
  const progress = fresh.length ? Math.round((doneCount / fresh.length) * 100) : 0;
  const v = { mode: 'auto', checked, passed: checked.filter(c => c.pass).length, failed: checked.filter(c => !c.pass).length, checked_at: new Date().toISOString() };
  await pool.query(`UPDATE ticket_codes SET verification=$1 WHERE code=$2`, [JSON.stringify(v), tk.code]).catch(() => {});
  return { checked, progress, total: fresh.length, doneCount, verification: v };
}

// AI-written, ticket-specific fix instructions — generated ONCE from the ticket's real findings
// (actual pages, current/target values, recommendations) and cached on the ticket. No templates.
function ticketItemsHash(items) {
  const crypto = require('crypto');
  return crypto.createHash('md5').update(items.map(i => `${i.id}:${(i.title || '').slice(0, 40)}`).sort().join('|')).digest('hex');
}
app.post('/api/control-centre/tickets/:code/instructions', async (req, res) => {
  try {
    const tk = (await pool.query('SELECT * FROM ticket_codes WHERE code=$1', [req.params.code])).rows[0];
    if (!tk) return res.status(404).json({ error: 'Ticket not found' });
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [tk.project_id])).rows[0];
    const items = (await pool.query('SELECT * FROM action_items WHERE code=$1 ORDER BY id', [req.params.code])).rows;
    if (!items.length) return res.status(400).json({ error: 'No findings on this ticket' });
    if (!anthropic) return res.status(503).json({ error: 'AI not configured' });

    const hash = ticketItemsHash(items);
    if (tk.how_to && tk.how_to.hash === hash && Array.isArray(tk.how_to.steps) && tk.how_to.steps.length) {
      return res.json({ ok: true, cached: true, steps: tk.how_to.steps });
    }

    const where = (TICKET_PLAYBOOK[tk.pillar_code] || TICKET_PLAYBOOK.GEN).where;
    const findings = items.slice(0, 15).map(i => ({
      title: (i.title || '').slice(0, 120),
      page: i.ranking_page || ((i.pages_affected || '').split(/[\n,]+/)[0] || '').trim() || null,
      problem: (i.description || '').slice(0, 250),
      current: (i.current_value || '').toString().slice(0, 120) || null,
      change_to: (i.new_value || '').toString().slice(0, 120) || null,
      keyword: i.keyword || null,
    }));

    const aiResp = await anthropic.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 900,
      system: `You write fix instructions for an SEO agency team member working on ONE ticket. Rules:
- Be concrete and specific to the findings given: name the actual pages, values and changes. NEVER give generic advice ("run an audit", "review your SEO").
- 3-6 short numbered steps a junior could follow without asking questions.
- The work is done in: "${where}" (the dashboard tool) — mention it where relevant.
- If the findings carry a "change_to" value, tell them to apply exactly that.
- Return JSON ONLY: {"steps": ["...", "..."]}`,
      messages: [{ role: 'user', content: `Project: ${project.name} (${project.domain})
Ticket ${tk.code} — category: ${items[0].category || tk.pillar_code} — fix type tool: ${where}
Findings:
${JSON.stringify(findings, null, 1)}` }],
    });
    let steps = [];
    try { steps = (JSON.parse(aiResp.content[0].text.match(/\{[\s\S]*\}/)[0]).steps || []).filter(x => typeof x === 'string'); } catch (e) {}
    if (!steps.length) return res.status(500).json({ error: 'AI returned no usable steps' });

    await pool.query('UPDATE ticket_codes SET how_to=$1 WHERE code=$2', [JSON.stringify({ steps, hash, generated_at: new Date().toISOString() }), req.params.code]);
    res.json({ ok: true, cached: false, steps });
  } catch (e) {
    console.error('[instructions] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Check progress WITHOUT closing — updates the bar, marks verified findings done
app.post('/api/control-centre/tickets/:code/verify', async (req, res) => {
  try {
    const tk = (await pool.query('SELECT * FROM ticket_codes WHERE code=$1', [req.params.code])).rows[0];
    if (!tk) return res.status(404).json({ error: 'Ticket not found' });
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [tk.project_id])).rows[0];
    const items = (await pool.query('SELECT * FROM action_items WHERE code=$1', [req.params.code])).rows;
    const r = await runTicketVerification(tk, project, items, req.auth?.userId);
    if (r.manual) return res.json({ ok: true, result: 'manual', message: r.note });
    res.json({ ok: true, result: 'checked', progress: r.progress, message: `Progress: ${r.progress}% (${r.doneCount}/${r.total} findings fixed).` });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Finish: verify, then close ONLY at 100%. Manual types go to lead review.
app.post('/api/control-centre/tickets/:code/finish', async (req, res) => {
  try {
    const tk = (await pool.query('SELECT * FROM ticket_codes WHERE code=$1', [req.params.code])).rows[0];
    if (!tk) return res.status(404).json({ error: 'Ticket not found' });
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [tk.project_id])).rows[0];
    const items = (await pool.query('SELECT * FROM action_items WHERE code=$1', [req.params.code])).rows;

    if (!AUTO_VERIFY_PILLARS.includes(tk.pillar_code)) {
      const v = { mode: 'manual', note: 'Sent to lead for review', checked_at: new Date().toISOString() };
      await pool.query(`UPDATE ticket_codes SET status='Ready for Review', finished_at=NOW(), verification=$1 WHERE code=$2`, [JSON.stringify(v), req.params.code]);
      return res.json({ ok: true, result: 'review', message: `Sent to the lead for review. Closed when: ${TICKET_DONE_WHEN[tk.pillar_code] || TICKET_DONE_WHEN.MANUAL}` });
    }

    const r = await runTicketVerification(tk, project, items, req.auth?.userId);
    if (r.manual) {
      const v = { mode: 'manual', note: r.note, checked_at: new Date().toISOString() };
      await pool.query(`UPDATE ticket_codes SET status='Ready for Review', finished_at=NOW(), verification=$1 WHERE code=$2`, [JSON.stringify(v), req.params.code]);
      return res.json({ ok: true, result: 'review', message: r.note + ' Sent to the lead.' });
    }
    if (r.progress === 100 && (!r.verification || r.verification.failed === 0)) {
      await pool.query(`UPDATE ticket_codes SET status='Done', finished_at=NOW(), verified_at=NOW(), closed_by=$2 WHERE code=$1`, [req.params.code, req.auth?.userId || null]);
      return res.json({ ok: true, result: 'closed', message: `Verified ✓ — the live check passes. Ticket closed.` });
    }
    await pool.query(`UPDATE ticket_codes SET status='In Progress' WHERE code=$1`, [req.params.code]);
    return res.json({ ok: true, result: 'failed', message: `Progress: ${r.progress}% (${r.doneCount}/${r.total} fixed) — not done yet, ticket stays In Progress. The failing pages are listed on the ticket.` });
  } catch (e) {
    console.error('[finish] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Status moves: Finish (→ Ready for Review), Done, Reopen (→ In Progress)
app.post('/api/control-centre/tickets/:code/status', async (req, res) => {
  try {
    const allowed = ['New', 'Assigned', 'In Progress', 'Ready for Review', 'Done'];
    const status = (req.body && req.body.status || '').trim();
    if (!allowed.includes(status)) return res.status(400).json({ error: `Status must be one of: ${allowed.join(', ')}` });
    const r = await pool.query(
      `UPDATE ticket_codes SET status=$1,
              finished_at = CASE WHEN $1='Done' THEN NOW() ELSE finished_at END,
              closed_by   = CASE WHEN $1='Done' THEN $3 ELSE closed_by END
        WHERE code=$2 RETURNING *`,
      [status, req.params.code, req.auth?.userId || null]);
    if (!r.rows.length) return res.status(404).json({ error: 'Ticket not found' });
    res.json({ ok: true, ticket: r.rows[0] });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

