// ==================== API COST TRACKING ====================

// Cost per API call estimates (USD)
const API_COST_RATES = {
  serpapi: { google: 0.01, google_maps: 0.01 },        // ~$50/5000 searches
  dataforseo: { serp: 0.004, maps: 0.002, ranked_keywords: 0.04, search_volume: 0.002 },
  anthropic: { haiku: 0.003 },                          // ~$0.003 per audit call (est. 3K tokens)
  pagespeed: { check: 0 },                              // free
  gsc: { query: 0 },                                    // free (OAuth)
};

// Log an API cost to the database
async function logApiCost(projectId, feature, provider, apiCalls, cost, details = {}) {
  try {
    await pool.query(
      `INSERT INTO api_costs (project_id, feature, provider, api_calls, cost, details) VALUES ($1,$2,$3,$4,$5,$6)`,
      [projectId, feature, provider, apiCalls, cost, JSON.stringify(details)]
    );
  } catch (e) {
    console.error('[cost-log] Error:', e.message);
  }
}

// Estimate cost for a feature before running
function estimateFeatureCost(feature, params = {}) {
  switch (feature) {
    case 'serp_sync': {
      const kwCount = params.keywords || 0;
      const provider = params.provider || 'serpapi';
      const rate = provider === 'serpapi' ? API_COST_RATES.serpapi.google : API_COST_RATES.dataforseo.serp;
      const volumeCost = API_COST_RATES.dataforseo.search_volume * Math.min(kwCount, 1); // 1 batch call
      return { calls: kwCount, cost: +(kwCount * rate + volumeCost).toFixed(4), provider };
    }
    case 'maps_sync': {
      const kwCount = params.keywords || 0;
      const provider = params.provider || 'serpapi';
      const rate = provider === 'serpapi' ? API_COST_RATES.serpapi.google : API_COST_RATES.dataforseo.serp;
      return { calls: kwCount, cost: +(kwCount * rate).toFixed(4), provider };
    }
    case 'grid_scan': {
      // Grid scan runs on DataForSEO Maps (dataForSeoMaps), not SerpAPI — estimate must match the real provider/rate
      const kwCount = params.keywords || 0;
      const gridPoints = (params.gridSize || 5) * (params.gridSize || 5);
      const totalCalls = kwCount * gridPoints;
      return { calls: totalCalls, cost: +(totalCalls * API_COST_RATES.dataforseo.maps).toFixed(4), provider: 'dataforseo' };
    }
    case 'discover_serp': {
      return { calls: 1, cost: +(API_COST_RATES.dataforseo.ranked_keywords).toFixed(4), provider: 'dataforseo' };
    }
    case 'discover_maps': {
      const kwCount = params.keywords || 30; // estimated service keywords
      const provider = params.provider || 'dataforseo';
      const rate = provider === 'serpapi' ? API_COST_RATES.serpapi.google_maps : API_COST_RATES.dataforseo.maps;
      const volumeCost = API_COST_RATES.dataforseo.search_volume;
      return { calls: kwCount, cost: +(kwCount * rate + volumeCost).toFixed(4), provider };
    }
    case 'gbp_audit': {
      return { calls: 2, cost: +(API_COST_RATES.serpapi.google_maps + API_COST_RATES.anthropic.haiku).toFixed(4), provider: 'serpapi+anthropic' };
    }
    case 'gsc_audit': {
      return { calls: 1, cost: +(API_COST_RATES.anthropic.haiku).toFixed(4), provider: 'anthropic' };
    }
    case 'website_audit': {
      const pages = params.pages || 15;
      return { calls: pages + 1, cost: +(API_COST_RATES.anthropic.haiku).toFixed(4), provider: 'anthropic' };
    }
    case 'pagespeed': {
      return { calls: params.pages || 15, cost: 0, provider: 'google' };
    }
    case 'handshake': {
      return { calls: 6, cost: +(API_COST_RATES.serpapi.google_maps * 3 + API_COST_RATES.anthropic.haiku * 2 + 0.01).toFixed(4), provider: 'serpapi+anthropic' };
    }
    default:
      return { calls: 0, cost: 0, provider: 'unknown' };
  }
}

// Get current month's spend for a project
async function getProjectMonthSpend(projectId) {
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
  const r = await pool.query(
    `SELECT COALESCE(SUM(cost), 0) as total_cost, COALESCE(SUM(api_calls), 0) as total_calls,
     json_agg(json_build_object('feature', feature, 'provider', provider, 'calls', api_calls, 'cost', cost, 'date', created_at) ORDER BY created_at DESC) as breakdown
     FROM api_costs WHERE project_id=$1 AND created_at >= $2`,
    [projectId, monthStart]
  );
  return { totalCost: parseFloat(r.rows[0].total_cost), totalCalls: parseInt(r.rows[0].total_calls), breakdown: r.rows[0].breakdown || [] };
}

// Get current month's spend across all projects (agency level)
async function getAgencyMonthSpend() {
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
  const r = await pool.query(
    `SELECT COALESCE(SUM(cost), 0) as total_cost, COALESCE(SUM(api_calls), 0) as total_calls FROM api_costs WHERE created_at >= $1`,
    [monthStart]
  );
  const byProject = await pool.query(
    `SELECT ac.project_id, p.name as project_name, COALESCE(SUM(ac.cost), 0) as cost, COALESCE(SUM(ac.api_calls), 0) as calls
     FROM api_costs ac LEFT JOIN projects p ON p.id = ac.project_id
     WHERE ac.created_at >= $1 GROUP BY ac.project_id, p.name ORDER BY cost DESC`,
    [monthStart]
  );
  const byFeature = await pool.query(
    `SELECT feature, provider, COALESCE(SUM(cost), 0) as cost, COALESCE(SUM(api_calls), 0) as calls
     FROM api_costs WHERE created_at >= $1 GROUP BY feature, provider ORDER BY cost DESC`,
    [monthStart]
  );
  return {
    totalCost: parseFloat(r.rows[0].total_cost),
    totalCalls: parseInt(r.rows[0].total_calls),
    byProject: byProject.rows.map(r => ({ ...r, cost: parseFloat(r.cost), calls: parseInt(r.calls) })),
    byFeature: byFeature.rows.map(r => ({ ...r, cost: parseFloat(r.cost), calls: parseInt(r.calls) })),
  };
}

// Check budget before running — returns { ok, warning }
async function checkBudget(projectId) {
  const spend = await getProjectMonthSpend(projectId);
  const projRes = await pool.query('SELECT monthly_budget FROM projects WHERE id=$1', [projectId]);
  const projectBudget = parseFloat(projRes.rows[0]?.monthly_budget) || 0;

  const agencyRes = await pool.query("SELECT value FROM agency_settings WHERE key='monthly_budget'");
  const agencyBudget = parseFloat(agencyRes.rows[0]?.value) || 0;

  const agencySpend = await getAgencyMonthSpend();

  const warnings = [];
  if (projectBudget > 0 && spend.totalCost >= projectBudget) {
    warnings.push(`Project budget exceeded: $${spend.totalCost.toFixed(2)} / $${projectBudget.toFixed(2)}`);
  } else if (projectBudget > 0 && spend.totalCost >= projectBudget * 0.8) {
    warnings.push(`Project budget at ${Math.round(spend.totalCost / projectBudget * 100)}%: $${spend.totalCost.toFixed(2)} / $${projectBudget.toFixed(2)}`);
  }
  if (agencyBudget > 0 && agencySpend.totalCost >= agencyBudget) {
    warnings.push(`Agency budget exceeded: $${agencySpend.totalCost.toFixed(2)} / $${agencyBudget.toFixed(2)}`);
  } else if (agencyBudget > 0 && agencySpend.totalCost >= agencyBudget * 0.8) {
    warnings.push(`Agency budget at ${Math.round(agencySpend.totalCost / agencyBudget * 100)}%: $${agencySpend.totalCost.toFixed(2)} / $${agencyBudget.toFixed(2)}`);
  }
  return { ok: warnings.length === 0, warnings, projectSpend: spend.totalCost, agencySpend: agencySpend.totalCost, projectBudget, agencyBudget };
}

// ==================== SERPAPI HELPER ====================

async function serpApiSearch(params) {
  if (!SERPAPI_KEY) throw new Error('SERPAPI_KEY not configured');
  // Filter out undefined/null/empty values to avoid sending them as strings
  const cleanParams = Object.fromEntries(Object.entries({ ...params, api_key: SERPAPI_KEY }).filter(([_, v]) => v != null && v !== ''));
  const searchParams = new URLSearchParams(cleanParams);
  const resp = await fetch(`https://serpapi.com/search.json?${searchParams}`);
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`SerpAPI error ${resp.status}: ${text.substring(0, 200)}`);
  }
  return resp.json();
}

// ==================== SEODITY HELPERS (lifetime plan — free monthly SERP credits) ====================

// Monthly credit accounting so we never blow past the plan cap; auto-fallback decisions use this.
async function seodityUsedThisMonth() {
  const month = new Date().toISOString().slice(0, 7);
  const r = await pool.query('SELECT used FROM seodity_usage WHERE month=$1', [month]).catch(() => ({ rows: [] }));
  return r.rows.length ? parseInt(r.rows[0].used) : 0;
}
async function seodityRecordUse(n) {
  const month = new Date().toISOString().slice(0, 7);
  await pool.query(
    `INSERT INTO seodity_usage (month, used) VALUES ($1, $2)
     ON CONFLICT (month) DO UPDATE SET used = seodity_usage.used + $2`, [month, n]).catch(() => {});
}
async function seodityCanSpend(n) {
  if (!SEODITY_API_KEY) return false;
  const used = await seodityUsedThisMonth();
  return used + n <= SEODITY_MONTHLY_BUDGET;
}

// Google SERP via Seodity — returns a SerpAPI-SHAPED object so existing parsing code works as-is.
async function seoditySerpSearch({ query, location, device }) {
  if (!SEODITY_API_KEY) throw new Error('SEODITY_API_KEY not configured');
  const params = new URLSearchParams({ query, location: location || 'Australia', language: 'English', device: device || 'desktop' });
  const resp = await fetch(`https://api.seodity.com/v1/api/serp/google/search?${params}`, {
    headers: { Authorization: `APIKey ${SEODITY_API_KEY}` },
    signal: AbortSignal.timeout(30000),
  });
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`Seodity error ${resp.status}: ${text.substring(0, 200)}`);
  }
  const d = await resp.json();
  if (d.request_info && d.request_info.success === false) {
    throw new Error(`Seodity request failed: ${(d.request_info.error || 'unknown').toString().slice(0, 200)}`);
  }
  // Record the REAL credit cost reported by the API (not an assumed 1 per search)
  const creditsUsed = parseInt(d.request_info && d.request_info.credits_used) || 1;
  await seodityRecordUse(creditsUsed);
  const r = d.result || {};
  return {
    organic_results: (r.organic_results || []).map(o => ({
      position: o.position, link: o.url, title: o.title, snippet: o.description,
    })),
    local_results: r.local_results || [],
    related_questions: r.related_questions || [],
    related_searches: r.related_searches || [],
    answer_box: r.answer_box || null,
    _provider: 'seodity',
  };
}

// ==================== DATAFORSEO HELPERS ====================

// DataForSEO Maps SERP — replaces serpApiSearch({ engine: 'google_maps', ... })
// Returns normalized results matching the shape the dashboard expects
async function dataForSeoMaps({ keyword, lat, lng, location, depth }) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured. Add DATAFORSEO_LOGIN and DATAFORSEO_PASSWORD.');
  const task = {
    keyword,
    language_code: 'en',
    depth: depth || 20,
    device: 'desktop',
    se_domain: 'google.com.au',
  };
  // GPS coordinates for grid scan accuracy
  if (lat != null && lng != null) {
    task.location_coordinate = `${lat},${lng},14z`;
  } else {
    // Use location name — normalize to DataForSEO format (no spaces after commas)
    task.location_name = (location || 'Perth,Western Australia,Australia').replace(/,\s+/g, ',');
  }
  const resp = await fetch('https://api.dataforseo.com/v3/serp/google/maps/live/advanced', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([task]),
  });
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`DataForSEO Maps error ${resp.status}: ${text.substring(0, 200)}`);
  }
  const data = await resp.json();
  const items = data.tasks?.[0]?.result?.[0]?.items || [];
  // Normalize to SerpAPI-like shape for compatibility
  const local_results = items.map((item, idx) => ({
    position: item.rank_group || (idx + 1),
    title: item.title || '',
    rating: item.rating?.value || null,
    reviews: item.rating?.votes_count || 0,
    type: item.category || '',
    address: item.address || '',
    phone: item.phone || '',
    website: item.url || '',
    domain: item.domain || '',
    data_id: item.cid || item.place_id || null,
    gps_coordinates: { latitude: item.latitude, longitude: item.longitude },
  }));
  return { local_results, cost: data.cost, source: 'dataforseo' };
}

// DataForSEO Organic SERP — replaces serpApiSearch({ engine: 'google', ... })
// Returns normalized results matching the shape the dashboard expects
async function dataForSeoSerp({ keyword, location, depth }) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured. Add DATAFORSEO_LOGIN and DATAFORSEO_PASSWORD.');
  // DataForSEO requires location_name without spaces after commas, e.g. "Perth,Western Australia,Australia"
  const normalizedLocation = (location || 'Perth,Western Australia,Australia').replace(/,\s+/g, ',');
  const task = {
    keyword,
    language_code: 'en',
    depth: depth || 30,
    device: 'desktop',
    se_domain: 'google.com.au',
    location_name: normalizedLocation,
  };
  const resp = await fetch('https://api.dataforseo.com/v3/serp/google/organic/live/advanced', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([task]),
  });
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`DataForSEO SERP error ${resp.status}: ${text.substring(0, 200)}`);
  }
  const data = await resp.json();
  const allItems = data.tasks?.[0]?.result?.[0]?.items || [];
  // Split into organic results and local pack (maps)
  const organic_results = allItems
    .filter(i => i.type === 'organic')
    .map((item, idx) => ({
      position: item.rank_group || (idx + 1),
      title: item.title || '',
      link: item.url || '',
      displayed_link: item.breadcrumb || item.url || '',
      snippet: item.description || '',
      domain: item.domain || '',
    }));
  // Extract local pack if present
  const localPack = allItems.find(i => i.type === 'maps' || i.type === 'local_pack');
  const local_results = { places: [] };
  if (localPack?.items) {
    local_results.places = localPack.items.map((item, idx) => ({
      position: idx + 1,
      title: item.title || '',
      rating: item.rating?.value || null,
      reviews: item.rating?.votes_count || 0,
      type: item.domain || '',
      address: item.address || '',
      website: item.url || '',
      domain: item.domain || '',
    }));
  }
  // Extract related searches
  const related_searches = allItems
    .filter(i => i.type === 'related_searches')
    .flatMap(i => (i.items || []).map(r => ({ query: r.title || r })));
  // Extract PAA
  const related_questions = allItems
    .filter(i => i.type === 'people_also_ask')
    .flatMap(i => (i.items || []).map(r => ({ question: r.title || r })));
  return { organic_results, local_results, related_searches, related_questions, cost: data.cost, source: 'dataforseo' };
}

// DataForSEO Ranked Keywords — discovers all keywords a domain ranks for
async function dataForSeoRankedKeywords({ domain, locationCode, limit, offset }) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured. Add DATAFORSEO_LOGIN and DATAFORSEO_PASSWORD.');
  const resp = await fetch('https://api.dataforseo.com/v3/dataforseo_labs/google/ranked_keywords/live', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([{
      target: domain,
      language_code: 'en',
      location_code: locationCode || 2036, // 2036 = Australia
      limit: limit || 100,
      offset: offset || 0,
      order_by: ['ranked_serp_element.serp_item.rank_group,asc'],
    }]),
  });
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`DataForSEO Ranked Keywords error ${resp.status}: ${text.substring(0, 200)}`);
  }
  const data = await resp.json();
  const task = data.tasks?.[0];
  const items = task?.result?.[0]?.items || [];
  const total = task?.result?.[0]?.total_count || 0;
  const keywords = items.map(i => ({
    keyword: i.keyword_data?.keyword,
    volume: i.keyword_data?.keyword_info?.search_volume,
    cpc: i.keyword_data?.keyword_info?.cpc,
    competition: i.keyword_data?.keyword_info?.competition_level,
    position: i.ranked_serp_element?.serp_item?.rank_group,
    url: i.ranked_serp_element?.serp_item?.relative_url,
    type: i.ranked_serp_element?.serp_item?.type,
  }));
  return { domain, total_count: total, keywords, cost: data.cost };
}

// DataForSEO Maps Place Details — replaces serpApiSearch({ engine: 'google_maps', data_id: ..., type: 'place' })
async function dataForSeoPlaceDetails({ cid, keyword, location }) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured.');
  // DataForSEO doesn't have a direct place-details-by-CID endpoint for Maps.
  // Workaround: search by business name + location and return the first match.
  // The caller should use dataForSeoMaps() with the business name as keyword instead.
  return dataForSeoMaps({ keyword: keyword || cid, location });
}

// ── DataForSEO Backlinks API helpers ──

async function dataForSeoBacklinksSummary(domain) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured.');
  const resp = await fetch('https://api.dataforseo.com/v3/backlinks/summary/live', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([{ target: domain, include_subdomains: true }])
  });
  const data = await resp.json();
  const taskStatus = data.tasks?.[0]?.status_code;
  const taskMsg = data.tasks?.[0]?.status_message;
  console.log(`[backlinks] Summary for "${domain}": task_status=${taskStatus}, msg="${taskMsg}"`);
  if (taskStatus === 20000 && data.tasks?.[0]?.result?.[0]) {
    const raw = data.tasks[0].result[0];
    console.log(`[backlinks] Raw summary ALL KEYS:`, Object.keys(raw).join(', '));
    console.log(`[backlinks] Raw summary VALUES:`, JSON.stringify(raw, null, 0).substring(0, 2000));
  }

  // If 40204 (not found), try with www. prefix
  if (taskStatus === 40204 && !domain.startsWith('www.')) {
    console.log(`[backlinks] Retrying with www.${domain}`);
    const resp2 = await fetch('https://api.dataforseo.com/v3/backlinks/summary/live', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
      body: JSON.stringify([{ target: 'www.' + domain, include_subdomains: true }])
    });
    const data2 = await resp2.json();
    const ts2 = data2.tasks?.[0]?.status_code;
    console.log(`[backlinks] www retry status=${ts2}`);
    if (ts2 === 20000 && data2.tasks?.[0]?.result?.[0]) {
      const r = data2.tasks[0].result[0];
      const nf = r.referring_links_attributes?.nofollow || 0;
      const tb = r.backlinks || 0;
      return {
        total_backlinks: tb,
        referring_domains: r.referring_domains || 0,
        referring_domains_nofollow: r.referring_domains_nofollow || 0,
        referring_ips: r.referring_ips || 0,
        domain_rank: r.rank || 0,
        dofollow: tb - nf,
        nofollow: nf,
        gov_backlinks: r.referring_links_tld?.gov || 0,
        edu_backlinks: r.referring_links_tld?.edu || 0,
        broken_backlinks: r.broken_backlinks || 0,
        broken_pages: r.broken_pages || 0,
        referring_pages: r.referring_pages || 0,
        spam_score: r.backlinks_spam_score || 0,
        cost: (data.cost || 0) + (data2.cost || 0),
        effective_target: 'www.' + domain
      };
    }
  }

  const r = data.tasks?.[0]?.result?.[0] || {};
  const nofollowCount = r.referring_links_attributes?.nofollow || 0;
  const totalBl = r.backlinks || 0;
  return {
    total_backlinks: totalBl,
    referring_domains: r.referring_domains || 0,
    referring_domains_nofollow: r.referring_domains_nofollow || 0,
    referring_ips: r.referring_ips || 0,
    domain_rank: r.rank || 0,
    dofollow: totalBl - nofollowCount,
    nofollow: nofollowCount,
    gov_backlinks: r.referring_links_tld?.gov || 0,
    edu_backlinks: r.referring_links_tld?.edu || 0,
    broken_backlinks: r.broken_backlinks || 0,
    broken_pages: r.broken_pages || 0,
    referring_pages: r.referring_pages || 0,
    spam_score: r.backlinks_spam_score || 0,
    cost: data.cost
  };
}

// Multi-signal backlink toxicity — uses DataForSEO's real backlink_spam_score plus hard signals.
// Low domain authority ALONE is NOT toxic (many legit small sites have low DR).
const SPAM_NICHE_RE = /casino|viagra|cialis|pharma|porn|\bsex\b|adult|gambling|betting|\bpoker\b|payday|\bloan\b|escort|replica|crypto.?pump/i;
function computeBacklinkToxicity(i) {
  const reasons = [];
  let score = 0;
  // DataForSEO's own spam score (0-100) is the primary, authoritative signal
  const dfsSpam = (typeof i.backlink_spam_score === 'number') ? i.backlink_spam_score
                : (typeof i.spam_score === 'number') ? i.spam_score : null;
  if (dfsSpam != null) {
    score += dfsSpam;
    if (dfsSpam >= 50) reasons.push(`Spam score ${dfsSpam}`);
  }
  // Hard signals
  if (i.domain_from_is_ip) { score += 35; reasons.push('IP-host domain'); }
  if (SPAM_NICHE_RE.test(i.domain_from || '')) { score += 45; reasons.push('Spam-niche domain'); }
  if (SPAM_NICHE_RE.test(i.anchor || '')) { score += 35; reasons.push('Spam-niche anchor'); }
  if (i.is_broken) { score += 15; reasons.push('Broken link'); }
  // Soft signal: very low authority + dofollow, only meaningful when we have no DFS spam score
  if (dfsSpam == null && (i.domain_from_rank || 0) < 5 && i.dofollow) { score += 12; reasons.push('Very low authority'); }
  score = Math.min(100, Math.round(score));
  const level = score >= 60 ? 'high' : score >= 30 ? 'medium' : 'low';
  return { toxic_score: score, toxic_level: level, toxic_reasons: reasons, dfs_spam_score: dfsSpam };
}

async function dataForSeoBacklinks(domain, limit = 500, offset = 0, orderBy) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured.');
  const body = [{
    target: domain,
    include_subdomains: true,
    limit,
    offset,
    mode: 'as_is',
    filters: null
  }];
  if (orderBy) body[0].order_by = [orderBy];
  const resp = await fetch('https://api.dataforseo.com/v3/backlinks/backlinks/live', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify(body)
  });
  const data = await resp.json();
  const result = data.tasks?.[0]?.result?.[0] || {};
  const items = result.items || [];
  return {
    total_count: result.total_count || 0,
    backlinks: items.map(i => {
      const tox = computeBacklinkToxicity(i);
      return {
        url_from: i.url_from || '',
        domain_from: i.domain_from || '',
        url_to: i.url_to || '',
        anchor: i.anchor || '',
        dofollow: i.dofollow,
        domain_from_rank: i.domain_from_rank || 0,
        page_from_rank: i.page_from_rank || 0,
        first_seen: i.first_seen,
        last_seen: i.last_seen,
        is_lost: i.is_lost || false,
        item_type: i.item_type || 'anchor',
        is_broken: i.is_broken || false,
        url_from_https: i.url_from_https,
        tld_from: i.tld_from || '',
        domain_from_is_ip: i.domain_from_is_ip || false,
        // Real DataForSEO spam score (0-100) + computed multi-signal toxicity
        dfs_spam_score: tox.dfs_spam_score,
        toxic_score: tox.toxic_score,
        toxic_reasons: tox.toxic_reasons,
        spam_score: tox.toxic_level // backward-compat: 'high'|'medium'|'low' for existing badge
      };
    }),
    cost: data.cost
  };
}

