async function dataForSeoNewLostBacklinks(domain, type, limit = 200) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured.');
  // type: 'new' or 'lost'
  const endpoint = type === 'new' ? 'backlinks/live' : 'backlinks/live';
  // Use date_from filter for new/lost detection
  const oneMonthAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
  const filters = type === 'new'
    ? ['first_seen', '>', oneMonthAgo]
    : ['is_lost', '=', true];
  const resp = await fetch('https://api.dataforseo.com/v3/backlinks/backlinks/live', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([{
      target: domain,
      include_subdomains: true,
      limit,
      mode: 'as_is',
      filters
    }])
  });
  const data = await resp.json();
  const items = data.tasks?.[0]?.result?.[0]?.items || [];
  return {
    count: items.length,
    links: items.map(i => ({
      url_from: i.url_from || '',
      domain_from: i.domain_from || '',
      url_to: i.url_to || '',
      anchor: i.anchor || '',
      dofollow: i.dofollow,
      domain_from_rank: i.domain_from_rank || 0,
      first_seen: i.first_seen,
      last_seen: i.last_seen,
      is_lost: i.is_lost || false
    })),
    cost: data.cost
  };
}

// Classify a prospect domain into a link-building "play" from its name/TLD. Drives outreach strategy.
function classifyLinkType(domain) {
  const d = (domain || '').toLowerCase();
  if (/(^|\.)(facebook|twitter|x|instagram|linkedin|pinterest|youtube|tiktok|reddit)\./.test(d)) return 'social';
  if (/(wikipedia|wikidata)\./.test(d)) return 'wiki';
  if (/(\.gov(\.|$)|\.edu(\.|$))/.test(d)) return 'authority';
  if (/(news|herald|times|post|tribune|gazette|abc|theage|smh|9news|7news|abc\.net)/.test(d)) return 'news';
  if (/(forum|community|board|discuss|stackexchange|quora)/.test(d)) return 'forum';
  if (/(directory|yellowpages|yelp|truelocal|hotfrog|startlocal|localsearch|womo|aussieweb|cylex|brownbook|find|listing|business\.|directories)/.test(d)) return 'directory';
  if (/(blog|wordpress|medium|substack|tumblr|blogspot)/.test(d)) return 'blog';
  return 'resource';
}

// Match a gap domain to a known Australian directory (for free/paid, price, difficulty, link metadata).
let _dirByDomain = null;
function normDirHost(h) { return (h || '').replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '').toLowerCase().replace(/\.au$/, ''); }
function directoryInfo(domain) {
  if (!_dirByDomain) {
    _dirByDomain = {};
    for (const d of AUSTRALIAN_DIRECTORIES) { const k = normDirHost(d.url); if (k) _dirByDomain[k] = d; }
  }
  const d = _dirByDomain[normDirHost(domain)];
  if (!d) return null;
  return {
    name: d.name,
    free: !!d.free,
    price: d.paid_option || (d.free ? 'Free' : ''),
    difficulty: d.difficulty || 'Easy',
    url: 'https://' + (d.url || '').replace(/^https?:\/\//, ''),
  };
}

// Detect low-quality / spam backlink sources so they don't pollute the gap as "opportunities".
// Covers: link-farm directories, SEO-stat/website-value tools (auto-generate a page linking to ANY domain),
// generic SEO link spam, and free-hosting throwaway subdomains. Known legit directories are never flagged.
const JUNK_BACKLINK_RE = new RegExp([
  // SEO stat / website-value / "report" tools that link to every domain they scan
  'siteprice', 'statshow', 'siteworth', 'websiteoutlook', 'hypestat', 'webstatsdomain', 'rank2traffic',
  'siteindices', 'sitevaluefox', 'worthofweb', 'kingranks', 'wtoregister', 'urlrate', 'clearwebstats',
  'easycounter', 'cubestat', 'websiteinformer', 'informer', 'statvoo', 'hupso', 'seoceros', 'seobility',
  'expireddomains', 'siteprice', 'similarsites', 'sitechecker', 'webrate', 'sur\\.ly', 'sitelike',
  // generic SEO / link spam
  'ahrefs-links', 'backlink', 'guestpost', 'articlesubmission', 'postonseo', 'seosandwitch', 'submiturl',
  'addurl', 'linkbuild', 'smallseotools', 'seotool', 'indexkings', 'prepostseo', 'bilalarticles',
  'seosandwich', 'articlebiz', 'bloggings', 'newses', 'kingranks',
].join('|'), 'i');
const FREE_HOST_RE = /\.(pages\.dev|netlify\.app|vercel\.app|web\.app|github\.io|wordpress\.com|blogspot\.|weebly\.com|wixsite\.com|webnode\.|surge\.sh|onrender\.com|herokuapp\.com|glitch\.me|repl\.co|000webhost|rf\.gd|epizy|infinityfreeapp)/i;

function isSpamLinkDir(domain) {
  if (directoryInfo(domain)) return false;
  return /(directory|listing|backlink|seolink|linkbuild|submit(url|site|link)|addurl|webdir|linkdir|rankdir)/i.test(domain || '');
}
// Broader junk check used to flag worthless gap rows as spam.
function isJunkBacklinkDomain(domain) {
  const d = domain || '';
  return isSpamLinkDir(d) || JUNK_BACKLINK_RE.test(d) || FREE_HOST_RE.test(d);
}

// Composite opportunity score (0-100): authority (domain rank) weighted with how many competitors already
// earned the link (more competitors = more proven-relevant and attainable for this niche).
function scoreOpportunity(rank, competitorsCount) {
  const r = Math.max(0, Math.min(1000, Number(rank) || 0));
  const c = Math.max(1, Number(competitorsCount) || 1);
  // Authority is tiered and dominant — a rank-0 domain (the signature of link-farm junk) earns nothing here,
  // so it can never outrank a domain with real authority no matter how many competitors link to it.
  const authority = r >= 300 ? 70 : r >= 150 ? 58 : r >= 80 ? 45 : r >= 30 ? 32 : r > 0 ? 18 : 0;
  const consensus = Math.min(c / 3, 1) * 25;  // up to 25 pts when 3+ competitors have it
  return Math.round(authority + consensus);
}

// Auto-discover competitor DOMAINS from data we already collected — Maps grid scans (competitors[].website)
// and the Players Handshake analysis — so backlink gap (and anything else) doesn't depend on someone
// manually typing competitors. Aggregates by domain, ranks by how dominant/frequent each competitor is.
const COMP_SKIP_HOST = /(facebook|instagram|google\.|google$|goo\.gl|gstatic|yelp|tripadvisor|yellowpages|truelocal|hotfrog|localsearch|youtube|linkedin|twitter|wikipedia|\.gov|oneflare|hipages|airtasker|productreview|womo|startlocal|cylex|aussieweb|brownbook|pinterest|tiktok|maps\.|bing\.|apple\.|reddit|quora|medium\.com|github|gumtree|seek\.com|indeed|glassdoor|trustpilot|clutch\.co|designrush|expertise\.com|threebestrated|wordstream)/;
function cleanHost(url) {
  return (url || '').replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '').toLowerCase();
}

// Resolve a competitor business NAME to its website domain via SerpAPI (local pack → knowledge graph →
// first non-aggregator organic result). Used when Maps grid scans captured the name but not the site.
async function resolveCompetitorWebsite(name, locationHint, ownDomain) {
  try {
    const data = await serpApiSearch({ engine: 'google', q: `${name} ${locationHint || ''}`.trim(), gl: 'au', hl: 'en', num: 5 });
    const lp = data?.local_results?.places || (Array.isArray(data?.local_results) ? data.local_results : []);
    for (const p of lp) { const h = cleanHost(p.website); if (h && h.includes('.') && h !== ownDomain && !COMP_SKIP_HOST.test(h)) return h; }
    const kg = cleanHost(data?.knowledge_graph?.website);
    if (kg && kg.includes('.') && kg !== ownDomain && !COMP_SKIP_HOST.test(kg)) return kg;
    for (const o of (data?.organic_results || [])) { const h = cleanHost(o.link); if (h && h.includes('.') && h !== ownDomain && !COMP_SKIP_HOST.test(h)) return h; }
  } catch (e) {}
  return null;
}

// Auto-discover competitor DOMAINS from data we already collected — Maps grid scans (competitors[].website
// or name) and the Players Handshake. When a competitor only has a name, resolve it to a domain via SerpAPI
// (cached in project_integrations kind='competitor_domains' so we never pay to resolve the same name twice).
async function discoverCompetitorDomains(projectId, project, resolve = true, preferSerp = false) {
  const ownDomain = cleanHost(project?.domain || project?.website || '');
  const locationHint = project?.location || (Array.isArray(project?.service_areas) ? project.service_areas[0] : '') || '';
  const domainAgg = new Map(); // host -> {domain,name,score,sources}
  const nameAgg = new Map();   // nameLower -> {name,score,sources}

  const addByDomain = (name, host, weight, source) => {
    if (!host || !host.includes('.') || host === ownDomain || COMP_SKIP_HOST.test(host)) return;
    const cur = domainAgg.get(host) || { domain: host, name: name || host, score: 0, sources: new Set() };
    cur.score += (weight || 0) + 1; cur.sources.add(source);
    if (name && (cur.name === host || !cur.name)) cur.name = name;
    domainAgg.set(host, cur);
  };
  const addByName = (name, weight, source) => {
    const key = (name || '').trim().toLowerCase();
    if (!key) return;
    const cur = nameAgg.get(key) || { name: name.trim(), score: 0, sources: new Set() };
    cur.score += (weight || 0) + 1; cur.sources.add(source);
    nameAgg.set(key, cur);
  };
  const ingest = (name, website, weight, source) => {
    const host = cleanHost(website);
    if (host && host.includes('.')) addByDomain(name, host, weight, source);
    else if (name) addByName(name, weight, source);
  };

  // 1. Maps grid scans
  try {
    const gs = await pool.query(`SELECT competitors FROM grid_scans WHERE project_id=$1 AND competitors IS NOT NULL AND competitors::text NOT IN ('[]','{}','null','""') ORDER BY scanned_at DESC LIMIT 40`, [projectId]);
    for (const row of gs.rows) {
      const c = row.competitors || {};
      const top = Array.isArray(c) ? c : (c.top || []);
      for (const x of top) ingest(x.name, x.website, (x.dominance || 0) + (x.appearances || 0), 'grid');
    }
  } catch (e) {}
  // 2. Players Handshake
  try {
    const hs = await pool.query(`SELECT data FROM audits WHERE project_id=$1 AND pillar='handshake' ORDER BY created_at DESC LIMIT 1`, [projectId]);
    for (const c of (hs.rows[0]?.data?.competitors || [])) ingest(c.name, c.website || c.gbp?.website, (c.appearances || 0) + (c.dominance || 0), 'handshake');
  } catch (e) {}
  // 3. Organic SERP competitors (from saved SERP analyses) — the domains actually ranking for our keywords.
  //    Weighted by ranking position (higher rank = stronger) and how often they appear across keywords.
  try {
    const sa = await pool.query(`SELECT competitors FROM serp_analysis WHERE project_id=$1`, [projectId]);
    for (const row of sa.rows) {
      let comps = row.competitors;
      if (typeof comps === 'string') { try { comps = JSON.parse(comps); } catch { comps = []; } }
      for (const c of (comps || [])) {
        let host = '';
        try { host = c.url ? new URL(c.url).hostname : ''; } catch { host = c.url || ''; }
        const pos = Number(c.position) || 10;
        ingest(c.title || null, host, Math.max(1, 6 - pos), 'serp'); // pos1→5, pos2→4, … floor 1
      }
    }
  } catch (e) {}

  // 4. Resolve the strongest name-only competitors to domains via SerpAPI (with a persistent cache).
  if (resolve && nameAgg.size && SERPAPI_KEY) {
    let cache = {};
    try { cache = (await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='competitor_domains'`, [projectId])).rows[0]?.config?.map || {}; } catch (e) {}
    const nameList = [...nameAgg.values()].sort((a, b) => b.score - a.score).slice(0, 8);
    let cacheDirty = false;
    for (const n of nameList) {
      const key = n.name.toLowerCase();
      let host = cache[key];
      if (host === undefined) { // not resolved before
        host = await resolveCompetitorWebsite(n.name, locationHint, ownDomain);
        cache[key] = host || null; cacheDirty = true;
      }
      if (host) addByDomain(n.name, host, n.score, [...n.sources][0] || 'grid');
    }
    if (cacheDirty) {
      try {
        await pool.query(
          `INSERT INTO project_integrations (project_id, kind, config) VALUES ($1,'competitor_domains',$2)
           ON CONFLICT (project_id, kind) DO UPDATE SET config=$2`,
          [projectId, JSON.stringify({ map: cache })]
        );
      } catch (e) {}
    }
  }

  let list = [...domainAgg.values()];
  if (preferSerp) {
    // For organic/SERP use, rank competitors that actually rank in search (source 'serp') first.
    list.sort((a, b) => (b.sources.has('serp') - a.sources.has('serp')) || (b.score - a.score));
  } else {
    list.sort((a, b) => b.score - a.score);
  }
  return list.map(c => ({ domain: c.domain, name: c.name, score: Math.round(c.score), sources: [...c.sources] }));
}

async function dataForSeoBacklinkGap(targetDomain, competitorDomains, opts = {}) {
  if (!DATAFORSEO_AUTH) throw new Error('DataForSEO not configured.');
  // Domain intersection: referring domains that link to the competitor TARGETS but NOT to our exclude_target.
  // Correct DataForSEO format: targets is a numbered object, exclude_targets is an array.
  const targets = {};
  competitorDomains.forEach((d, i) => { targets[String(i + 1)] = d; });

  const payload = {
    targets,
    // 'partial' = referring domains linking to ANY of the targets (true link gap). 'all' would require a
    // domain to link to EVERY competitor — almost never matches, which is why it returned 0.
    intersection_mode: opts.intersection_mode || 'partial',
    backlinks_status_type: 'live',
    include_subdomains: true,
    limit: 200,
    order_by: ['1.rank,desc']
  };
  if (opts.exclude !== false) payload.exclude_targets = [targetDomain];

  const resp = await fetch('https://api.dataforseo.com/v3/backlinks/domain_intersection/live', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
    body: JSON.stringify([payload])
  });
  const data = await resp.json();
  const task = data.tasks?.[0];
  if (task && task.status_code >= 40000) {
    throw new Error(`DataForSEO: ${task.status_message || 'error ' + task.status_code}`);
  }
  const result = task?.result?.[0];
  const items = result?.items || [];

  const opportunities = items.map(it => {
    const di = it.domain_intersection || {};
    const entries = Object.values(di);
    const refDomain = (entries[0]?.target || '')
      .replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '');
    const rank = entries.reduce((m, e) => Math.max(m, e.rank || 0), 0);
    return {
      domain: refDomain,
      rank,
      competitors_count: it.summary?.intersections_count || entries.length,
    };
  }).filter(o => o.domain);

  return {
    opportunities,
    total: result?.total_count || 0,
    cost: data.cost,
    debug: { status_message: task?.status_message, status_code: task?.status_code, items_count: result?.items_count, sent_targets: targets, mode: payload.intersection_mode, excluded: opts.exclude !== false }
  };
}

// ==================== 11a-ii. UULE v2 Encoder (GPS → Google location param) ====================
// Encodes latitude/longitude into a UULE v2 string for SerpAPI's `uule` parameter.
// This gives suburb-level accuracy for organic SERP results (unlike `location` which only accepts cities).
function generateUULE(lat, lng) {
  const timestamp = Date.now() * 1000; // microseconds
  const latE7 = Math.round(lat * 1e7);
  const lngE7 = Math.round(lng * 1e7);
  const payload = `role:1\nproducer:12\nprovenance:0\ntimestamp:${timestamp}\nlatlng{\nlatitude_e7:${latE7}\nlongitude_e7:${lngE7}\n}\nradius:-1\n`;
  const encoded = Buffer.from(payload).toString('base64');
  return 'a+' + encoded;
}

// ==================== 11b. SPEED AUDIT (via Google PageSpeed Insights API) ====================

// Helper: get WordPress URL for a project
async function getProjectWpUrl(projectId, userId) {
  const result = await pool.query('SELECT wordpress_url FROM projects WHERE id=$1 AND user_id=$2', [projectId, userId]);
  if (result.rows.length === 0) return null;
  return result.rows[0].wordpress_url;
}

// Helper: fetch from WP REST API
async function wpFetch(wpUrl, endpoint) {
  const url = `${wpUrl.replace(/\/$/, '')}/wp-json/${endpoint}`;
  const resp = await fetch(url);
  if (!resp.ok) throw new Error(`WP API error: ${resp.status} ${resp.statusText}`);
  return resp.json();
}

// Helper: run Google PageSpeed Insights on a URL and extract image issues
async function runPageSpeedAudit(url, strategy = 'mobile', retries = 3) {
  const PAGESPEED_KEY = process.env.PAGESPEED_API_KEY;
  const keyParam = PAGESPEED_KEY ? `&key=${PAGESPEED_KEY}` : '';
  const apiUrl = `https://www.googleapis.com/pagespeedonline/v5/runPagespeed?url=${encodeURIComponent(url)}&strategy=${strategy}&category=performance${keyParam}`;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const resp = await fetch(apiUrl, { signal: AbortSignal.timeout(90000) });
      if (!resp.ok) {
        const text = await resp.text();
        let msg = `HTTP ${resp.status}`;
        try { const j = JSON.parse(text); msg = j.error?.message || j.error?.errors?.[0]?.message || msg; } catch {}
        if (attempt < retries) {
          const delay = 5000 + attempt * 5000; // 5s, 10s, 15s
          console.log(`[pagespeed] ${strategy} ${url}: ${msg} — retry ${attempt + 1}/${retries} in ${delay/1000}s`);
          await new Promise(r => setTimeout(r, delay));
          continue;
        }
        throw new Error(`PageSpeed error: ${msg}`);
      }
      const data = await resp.json();
      // Check for Lighthouse errors in the response body (API returns 200 but Lighthouse failed)
      const runtimeErr = data.lighthouseResult?.runtimeError;
      if (runtimeErr && (runtimeErr.code === 'ERRORED_DOCUMENT_REQUEST' || runtimeErr.code === 'UNKNOWN_ERROR')) {
        if (attempt < retries) {
          const delay = 5000 + attempt * 5000;
          console.log(`[pagespeed] ${strategy} ${url}: Lighthouse ${runtimeErr.code} — retry ${attempt + 1}/${retries} in ${delay/1000}s`);
          await new Promise(r => setTimeout(r, delay));
          continue;
        }
        throw new Error(`PageSpeed error: Lighthouse returned error: ${runtimeErr.code}. ${runtimeErr.message || ''}`);
      }
      return data;
    } catch (err) {
      // ECONNRESET / socket hang up — connection dropped, use longer backoff
      const isConnErr = /ECONNRESET|ETIMEDOUT|socket hang up|network|UND_ERR/i.test(err.message);
      if (attempt < retries) {
        const delay = isConnErr ? (8000 + attempt * 8000) : (5000 + attempt * 5000);
        console.log(`[pagespeed] ${strategy} ${url}: ${err.message} — retry ${attempt + 1}/${retries} in ${delay/1000}s`);
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      throw err;
    }
  }
}

// Helper: extract image data from Lighthouse results
function extractImageIssues(lighthouseData) {
  const audits = lighthouseData?.lighthouseResult?.audits || {};
  const images = [];
  const seenSrcs = new Set();

  const imageAudits = [
    { key: 'uses-optimized-images', issue: 'too_large' },
    { key: 'modern-image-formats', issue: 'no_webp' },
    { key: 'unsized-images', issue: 'missing_width' },
    { key: 'offscreen-images', issue: 'no_lazy_load' },
    { key: 'uses-responsive-images', issue: 'oversized' },
  ];

  for (const { key, issue } of imageAudits) {
    const audit = audits[key];
    if (!audit?.details?.items) continue;
    for (const item of audit.details.items) {
      const src = item.url || item.node?.snippet || '';
      if (!src || src.startsWith('data:')) continue;
      const shortSrc = src.split('?')[0];
      if (seenSrcs.has(shortSrc)) {
        const existing = images.find(i => i.src.split('?')[0] === shortSrc);
        if (existing && !existing.issues.includes(issue)) existing.issues.push(issue);
      } else {
        seenSrcs.add(shortSrc);
        images.push({
          src,
          file_size_kb: item.totalBytes ? Math.round(item.totalBytes / 1024) : null,
          width: item.node?.boundingRect?.width || null,
          height: item.node?.boundingRect?.height || null,
          has_webp: issue !== 'no_webp',
          issues: [issue],
          wastedBytes: item.wastedBytes || 0,
        });
      }
    }
  }

  // Check for missing alt text
  const altAudit = audits['image-alt'];
  if (altAudit?.details?.items) {
    for (const item of altAudit.details.items) {
      const src = item.node?.snippet?.match(/src="([^"]+)"/)?.[1] || '';
      if (!src) continue;
      const shortSrc = src.split('?')[0];
      if (seenSrcs.has(shortSrc)) {
        const existing = images.find(i => i.src.split('?')[0] === shortSrc);
        if (existing && !existing.issues.includes('missing_alt')) existing.issues.push('missing_alt');
      } else {
        seenSrcs.add(shortSrc);
        images.push({ src, file_size_kb: null, width: null, height: null, has_webp: true, issues: ['missing_alt'], wastedBytes: 0 });
      }
    }
  }

  return images;
}

// Helper: discover pages from sitemap or WP REST API
async function discoverPages(projectUrl, wpUrl, authHeaders = null) {
  const pages = [];
  const baseUrl = projectUrl.replace(/\/$/, '');
  const seenUrls = new Set();

  // Helper: extract page URLs from a single sitemap XML
  // wpType: 'page' or 'post' inferred from sub-sitemap URL (e.g. wp-sitemap-posts-page-1.xml vs wp-sitemap-posts-post-1.xml)
  function extractPagesFromSitemap(xml, sitemapUrl) {
    // Detect type from sub-sitemap URL: "page" sitemaps = WP pages, "post" sitemaps = WP posts
    const wpType = sitemapUrl && /[\-\/]page[\-\d]*\.xml/i.test(sitemapUrl) ? 'page'
      : sitemapUrl && /[\-\/]post[\-\d]*\.xml/i.test(sitemapUrl) ? 'post' : 'unknown';
    const urlMatches = xml.match(/<loc>([^<]+)<\/loc>/g) || [];
    for (const match of urlMatches) {
      const url = match.replace(/<\/?loc>/g, '');
      if (url.endsWith('.pdf') || url.match(/\.(jpg|png|gif|svg)$/i)) continue;
      if (url.endsWith('.xml')) continue; // skip sub-sitemap refs (handled separately)
      if (seenUrls.has(url)) continue;
      seenUrls.add(url);
      const slug = url.replace(baseUrl, '').replace(/^\/|\/$/g, '') || 'home';
      pages.push({ page_id: slug, title: slug === 'home' ? 'Homepage' : slug.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase()), slug, url, wpType });
    }
  }

  // Try multiple sitemap URL patterns (sites use different paths)
  const sitemapUrls = [
    `${baseUrl}/sitemap.xml`,
    `${baseUrl}/sitemap_index.xml`,
    `${baseUrl}/wp-sitemap.xml`,
  ];
  const fetchHeaders = { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' };

  for (const sitemapUrl of sitemapUrls) {
    if (pages.length > 1) break; // already found pages from a previous sitemap URL
    try {
      const sitemapResp = await fetch(sitemapUrl, { headers: fetchHeaders, signal: AbortSignal.timeout(15000), redirect: 'follow' });
      if (!sitemapResp.ok) { console.log(`[discoverPages] ${sitemapUrl}: HTTP ${sitemapResp.status}`); continue; }
      const xml = await sitemapResp.text();
      console.log(`[discoverPages] ${sitemapUrl}: fetched ${xml.length} bytes`);

      // Check if this is a sitemap index (contains sub-sitemaps)
      const subSitemapMatches = xml.match(/<loc>([^<]+\.xml)<\/loc>/g) || [];
      if (subSitemapMatches.length > 0) {
        // Sort so page-sitemaps come before post-sitemaps, skip category/author sitemaps
        const subUrls = subSitemapMatches.map(m => m.replace(/<\/?loc>/g, ''))
          .filter(u => !/(category|tag|author)[\-_]/.test(u));
        subUrls.sort((a, b) => {
          const aIsPage = /[\-\/]page[\-\d]*\.xml/i.test(a) ? 0 : 1;
          const bIsPage = /[\-\/]page[\-\d]*\.xml/i.test(b) ? 0 : 1;
          return aIsPage - bIsPage;
        });
        console.log(`[discoverPages] Sitemap index with ${subUrls.length} sub-sitemaps: ${subUrls.join(', ')}`);
        for (const subUrl of subUrls) {
          try {
            const subResp = await fetch(subUrl, { headers: fetchHeaders, signal: AbortSignal.timeout(15000), redirect: 'follow' });
            if (subResp.ok) {
              const subXml = await subResp.text();
              extractPagesFromSitemap(subXml, subUrl);
              console.log(`[discoverPages] Sub-sitemap ${subUrl}: ${pages.length} pages total`);
            } else {
              console.log(`[discoverPages] Sub-sitemap ${subUrl}: HTTP ${subResp.status}`);
            }
          } catch (e) { console.log(`[discoverPages] Sub-sitemap ${subUrl} failed: ${e.message}`); }
        }
      } else {
        extractPagesFromSitemap(xml, null);
        console.log(`[discoverPages] Direct sitemap: ${pages.length} pages`);
      }
    } catch (e) { console.log(`[discoverPages] ${sitemapUrl} failed: ${e.message}`); }
  }

  // Also try direct sub-sitemap URLs if we still have few pages (some hosts block index but not individual sitemaps)
  if (pages.length <= 1) {
    const directSitemaps = [
      `${baseUrl}/page-sitemap.xml`,
      `${baseUrl}/post-sitemap.xml`,
      `${baseUrl}/wp-sitemap-posts-page-1.xml`,
      `${baseUrl}/wp-sitemap-posts-post-1.xml`,
    ];
    for (const dsUrl of directSitemaps) {
      try {
        const dsResp = await fetch(dsUrl, { headers: fetchHeaders, signal: AbortSignal.timeout(10000), redirect: 'follow' });
        if (dsResp.ok) {
          const dsXml = await dsResp.text();
          extractPagesFromSitemap(dsXml, dsUrl);
          console.log(`[discoverPages] Direct sub-sitemap ${dsUrl}: ${pages.length} pages total`);
        }
      } catch (e) { /* skip */ }
    }
  }

  console.log(`[discoverPages] After sitemap phase: ${pages.length} pages found`);

  // Try WP REST API — always run if available (supplements sitemap with wpType data)
  console.log(`[discoverPages] WP REST API: wpUrl=${wpUrl}, hasAuth=${!!authHeaders}`);
  if (wpUrl) {
    try {
      const wpBase = wpUrl.replace(/\/$/, '');
      const fetchOpts = { signal: AbortSignal.timeout(30000), headers: { ...fetchHeaders, ...(authHeaders || {}) } };
      // Paginate to get ALL published pages and posts
      for (const postType of ['pages', 'posts']) {
        let page = 1;
        while (true) {
          const apiUrl = `${wpBase}/wp-json/wp/v2/${postType}?per_page=100&page=${page}&status=publish&_fields=id,title,slug,link`;
          console.log(`[discoverPages] WP REST: fetching ${apiUrl}`);
          const resp = await fetch(apiUrl, fetchOpts);
          if (!resp.ok) { console.log(`[discoverPages] WP REST ${postType} page ${page}: HTTP ${resp.status}`); break; }
          const wpItems = await resp.json();
          if (!Array.isArray(wpItems) || wpItems.length === 0) break;
          for (const p of wpItems) {
            const url = p.link || '';
            if (seenUrls.has(url)) {
              // Already from sitemap — update wpType if unknown
              const existing = pages.find(pg => pg.url === url);
              if (existing && existing.wpType === 'unknown') existing.wpType = postType === 'pages' ? 'page' : 'post';
              continue;
            }
            seenUrls.add(url);
            pages.push({ page_id: String(p.id), title: p.title?.rendered || p.slug, slug: p.slug, url, wpType: postType === 'pages' ? 'page' : 'post' });
          }
          if (wpItems.length < 100) break;
          page++;
        }
      }
    } catch (e) { console.log('[discoverPages] WP REST API failed:', e.message); }
    console.log(`[discoverPages] After WP REST API: ${pages.length} pages found`);
  }

  // Fallback: just test the homepage
  if (pages.length === 0) {
    pages.push({ page_id: 'home', title: 'Homepage', slug: '', url: baseUrl });
  }

  return pages;
}

// Robustly collect ALL page URL paths from the XML sitemap (follows a Yoast/WP sitemap index).
// Used as a reliable supplement to discoverPages for suburb-page detection. Returns slug paths
// like "plumber-kallangur" (no leading/trailing slash).
async function collectSitemapPaths(baseUrl) {
  const out = []; const seen = new Set();
  const ua = { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' };
  const base = (baseUrl || '').replace(/\/+$/, '');
  const grabLocs = (xml) => (xml.match(/<loc>([^<]+)<\/loc>/g) || []).map(m => m.replace(/<\/?loc>/g, ''));
  const addPath = (u) => { try { const p = new URL(u).pathname.replace(/^\/|\/$/g, ''); if (p && !seen.has(p)) { seen.add(p); out.push(p); } } catch {} };
  const indexes = [`${base}/sitemap_index.xml`, `${base}/sitemap.xml`, `${base}/wp-sitemap.xml`, `${base}/page-sitemap.xml`];
  for (const idx of indexes) {
    try {
      const r = await fetch(idx, { headers: ua, signal: AbortSignal.timeout(12000), redirect: 'follow' });
      if (!r.ok) continue;
      const xml = await r.text();
      const locs = grabLocs(xml);
      const subs = locs.filter(u => u.endsWith('.xml') && !/(category|tag|author)/i.test(u));
      locs.filter(u => !u.endsWith('.xml')).forEach(addPath);
      for (const sub of subs.slice(0, 15)) {
        try {
          const rs = await fetch(sub, { headers: ua, signal: AbortSignal.timeout(12000), redirect: 'follow' });
          if (rs.ok) grabLocs(await rs.text()).filter(x => !x.endsWith('.xml')).forEach(addPath);
        } catch {}
      }
      if (out.length) break; // got pages — stop trying other index URLs
    } catch {}
  }
  return out;
}

// Helper: check if an audit was already completed this month for a project+pillar
async function checkMonthlyAuditLimit(projectId, pillar, force = false) {
  if (force) return { limited: false };
  const { rows } = await pool.query(
    `SELECT id, completed_at FROM audits
     WHERE project_id=$1 AND pillar=$2 AND status='completed'
     AND completed_at >= date_trunc('month', CURRENT_DATE)
     ORDER BY completed_at DESC LIMIT 1`,
    [projectId, pillar]
  );
  if (rows.length > 0) {
    const completedAt = new Date(rows[0].completed_at);
    const nextMonth = new Date(completedAt.getFullYear(), completedAt.getMonth() + 1, 1);
    const daysUntil = Math.ceil((nextMonth - Date.now()) / 86400000);
    return { limited: true, lastAudit: completedAt, nextAvailable: nextMonth, daysUntil, canForce: true };
  }
  return { limited: false };
}

// Run speed audit on ALL pages (via Google PageSpeed Insights) — async background job
app.post('/api/speed-audit/:projectId/run', async (req, res) => {
  try {
    const projRes = await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.projectId]);
    if (projRes.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const project = projRes.rows[0];
    const siteUrl = project.wordpress_url || (project.domain ? `https://${project.domain.replace(/^https?:\/\//, '')}` : null);
    if (!siteUrl) return res.status(400).json({ error: 'Website URL or domain not configured. Set it in Project Settings.' });

    // Cancel any running speed audits
    await pool.query(`UPDATE audits SET status='failed', completed_at=NOW() WHERE project_id=$1 AND pillar='speed' AND status='running'`, [req.params.projectId]);

    // Create audit record
    const auditRes = await pool.query(
      `INSERT INTO audits (project_id, pillar, status, started_at) VALUES ($1, 'speed', 'running', NOW()) RETURNING id`,
      [req.params.projectId]
    );
    const auditId = auditRes.rows[0].id;

    // Return immediately
    res.json({ auditId, status: 'running' });

    // Run in background
    (async () => {
      try {
        // Try connector cache first (plugin push data — Cloudflare safe)
        let pages = [];
        try {
          const cache = await getConnectorCache(req.params.projectId);
          if (cache && Array.isArray(cache.pages) && cache.pages.length > 0) {
            pages = cache.pages.map(p => ({
              page_id: String(p.id || p.slug || ''),
              title: p.title || p.slug || '',
              slug: p.slug || '',
              url: p.url || '',
              wpType: p.type || p.wpType || '',
            })).filter(p => p.url);
            console.log(`[speed-audit] Using ${pages.length} pages from connector cache`);
          }
        } catch (cacheErr) {
          console.log(`[speed-audit] Connector cache unavailable: ${cacheErr.message}`);
        }
        // Fallback to external discovery if no cache (retry on connection errors)
        if (pages.length === 0) {
          for (let discAttempt = 0; discAttempt < 3; discAttempt++) {
            try {
              pages = await discoverPages(siteUrl, project.wordpress_url, getWpAuthHeaders(project));
              break;
            } catch (discErr) {
              if (discAttempt < 2 && /ECONNRESET|ETIMEDOUT|socket hang up|UND_ERR/i.test(discErr.message)) {
                console.log(`[speed-audit] Page discovery failed (${discErr.message}), retry ${discAttempt + 1}/2...`);
                await new Promise(r => setTimeout(r, 5000));
                continue;
              }
              throw discErr;
            }
          }
        }
        // Sort: homepage → service pages → blog posts. Always sort, not just when >50.
        const baseClean = siteUrl.replace(/\/$/, '');
        // Detect blog posts by WP type or URL pattern (no title guessing — too noisy)
        const blogUrlPattern = /\/(blog|news|category|tag|author|20\d{2})\//i;
        function isBlogPost(p) {
          if (p.wpType === 'post') return true;
          if (blogUrlPattern.test(p.url)) return true;
          return false;
        }
        function isHome(p) {
          return p.slug === '' || p.slug === 'home' || p.slug === '/' || p.url.replace(/\/$/, '') === baseClean;
        }
        // Tag each page for logging
        pages.forEach(p => { p._isHome = isHome(p); p._isBlog = isBlogPost(p); });
        console.log(`[speed-audit] Sort: ${pages.filter(p=>p._isHome).length} home, ${pages.filter(p=>!p._isHome && !p._isBlog).length} service, ${pages.filter(p=>p._isBlog).length} blog`);
        console.log(`[speed-audit] Sample wpTypes:`, pages.slice(0, 5).map(p => `${p.wpType||'none'}:${p.slug||p.url}`));
        pages.sort((a, b) => {
          const aRank = a._isHome ? 0 : a._isBlog ? 2 : 1;
          const bRank = b._isHome ? 0 : b._isBlog ? 2 : 1;
          if (aRank !== bRank) return aRank - bRank;
          return (a.url || '').localeCompare(b.url || '');
        });
        if (pages.length > 50) {
          pages = pages.slice(0, 50);
          console.log(`[speed-audit] Capped to 50 pages (homepage + services first)`);
        }
        console.log(`[speed-audit] Total ${pages.length} pages for project ${req.params.projectId}`);

        // Save total immediately so frontend can show counter
        await pool.query(`UPDATE audits SET audit_data=$1 WHERE id=$2`,
          [JSON.stringify({ progress: 0, total: pages.length }), auditId]);

        const BATCH_SIZE = 3; // 3 pages at a time — parallel mobile+desktop per page
        const results = [];

        function extractCwvAndOpps(psData) {
          const metrics = psData.lighthouseResult?.audits || {};
          const score = Math.round((psData.lighthouseResult?.categories?.performance?.score || 0) * 100);
          const opportunities = [];
          const fixableAudits = [
            'unsized-images', 'render-blocking-resources', 'unused-css', 'unused-javascript',
            'uses-responsive-images', 'offscreen-images', 'uses-optimized-images', 'modern-image-formats',
            'uses-text-compression', 'uses-rel-preconnect', 'uses-rel-preload', 'font-display',
            'third-party-summary', 'dom-size', 'critical-request-chains', 'largest-contentful-paint-element',
            'layout-shift-elements', 'long-tasks', 'efficient-animated-content', 'duplicated-javascript',
            'legacy-javascript', 'total-byte-weight', 'mainthread-work-breakdown',
          ];
          for (const key of fixableAudits) {
            const audit = metrics[key];
            if (audit && audit.score !== null && audit.score < 1) {
              const opp = { id: key, title: audit.title, score: audit.score, displayValue: audit.displayValue || '' };
              if (audit.details?.items?.length) {
                opp.items = audit.details.items.slice(0, 10).map(item => {
                  const cleaned = {};
                  if (item.url) cleaned.url = item.url;
                  if (item.node?.snippet) cleaned.snippet = item.node.snippet.slice(0, 200);
                  if (item.wastedBytes) cleaned.wastedBytes = item.wastedBytes;
                  if (item.wastedMs) cleaned.wastedMs = item.wastedMs;
                  if (item.totalBytes) cleaned.totalBytes = item.totalBytes;
                  if (item.source) cleaned.source = typeof item.source === 'object' ? item.source.url : item.source;
                  return Object.keys(cleaned).length > 0 ? cleaned : { raw: JSON.stringify(item).slice(0, 150) };
                });
              }
              opportunities.push(opp);
            }
          }
          return {
            score,
            cwv: {
              lcp: metrics['largest-contentful-paint']?.displayValue || 'N/A',
              fid: metrics['max-potential-fid']?.displayValue || 'N/A',
              cls: metrics['cumulative-layout-shift']?.displayValue || 'N/A',
              fcp: metrics['first-contentful-paint']?.displayValue || 'N/A',
              si: metrics['speed-index']?.displayValue || 'N/A',
              tbt: metrics['total-blocking-time']?.displayValue || 'N/A',
              score,
            },
            opportunities,
          };
        }

        async function processPage(page) {
          try {
            // Run mobile + desktop in parallel (retries handle failures)
            const [mobileData, desktopData] = await Promise.allSettled([
              runPageSpeedAudit(page.url, 'mobile'),
              runPageSpeedAudit(page.url, 'desktop'),
            ]);
            if (mobileData.status === 'rejected') throw new Error(mobileData.reason?.message || 'Mobile audit failed');
            const mobile = extractCwvAndOpps(mobileData.value);
            let desktop = { score: 0, cwv: {}, opportunities: [] };
            if (desktopData.status === 'fulfilled') {
              desktop = extractCwvAndOpps(desktopData.value);
            } else {
              console.warn(`[speed-audit] Desktop failed for ${page.url}: ${desktopData.reason?.message} — using mobile only`);
            }

            return {
              page_id: page.page_id, title: page.title, slug: page.slug, url: page.url,
              performance_score: mobile.score,
              cwv: mobile.cwv,
              opportunities: mobile.opportunities,
              desktop_score: desktop.score,
              desktop_cwv: desktop.cwv,
              desktop_opportunities: desktop.opportunities,
            };
          } catch (err) {
            console.warn(`[speed-audit] Failed for ${page.url}: ${err.message}`);
            return { page_id: page.page_id, title: page.title, slug: page.slug, url: page.url, error: err.message };
          }
        }

        for (let i = 0; i < pages.length; i += BATCH_SIZE) {
          // Check if this audit was cancelled (new audit started)
          const statusCheck = await pool.query('SELECT status FROM audits WHERE id=$1', [auditId]);
          if (!statusCheck.rows[0] || statusCheck.rows[0].status !== 'running') {
            console.log(`[speed-audit] Audit ${auditId} was cancelled — stopping background job`);
            return;
          }
          const batch = pages.slice(i, i + BATCH_SIZE);
          const batchResults = await Promise.all(batch.map(processPage));
          results.push(...batchResults);
          console.log(`[speed-audit] Progress: ${results.length}/${pages.length} pages`);
          // Save partial results so frontend can show them incrementally
          await pool.query(`UPDATE audits SET audit_data=$1 WHERE id=$2`,
            [JSON.stringify({ progress: results.length, total: pages.length, results }), auditId]);
          // Brief pause between batches
          if (i + BATCH_SIZE < pages.length) await new Promise(r => setTimeout(r, 2000));
        }

        await pool.query(
          `UPDATE audits SET status='completed', completed_at=NOW(), audit_data=$1 WHERE id=$2`,
          [JSON.stringify({ results, ran_at: new Date().toISOString() }), auditId]
        );
        console.log(`[speed-audit] Completed: ${results.length} pages for project ${req.params.projectId}`);

        // CWV data stays in PageSpeed Scores page only — no duplicate findings in Website Audit
        // Clean up any old CWV findings that were previously created
        try {
          await pool.query(`DELETE FROM audit_findings WHERE project_id=$1 AND pillar='website' AND category='Core Web Vitals'`, [req.params.projectId]);
          const findingsCount = 0;
          console.log(`[speed-audit] Created ${findingsCount} CWV findings for project ${req.params.projectId}`);
        } catch (findErr) {
          console.error('[speed-audit] Error creating findings:', findErr.message);
        }
      } catch (bgErr) {
        console.error('[speed-audit] Background error:', bgErr.message);
        try { await pool.query(`UPDATE audits SET status='failed', completed_at=NOW(), audit_data=$1 WHERE id=$2`,
          [JSON.stringify({ error: bgErr.message }), auditId]); } catch (e2) {}
      }
    })();
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Poll speed audit status
app.get('/api/speed-audit/:projectId/status', async (req, res) => {
  try {
    const result = await pool.query(
      `SELECT id, status, audit_data, started_at, completed_at FROM audits WHERE project_id=$1 AND pillar='speed' ORDER BY started_at DESC LIMIT 1`,
      [req.params.projectId]
    );
    if (result.rows.length === 0) return res.json({ status: 'none' });
    const audit = result.rows[0];
    // Auto-fail audits stuck running for more than 10 minutes (e.g. server restarted)
    if (audit.status === 'running' && audit.started_at) {
      const elapsed = Date.now() - new Date(audit.started_at).getTime();
      if (elapsed > 30 * 60 * 1000) {
        await pool.query(`UPDATE audits SET status='failed', completed_at=NOW(), audit_data='{"error":"Audit timed out"}'::jsonb WHERE id=$1`, [audit.id]);
        // Fall through to failed handler below
        audit.status = 'failed';
      }
    }
    // If latest audit failed, return the best completed audit (most results)
    if (audit.status === 'failed') {
      const lastGood = await pool.query(
        `SELECT id, status, audit_data, started_at, completed_at FROM audits WHERE project_id=$1 AND pillar='speed' AND status='completed' ORDER BY completed_at DESC LIMIT 3`,
        [req.params.projectId]
      );
      // Pick the completed audit with the most results
      let bestAudit = null, bestCount = 0;
      for (const row of lastGood.rows) {
        const d = typeof row.audit_data === 'string' ? JSON.parse(row.audit_data) : (row.audit_data || {});
        const count = (d.results || []).filter(r => r.cwv && !r.error).length;
        if (count > bestCount) { bestCount = count; bestAudit = { row, data: d }; }
      }
      if (bestAudit) {
        return res.json({
          status: 'completed',
          auditId: bestAudit.row.id,
          results: bestAudit.data.results || null,
          total_pages: (bestAudit.data.results || []).length,
          error: null,
          warning: 'Showing best available results.',
          startedAt: bestAudit.row.started_at,
          completedAt: bestAudit.row.completed_at,
        });
      }
      // No previous completed audit — return the failure
      const failData = typeof audit.audit_data === 'string' ? JSON.parse(audit.audit_data) : (audit.audit_data || {});
      return res.json({ status: 'failed', error: failData.error || 'Speed audit failed. Please run again.' });
    }
    const data = typeof audit.audit_data === 'string' ? JSON.parse(audit.audit_data) : (audit.audit_data || {});
    res.json({
      status: audit.status,
      auditId: audit.id,
      results: data.results || null,
      total_pages: (data.results || []).length,
      progress: data.progress || null,
      total: data.total || null,
      error: data.error || null,
      startedAt: audit.started_at,
      completedAt: audit.completed_at,
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

