// ==================== INDEXING STATUS CHECK ====================

const DAILY_URL_INSPECTION_BUDGET = 2000;

// Get today's URL Inspection API usage across all projects
async function getUrlInspectionUsageToday() {
  const result = await pool.query(
    `SELECT COALESCE(SUM((audit_data->>'total')::int), 0) as used
     FROM audits WHERE pillar='indexing' AND status='completed'
     AND completed_at >= CURRENT_DATE`
  );
  return parseInt(result.rows[0]?.used || 0);
}

// Discover all important pages and check indexing status
app.post('/api/projects/:projectId/indexing/check', async (req, res) => {
  const { projectId } = req.params;
  try {
    const proj = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (proj.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const project = proj.rows[0];
    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
    const gscProperty = project.gsc_property;

    const accessToken = await getGscAccessToken(req.auth?.userId);
    if (!accessToken) return res.status(400).json({ error: 'GSC not connected. Connect in Agency Integrations.' });

    // Check daily budget
    const usedToday = await getUrlInspectionUsageToday();
    const remaining = DAILY_URL_INSPECTION_BUDGET - usedToday;
    if (remaining <= 0) return res.status(429).json({ error: `Daily URL Inspection budget exhausted (${DAILY_URL_INSPECTION_BUDGET} calls). Try again tomorrow.`, used: usedToday });

    // Find matching GSC site
    let matchedSite = gscProperty;
    if (!matchedSite) {
      const sites = await fetch('https://www.googleapis.com/webmasters/v3/sites', {
        headers: { Authorization: `Bearer ${accessToken}` }
      }).then(r => r.json());
      matchedSite = (sites.siteEntry || []).map(s => s.siteUrl).find(s => s.includes(domain.replace(/^www\./, '')));
    }
    if (!matchedSite) return res.status(400).json({ error: 'GSC property not found. Set it in Project Settings.' });

    const baseUrl = `https://${domain}`;

    // Discover all pages via sitemap + WP REST API
    const authHeaders = getWpAuthHeaders(project);
    const discovered = await discoverPages(baseUrl, project.wordpress_url, authHeaders);
    let allPages = discovered.map(p => p.url).filter(Boolean);
    // Ensure homepage is included
    if (!allPages.some(u => u.replace(/\/$/, '') === baseUrl)) allPages.unshift(baseUrl + '/');

    // Cap to remaining daily budget
    if (allPages.length > remaining) {
      console.log(`[indexing] Capping ${allPages.length} pages to ${remaining} (daily budget: ${usedToday}/${DAILY_URL_INSPECTION_BUDGET} used)`);
      allPages = allPages.slice(0, remaining);
    }
    console.log(`[indexing] Checking ${allPages.length} pages for project ${projectId} (budget: ${usedToday + allPages.length}/${DAILY_URL_INSPECTION_BUDGET})`);

    // Cancel any running indexing audits
    await pool.query(`UPDATE audits SET status='failed', completed_at=NOW() WHERE project_id=$1 AND pillar='indexing' AND status='running'`, [projectId]);

    // Create audit record
    const auditRes2 = await pool.query(
      `INSERT INTO audits (project_id, pillar, status, audit_data, started_at) VALUES ($1::int, 'indexing', 'running', $2::jsonb, NOW()) RETURNING id`,
      [parseInt(projectId), JSON.stringify({ progress: 0, total: allPages.length })]
    );
    const auditId = auditRes2.rows[0].id;

    // Return immediately
    res.json({ auditId, status: 'running', total: allPages.length, budget: { used: usedToday, remaining: remaining - allPages.length, limit: DAILY_URL_INSPECTION_BUDGET } });

    // Run in background
    (async () => {
      try {
        const results = [];
        // Inspect one URL — ALWAYS resolves (never hangs the loop). 20s hard timeout per call.
        const inspectOne = async (pageUrl) => {
          let path; try { path = new URL(pageUrl).pathname; } catch { path = pageUrl; }
          try {
            const inspRes = await fetch('https://searchconsole.googleapis.com/v1/urlInspection/index:inspect', {
              method: 'POST',
              headers: { Authorization: `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
              body: JSON.stringify({ inspectionUrl: pageUrl, siteUrl: matchedSite }),
              signal: AbortSignal.timeout(20000)
            });
            if (inspRes.ok) {
              const inspData = await inspRes.json();
              const idx = inspData.inspectionResult?.indexStatusResult || {};
              const mobile = inspData.inspectionResult?.mobileUsabilityResult || {};
              const rich = inspData.inspectionResult?.richResultsResult || {};
              return {
                url: pageUrl, path,
                verdict: idx.verdict || 'UNKNOWN',
                coverageState: idx.coverageState || 'Unknown',
                robotsTxtState: idx.robotsTxtState || null,
                indexingState: idx.indexingState || null,
                pageFetchState: idx.pageFetchState || null,
                lastCrawlTime: idx.lastCrawlTime || null,
                crawledAs: idx.crawledAs || null,
                googleCanonical: idx.googleCanonical || null,
                userCanonical: idx.userCanonical || null,
                referringUrls: idx.referringUrls || [],
                mobileVerdict: mobile.verdict || null,
                mobileIssues: (mobile.issues || []).map(i => i.issueType),
                richVerdict: rich.verdict || null,
              };
            }
            const errText = await inspRes.text();
            return { url: pageUrl, path, verdict: 'ERROR', coverageState: `API error: ${inspRes.status}`, error: errText.substring(0, 100) };
          } catch (e) {
            return { url: pageUrl, path, verdict: 'ERROR', coverageState: e.name === 'TimeoutError' ? 'Timed out (20s)' : e.message };
          }
        };

        // Run in concurrent batches of 5 — fast, and one slow/hung URL can't stall the rest.
        const BATCH = 5;
        for (let i = 0; i < allPages.length; i += BATCH) {
          const slice = allPages.slice(i, i + BATCH);
          const batchResults = await Promise.all(slice.map(inspectOne));
          results.push(...batchResults);
          await pool.query(`UPDATE audits SET audit_data=$1 WHERE id=$2`,
            [JSON.stringify({ progress: results.length, total: allPages.length, progress_at: Date.now() }), auditId]);
          console.log(`[indexing] Progress: ${results.length}/${allPages.length} pages`);
        }

        const indexed = results.filter(r => r.verdict === 'PASS').length;
        const notIndexed = results.filter(r => r.verdict === 'FAIL' || r.verdict === 'NEUTRAL').length;
        const errors = results.filter(r => r.verdict === 'ERROR').length;

        const sortedResults = results.sort((a, b) => {
          const order = { FAIL: 0, NEUTRAL: 1, ERROR: 2, UNKNOWN: 3, PASS: 4 };
          return (order[a.verdict] || 3) - (order[b.verdict] || 3);
        });

        const auditData = { total: sortedResults.length, indexed, notIndexed, errors, results: sortedResults, ran_at: new Date().toISOString() };
        await pool.query(`UPDATE audits SET status='completed', completed_at=NOW(), audit_data=$1 WHERE id=$2`,
          [JSON.stringify(auditData), auditId]);
        console.log(`[indexing] Done: ${indexed} indexed, ${notIndexed} not indexed, ${errors} errors out of ${results.length}`);
      } catch (bgErr) {
        console.error('[indexing] Background error:', bgErr.message);
        try { await pool.query(`UPDATE audits SET status='failed', completed_at=NOW(), audit_data=$1 WHERE id=$2`,
          [JSON.stringify({ error: bgErr.message }), auditId]); } catch (e2) {}
      }
    })();
  } catch (e) {
    console.error('[indexing] Error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Resolve the GSC site URL for a project (uses gsc_property, else matches by domain)
async function resolveGscSite(project, accessToken) {
  const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
  if (project.gsc_property) return project.gsc_property;
  const sites = await fetch('https://www.googleapis.com/webmasters/v3/sites', {
    headers: { Authorization: `Bearer ${accessToken}` }
  }).then(r => r.json());
  return (sites.siteEntry || []).map(s => s.siteUrl).find(s => s.includes(domain.replace(/^www\./, '')));
}

// List sitemaps submitted to GSC + their status (legitimate Search Console API)
app.get('/api/projects/:projectId/indexing/sitemaps', async (req, res) => {
  try {
    const proj = await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.projectId]);
    if (proj.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const project = proj.rows[0];
    const accessToken = await getGscAccessToken(req.auth?.userId);
    if (!accessToken) return res.status(400).json({ error: 'GSC not connected. Connect in Agency Integrations.' });
    const matchedSite = await resolveGscSite(project, accessToken);
    if (!matchedSite) return res.status(400).json({ error: 'GSC property not found. Set it in Project Settings.' });

    const smRes = await fetch(`https://www.googleapis.com/webmasters/v3/sites/${encodeURIComponent(matchedSite)}/sitemaps`, {
      headers: { Authorization: `Bearer ${accessToken}` }
    }).then(r => r.json());
    const sitemaps = (smRes.sitemap || []).map(s => ({
      path: s.path,
      lastSubmitted: s.lastSubmitted || null,
      lastDownloaded: s.lastDownloaded || null,
      isPending: s.isPending || false,
      isSitemapsIndex: s.isSitemapsIndex || false,
      warnings: parseInt(s.warnings || 0),
      errors: parseInt(s.errors || 0),
      // contents = per-type submitted/indexed counts
      submitted: (s.contents || []).reduce((sum, c) => sum + parseInt(c.submitted || 0), 0),
      indexed: (s.contents || []).reduce((sum, c) => sum + parseInt(c.indexed || 0), 0)
    }));
    res.json({ site: matchedSite, sitemaps });
  } catch (e) {
    console.error('[sitemaps] List error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Submit (or resubmit) a sitemap to Google Search Console — the legitimate way to push pages for indexing
app.post('/api/projects/:projectId/indexing/submit-sitemap', async (req, res) => {
  try {
    const proj = await pool.query('SELECT * FROM projects WHERE id=$1', [req.params.projectId]);
    if (proj.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const project = proj.rows[0];
    const accessToken = await getGscAccessToken(req.auth?.userId);
    if (!accessToken) return res.status(400).json({ error: 'GSC not connected. Connect in Agency Integrations.' });
    const matchedSite = await resolveGscSite(project, accessToken);
    if (!matchedSite) return res.status(400).json({ error: 'GSC property not found. Set it in Project Settings.' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
    // Use provided sitemap URL, else auto-detect the common WordPress/Yoast sitemap index
    let feedpath = (req.body && req.body.sitemap_url || '').trim();
    if (!feedpath) {
      // Probe likely sitemap locations, pick the first that returns 200
      const candidates = [`https://${domain}/sitemap_index.xml`, `https://${domain}/sitemap.xml`, `https://${domain}/wp-sitemap.xml`];
      for (const c of candidates) {
        try { const r = await fetch(c, { method: 'GET' }); if (r.ok) { feedpath = c; break; } } catch (e) {}
      }
      if (!feedpath) feedpath = candidates[0]; // fall back to sitemap_index.xml
    }
    if (!/^https?:\/\//.test(feedpath)) feedpath = `https://${domain}/${feedpath.replace(/^\/+/, '')}`;

    // Helper: is this sitemap already registered in GSC for this property?
    const alreadySubmitted = async () => {
      try {
        const list = await fetch(`https://www.googleapis.com/webmasters/v3/sites/${encodeURIComponent(matchedSite)}/sitemaps`, {
          headers: { Authorization: `Bearer ${accessToken}` }
        }).then(r => r.json());
        const norm = u => (u || '').replace(/\/+$/, '');
        const fp = norm(feedpath);
        return (list.sitemap || []).find(s => norm(s.path) === fp || norm(s.path).endsWith(fp.split('/').pop()));
      } catch (e) { return null; }
    };

    // PUT submits the sitemap to Google (idempotent — also used to resubmit/refresh)
    const submitRes = await fetch(`https://www.googleapis.com/webmasters/v3/sites/${encodeURIComponent(matchedSite)}/sitemaps/${encodeURIComponent(feedpath)}`, {
      method: 'PUT', headers: { Authorization: `Bearer ${accessToken}` }
    });
    if (!submitRes.ok && submitRes.status !== 204) {
      const t = await submitRes.text();
      // The sitemap may already be registered (the PUT can 403 for read-only/"restricted"
      // GSC users even though Google already has the sitemap). Don't alarm the user in that case.
      const existing = await alreadySubmitted();
      if (existing) {
        return res.json({
          success: true,
          alreadySubmitted: true,
          submitted: feedpath,
          site: matchedSite,
          status: { path: existing.path, lastSubmitted: existing.lastSubmitted || null, isPending: existing.isPending || false, errors: parseInt(existing.errors || 0), warnings: parseInt(existing.warnings || 0) },
          message: 'Google already has this sitemap (status OK). No resubmission needed — Google re-reads it automatically.',
        });
      }
      const hint = submitRes.status === 403
        ? `The connected Google account is read-only ("Restricted") on this property, so it can't submit via the API. In Search Console → Settings → Users and permissions, set this account to "Owner" or "Full", or submit the sitemap manually once in Search Console.`
        : `Make sure ${feedpath} loads and the GSC property is verified.`;
      return res.status(400).json({ error: `Google rejected the sitemap (${submitRes.status}). ${hint}`, detail: t.substring(0, 300) });
    }

    // Read back status so the UI can confirm
    let status = null;
    try {
      const smRes = await fetch(`https://www.googleapis.com/webmasters/v3/sites/${encodeURIComponent(matchedSite)}/sitemaps/${encodeURIComponent(feedpath)}`, {
        headers: { Authorization: `Bearer ${accessToken}` }
      }).then(r => r.json());
      status = { path: smRes.path, lastSubmitted: smRes.lastSubmitted, isPending: smRes.isPending, errors: parseInt(smRes.errors || 0), warnings: parseInt(smRes.warnings || 0) };
    } catch (e) {}

    console.log(`[sitemaps] Submitted ${feedpath} to ${matchedSite}`);
    res.json({ success: true, submitted: feedpath, site: matchedSite, status });
  } catch (e) {
    console.error('[sitemaps] Submit error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Get latest indexing results (persistence across navigation + polling)
app.get('/api/projects/:projectId/audits/indexing/latest', async (req, res) => {
  try {
    const result = await pool.query(
      `SELECT id, status, audit_data, started_at, completed_at FROM audits WHERE project_id=$1 AND pillar='indexing' ORDER BY started_at DESC LIMIT 1`,
      [req.params.projectId]
    );
    if (result.rows.length === 0) return res.json({ status: 'none', results: [] });
    const audit = result.rows[0];
    // Auto-fail stuck running audits — based on PROGRESS stalling, not just total time.
    // A healthy run updates progress_at every batch (~2s); if it freezes for 4 min it's hung.
    if (audit.status === 'running' && audit.started_at) {
      const data = typeof audit.audit_data === 'string' ? JSON.parse(audit.audit_data) : (audit.audit_data || {});
      const elapsed = Date.now() - new Date(audit.started_at).getTime();
      const sinceProgress = data.progress_at ? (Date.now() - data.progress_at) : elapsed;
      const stalled = sinceProgress > 4 * 60 * 1000;      // no progress for 4 min
      const overall = elapsed > 30 * 60 * 1000;            // absolute safety cap
      if (stalled || overall) {
        await pool.query(`UPDATE audits SET status='failed', completed_at=NOW(), audit_data='{"error":"Audit stalled — please re-run"}'::jsonb WHERE id=$1`, [audit.id]);
        // Fall through to find last completed audit below
      } else {
        // Still running — return progress
        return res.json({ status: 'running', ...data, completed_at: audit.completed_at });
      }
    }
    if (audit.status === 'completed') {
      const data = typeof audit.audit_data === 'string' ? JSON.parse(audit.audit_data) : (audit.audit_data || {});
      return res.json({ status: audit.status, ...data, completed_at: audit.completed_at });
    }
    // Latest audit is failed/timed-out — find last completed one instead
    const completedResult = await pool.query(
      `SELECT id, status, audit_data, started_at, completed_at FROM audits WHERE project_id=$1 AND pillar='indexing' AND status='completed' ORDER BY started_at DESC LIMIT 1`,
      [req.params.projectId]
    );
    if (completedResult.rows.length > 0) {
      const completed = completedResult.rows[0];
      const data = typeof completed.audit_data === 'string' ? JSON.parse(completed.audit_data) : (completed.audit_data || {});
      return res.json({ status: 'completed', ...data, completed_at: completed.completed_at, note: 'Last run failed; showing previous results.' });
    }
    // No completed audits at all
    res.json({ status: 'none', results: [] });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

