// Check if SEO Room Connector plugin is installed on WordPress site
app.get('/api/projects/:projectId/plugin-status', async (req, res) => {
  try {
    const { projectId } = req.params;
    const projRes = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (!projRes.rows.length) return res.status(404).json({ error: 'Project not found' });
    const project = projRes.rows[0];
    const wpUrl = (project.wordpress_url || '').replace(/\/$/, '');
    if (!wpUrl) return res.json({ installed: false, reason: 'no_wordpress_url' });
    const authHeaders = getWpAuthHeaders(project);
    // Check multiple endpoints — BerqWP firewall may block some
    const endpoints = [
      `${wpUrl}/wp-json/seoroom-opt/v1/status`,
      `${wpUrl}/wp-json/seoroom/v1/yoast-scores`,
      `${wpUrl}/wp-json/seoroom/v1/purge-cache`,
      `${wpUrl}/wp-json/seoroom/v1/cwv-fixes`,
    ];
    const pluginCheckUA = { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' };
    console.log(`[plugin-status] Checking ${wpUrl}, hasAuth: ${!!authHeaders}`);
    // 1. Check if seoroom namespace exists in WP REST index (most reliable)
    try {
      const indexResp = await fetch(`${wpUrl}/wp-json`, {
        signal: AbortSignal.timeout(6000),
        headers: { ...pluginCheckUA, ...(authHeaders || {}) },
      });
      console.log(`[plugin-status] /wp-json index: ${indexResp.status}`);
      if (indexResp.ok) {
        const indexData = await indexResp.json();
        const nsList = indexData.namespaces || [];
        const hasNs = nsList.includes('seoroom/v1') || nsList.includes('seoroom-opt/v1');
        console.log(`[plugin-status] namespaces include seoroom: ${hasNs}, all: ${nsList.filter(n => n.includes('seo')).join(', ')}`);
        if (hasNs) {
          return res.json({ installed: true });
        }
      }
    } catch (e) { console.log(`[plugin-status] /wp-json index error: ${e.message}`); }

    // 2. Check for seoroom-schema plugin via WP plugins endpoint (needs auth)
    if (authHeaders) {
      try {
        const pluginsResp = await fetch(`${wpUrl}/wp-json/wp/v2/plugins`, {
          signal: AbortSignal.timeout(6000),
          headers: { ...pluginCheckUA, ...authHeaders },
        });
        if (pluginsResp.ok) {
          const plugins = await pluginsResp.json();
          const hasSeoroom = plugins.some(p => (p.plugin || '').includes('seoroom') && p.status === 'active');
          console.log(`[plugin-status] WP plugins check: ${hasSeoroom}, plugins: ${plugins.map(p => p.plugin).filter(p => p.includes('seo')).join(', ')}`);
          if (hasSeoroom) return res.json({ installed: true });
        } else {
          console.log(`[plugin-status] WP plugins endpoint: ${pluginsResp.status}`);
        }
      } catch (e) { console.log(`[plugin-status] WP plugins check error: ${e.message}`); }
    }

    // 3. Probe seoroom REST endpoints (old seoroom-helper plugin)
    for (const ep of endpoints) {
      try {
        const resp = await fetch(ep, {
          signal: AbortSignal.timeout(6000),
          headers: { ...pluginCheckUA, ...(authHeaders || {}) },
        });
        if (resp.status === 404) {
          try {
            const body = await resp.json();
            if (body.code === 'rest_no_route') continue;
          } catch {}
          continue;
        }
        return res.json({ installed: true });
      } catch {}
    }

    // 4. Check if _seoroom_schema meta is registered (seoroom-schema plugin)
    try {
      const pagesResp = await fetch(`${wpUrl}/wp-json/wp/v2/pages?per_page=1&_fields=id,meta`, {
        signal: AbortSignal.timeout(6000),
        headers: { ...pluginCheckUA, ...(authHeaders || {}) },
      });
      if (pagesResp.ok) {
        const pages = await pagesResp.json();
        if (pages.length > 0 && pages[0].meta && '_seoroom_schema' in pages[0].meta) {
          console.log(`[plugin-status] Found _seoroom_schema meta field — plugin active`);
          return res.json({ installed: true });
        }
      }
    } catch (e) { console.log(`[plugin-status] meta check error: ${e.message}`); }

    return res.json({ installed: false, reason: 'not_found' });
  } catch (err) {
    console.error('[plugin-status]', err);
    res.status(500).json({ error: err.message });
  }
});

