// POST: start background Maps discovery
app.post('/api/projects/:projectId/discovery/maps/run', async (req, res) => {
  const mapsProvider = (req.body?.provider || 'dataforseo').toLowerCase();
  const { projectId } = req.params;
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/$/, '').replace(/^www\./, '');
    if (!domain) return res.status(400).json({ error: 'No domain configured' });

    // Check if already running (with 5min timeout)
    const existing = (await pool.query('SELECT maps_status, maps_count, updated_at FROM discovery_cache WHERE project_id=$1', [projectId])).rows[0];
    if (existing?.maps_status === 'running') {
      const ageMinutes = (Date.now() - new Date(existing.updated_at).getTime()) / 60000;
      if (ageMinutes < 5) return res.json({ maps_status: 'running', message: 'Already running' });
    }

    // ── Monthly rate limit: 1 Maps discovery per project per calendar month ──
    const force = req.body?.force === true;
    if (!force && existing?.maps_status === 'done' && existing.maps_count > 0) {
      const last = new Date(existing.updated_at);
      const now = new Date();
      if (last.getFullYear() === now.getFullYear() && last.getMonth() === now.getMonth()) {
        return res.status(429).json({
          error: `Maps Discovery already run this month (${last.toLocaleDateString('en-AU', { day: 'numeric', month: 'short', year: 'numeric' })}). Next run available ${new Date(now.getFullYear(), now.getMonth() + 1, 1).toLocaleDateString('en-AU', { day: 'numeric', month: 'short' })}.`,
          canForce: true
        });
      }
    }

    // Ensure discovery_cache row exists, mark maps as running
    await pool.query(
      `INSERT INTO discovery_cache (project_id, status, maps_status, keywords, maps_keywords, updated_at)
       VALUES ($1, COALESCE((SELECT status FROM discovery_cache WHERE project_id=$1), 'idle'), 'running', COALESCE((SELECT keywords FROM discovery_cache WHERE project_id=$1), '[]'), '[]', NOW())
       ON CONFLICT (project_id) DO UPDATE SET maps_status='running', updated_at=NOW()`,
      [projectId]
    );
    res.json({ maps_status: 'running' });

    // Run in background
    (async () => {
      try {
        const businessName = (project.business_name || project.name || '').toLowerCase();
        const bizNoSpaces = businessName.replace(/\s+/g, '');
        const domainLower = domain.toLowerCase();
        const domainBase = domainLower.replace(/\.com\.au$|\.com$|\.net\.au$|\.au$/, '');
        const location = resolveDataForSeoLocation(project.location);
        const locLower = location.toLowerCase().split(',')[0].trim().replace(/[^a-z\s]/g, '').trim();
        // Center on the BUSINESS, not the city: use the centroid of the project's GBP service
        // areas when available (a local pack only shows the business near its real service core —
        // checking at the city CBD finds nothing for a suburban business).
        let locGps = null; let centerLabel = locLower;
        const areaPts = [];
        for (const a of (Array.isArray(project.service_areas) ? project.service_areas : [])) {
          const nm = (typeof a === 'string' ? a : (a.name || a.placeName || '')).toLowerCase().split(',')[0]
            .replace(/\b(qld|wa|nsw|vic|sa|tas|nt|act)\b/g, '').replace(/[0-9]/g, '').replace(/\s+/g, ' ').trim();
          if (SUBURB_GPS[nm]) areaPts.push(SUBURB_GPS[nm]);
        }
        if (areaPts.length >= 2) {
          locGps = {
            lat: areaPts.reduce((s, p) => s + p.lat, 0) / areaPts.length,
            lng: areaPts.reduce((s, p) => s + p.lng, 0) / areaPts.length,
          };
          centerLabel = `service-area centroid of ${areaPts.length} suburbs`;
        }
        if (!locGps) locGps = SUBURB_GPS[locLower] || SUBURB_GPS['perth'] || { lat: -31.9505, lng: 115.8605 };

        console.log(`[maps-discovery] Starting for "${businessName}" (${domain}), center=${centerLabel} (${locGps.lat.toFixed(4)},${locGps.lng.toFixed(4)})`);

        // Step 1: Build service keywords to scan
        // Sources: industry, existing grid scan keywords, rank_keywords with location, website pages
        const serviceSet = new Set();

        // From existing grid scans
        const gridKws = await pool.query('SELECT DISTINCT keyword FROM grid_scans WHERE project_id=$1', [projectId]);
        for (const r of gridKws.rows) serviceSet.add(r.keyword.toLowerCase().trim());

        // From rank_keywords with location (maps keywords)
        const mapsKws = await pool.query('SELECT DISTINCT keyword FROM rank_keywords WHERE project_id=$1 AND location IS NOT NULL AND location != \'\'', [projectId]);
        for (const r of mapsKws.rows) serviceSet.add(r.keyword.toLowerCase().trim());

        // From industry — generate common service terms
        const industry = (project.industry || '').toLowerCase();
        const INDUSTRY_SERVICES = {
          plumbing: ['plumber', 'plumbing', 'hot water', 'blocked drain', 'gas fitter', 'gas fitting', 'leak detection', 'burst pipe', 'toilet repair', 'tap repair', 'bathroom renovation', 'water heater', 'drain cleaning', 'emergency plumber', 'plumbing services', 'gas plumber'],
          electrical: ['electrician', 'electrical', 'rewiring', 'switchboard upgrade', 'ceiling fan installation', 'smoke alarm', 'safety switch', 'power point', 'lighting', 'emergency electrician'],
          hvac: ['air conditioning', 'heating', 'cooling', 'ducted air conditioning', 'split system', 'evaporative cooling', 'ac repair', 'ac installation'],
          roofing: ['roofer', 'roofing', 'roof repair', 'roof restoration', 'roof painting', 'gutter cleaning', 'gutter replacement', 'roof leak', 'metal roofing', 'tile roofing'],
          landscaping: ['landscaper', 'landscaping', 'garden design', 'lawn mowing', 'tree removal', 'retaining wall', 'paving', 'reticulation'],
          cleaning: ['cleaner', 'cleaning', 'carpet cleaning', 'end of lease cleaning', 'office cleaning', 'window cleaning', 'pressure washing'],
          pest: ['pest control', 'termite inspection', 'ant treatment', 'spider spray', 'rodent control', 'cockroach treatment'],
          computing: ['computer repair', 'laptop repair', 'data recovery', 'virus removal', 'screen repair', 'it support', 'computer service'],
          locksmith: ['locksmith', 'car key', 'car key replacement', 'car key cutting', 'car locksmith', 'auto locksmith', 'emergency locksmith', 'lock change', 'lock repair', 'key cutting', 'transponder key', 'car key programming', 'immobiliser', 'car immobiliser', 'lost car key', 'spare car key', 'remote key', 'smart key', 'flip key'],
          automotive: ['car key', 'car key replacement', 'car key cutting', 'auto locksmith', 'car locksmith', 'transponder key', 'car key programming', 'immobiliser', 'car immobiliser', 'lost car key', 'spare car key', 'remote key', 'car key copy', 'car key rescue'],
          painting: ['painter', 'painting', 'house painting', 'interior painting', 'exterior painting', 'commercial painting', 'residential painting', 'spray painting', 'roof painting'],
          building: ['builder', 'building', 'home builder', 'renovation', 'extension', 'granny flat', 'new home', 'commercial builder'],
        };
        // Match industry to templates — also check business_name and domain
        for (const [key, terms] of Object.entries(INDUSTRY_SERVICES)) {
          if (industry.includes(key) || (project.name || '').toLowerCase().includes(key) || businessName.includes(key) || domainBase.includes(key)) {
            for (const t of terms) serviceSet.add(t);
          }
        }
        // Fallback: add business name words as search terms
        const nameParts = businessName.split(/\s+/).filter(w => w.length > 2 && !['pty', 'ltd', 'the', 'and'].includes(w));
        if (nameParts.length >= 2) serviceSet.add(nameParts.join(' '));
        for (const part of nameParts) { if (part.length > 3) serviceSet.add(part); }

        // From website pages — extract service terms from slugs
        try {
          const projectUrl = project.domain.startsWith('http') ? project.domain : 'https://' + project.domain;
          const wpUrl = project.wp_url || projectUrl;
          const pages = await discoverPages(projectUrl, wpUrl);
          for (const page of pages) {
            const slug = (page.slug || '').toLowerCase().replace(/-/g, ' ').trim();
            if (slug.length > 3 && !slug.includes('contact') && !slug.includes('about') && !slug.includes('blog') && !slug.includes('privacy') && !slug.includes('terms')) {
              let svc = slug;
              const allSubs = Object.keys(SUBURB_GPS).sort((a, b) => b.length - a.length);
              for (const sub of allSubs) {
                svc = svc.replace(new RegExp('\\b' + sub.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'g'), '').trim();
              }
              svc = svc.replace(/\s+/g, ' ').trim();
              if (svc.length > 3) serviceSet.add(svc);
            }
          }
        } catch (e) { console.log('[maps-discovery] Page crawl skipped:', e.message); }

        // From organic keywords (DataForSEO ranked_keywords) — the main source
        // This matches what the old "Discovered Local Keywords" modal did
        try {
          const orgResult = await dataForSeoRankedKeywords({ domain, locationCode: 2036, limit: 200, offset: 0 });
          const localSignals = ['near me', 'repair', 'fix', 'shop', 'store', 'service', 'services'];
          const serviceAreas = Array.isArray(project.service_areas) ? project.service_areas : [];
          for (const area of serviceAreas) {
            const areaLower = (typeof area === 'string' ? area : area.name || '').toLowerCase().trim();
            if (areaLower && !localSignals.includes(areaLower)) localSignals.push(areaLower);
          }
          const locParts = (project.location || '').split(',').map(p => p.trim().toLowerCase()).filter(p => p.length > 2);
          for (const part of locParts) { if (!localSignals.includes(part)) localSignals.push(part); }
          // Add all suburb names as local signals
          for (const sub of Object.keys(SUBURB_GPS)) { if (!localSignals.includes(sub)) localSignals.push(sub); }

          for (const kw of orgResult.keywords) {
            const kwLow = (kw.keyword || '').toLowerCase();
            const isLocal = localSignals.some(sig => kwLow.includes(sig));
            if (isLocal) serviceSet.add(kwLow);
          }
          console.log(`[maps-discovery] Added organic keywords, total now: ${serviceSet.size}`);
        } catch (e) { console.log('[maps-discovery] Organic keywords skipped:', e.message); }

        const services = [...serviceSet].filter(s => s.length > 2);
        console.log(`[maps-discovery] ${services.length} service keywords to scan (provider=${mapsProvider}): ${services.slice(0, 15).join(', ')}`);

        // Step 2: Check each service on Maps from business location
        const foundKeywords = [];
        let totalCost = 0;

        const matchBusiness = (r) => {
          const titleLow = (r.title || '').toLowerCase();
          const titleNoSpaces = titleLow.replace(/\s+/g, '');
          const rDomain = (r.domain || '').toLowerCase();
          const rWebsite = (r.website || '').toLowerCase();
          return titleLow.includes(businessName)
            || titleNoSpaces.includes(bizNoSpaces)
            || rDomain.includes(domainLower)
            || rWebsite.includes(domainLower)
            || titleNoSpaces.includes(domainBase);
        };

        // Maps search helper — SerpAPI or DataForSEO
        async function discoverMapsSearch(keyword) {
          if (mapsProvider === 'serpapi') {
            const data = await serpApiSearch({
              engine: 'google_maps',
              q: keyword,
              ll: `@${locGps.lat},${locGps.lng},14z`,
              google_domain: 'google.com.au',
              hl: 'en',
            });
            // Normalize SerpAPI google_maps response to match expected shape
            const results = (data.local_results || []).map((r, idx) => ({
              position: r.position || (idx + 1),
              title: r.title || '',
              rating: r.rating || null,
              reviews: r.reviews || 0,
              type: r.type || '',
              address: r.address || '',
              website: r.website || '',
              domain: r.website ? r.website.replace(/^https?:\/\//, '').split('/')[0].replace(/^www\./, '') : '',
            }));
            return { local_results: results, cost: 0 };
          } else {
            return dataForSeoMaps({ keyword, lat: locGps.lat, lng: locGps.lng });
          }
        }

        for (let i = 0; i < services.length; i += 5) {
          const batch = services.slice(i, i + 5);
          const promises = batch.map(async (keyword) => {
            try {
              const data = await discoverMapsSearch(keyword);
              totalCost += data.cost || 0;
              const results = data.local_results || [];
              for (const r of results) {
                if (matchBusiness(r)) {
                  foundKeywords.push({
                    keyword,
                    maps_position: r.position,
                    on_maps: true,
                    total_results: results.length,
                  });
                  console.log(`[maps-discovery] FOUND: "${keyword}" → #${r.position}`);
                  break;
                }
              }
            } catch (e) {
              console.error(`[maps-discovery] Error checking "${keyword}":`, e.message);
            }
          });
          await Promise.all(promises);
        }

        // Step 3: Get search volume for found keywords
        if (foundKeywords.length > 0) {
          try {
            const volumeResp = await fetch('https://api.dataforseo.com/v3/keywords_data/google_ads/search_volume/live', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
              body: JSON.stringify([{ keywords: foundKeywords.map(k => k.keyword), location_code: 2036, language_code: 'en' }]),
            });
            if (volumeResp.ok) {
              const volData = await volumeResp.json();
              const volItems = volData.tasks?.[0]?.result || [];
              totalCost += volData.cost || 0;
              for (const item of volItems) {
                const kw = foundKeywords.find(k => k.keyword.toLowerCase() === (item.keyword || '').toLowerCase());
                if (kw) {
                  kw.volume = item.search_volume || 0;
                  kw.cpc = item.cpc || 0;
                  kw.competition = item.competition || 0;
                }
              }
            }
          } catch (e) { console.log('[maps-discovery] Volume fetch skipped:', e.message); }
        }

        // Sort by position
        foundKeywords.sort((a, b) => (a.maps_position || 99) - (b.maps_position || 99));

        const discMapsCost = mapsProvider === 'serpapi' ? services.length * API_COST_RATES.serpapi.google_maps : totalCost;
        await logApiCost(parseInt(projectId), 'discover_maps', mapsProvider, services.length, discMapsCost, { found: foundKeywords.length });
        console.log(`[maps-discovery] Done. Found ${foundKeywords.length} keywords where business ranks on Maps. Cost: $${discMapsCost.toFixed(4)}`);

        // Save to DB
        await pool.query(
          `UPDATE discovery_cache SET maps_status='done', maps_keywords=$2, maps_count=$3, maps_cost=$4, updated_at=NOW() WHERE project_id=$1`,
          [projectId, JSON.stringify(foundKeywords), foundKeywords.length, totalCost]
        );
      } catch (e) {
        console.error(`[maps-discovery] Background error:`, e.message);
        await pool.query(
          `UPDATE discovery_cache SET maps_status='error', updated_at=NOW() WHERE project_id=$1`,
          [projectId]
        ).catch(() => {});
      }
    })();
  } catch (e) { res.status(500).json({ error: e.message }); }
});

