// ==================== LOCAL INTEL — AUTO-DISCOVER SUBURBS ====================
// Scans the website for /service-areas/ (or /locations/, /areas/, /suburbs/) pages,
// extracts suburb names, and saves them to project.service_areas (Project Settings).
// If no location pages found, falls back to GBP service areas.

app.post('/api/projects/:id/discover-suburbs', async (req, res) => {
  const projectId = req.params.id;
  try {
    const projR = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    const project = projR.rows[0];

    // 1. Discover all website pages
    const projectUrl = project.domain?.startsWith('http') ? project.domain : `https://${project.domain}`;
    let allPages = [];
    // From onpage_audit_cache
    const opR = await pool.query('SELECT results FROM onpage_audit_cache WHERE project_id=$1', [projectId]);
    const seenUrls = new Set();
    if (opR.rows[0]?.results) {
      const results = typeof opR.rows[0].results === 'string' ? JSON.parse(opR.rows[0].results) : opR.rows[0].results;
      if (Array.isArray(results)) {
        for (const p of results) {
          const url = (p.url || p.link || '').replace(/\/+$/, '');
          if (url) { seenUrls.add(url.toLowerCase()); allPages.push({ url, title: p.title || '' }); }
        }
      }
    }
    // From sitemap / WP REST
    try {
      const discovered = await discoverPages(projectUrl, project.wordpress_url);
      for (const dp of discovered) {
        const dpUrl = (dp.url || dp.loc || '').replace(/\/+$/, '');
        if (dpUrl && !seenUrls.has(dpUrl.toLowerCase())) {
          seenUrls.add(dpUrl.toLowerCase());
          allPages.push({ url: dpUrl, title: dp.title || '' });
        }
      }
    } catch (e) { console.log('[discover-suburbs] discoverPages error:', e.message); }

    // 2. Extract suburb names from location page URLs
    const normalize = s => s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
    const suburbs = [];
    const seenSuburbs = new Set();

    // Get GBP suburbs for matching
    const rcR = await pool.query("SELECT config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    const rc = rcR.rows[0]?.config ? (typeof rcR.rows[0].config === 'string' ? JSON.parse(rcR.rows[0].config) : rcR.rows[0].config) : null;
    const gbpSuburbs = [];
    if (rc?.profile?.serviceArea?.places?.placeInfos) {
      for (const p of rc.profile.serviceArea.places.placeInfos) {
        const name = (p.placeName || '').replace(/,?\s*(WA|Australia|VIC|NSW|QLD|SA|NT|TAS|ACT)\s*/gi, '').replace(/\d{4}/, '').trim();
        if (name) gbpSuburbs.push(name);
      }
    }

    for (const page of allPages) {
      const url = (page.url || '').toLowerCase();
      const saMatch = url.match(/\/(service-?areas?|locations?|areas?|suburbs?)\/([\w-]+)\/?$/);
      if (saMatch) {
        let suburbSlug = saMatch[2];
        // Try to match against GBP suburbs for proper casing
        const gbpMatch = gbpSuburbs.find(s => {
          const gn = normalize(s).replace(/\s+/g, '-');
          return suburbSlug.endsWith(gn) || suburbSlug === gn;
        });
        if (gbpMatch) {
          suburbSlug = normalize(gbpMatch).replace(/\s+/g, '-');
        } else if (suburbSlug.includes('-')) {
          const parts = suburbSlug.split('-');
          const last2 = parts.slice(-2).join('-');
          const last1 = parts[parts.length - 1];
          if (parts.length >= 3 && parts[parts.length - 2].length >= 3 && last1.length >= 3) {
            suburbSlug = last2;
          } else {
            suburbSlug = last1;
          }
        }
        const suburbName = suburbSlug.replace(/-/g, ' ').trim();
        const n = normalize(suburbName);
        if (n && n.length > 1 && !seenSuburbs.has(n)) {
          seenSuburbs.add(n);
          const cap = n.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
          suburbs.push(cap);
        }
      }
    }

    // 2b. Also detect suburbs from custom URL patterns (e.g. /plumber-warner/) by matching GBP suburb names
    let source = 'website';
    if (suburbs.length === 0 && gbpSuburbs.length > 0) {
      for (const page of allPages) {
        const url = (page.url || '').toLowerCase();
        try {
          const urlPath = new URL(url.startsWith('http') ? url : 'https://x.com' + url).pathname.toLowerCase();
          for (const gs of gbpSuburbs) {
            const gSlug = normalize(gs).replace(/\s+/g, '-');
            if (gSlug.length > 2 && urlPath.includes(gSlug)) {
              const n = normalize(gs);
              if (!seenSuburbs.has(n)) {
                seenSuburbs.add(n);
                suburbs.push(gs);
              }
            }
          }
        } catch {}
      }
      if (suburbs.length > 0) source = 'website'; // detected from custom URL patterns
    }

    // 3. Fallback: if no location pages, use GBP service areas
    if (suburbs.length === 0 && gbpSuburbs.length > 0) {
      source = 'gbp';
      for (const s of gbpSuburbs) {
        const n = normalize(s);
        if (!seenSuburbs.has(n)) {
          seenSuburbs.add(n);
          suburbs.push(s);
        }
      }
    }

    // 4. Save to project.service_areas
    await pool.query('UPDATE projects SET service_areas=$1 WHERE id=$2', [JSON.stringify(suburbs), projectId]);

    console.log(`[discover-suburbs] Project ${projectId}: found ${suburbs.length} suburbs from ${source}`);
    res.json({ suburbs, source, count: suburbs.length });
  } catch (e) {
    console.error('[discover-suburbs] Error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// ==================== LOCAL INTEL — CONSOLIDATION ====================

app.get('/api/projects/:id/local-intel', async (req, res) => {
  const projectId = req.params.id;
  try {
    const projR = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    const project = projR.rows[0];
    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '').toLowerCase();

    // 1. RC profile (GBP data) — auto-fetch from RC API if missing
    let rcR = await pool.query("SELECT config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    let rc = rcR.rows[0]?.config ? (typeof rcR.rows[0].config === 'string' ? JSON.parse(rcR.rows[0].config) : rcR.rows[0].config) : null;

    // Auto-sync from RC API if rc_profile missing/empty and project has rc_location_id or gbp_location_id
    if ((!rc || !rc.profile?.title) && (project.rc_location_id || project.gbp_location_id)) {
      const RC_TOKEN = process.env.RC_API_TOKEN;
      if (RC_TOKEN) {
        try {
          // Use rc_location_id (RC internal DB ID) for profile fetch — more reliable than gbp_location_id
          const rcDbId = project.rc_location_id;
          const rcHeaders = { 'Authorization': `Bearer ${RC_TOKEN}`, 'Accept': 'application/json' };
          const RC_BASE = 'https://local.ratingcaptain.com/api';
          console.log(`[local-intel] Auto-fetching RC profile for project ${projectId} (rc_id=${rcDbId}, gbp=${project.gbp_location_id})...`);

          // Fetch profile by RC DB ID + extended list for reviews/rating
          const fetches = [
            fetch(`${RC_BASE}/locations/extended?current_page=1&type=active_profiles`, { headers: rcHeaders }),
          ];
          if (rcDbId) fetches.unshift(fetch(`${RC_BASE}/locations/${rcDbId}`, { headers: rcHeaders }));

          const results = await Promise.allSettled(fetches);

          let profile = null, reviews_stats = null;
          const profileIdx = rcDbId ? 0 : -1;
          const extIdx = rcDbId ? 1 : 0;

          if (profileIdx >= 0 && results[profileIdx].status === 'fulfilled' && results[profileIdx].value.ok) {
            profile = await results[profileIdx].value.json();
            console.log(`[local-intel] Fetched profile: ${profile.title || 'unknown'}`);
          }
          if (results[extIdx]?.status === 'fulfilled' && results[extIdx].value.ok) {
            const extData = await results[extIdx].value.json();
            // Match by gbp_location_id OR rc_location_id
            const loc = (extData.data || []).find(l =>
              l.location_id === project.gbp_location_id ||
              l.id === project.rc_location_id
            );
            if (loc) {
              reviews_stats = { total_reviews: loc.reviews_amount || 0, average_rating: loc.rating || 0, reply_rate: 0, replied_count: 0, unreplied_count: 0 };
              // If profile fetch failed, use extended data name as fallback
              if (!profile && loc.name) {
                console.log(`[local-intel] Using extended data as profile fallback for ${loc.name}`);
              }
            }
          }

          if (profile) {
            const rcData = { location_id: project.gbp_location_id, profile, healthcheck: [], reviews_stats: reviews_stats || {}, posts: { count: 0, published_posts: [] }, synced_at: new Date().toISOString() };
            await pool.query(
              `INSERT INTO project_integrations (project_id, kind, config, status, updated_at)
               VALUES ($1, 'rc_profile', $2, 'connected', NOW())
               ON CONFLICT (project_id, kind) DO UPDATE SET config=$2, status='connected', updated_at=NOW()`,
              [projectId, JSON.stringify(rcData)]
            );
            rc = rcData;
            console.log(`[local-intel] Auto-synced RC profile for project ${projectId}: ${profile.title}`);
          }
        } catch (e) {
          console.log(`[local-intel] Auto-sync failed for project ${projectId}: ${e.message}`);
        }
      }
    }

    const profile = rc?.profile || null;
    console.log(`[local-intel] RC profile keys: ${profile ? Object.keys(profile).join(', ') : 'null'}`);
    if (profile) {
      console.log(`[local-intel] serviceArea: ${profile.serviceArea ? JSON.stringify(Object.keys(profile.serviceArea)) : 'missing'}`);
      console.log(`[local-intel] categories: ${profile.categories ? JSON.stringify(Object.keys(profile.categories)) : 'missing'}`);
      console.log(`[local-intel] serviceItems: ${profile.serviceItems ? profile.serviceItems.length + ' items' : 'missing'}`);
      console.log(`[local-intel] description: ${profile.description ? profile.description.substring(0, 80) + '...' : (profile.profile?.description ? 'nested in profile.profile' : 'missing')}`);
    }

    // Extract GBP suburbs from service areas (RC profile first, fallback to project.service_areas)
    const gbpSuburbs = [];
    if (profile?.serviceArea?.places?.placeInfos) {
      for (const p of profile.serviceArea.places.placeInfos) {
        const name = (p.placeName || '').replace(/,?\s*(WA|Australia|VIC|NSW|QLD|SA|NT|TAS|ACT)\s*/gi, '').replace(/\d{4}/, '').trim();
        if (name) gbpSuburbs.push(name);
      }
    }
    // Fallback: use project.service_areas if RC profile has none
    if (gbpSuburbs.length === 0 && Array.isArray(project.service_areas) && project.service_areas.length > 0) {
      for (const a of project.service_areas) {
        const name = (typeof a === 'string' ? a : a.name || '').replace(/,?\s*(WA|Australia|VIC|NSW|QLD|SA|NT|TAS|ACT)\s*/gi, '').replace(/\d{4}/, '').trim();
        if (name) gbpSuburbs.push(name);
      }
      console.log(`[local-intel] Using project.service_areas fallback: ${gbpSuburbs.length} suburbs`);
    }
    // Extract GBP services — resolve structuredServiceItem IDs via category serviceTypes
    const gbpServices = [];
    if (profile?.serviceItems) {
      // Build serviceTypeId → displayName map from categories
      const svcTypeMap = {};
      const allCats = [profile.categories?.primaryCategory, ...(profile.categories?.additionalCategories || [])].filter(Boolean);
      for (const cat of allCats) {
        for (const st of (cat.serviceTypes || [])) {
          if (st.serviceTypeId && st.displayName) svcTypeMap[st.serviceTypeId] = st.displayName;
        }
      }
      for (const si of profile.serviceItems) {
        const label = si.freeFormServiceItem?.label?.displayName || '';
        const structId = si.structuredServiceItem?.serviceTypeId || '';
        const structLabel = si.structuredServiceItem?.description || svcTypeMap[structId] || '';
        const finalLabel = label || structLabel;
        if (finalLabel && !finalLabel.startsWith('job_type_id:')) gbpServices.push(finalLabel);
      }
    }

    // Extract GBP categories
    const gbpCategories = [];
    if (profile?.categories?.primaryCategory) gbpCategories.push(profile.categories.primaryCategory.displayName);
    if (profile?.categories?.additionalCategories) {
      for (const c of profile.categories.additionalCategories) gbpCategories.push(c.displayName);
    }

    // Extract GBP products (from extension data or RC profile)
    const gbpProductNames = new Set();
    if (profile?.products && Array.isArray(profile.products)) {
      for (const prod of profile.products) {
        const pName = prod.name || prod.title || prod.productName || (typeof prod === 'string' ? prod : '');
        if (pName) gbpProductNames.add(normalize(pName));
      }
    }

    // Extract GBP posts topics — from RC cached data, or fetch from RC API
    const gbpPosts = [];
    const now = new Date();
    const thisMonthStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
    let gbpPostsThisMonth = 0;
    if (rc?.posts?.published_posts && rc.posts.published_posts.length > 0) {
      for (const p of rc.posts.published_posts) {
        gbpPosts.push({ summary: (p.summary || '').substring(0, 120), state: p.state, url: p.callToAction?.url || '', createTime: p.createTime || '' });
        if ((p.createTime || '').startsWith(thisMonthStr)) gbpPostsThisMonth++;
      }
    }
    // Fetch from RC posts API if no cached posts
    if (gbpPosts.length === 0) {
      const RC_TOKEN = process.env.RC_API_TOKEN;
      const gbpLocId = project.gbp_location_id;
      if (RC_TOKEN && gbpLocId) {
        try {
          // Use getRcLocationDetails to get the correct location_id format
          let rcLocDetail = null;
          try { rcLocDetail = await getRcLocationDetails(projectId); } catch (e) { /* no RC location */ }
          const postLocId = rcLocDetail?.location_id || gbpLocId;
          const url = `https://local.ratingcaptain.com/api/posts?location_id=${encodeURIComponent(postLocId)}&status=all&per_page=100&page=1`;
          console.log(`[local-intel] Fetching posts from RC: ${url}`);
          const resp = await fetch(url, { headers: { 'Authorization': `Bearer ${RC_TOKEN}`, 'Accept': 'application/json' } });
          if (resp.ok) {
            const data = await resp.json();
            const posts = data.data || data.posts || (Array.isArray(data) ? data : []);
            for (const p of posts) {
              if (p.status === 'published' || p.state === 'LIVE') {
                gbpPosts.push({ summary: (p.summary || p.content || p.text || '').substring(0, 120), state: p.state || p.status, url: p.callToAction?.url || p.url || '', createTime: p.createTime || p.created_at || p.publish_date || '' });
                if ((p.createTime || p.created_at || p.publish_date || '').startsWith(thisMonthStr)) gbpPostsThisMonth++;
              }
            }
            console.log(`[local-intel] Fetched ${gbpPosts.length} published posts from RC API (total in response: ${posts.length})`);
          } else {
            console.log(`[local-intel] RC posts API returned ${resp.status}`);
          }
        } catch (e) { console.log(`[local-intel] RC posts fetch failed: ${e.message}`); }
      }
    }
    // Fallback: load posts from seed file
    if (gbpPosts.length === 0) {
      try {
        const seedPath = require('path').join(__dirname, 'data', 'local_intel_seed.json');
        if (require('fs').existsSync(seedPath)) {
          const seed = JSON.parse(require('fs').readFileSync(seedPath, 'utf8'));
          const locId = project.gbp_location_id;
          const locData = seed[locId];
          if (locData?.posts) {
            for (const p of locData.posts) {
              gbpPosts.push({ summary: (p.summary || '').substring(0, 200), state: 'LIVE', url: '', createTime: '' });
            }
            console.log(`[local-intel] Using ${gbpPosts.length} posts from seed file for ${locId}`);
          }
        }
      } catch (e) { console.log(`[local-intel] Seed posts fallback failed: ${e.message}`); }
    }

    // 2. Website pages (from onpage_audit_cache + discoverPages for full coverage)
    const opR = await pool.query('SELECT results FROM onpage_audit_cache WHERE project_id=$1', [projectId]);
    const websitePages = [];
    const seenUrls = new Set();
    if (opR.rows[0]?.results) {
      const results = typeof opR.rows[0].results === 'string' ? JSON.parse(opR.rows[0].results) : opR.rows[0].results;
      if (Array.isArray(results)) {
        for (const p of results) {
          const url = p.url || p.link || '';
          websitePages.push({
            url,
            title: p.title || p.yoast_title || '',
            slug: (p.slug || p.url || '').toLowerCase(),
            type: p.type || 'page',
            wordCount: p.wordCount || p.word_count || 0,
          });
          if (url) seenUrls.add(url.toLowerCase().replace(/\/+$/, ''));
        }
      }
    }
    // Also discover pages from sitemap/WP REST to catch /service-areas/ pages not in onpage cache
    try {
      const projectUrl = project.domain?.startsWith('http') ? project.domain : `https://${project.domain}`;
      const discovered = await discoverPages(projectUrl, project.wordpress_url);
      for (const dp of discovered) {
        const dpUrl = (dp.url || dp.loc || '').replace(/\/+$/, '');
        if (dpUrl && !seenUrls.has(dpUrl.toLowerCase())) {
          seenUrls.add(dpUrl.toLowerCase());
          const slug = dpUrl.replace(/^https?:\/\/[^/]+/, '');
          websitePages.push({ url: slug || dpUrl, title: dp.title || '', slug: slug.toLowerCase(), type: 'page', wordCount: 0 });
        }
      }
    } catch (e) { console.log('[local-intel] discoverPages fallback error:', e.message); }

    // 3. Rank keywords
    const kwR = await pool.query('SELECT id, keyword, location, search_volume FROM rank_keywords WHERE project_id=$1', [projectId]);
    const rankKeywords = kwR.rows;

    // Latest rank tracking per keyword
    const rtR = await pool.query(`
      SELECT DISTINCT ON (keyword) keyword, serp_position, maps_position, serp_url, checked_at
      FROM rank_tracking WHERE project_id=$1 ORDER BY keyword, checked_at DESC
    `, [projectId]);
    const rankMap = {};
    for (const r of rtR.rows) rankMap[r.keyword.toLowerCase()] = r;

    // 4. Grid scans (latest per keyword+location) — include competitors + center coords
    const gsR = await pool.query(`
      SELECT DISTINCT ON (keyword, COALESCE(location,'')) keyword, location, arp, atrp, solv, found_in, data_points, competitors, center_lat, center_lng, scanned_at
      FROM grid_scans WHERE project_id=$1 ORDER BY keyword, COALESCE(location,''), scanned_at DESC
    `, [projectId]);
    const gridMap = {};
    for (const g of gsR.rows) {
      const comps = typeof g.competitors === 'string' ? JSON.parse(g.competitors) : (g.competitors || {});
      const mapKey = g.location ? `${g.keyword} ${g.location}`.toLowerCase() : g.keyword.toLowerCase();
      gridMap[mapKey] = { ...g, competitors: comps };
    }

    // 4b. External audit competitor findings
    const extR = await pool.query(`
      SELECT title, description, severity, category, current_value, recommended_value
      FROM audit_findings WHERE project_id=$1 AND pillar IN ('gbp', 'gbp_external') AND category='Competitor Analysis'
      ORDER BY severity DESC
    `, [projectId]);
    const extCompetitorFindings = extR.rows;

    // 4c. Aggregate top competitors across all grid scans
    const competitorAgg = {};
    for (const [, gs] of Object.entries(gridMap)) {
      const top = gs.competitors?.top || [];
      for (const c of top) {
        const n = (c.name || c.title || '').toLowerCase().trim();
        if (!n) continue;
        if (!competitorAgg[n]) competitorAgg[n] = { name: c.name || c.title, rating: c.rating, reviews: c.reviews, type: c.type, keywords: 0, top1: 0, top3: 0, totalDominance: 0 };
        competitorAgg[n].keywords++;
        competitorAgg[n].top1 += c.top1 || 0;
        competitorAgg[n].top3 += c.top3 || 0;
        competitorAgg[n].totalDominance += c.dominance || 0;
        if (c.rating) competitorAgg[n].rating = c.rating;
        if (c.reviews) competitorAgg[n].reviews = Math.max(competitorAgg[n].reviews || 0, c.reviews);
      }
    }
    const topCompetitors = Object.values(competitorAgg)
      .map(c => ({ ...c, avgDominance: c.keywords ? Math.round(c.totalDominance / c.keywords) : 0 }))
      .sort((a, b) => b.keywords - a.keywords)
      .slice(0, 10);

    // 5. GSC keywords
    const gscR = await pool.query('SELECT keyword, clicks, impressions, ctr, position FROM gsc_keywords WHERE project_id=$1 ORDER BY impressions DESC LIMIT 500', [projectId]);
    const gscKeywords = gscR.rows;
    const gscMap = {};
    for (const g of gscKeywords) gscMap[g.keyword.toLowerCase()] = g;

    // 5b. Indexing results (latest completed audit)
    const idxR = await pool.query(
      `SELECT audit_data FROM audits WHERE project_id=$1 AND pillar='indexing' AND status='completed' ORDER BY completed_at DESC LIMIT 1`,
      [projectId]
    );
    const indexingMap = {}; // path -> { verdict, coverageState }
    let indexingTotal = 0, indexingIndexed = 0, indexingNotIndexed = 0;
    if (idxR.rows[0]?.audit_data) {
      const idxData = typeof idxR.rows[0].audit_data === 'string' ? JSON.parse(idxR.rows[0].audit_data) : idxR.rows[0].audit_data;
      if (Array.isArray(idxData.results)) {
        indexingTotal = idxData.results.length;
        for (const r of idxData.results) {
          const path = (r.path || r.url || '').toLowerCase().replace(/\/+$/, '');
          indexingMap[path] = { verdict: r.verdict, state: r.coverageState };
          if (r.verdict === 'PASS') indexingIndexed++;
          else if (r.verdict === 'FAIL' || r.verdict === 'NEUTRAL') indexingNotIndexed++;
        }
      }
    }

    // 6. Reviews stats
    let reviewStats = rc?.reviews_stats || {};
    console.log(`[local-intel] reviewStats from RC: total_reviews=${reviewStats.total_reviews}, avg_rating=${reviewStats.average_rating}`);

    // ============ CROSS-REFERENCE: LOCATIONS ============
    // SOURCE OF TRUTH: Website pages (location pages discovered from sitemap)
    // Patterns: /plumber-{suburb}/, /service-areas/{suburb}/, /locations/{suburb}/
    // Then cross-reference with GBP service areas to find gaps
    const normalize = s => s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
    const projectBase = project.domain?.startsWith('http') ? project.domain.replace(/\/+$/, '') : `https://${project.domain}`.replace(/\/+$/, '');
    const absUrl = (u) => u && u.startsWith('/') ? projectBase + u : u;
    const allSuburbNames = new Set();
    const suburbSources = {};
    let suburbSource = 'website';
    let hasLocationPages = false;

    // Step 1: Discover location pages from website (source of truth)
    for (const page of websitePages) {
      let urlPath = '';
      try { urlPath = new URL((page.url || '').startsWith('http') ? page.url : 'https://x.com' + (page.url || '')).pathname.replace(/^\/|\/$/g, '').toLowerCase(); } catch { urlPath = (page.slug || '').toLowerCase(); }
      if (!urlPath) continue;

      let suburbName = null;

      // Pattern 1: /plumber-{suburb}/ (most common for plumbing/trade sites)
      const plumberMatch = urlPath.match(/^plumber-([\w-]+)$/);
      if (plumberMatch) {
        suburbName = plumberMatch[1].replace(/-/g, ' ');
      }
      // Pattern 2: /service-areas/{slug}/, /locations/{slug}/
      // Slug may be just "{suburb}" or "{service}-{suburb}" (e.g. "car-key-replacement-alkimos")
      // Strategy: try matching the tail against GBP suburbs first, then strip longest non-suburb prefix
      if (!suburbName) {
        const saMatch = urlPath.match(/^(service-?areas?|locations?|areas?|suburbs?)\/([\w-]+)$/);
        if (saMatch) {
          const rawSlug = saMatch[2];
          const words = rawSlug.split('-');
          // Try progressively shorter tails to find the suburb part
          // e.g. "car-key-replacement-alkimos" → try "alkimos", "replacement-alkimos", etc.
          let bestSuburb = null;
          for (let start = words.length - 1; start >= 0; start--) {
            const candidate = words.slice(start).join(' ');
            const candidateNorm = candidate.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
            // Check against GBP suburbs
            if (gbpSuburbs.some(gs => normalize(gs) === candidateNorm)) {
              bestSuburb = candidate;
              break; // shortest match from the end = just the suburb
            }
          }
          // If no GBP match found, take the last 1-2 words as suburb (heuristic: service names are longer)
          if (!bestSuburb) {
            if (words.length >= 3) {
              // Last 1-2 words are likely the suburb
              bestSuburb = words.length <= 2 ? words.join(' ') : words.slice(-1).join(' ');
              // If single word is too short (< 4 chars) and there's a second word, take last 2
              if (bestSuburb.length < 4 && words.length >= 2) bestSuburb = words.slice(-2).join(' ');
            } else {
              bestSuburb = words.join(' ');
            }
          }
          suburbName = bestSuburb;
        }
      }
      // Pattern 3: /{trade}-{suburb}/ where trade is a known profession word
      if (!suburbName) {
        const tradeMatch = urlPath.match(/^(electrician|carpenter|painter|roofer|landscaper|handyman)-([\w-]+)$/);
        if (tradeMatch) suburbName = tradeMatch[2].replace(/-/g, ' ');
      }
      // Pattern 4: ANY page URL ending with a known GBP suburb (e.g. /computer-repairs-bayswater/, /car-key-replacement-alkimos/)
      // This catches ALL business types regardless of trade prefix
      if (!suburbName && gbpSuburbs.length > 0) {
        const slugWords = urlPath.replace(/\//g, '').split('-');
        // Try matching 1-word, 2-word, and 3-word suburb names from the end of the URL
        for (let tailLen = 1; tailLen <= Math.min(3, slugWords.length - 1); tailLen++) {
          const tail = slugWords.slice(-tailLen).join(' ');
          const tailNorm = tail.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
          if (tailNorm.length < 3) continue;
          if (gbpSuburbs.some(gs => normalize(gs) === tailNorm)) {
            suburbName = tail;
            break;
          }
        }
      }

      if (suburbName) {
        if (suburbName.length < 2) continue;
        const n = normalize(suburbName);
        const cap = n.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
        hasLocationPages = true;
        if (!suburbSources[n]) {
          allSuburbNames.add(n);
          suburbSources[n] = { original: cap, inGbp: false, fromWebsite: true, hasPage: true, pages: [] };
        }
        const normUrl = (page.url || '').replace(/\/+$/, '');
        if (!suburbSources[n].pages.find(p => p.url.replace(/\/+$/, '') === normUrl)) {
          suburbSources[n].pages.push({ url: absUrl(page.url), title: page.title || cap });
        }
      }
    }

    // If no location pages found on website, fall back to GBP service areas
    if (allSuburbNames.size === 0) {
      suburbSource = gbpSuburbs.length > 0 ? 'gbp' : 'none';
      for (const s of gbpSuburbs) {
        const n = normalize(s);
        if (n && n.length > 1) {
          allSuburbNames.add(n);
          suburbSources[n] = { original: s, inGbp: true, fromWebsite: false, hasPage: false, pages: [] };
        }
      }
    }

    // SIGNAL 2: Check if each suburb is in GBP service areas + track GBP-only locations
    const gbpOnlyLocations = [];
    for (const s of gbpSuburbs) {
      const n = normalize(s);
      if (suburbSources[n]) {
        suburbSources[n].inGbp = true;
      } else if (n && n.length > 1 && hasLocationPages) {
        // This suburb is in GBP but has no website page — it's a gap
        gbpOnlyLocations.push(s);
      }
    }

    // Cross-reference: Review mentions — use cached reviews from DB, or load from seed file
    let allReviews = [];
    let cachedCount = 0;
    // 1. Check for cached reviews in reviews_cache table (use if < 30 days old)
    try {
      const rvR = await pool.query('SELECT reviews, total_count, updated_at FROM reviews_cache WHERE project_id=$1', [projectId]);
      if (rvR.rows[0]?.reviews) {
        const cached = typeof rvR.rows[0].reviews === 'string' ? JSON.parse(rvR.rows[0].reviews) : rvR.rows[0].reviews;
        const ageMs = Date.now() - new Date(rvR.rows[0].updated_at).getTime();
        if (Array.isArray(cached) && cached.length > 0 && ageMs < 30 * 24 * 60 * 60 * 1000) {
          allReviews = cached;
          cachedCount = cached.length;
          console.log(`[local-intel] Using ${cached.length} cached reviews (age: ${Math.round(ageMs / 3600000)}h)`);
        }
      }
    } catch (e) { /* reviews_cache table may not exist yet */ }
    // 2. Always check seed file — use if it has MORE reviews than cache (seed was updated)
    {
      try {
        const seedPath = require('path').join(__dirname, 'data', 'local_intel_seed.json');
        if (require('fs').existsSync(seedPath)) {
          const seed = JSON.parse(require('fs').readFileSync(seedPath, 'utf8'));
          const locId = project.gbp_location_id;
          const locData = seed[locId];
          if (locData?.reviews) {
            const seedReviews = locData.reviews.filter(r => r.comment).map(r => ({
              comment: r.comment || '',
              reviewer: '',
              rating: 5,
              date: null,
              reply: r.reply || ''
            }));
            // Use seed if cache is empty OR seed has more data (updated seed deployed)
            if (seedReviews.length > cachedCount) {
              allReviews = seedReviews;
              console.log(`[local-intel] Using ${allReviews.length} reviews from seed file for ${locId} (seed > cache ${cachedCount})`);
              // Re-cache to DB
              try {
                await pool.query(
                  `INSERT INTO reviews_cache (project_id, reviews, total_count, updated_at)
                   VALUES ($1, $2, $3, NOW())
                   ON CONFLICT (project_id)
                   DO UPDATE SET reviews=$2, total_count=$3, updated_at=NOW()`,
                  [projectId, JSON.stringify(allReviews), locData.total_reviews || allReviews.length]
                );
              } catch (ce) { /* ignore cache write error */ }
            }
          }
        }
      } catch (e) { console.log(`[local-intel] Seed file fallback failed: ${e.message}`); }
    }

    // Recalculate review stats from actual loaded reviews (DB/seed may have stale reply_rate)
    if (allReviews.length > 0 && reviewStats) {
      const repliedCount = allReviews.filter(r => r.reply || r.review_reply?.comment || r.response).length;
      reviewStats.total_reviews = Math.max(reviewStats.total_reviews || 0, allReviews.length);
      reviewStats.replied_count = repliedCount;
      reviewStats.unreplied_count = allReviews.length - repliedCount;
      reviewStats.reply_rate = Math.round((repliedCount / allReviews.length) * 1000) / 10;
      console.log(`[local-intel] Recalculated reply_rate: ${reviewStats.reply_rate}% (${repliedCount}/${allReviews.length})`);
    }

    // Scan review text + reply text for suburb mentions
    console.log(`[local-intel] Reviews: ${allReviews.length}, Posts: ${gbpPosts.length}, Suburbs: ${allSuburbNames.size}`);
    for (const review of allReviews) {
      const text = normalize(review.comment || review.text || '');
      const replyText = normalize(review.reply || review.review_reply?.comment || review.response || '');
      const fullText = text + ' ' + replyText;
      for (const n of allSuburbNames) {
        // Only match suburb names 4+ chars to avoid false positives (e.g. "como" in "recommend")
        if (n.length >= 4 && fullText.includes(n)) {
          if (!suburbSources[n].reviewMentions) suburbSources[n].reviewMentions = [];
          suburbSources[n].reviewMentions.push({
            reviewer: review.reviewer?.displayName || review.reviewer || '',
            rating: review.rating || review.starRating || 0,
            snippet: (review.comment || review.text || '').substring(0, 100),
          });
        }
      }
    }

    // Match GBP posts to suburbs
    for (const post of gbpPosts) {
      const postText = normalize(post.summary || '');
      for (const n of allSuburbNames) {
        if (n.length >= 4 && postText.includes(n)) {
          if (!suburbSources[n].postMentions) suburbSources[n].postMentions = [];
          suburbSources[n].postMentions.push({ summary: (post.summary || '').substring(0, 120), date: post.createTime || '' });
        }
      }
    }

    // Match keywords to suburbs
    for (const kw of rankKeywords) {
      const kwN = normalize(kw.keyword);
      for (const n of allSuburbNames) {
        if (kwN.includes(n)) {
          if (!suburbSources[n].keywords) suburbSources[n].keywords = [];
          const rt = rankMap[kw.keyword.toLowerCase()];
          suburbSources[n].keywords.push({ keyword: kw.keyword, volume: kw.search_volume, serp: rt?.serp_position, maps: rt?.maps_position });
        }
      }
    }

    // Match grid scans to suburbs
    for (const [kwLower, gs] of Object.entries(gridMap)) {
      for (const n of allSuburbNames) {
        if (kwLower.includes(n)) {
          if (!suburbSources[n].gridScans) suburbSources[n].gridScans = [];
          suburbSources[n].gridScans.push({ keyword: kwLower, arp: gs.arp, atrp: gs.atrp, solv: gs.solv, found_in: gs.found_in });
        }
      }
    }

    // Match GSC data to suburbs
    for (const [kwLower, gsc] of Object.entries(gscMap)) {
      for (const n of allSuburbNames) {
        if (kwLower.includes(n)) {
          if (!suburbSources[n].gsc) suburbSources[n].gsc = [];
          suburbSources[n].gsc.push({ keyword: kwLower, clicks: gsc.clicks, impressions: gsc.impressions });
        }
      }
    }

    // Match indexing status to suburbs (check if suburb pages are indexed)
    for (const n of allSuburbNames) {
      const s = suburbSources[n];
      if (s.pages?.length) {
        s.indexing = [];
        for (const page of s.pages) {
          const pageUrl = (page.url || '').toLowerCase();
          let path;
          try { path = new URL(pageUrl).pathname.replace(/\/+$/, ''); } catch { path = pageUrl.replace(/\/+$/, ''); }
          const idx = indexingMap[path] || indexingMap[path.toLowerCase()];
          if (idx) s.indexing.push({ url: page.url, ...idx });
        }
      }
    }

    // Get business center coordinates from grid scans, RC profile address, or project location
    let bizLat = null, bizLng = null;
    for (const gs of Object.values(gridMap)) {
      if (gs.center_lat && gs.center_lng) { bizLat = parseFloat(gs.center_lat); bizLng = parseFloat(gs.center_lng); break; }
    }
    // Fallback: RC profile storefrontAddress locality → SUBURB_GPS
    if (!bizLat && rc?.profile?.storefrontAddress?.locality) {
      const loc = rc.profile.storefrontAddress.locality.toLowerCase().replace(/\s+/g, ' ').trim();
      if (SUBURB_GPS[loc]) { bizLat = SUBURB_GPS[loc].lat; bizLng = SUBURB_GPS[loc].lng; }
    }
    // Fallback: project.location → parse suburb name → SUBURB_GPS
    if (!bizLat && project.location) {
      const locParts = project.location.replace(/,/g, ' ').replace(/\s+(WA|QLD|NSW|VIC|SA|NT|TAS|ACT|Australia)\s*/gi, ' ').trim().toLowerCase().split(/\s+/);
      // Try full string first, then first word (suburb name)
      const locFull = locParts.join(' ');
      if (SUBURB_GPS[locFull]) { bizLat = SUBURB_GPS[locFull].lat; bizLng = SUBURB_GPS[locFull].lng; }
      else if (SUBURB_GPS[locParts[0]]) { bizLat = SUBURB_GPS[locParts[0]].lat; bizLng = SUBURB_GPS[locParts[0]].lng; }
    }
    console.log(`[local-intel] bizLat=${bizLat}, bizLng=${bizLng}, location="${project.location}", rcLocality="${rc?.profile?.storefrontAddress?.locality}"`);
    // Haversine distance helper (km)
    const haversineDist = (lat1, lng1, lat2, lng2) => {
      const R = 6371, toRad = d => d * Math.PI / 180;
      const dLat = toRad(lat2 - lat1), dLng = toRad(lng2 - lng1);
      const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng/2)**2;
      return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    };

    // Build suburb matrix
    const suburbMatrix = Array.from(allSuburbNames).map(n => {
      const s = suburbSources[n];
      const gaps = [];
      if (!s.hasPage) gaps.push('Create suburb landing page');
      if (!s.inGbp) gaps.push('Add to GBP service areas');
      if (!s.reviewMentions?.length) gaps.push('Get reviews mentioning this suburb');
      if (!s.keywords?.length) gaps.push('Add keyword tracking');
      if (!s.gridScans?.length) gaps.push('Run grid scan');
      // Indexing status for this suburb's pages
      const indexedPages = s.indexing?.filter(i => i.verdict === 'PASS').length || 0;
      const notIndexedPages = s.indexing?.filter(i => i.verdict === 'FAIL' || i.verdict === 'NEUTRAL').length || 0;
      if (notIndexedPages > 0) gaps.push('Fix indexing issues');

      // Auto-link: avgRank from grid scans ARP (or ATRP if not found), or keyword maps positions
      let avgRank = null;
      let rankSource = null;
      if (s.gridScans?.length) {
        const arps = s.gridScans.map(g => g.arp).filter(v => v != null && v > 0);
        if (arps.length) {
          avgRank = Math.round(arps.reduce((a, b) => a + b, 0) / arps.length * 10) / 10;
          rankSource = 'arp';
        } else {
          // Business not found — use ATRP (treats unfound as 21)
          const atrps = s.gridScans.map(g => g.atrp).filter(v => v != null && v > 0);
          if (atrps.length) {
            avgRank = Math.round(atrps.reduce((a, b) => a + b, 0) / atrps.length * 10) / 10;
            rankSource = 'atrp';
          }
        }
      }
      if (avgRank == null && s.keywords?.length) {
        const mapsPos = s.keywords.map(k => k.maps).filter(v => v != null && v > 0);
        if (mapsPos.length) { avgRank = Math.round(mapsPos.reduce((a, b) => a + b, 0) / mapsPos.length * 10) / 10; rankSource = 'serp'; }
      }

      // Auto-link: distance from business center to suburb GPS
      let distance = null;
      const subGps = SUBURB_GPS[n];
      if (bizLat && subGps) {
        distance = Math.round(haversineDist(bizLat, bizLng, subGps.lat, subGps.lng) * 10) / 10;
      }

      return {
        suburb: s.original,
        hasPage: !!s.hasPage,
        inGbp: !!s.inGbp,
        fromWebsite: !!s.fromWebsite,
        pageCount: s.pages?.length || 0,
        pages: (s.pages || []).slice(0, 3),
        keywordCount: s.keywords?.length || 0,
        keywords: (s.keywords || []).slice(0, 5),
        gridScanCount: s.gridScans?.length || 0,
        bestSolv: s.gridScans?.length ? Math.max(...s.gridScans.map(g => g.solv || 0)) : null,
        avgRank,
        rankSource,
        distance,
        gscImpressions: s.gsc?.reduce((sum, g) => sum + (g.impressions || 0), 0) || 0,
        gscClicks: s.gsc?.reduce((sum, g) => sum + (g.clicks || 0), 0) || 0,
        reviewMentions: s.reviewMentions?.length || 0,
        reviewSnippets: (s.reviewMentions || []).slice(0, 3),
        postMentions: s.postMentions?.length || 0,
        indexedPages,
        notIndexedPages,
        indexingStatus: notIndexedPages > 0 ? 'issues' : indexedPages > 0 ? 'indexed' : s.hasPage ? 'unchecked' : null,
        gaps,
        score: (s.hasPage ? 20 : 0) + (s.inGbp ? 20 : 0) + (s.reviewMentions?.length ? 20 : 0) + (s.keywords?.length ? 15 : 0) + (s.gridScans?.length ? 10 : 0) + (s.gsc?.length ? 15 : 0),
      };
    }).sort((a, b) => b.score - a.score);

    // ============ CROSS-REFERENCE: SERVICES & PRODUCTS ============
    // Auto-populate defined_services from GBP if empty
    let definedServices = Array.isArray(project.defined_services) ? project.defined_services : [];
    if (definedServices.length === 0 && gbpServices.length > 0) {
      definedServices = [...gbpServices];
      await pool.query('UPDATE projects SET defined_services=$1 WHERE id=$2', [JSON.stringify(definedServices), projectId]);
      console.log(`[local-intel] Auto-populated ${definedServices.length} services from GBP for project ${projectId}`);
    }
    const definedProducts = Array.isArray(project.defined_products) ? project.defined_products : [];
    const allOfferings = [
      ...definedServices.map(name => ({ name, type: 'service' })),
      ...definedProducts.map(name => ({ name, type: 'product' })),
    ];

    // Build suburb slug set for matching service+suburb combo pages
    const suburbSlugsSet = new Set();
    for (const n of allSuburbNames) suburbSlugsSet.add(n.replace(/\s+/g, '-'));

    // Get GBP services from RC cache for cross-reference
    const gbpServiceNames = new Set();
    const gbpServiceList = [];
    let rcCacheServices = [];
    let rcCacheProducts = [];
    try {
      const rcCacheR = await pool.query('SELECT profile FROM rc_profile_cache WHERE project_id=$1', [projectId]);
      if (rcCacheR.rows[0]?.profile?.services) rcCacheServices = rcCacheR.rows[0].profile.services;
      if (rcCacheR.rows[0]?.profile?.products) rcCacheProducts = rcCacheR.rows[0].profile.products;
    } catch (e) {}
    for (const s of rcCacheServices) { gbpServiceNames.add(normalize(s)); gbpServiceList.push(s); }
    for (const s of gbpServices) { const n = normalize(s); if (!gbpServiceNames.has(n)) { gbpServiceNames.add(n); gbpServiceList.push(s); } }
    for (const cat of gbpCategories) { const n = normalize(cat); if (!gbpServiceNames.has(n)) { gbpServiceNames.add(n); gbpServiceList.push(cat); } }
    // Also add RC cache products to gbpProductNames
    for (const p of rcCacheProducts) {
      const pName = typeof p === 'string' ? p : (p.name || p.title || '');
      if (pName) gbpProductNames.add(normalize(pName));
    }

    // For each defined service/product, find matching pages and cross-reference
    // Stem matching: "plumbing" matches "plumber", "drains" matches "drain"
    const stemMatch = (word, text) => {
      if (text.includes(word)) return true;
      const stem = word.substring(0, Math.min(word.length, 5));
      return stem.length >= 4 && text.includes(stem);
    };

    let _svcDebugIdx = 0;
    const serviceMatrix = allOfferings.map(({ name, type }) => {
      const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
      const nameNorm = normalize(name);
      const nameWords = nameNorm.split(/\s+/).filter(w => w.length >= 3);
      const slugWords = slug.split('-').filter(w => w.length >= 3);

      // Find ALL pages matching this service (stem matching, skip blog-style URLs)
      const allMatches = [];
      for (const page of websitePages) {
        let rawSlug = '';
        try { rawSlug = new URL(page.url?.startsWith('http') ? page.url : 'https://x.com' + (page.url || '')).pathname.replace(/^\/|\/$/g, '').toLowerCase(); } catch { rawSlug = (page.slug || '').toLowerCase(); }
        if (!rawSlug) continue;
        // Skip blog-style URLs (long slug with many words = likely a blog post, not a service page)
        const slugParts = rawSlug.split('-');
        if (slugParts.length > 8) continue; // e.g. "blocked-drains-can-worsen-during-the-holiday-rush" = 8 words
        // Check if URL contains service words (stem matching)
        const hasServiceMatch = slugWords.length > 0 && slugWords.every(w => stemMatch(w, rawSlug));
        if (!hasServiceMatch) continue;
        // Detect suburb in URL: check against known suburbs
        let matchedSuburb = null;
        for (const subSlug of suburbSlugsSet) {
          if (subSlug.length >= 3 && rawSlug.includes(subSlug)) {
            // Verify it's a word boundary match (not partial word)
            const idx = rawSlug.indexOf(subSlug);
            const before = idx === 0 || rawSlug[idx - 1] === '-';
            const after = idx + subSlug.length === rawSlug.length || rawSlug[idx + subSlug.length] === '-';
            if (before && after) { matchedSuburb = subSlug; break; }
          }
        }
        // Also check for brisbane/north-brisbane even if not in suburbSlugsSet
        if (!matchedSuburb) {
          const citySuburbs = ['brisbane', 'north-brisbane', 'south-brisbane'];
          for (const cs of citySuburbs) {
            if (rawSlug.endsWith('-' + cs) || rawSlug.startsWith(cs + '-')) {
              matchedSuburb = cs; break;
            }
          }
        }
        allMatches.push({ url: page.url, title: page.title || name, suburb: matchedSuburb, rawSlug });
      }

      // Separate: main service page (no suburb or the primary city page) vs suburb-specific pages
      // Main page = shortest matching URL (most likely the core service page)
      allMatches.sort((a, b) => a.rawSlug.length - b.rawSlug.length);
      // URLs made absolute using projectBase/absUrl defined above
      let mainPage = allMatches[0] ? { ...allMatches[0], url: absUrl(allMatches[0].url) } : null;
      const nonSuburbPages = allMatches.filter(m => !m.suburb).map(m => ({ url: absUrl(m.url), title: m.title }));
      let suburbPages = allMatches.filter(m => m.suburb).map(m => ({
        suburb: m.suburb.replace(/-/g, ' ').split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
        url: absUrl(m.url), title: m.title
      }));
      const hasPage = allMatches.length > 0;

      // If this service has no service-specific suburb pages but the site has generic location pages
      // (e.g. /service-areas/car-key-replacement-{suburb}/), count ALL location pages as suburb coverage.
      // Rationale: location pages cover all services the business offers in that suburb.
      if (suburbPages.length === 0 && hasLocationPages && type === 'service') {
        const genericSuburbPages = [];
        for (const [n, src] of Object.entries(suburbSources)) {
          if (src.hasPage && src.pages.length > 0) {
            genericSuburbPages.push({
              suburb: src.original,
              url: src.pages[0].url,
              title: src.pages[0].title
            });
          }
        }
        suburbPages = genericSuburbPages;
      }

      // Missing suburbs: locations with website pages but no service-specific page
      const coveredSuburbs = new Set(suburbPages.map(sp => normalize(sp.suburb)));
      const missingSuburbs = Array.from(allSuburbNames)
        .filter(n => !coveredSuburbs.has(n))
        .map(n => ({ suburb: suburbSources[n]?.original || n, hasPage: !!suburbSources[n]?.hasPage }));

      // Check if in GBP (fuzzy match against services + products + description + posts)
      let inGbp = false;
      const gbpSetsToCheck = type === 'product' ? [gbpProductNames, gbpServiceNames] : [gbpServiceNames, gbpProductNames];
      for (const gbpSet of gbpSetsToCheck) {
        if (inGbp) break;
        for (const gn of gbpSet) {
          if (gn === nameNorm) { inGbp = true; break; }
          if (nameWords.length > 0 && nameWords.every(w => gn.includes(w))) { inGbp = true; break; }
          const gnWords = gn.split(/\s+/).filter(w => w.length >= 3);
          if (gnWords.length > 0 && gnWords.every(w => nameNorm.includes(w))) { inGbp = true; break; }
        }
      }
      // For products, also check if name appears in GBP description or posts
      if (!inGbp && type === 'product') {
        const gbpDesc = normalize(profile?.profile?.description || '');
        if (gbpDesc && nameWords.filter(w => w.length >= 3).some(w => gbpDesc.includes(w))) inGbp = true;
        if (!inGbp) {
          for (const post of gbpPosts) {
            const postText = normalize(post.summary || '');
            if (nameWords.filter(w => w.length >= 3).some(w => postText.includes(w))) { inGbp = true; break; }
          }
        }
      }

      // Match keywords
      const keywords = [];
      for (const kw of rankKeywords) {
        const kwN = normalize(kw.keyword);
        if (nameWords.length > 0 && nameWords.some(w => kwN.includes(w))) {
          const rt = rankMap[kw.keyword.toLowerCase()];
          keywords.push({ keyword: kw.keyword, volume: kw.search_volume, serp: rt?.serp_position, maps: rt?.maps_position });
        }
      }

      // Match GBP posts
      const posts = [];
      for (const post of gbpPosts) {
        const postText = normalize(post.summary);
        if (nameWords.length > 0 && nameWords.some(w => postText.includes(w))) posts.push(post);
      }

      // Match GSC data
      const gscData = [];
      for (const [kwLower, gsc] of Object.entries(gscMap)) {
        if (nameWords.length > 0 && nameWords.some(w => kwLower.includes(w))) {
          gscData.push({ keyword: kwLower, clicks: gsc.clicks, impressions: gsc.impressions });
        }
      }

      // Match reviews mentioning this service (check both customer text + business reply)
      const reviewMentions = [];
      for (const review of allReviews) {
        const text = normalize(review.comment || review.text || '');
        const replyText = normalize(review.reply || review.review_reply?.comment || review.response || '');
        const fullText = text + ' ' + replyText;
        if (nameWords.length > 0 && nameWords.filter(w => w.length >= 3).some(w => fullText.includes(w))) {
          reviewMentions.push({
            reviewer: review.reviewer?.displayName || review.reviewer || '',
            rating: review.rating || review.starRating || 0,
            snippet: (review.comment || review.text || '').substring(0, 120),
          });
        }
      }

      // Debug first 3 services
      if (_svcDebugIdx++ < 3) {
        console.log(`[local-intel] SVC "${name}": nameWords=[${nameWords.join(',')}], reviewMentions=${reviewMentions.length}, posts=${posts.length}, allReviews=${allReviews.length}`);
      }

      // Build gaps
      const gaps = [];
      if (!hasPage) gaps.push(type === 'product' ? 'Create product page' : 'Create service page');
      if (!inGbp) gaps.push('Add to GBP services');
      if (reviewMentions.length === 0) gaps.push('Get reviews mentioning this service');
      if (type === 'service' && suburbPages.length === 0 && allSuburbNames.size > 0) gaps.push('Create suburb landing pages');
      if (!keywords.length) gaps.push('Add keyword tracking');

      const score = type === 'product'
        ? (hasPage ? 40 : 0) + (inGbp ? 30 : 0) + (keywords.length ? 15 : 0) + (gscData.length ? 15 : 0)
        : (hasPage ? 25 : 0) + (inGbp ? 20 : 0) + (suburbPages.length > 0 ? 15 : 0) + (keywords.length ? 15 : 0) + (posts.length ? 10 : 0) + (gscData.length ? 15 : 0);

      return {
        service: name,
        type,
        source: 'defined',
        inGbp,
        hasPage,
        mainPage: mainPage ? { url: mainPage.url, title: mainPage.title } : null,
        allPages: nonSuburbPages.slice(0, 10),
        suburbPageCount: suburbPages.length,
        suburbPages: suburbPages.slice(0, 50),
        missingSuburbs: missingSuburbs.slice(0, 50),
        totalSuburbs: allSuburbNames.size,
        pageCount: allMatches.length,
        keywordCount: keywords.length,
        postCount: posts.length,
        postSnippets: posts.slice(0, 5).map(p => ({ summary: (p.summary || '').substring(0, 120), date: p.date || p.createTime || '' })),
        reviewMentionCount: reviewMentions.length,
        reviewSnippets: reviewMentions.slice(0, 3),
        gscImpressions: gscData.reduce((sum, g) => sum + (g.impressions || 0), 0),
        gaps,
        score,
      };
    }).sort((a, b) => b.score - a.score);

    // GBP-only services (in GBP but not in defined_services or defined_products)
    const allDefinedNorm = new Set(allOfferings.map(o => normalize(o.name)));
    const gbpOnlyServices = gbpServiceList.filter(gs => {
      const gn = normalize(gs);
      // Check if matched by any defined offering
      for (const dn of allDefinedNorm) {
        if (gn === dn) return false;
        const dWords = dn.split(/\s+/).filter(w => w.length >= 3);
        if (dWords.length > 0 && dWords.every(w => gn.includes(w))) return false;
        const gWords = gn.split(/\s+/).filter(w => w.length >= 3);
        if (gWords.length > 0 && gWords.every(w => dn.includes(w))) return false;
      }
      return true;
    });

    // allServiceNames for backward compatibility with suburb×service matrix
    const allServiceNames = new Set(allOfferings.map(o => normalize(o.name)));
    const serviceSources = {};
    for (const item of serviceMatrix) {
      serviceSources[normalize(item.service)] = { original: item.service, mainPage: item.mainPage, suburbPages: item.suburbPages || [] };
    }

    // ============ GENERATE RECOMMENDATIONS ============
    const recommendations = [];
    const suburbsNotInGbp = suburbMatrix.filter(s => !s.inGbp && s.pageCount > 0);
    if (suburbsNotInGbp.length) recommendations.push({ priority: 'high', type: 'gbp', icon: 'fas fa-map-marker-alt', title: `Add ${suburbsNotInGbp.length} suburbs to GBP service areas`, detail: `These suburbs have website pages but aren't listed in your GBP service areas. Adding them improves Maps visibility.`, items: suburbsNotInGbp.map(s => s.suburb) });

    const suburbsNoPage = suburbMatrix.filter(s => s.inGbp && s.pageCount === 0);
    if (suburbsNoPage.length) recommendations.push({ priority: 'critical', type: 'website', icon: 'fas fa-file-alt', title: `Create ${suburbsNoPage.length} suburb landing pages`, detail: `These suburbs are in your GBP service areas but have no matching page on your website. Create dedicated landing pages to rank locally.`, items: suburbsNoPage.map(s => s.suburb) });

    const servicesNoPage = serviceMatrix.filter(s => s.inGbp && s.pageCount === 0);
    if (servicesNoPage.length > 0) {
      recommendations.push({ priority: 'high', type: 'website', icon: 'fas fa-wrench', title: `Create pages for ${servicesNoPage.length} GBP services`, detail: `These services are listed on your GBP profile but have no dedicated website page. Each service should have its own page for better rankings.`, items: servicesNoPage.map(s => s.service) });
    }

    const suburbsNoKeywords = suburbMatrix.filter(s => (s.inGbp || s.pageCount > 0) && s.keywordCount === 0);
    if (suburbsNoKeywords.length) recommendations.push({ priority: 'medium', type: 'tracking', icon: 'fas fa-search', title: `Track keywords for ${suburbsNoKeywords.length} suburbs`, detail: `No rank tracking set up for these suburbs. Add keywords to monitor your SERP and Maps positions.`, items: suburbsNoKeywords.map(s => s.suburb) });

    const suburbsNoGrid = suburbMatrix.filter(s => s.inGbp && s.gridScanCount === 0);
    if (suburbsNoGrid.length) recommendations.push({ priority: 'medium', type: 'tracking', icon: 'fas fa-th', title: `Run grid scans for ${suburbsNoGrid.length} GBP suburbs`, detail: `No Maps grid coverage data for these suburbs. Grid scans show your exact position from multiple points around each area.`, items: suburbsNoGrid.map(s => s.suburb) });

    const servicesNoPost = serviceMatrix.filter(s => s.inGbp && s.pageCount > 0 && s.postCount === 0).slice(0, 10);
    if (servicesNoPost.length) recommendations.push({ priority: 'low', type: 'gbp', icon: 'fas fa-calendar-alt', title: `Write GBP posts for ${servicesNoPost.length} services`, detail: `These services have website pages but no GBP posts. Regular posts boost engagement and visibility in Maps.`, items: servicesNoPost.map(s => s.service) });

    // ============ GSC → GBP INSIGHTS ============
    // 1. GSC queries with suburb names NOT in GBP service areas → add to GBP
    const gscSuburbsNotInGbp = [];
    for (const gsc of gscKeywords) {
      const kwN = normalize(gsc.keyword);
      // Check if this GSC query mentions a suburb not in GBP
      for (const n of allSuburbNames) {
        const s = suburbSources[n]?.original || n;
        if (kwN.includes(n) && !gbpSuburbs.some(g => normalize(g) === n) && gsc.impressions >= 10) {
          if (!gscSuburbsNotInGbp.find(x => x.suburb === s)) {
            gscSuburbsNotInGbp.push({ suburb: s, keyword: gsc.keyword, impressions: gsc.impressions, clicks: gsc.clicks });
          }
        }
      }
    }
    if (gscSuburbsNotInGbp.length) {
      recommendations.push({ priority: 'high', type: 'gsc_gbp', icon: 'fas fa-chart-line',
        title: `GSC shows traffic for ${gscSuburbsNotInGbp.length} suburbs not in GBP`,
        detail: `Google sends impressions for these suburbs but they aren't in your GBP service areas. Adding them could boost Maps visibility.`,
        items: gscSuburbsNotInGbp.map(s => `${s.suburb} (${s.impressions} imp)`)
      });
    }

    // 2. High impression, low CTR suburb keywords → meta title missing suburb name
    const lowCtrSuburbKws = gscKeywords.filter(g => {
      const kwN = normalize(g.keyword);
      return g.impressions >= 50 && g.ctr < 0.03 && allSuburbNames.has([...allSuburbNames].find(n => kwN.includes(n)));
    }).slice(0, 10);
    if (lowCtrSuburbKws.length) {
      recommendations.push({ priority: 'high', type: 'gsc_gbp', icon: 'fas fa-mouse-pointer',
        title: `${lowCtrSuburbKws.length} local keywords have high impressions but low CTR (<3%)`,
        detail: `Keywords like "${lowCtrSuburbKws[0]?.keyword}" get impressions but few clicks. Add suburb names to meta titles and descriptions to improve CTR.`,
        items: lowCtrSuburbKws.map(g => `${g.keyword} (${g.impressions} imp, ${(g.ctr * 100).toFixed(1)}% CTR)`)
      });
    }

    // 3. GSC queries that don't match any GBP service → potential new services
    const unmatchedGscServices = [];
    for (const gsc of gscKeywords.slice(0, 100)) {
      const kwN = normalize(gsc.keyword);
      if (gsc.impressions < 20) continue;
      const matchesService = [...allServiceNames].some(n => {
        const words = n.split(/\s+/);
        const keyPart = words.length > 1 ? words.slice(0, 2).join(' ') : words[0];
        return kwN.includes(keyPart);
      });
      if (!matchesService && !kwN.includes(normalize(project.business_name || '')) && kwN.length > 5) {
        unmatchedGscServices.push({ keyword: gsc.keyword, impressions: gsc.impressions, clicks: gsc.clicks, position: gsc.position });
      }
    }
    if (unmatchedGscServices.length > 0) {
      recommendations.push({ priority: 'medium', type: 'gsc_gbp', icon: 'fas fa-plus-circle',
        title: `${unmatchedGscServices.length} GSC queries don't match any GBP service`,
        detail: `You rank for these queries in Google but they aren't listed as GBP services. Consider adding them to your profile.`,
        items: unmatchedGscServices.slice(0, 15).map(g => `${g.keyword} (${g.impressions} imp, pos ${Math.round(g.position)})`)
      });
    }

    // 4. GBP services with zero GSC visibility → content gap
    const servicesZeroGsc = serviceMatrix.filter(s => s.inGbp && s.gscImpressions === 0 && s.pageCount > 0);
    if (servicesZeroGsc.length) {
      recommendations.push({ priority: 'medium', type: 'gsc_gbp', icon: 'fas fa-eye-slash',
        title: `${servicesZeroGsc.length} GBP services have pages but zero GSC visibility`,
        detail: `These services have website pages but get zero impressions in Search Console. Pages may need better content or internal linking.`,
        items: servicesZeroGsc.map(s => s.service)
      });
    }

    // 5. Competitor threats from grid scans
    if (topCompetitors.length > 0) {
      const dominant = topCompetitors.filter(c => c.avgDominance > 30);
      if (dominant.length) {
        recommendations.push({ priority: 'high', type: 'competitor', icon: 'fas fa-shield-alt',
          title: `${dominant.length} competitors dominate across multiple keywords`,
          detail: `These competitors have over 30% dominance in grid scans. Compare their GBP profiles to find gaps you can close.`,
          items: dominant.map(c => `${c.name} — ${c.reviews || '?'} reviews, ${c.avgDominance}% dominance`)
        });
      }
    }

    // 6. External audit competitor findings
    if (extCompetitorFindings.length) {
      const criticals = extCompetitorFindings.filter(f => f.severity === 'critical' || f.severity === 'high');
      if (criticals.length) {
        recommendations.push({ priority: 'high', type: 'competitor', icon: 'fas fa-users',
          title: `${criticals.length} competitor threats from GBP audit`,
          detail: `Critical competitor issues identified in your GBP external audit that need attention.`,
          items: criticals.map(f => f.title)
        });
      }
    }

    // ============ CROSS-REFERENCE: SUBURB × SERVICE MATRIX ============
    // For each suburb×service combo: actual rank position + diagnostic data
    const matrixRows = [];
    for (const subN of allSuburbNames) {
      const sub = suburbSources[subN];
      const row = { suburb: sub.original, services: {} };
      for (const svcN of allServiceNames) {
        const svc = serviceSources[svcN];
        const subSlug = subN.replace(/\s+/g, '-');
        const svcWords = svcN.split(/\s+/);
        const svcKey = svcWords.length > 1 ? svcWords.slice(0, 2).join(' ') : svcWords[0];
        const svcSlug = svcKey.replace(/\s+/g, '-');

        // 1. Check if page exists for this combo
        let hasPage = false, pageUrl = '', pageWordCount = 0;
        for (const page of websitePages) {
          const slug = normalize(page.slug || page.url || '');
          if ((slug.includes(subSlug) || slug.includes(subN.replace(/\s+/g, ''))) && slug.includes(svcSlug)) {
            hasPage = true; pageUrl = page.url; pageWordCount = page.wordCount || 0; break;
          }
        }
        // Also check for suburb-only pages (e.g. /plumber-murdoch/)
        if (!hasPage) {
          for (const page of websitePages) {
            const slug = normalize(page.slug || page.url || '');
            if (slug.includes(subSlug) || slug.includes(subN.replace(/\s+/g, ''))) {
              hasPage = true; pageUrl = page.url; pageWordCount = page.wordCount || 0; break;
            }
          }
        }

        // 2. Indexing status
        let isIndexed = null;
        if (hasPage && pageUrl) {
          let path;
          try { path = new URL(pageUrl.toLowerCase()).pathname.replace(/\/+$/, ''); } catch { path = pageUrl.toLowerCase().replace(/\/+$/, ''); }
          const idx = indexingMap[path];
          if (idx) isIndexed = idx.verdict === 'PASS';
        }

        // 3. Rank data — Maps position from grid scan is primary, SERP tracking as fallback
        let mapsRank = null, serpRank = null, gridSolv = null, gridArp = null;
        let topCompetitor = null;
        for (const [kwLower, gs] of Object.entries(gridMap)) {
          if (kwLower.includes(subN) && kwLower.includes(svcKey)) {
            gridSolv = gs.solv;
            gridArp = gs.arp;
            // ARP is the average rank where found — use as maps rank indicator
            if (gs.arp) mapsRank = Math.round(gs.arp);
            // Get top competitor for this keyword
            const tops = gs.competitors?.top || [];
            if (tops.length > 0) topCompetitor = { name: tops[0].name || tops[0].title, rating: tops[0].rating, reviews: tops[0].reviews, dominance: tops[0].dominance };
            break;
          }
        }
        // SERP rank from rank_tracking + search volume
        let kwVolume = null, kwName = null;
        for (const kw of rankKeywords) {
          const kwN = normalize(kw.keyword);
          if (kwN.includes(subN) && kwN.includes(svcKey)) {
            kwName = kw.keyword;
            kwVolume = kw.search_volume || null;
            const rt = rankMap[kw.keyword.toLowerCase()];
            if (rt) {
              if (rt.maps_position) mapsRank = mapsRank || rt.maps_position;
              if (rt.serp_position) serpRank = rt.serp_position;
            }
            break;
          }
        }

        // 4. GSC impressions
        let gscImp = 0, gscClicks = 0, gscCtr = 0;
        for (const [kwLower, gsc] of Object.entries(gscMap)) {
          if (kwLower.includes(subN) && kwLower.includes(svcKey)) {
            gscImp += gsc.impressions || 0;
            gscClicks += gsc.clicks || 0;
            if (gsc.ctr) gscCtr = Math.max(gscCtr, gsc.ctr);
          }
        }

        // 5. GBP post exists for this service?
        let hasGbpPost = false;
        for (const post of gbpPosts) {
          if (normalize(post.summary).includes(svcKey)) { hasGbpPost = true; break; }
        }

        // Maps-only rank for the matrix (this page is Maps-focused)
        const rank = mapsRank || null;

        // Build diagnosis — what's helping and what's hurting
        const actions = [];
        if (!hasPage) actions.push({ type: 'critical', text: 'Create landing page', nav: 'ow-queue' });
        else if (isIndexed === false) actions.push({ type: 'critical', text: 'Page not indexed — fix indexing', nav: 'indexing' });
        else if (pageWordCount > 0 && pageWordCount < 500) actions.push({ type: 'high', text: `Page only ${pageWordCount} words — expand content`, nav: 'ow-queue' });
        if (!mapsRank) actions.push({ type: 'high', text: 'No Maps rank — run grid scan', nav: 'maps-rankings' });
        if (rank && rank > 3 && !hasGbpPost) actions.push({ type: 'medium', text: 'Write GBP post about this service', nav: 'gbp-posts' });
        if (rank && rank > 3 && topCompetitor && topCompetitor.reviews > (reviewStats?.total_reviews || 0)) {
          actions.push({ type: 'medium', text: `Top competitor has ${topCompetitor.reviews} reviews vs your ${reviewStats?.total_reviews || 0}` });
        }
        if (gscImp > 50 && gscCtr < 0.03) actions.push({ type: 'medium', text: 'Low CTR — improve meta title/description' });

        const signals = (hasPage ? 1 : 0) + (isIndexed === true ? 1 : 0) + (rank != null ? 1 : 0) + (gridSolv != null ? 1 : 0) + (gscImp > 0 ? 1 : 0);
        row.services[svc.original] = {
          rank, mapsRank, serpRank, gridSolv, gridArp,
          hasPage, pageUrl, pageWordCount, isIndexed,
          gscImp, gscClicks, gscCtr,
          kwName, kwVolume,
          hasGbpPost, topCompetitor,
          actions, signals,
        };
      }
      matrixRows.push(row);
    }
    // Matrix summary: total combos, covered (signals>0), fully covered (signals>=4)
    const totalCombos = allSuburbNames.size * allServiceNames.size;
    const coveredCombos = matrixRows.reduce((sum, r) => sum + Object.values(r.services).filter(s => s.signals > 0).length, 0);
    const fullyCovered = matrixRows.reduce((sum, r) => sum + Object.values(r.services).filter(s => s.signals >= 4).length, 0);

    // Summary scores — average coverage across all suburbs/services
    const suburbCoverage = suburbMatrix.length ? Math.round(suburbMatrix.reduce((sum, s) => sum + s.score, 0) / suburbMatrix.length) : 0;
    const serviceCoverage = serviceMatrix.length ? Math.round(serviceMatrix.reduce((sum, s) => sum + s.score, 0) / serviceMatrix.length) : 0;
    const totalGaps = recommendations.reduce((sum, r) => sum + (r.items?.length || 1), 0);

    // ============ KPI DATA ============
    // GBP profile completeness
    const gbpAddress = [
      ...(profile?.storefrontAddress?.addressLines || []),
      profile?.storefrontAddress?.locality,
      profile?.storefrontAddress?.administrativeArea,
      profile?.storefrontAddress?.postalCode,
    ].filter(Boolean).join(', ');
    // Service-area businesses hide their address — that's normal, not a problem
    const isServiceArea = project.is_local_business !== false && gbpSuburbs.length > 0 && !gbpAddress;
    const gbpCompleteness = {
      hasName: !!profile?.title,
      hasAddress: !!gbpAddress || isServiceArea,
      addressHidden: isServiceArea,
      hasDescription: !!profile?.profile?.description,
      hasPhone: !!profile?.phoneNumbers?.primaryPhone,
      hasWebsite: !!profile?.websiteUri,
      hasHours: !!(profile?.regularHours?.periods?.length),
      hasCategories: gbpCategories.length > 0,
      hasPhotos: !!(profile?.media?.length),
      hasServiceAreas: gbpSuburbs.length > 0,
      hasServices: gbpServices.length > 0,
      categoriesCount: gbpCategories.length,
      photosCount: profile?.media?.length || 0,
      serviceAreasCount: gbpSuburbs.length,
      servicesCount: gbpServices.length,
      description: profile?.profile?.description ? profile.profile.description.substring(0, 200) : null,
      phone: profile?.phoneNumbers?.primaryPhone || null,
      website: profile?.websiteUri || null,
      name: profile?.title || null,
      address: gbpAddress || null,
      primaryCategory: profile?.categories?.primaryCategory?.displayName || null,
    };
    const gbpFields = ['hasName', 'hasAddress', 'hasDescription', 'hasPhone', 'hasWebsite', 'hasHours', 'hasCategories', 'hasServiceAreas', 'hasServices'];
    const gbpFieldLabels = { hasName: 'Business Name', hasAddress: 'Business Address', hasDescription: 'Business Description', hasPhone: 'Phone Number', hasWebsite: 'Website URL', hasHours: 'Business Hours', hasCategories: 'Categories', hasServiceAreas: 'Service Areas', hasServices: 'Services List' };
    const gbpFilledCount = gbpFields.filter(f => gbpCompleteness[f]).length;
    gbpCompleteness.filledCount = gbpFilledCount;
    gbpCompleteness.totalFields = gbpFields.length;
    gbpCompleteness.missingFields = gbpFields.filter(f => !gbpCompleteness[f]).map(f => gbpFieldLabels[f] || f);
    // All fields with status for detail view
    gbpCompleteness.allFields = gbpFields.map(f => ({ key: f, label: gbpFieldLabels[f] || f, done: !!gbpCompleteness[f] }));

    // ============ GBP AUDIT CHECKS (based on Google's official ranking documentation) ============
    const gbpAuditChecks = [];

    // 1. Verified status
    // GBP Management API has 0 quota so metadata.hasVoiceOfMerchant is unavailable.
    // Infer verification: if profile has reviews, rating, or categories from SerpAPI, it's verified.
    const hasApiVerification = !!profile?.metadata?.hasVoiceOfMerchant;
    const inferredVerified = !!(gbpCompleteness.hasName && (reviewStats?.total_reviews > 0 || gbpCategories.length > 0));
    const isVerified = hasApiVerification || inferredVerified;
    gbpAuditChecks.push({
      id: 'verified',
      title: 'Business Verification',
      status: isVerified ? 'pass' : 'critical',
      value: isVerified ? 'Verified' : 'Not verified',
      recommendation: isVerified ? null : 'Verify your business on Google. Unverified businesses are far less likely to appear in search results.',
    });

    // 2. Review response rate
    const replyRate = reviewStats?.reply_rate ?? null;
    const unrepliedCount = reviewStats?.unreplied_count ?? null;
    gbpAuditChecks.push({
      id: 'review-response',
      title: 'Review Response Rate',
      status: replyRate === 100 ? 'pass' : replyRate >= 80 ? 'warning' : replyRate !== null ? 'critical' : 'unknown',
      value: replyRate !== null ? `${replyRate}% (${unrepliedCount} unreplied)` : 'No data',
      recommendation: replyRate === 100 ? null : replyRate !== null
        ? `Respond to all ${unrepliedCount} unreplied reviews. Google says responding to reviews improves local ranking.`
        : 'Sync reviews to check response rate.',
    });

    // 3. Business name compliance — check for keyword stuffing, location info, taglines
    const bizName = profile?.title || '';
    const nameIssues = [];
    // Check if name contains category keywords
    for (const cat of gbpCategories) {
      if (bizName.toLowerCase().includes(cat.toLowerCase()) && cat.toLowerCase() !== bizName.toLowerCase()) {
        // Allow if it's genuinely part of the name (e.g. "Joe's Plumbing" for a Plumber)
        // Flag if the full category name appears (e.g. "Best Locksmith Perth" contains "Locksmith")
      }
    }
    // Check for common stuffing patterns
    if (/\b(best|top|#1|number one|cheapest|affordable|leading|premier|expert)\b/i.test(bizName)) {
      nameIssues.push('Contains marketing terms (e.g. "best", "top", "cheapest")');
    }
    if (/[®™©]/.test(bizName)) {
      nameIssues.push('Contains trademark/registered signs (®, ™, ©)');
    }
    if (/\b(LLC|LTD|INC|PTY|CO\b|CORP)\b/i.test(bizName)) {
      nameIssues.push('Contains legal terms (LLC, LTD, etc.) — only allowed if consistently shown on signage');
    }
    if (/\d{4,}/.test(bizName) && !/\d{4}/.test(bizName.replace(/\d{10,}/, ''))) {
      // phone number in name
      nameIssues.push('May contain phone number');
    }
    gbpAuditChecks.push({
      id: 'name-compliance',
      title: 'Business Name Compliance',
      status: nameIssues.length === 0 ? 'pass' : 'warning',
      value: nameIssues.length === 0 ? `"${bizName}" — compliant` : `"${bizName}" — ${nameIssues.length} issue(s)`,
      issues: nameIssues,
      recommendation: nameIssues.length ? `Google prohibits keyword stuffing in business names. Issues: ${nameIssues.join('; ')}` : null,
    });

    // 4. Category optimization — fewest + most specific
    const totalCategories = gbpCategories.length;
    const catIssues = [];
    if (totalCategories > 5) catIssues.push(`${totalCategories} categories — Google says use fewest possible`);
    if (totalCategories === 0) catIssues.push('No categories set');
    // Check for redundant/broad categories (primary should be most specific)
    gbpAuditChecks.push({
      id: 'category-optimization',
      title: 'Category Optimization',
      status: catIssues.length === 0 ? 'pass' : totalCategories === 0 ? 'critical' : 'warning',
      value: `${totalCategories} categories — Primary: ${profile?.categories?.primaryCategory?.displayName || 'None'}`,
      categories: gbpCategories,
      issues: catIssues,
      recommendation: catIssues.length ? `Google says: "Use as few categories as possible, choose the most specific." ${catIssues.join('. ')}` : null,
    });

    // 5. Service area boundary — max ~2 hours driving from base
    const saIssues = [];
    if (gbpSuburbs.length > 20) {
      saIssues.push(`${gbpSuburbs.length} service areas — Google allows max 20`);
    }
    if (gbpSuburbs.length === 0 && !gbpAddress) {
      saIssues.push('No service area and no address set — Google needs at least one');
    }
    // Check for very distant areas using SUBURB_GPS if available
    const businessLat = profile?.latlng?.latitude || null;
    const businessLng = profile?.latlng?.longitude || null;
    gbpAuditChecks.push({
      id: 'service-area-boundary',
      title: 'Service Area Boundary',
      status: saIssues.length === 0 ? 'pass' : 'warning',
      value: `${gbpSuburbs.length} service areas set`,
      serviceAreas: gbpSuburbs,
      issues: saIssues,
      recommendation: saIssues.length ? `Google says service area shouldn't extend farther than ~2 hours driving. ${saIssues.join('. ')}` : null,
    });

    // 6. Hours freshness — check if hours are configured. Days not in regularHours.periods are "Closed" (valid, not missing).
    const hoursPeriods = profile?.regularHours?.periods || [];
    const daysWithHours = new Set(hoursPeriods.map(p => p.openDay));
    const allDays = ['MONDAY', 'TUESDAY', 'WEDNESDAY', 'THURSDAY', 'FRIDAY', 'SATURDAY', 'SUNDAY'];
    const closedDays = allDays.filter(d => !daysWithHours.has(d));
    const hoursIssues = [];
    if (hoursPeriods.length === 0) {
      hoursIssues.push('No business hours set');
    }
    // Days not in periods are explicitly closed — that's valid, not "missing"
    const hasSpecialHours = !!profile?.specialHours?.specialHourPeriods?.length;
    if (!hasSpecialHours && hoursPeriods.length > 0) {
      hoursIssues.push('No special hours set — add holiday hours to keep profile accurate');
    }
    const closedDaysLabel = closedDays.length > 0 ? `, closed ${closedDays.map(d => d.charAt(0) + d.slice(1).toLowerCase()).join(', ')}` : '';
    gbpAuditChecks.push({
      id: 'hours-completeness',
      title: 'Hours Completeness',
      status: hoursIssues.length === 0 ? 'pass' : hoursPeriods.length === 0 ? 'critical' : 'warning',
      value: hoursPeriods.length > 0 ? `7/7 days set (open ${daysWithHours.size}${closedDaysLabel})${hasSpecialHours ? ', has special hours' : ', no special hours'}` : 'Not set',
      missingDays: [],
      issues: hoursIssues,
      recommendation: hoursIssues.length ? `Google says keep hours up to date including special hours. ${hoursIssues.join('. ')}` : null,
    });

    // 7. Photo benchmarks — compare to competitors
    const photoCount = profile?.media?.length || 0;
    const compPhotos = topCompetitors.filter(c => c.photos > 0).map(c => c.photos);
    const avgCompPhotos = compPhotos.length ? Math.round(compPhotos.reduce((a, b) => a + b, 0) / compPhotos.length) : null;
    const photoIssues = [];
    if (photoCount === 0) {
      photoIssues.push('No photos uploaded');
    } else if (photoCount < 5) {
      photoIssues.push(`Only ${photoCount} photos — aim for at least 10-20`);
    }
    if (avgCompPhotos && photoCount < avgCompPhotos) {
      photoIssues.push(`Competitors average ${avgCompPhotos} photos, you have ${photoCount}`);
    }
    const photoTypes = [
      'Logo — your business logo (appears on Maps)',
      'Cover photo — hero image that represents your business',
      'Exterior — shopfront/van/vehicle branding so customers recognise you',
      'Interior/workspace — your workshop, tools, or office setup',
      'Team — photos of you and your team on the job',
      'At work — action shots of services being performed (e.g. cutting keys, unlocking cars)',
      'Completed jobs — before/after or finished results',
      'Equipment — specialist tools and technology you use',
      'Branded vehicle — if mobile service, show your branded van/car',
      'Customer interactions — with permission, happy customers receiving service'
    ];
    gbpAuditChecks.push({
      id: 'photo-benchmarks',
      title: 'Photos & Media',
      status: photoIssues.length === 0 ? 'pass' : photoCount === 0 ? 'critical' : 'warning',
      value: `${photoCount} photos${avgCompPhotos ? ` (competitors avg: ${avgCompPhotos})` : ''}`,
      issues: photoIssues,
      photoTypes,
      recommendation: photoIssues.length ? `Google says photos and videos show what you offer. Upload at least 10-20 high-quality photos across these categories:\n${photoTypes.map((t, i) => `${i + 1}. ${t}`).join('\n')}\n\nTips: Use real photos (not stock), geo-tag them to your location, and add new photos monthly to signal activity.` : null,
    });

    // Competitor benchmarks (from grid scan data)
    const compReviews = topCompetitors.filter(c => c.reviews > 0).map(c => c.reviews);
    const compRatings = topCompetitors.filter(c => c.rating > 0).map(c => c.rating);
    const competitorBenchmarks = {
      avgReviews: compReviews.length ? Math.round(compReviews.reduce((a, b) => a + b, 0) / compReviews.length) : null,
      maxReviews: compReviews.length ? Math.max(...compReviews) : null,
      medianReviews: compReviews.length ? compReviews.sort((a, b) => a - b)[Math.floor(compReviews.length / 2)] : null,
      avgRating: compRatings.length ? +(compRatings.reduce((a, b) => a + b, 0) / compRatings.length).toFixed(1) : null,
      topCompetitorName: topCompetitors[0]?.name || null,
      topCompetitorReviews: topCompetitors[0]?.reviews || null,
      topCompetitorRating: topCompetitors[0]?.rating || null,
    };

    // Citation/directory data — use citations table + auto-detect from existing data
    let citationStatusMap = {};
    let citationScanned = false;
    try {
      const citR = await pool.query(`SELECT directory_name, status, listing_url FROM citations WHERE project_id=$1`, [projectId]);
      citationScanned = citR.rows.length > 0;
      for (const row of citR.rows) citationStatusMap[row.directory_name] = { status: row.status, url: row.listing_url };
    } catch (e) { /* citations table may not exist yet */ }

    // Auto-detect known listings from data we already have (no scan needed)
    if (!citationStatusMap['Google Business Profile'] && (project.gbp_location_id || profile)) {
      const placeId = project.gbp_location_id;
      citationStatusMap['Google Business Profile'] = {
        status: 'listed',
        url: placeId ? `https://www.google.com/maps/place/?q=place_id:${placeId}` : 'https://business.google.com',
      };
    }
    // Detect Facebook from RC profile if available
    if (!citationStatusMap['Facebook Business'] && rc?.profile?.facebookUrl) {
      citationStatusMap['Facebook Business'] = { status: 'listed', url: rc.profile.facebookUrl };
    }

    const directoryList = AUSTRALIAN_DIRECTORIES.map(d => ({
      name: d.name, url: d.url, type: d.type, free: d.free, paid_option: d.paid_option || null,
      difficulty: d.difficulty, priority: d.priority, description: d.description,
      listed: citationStatusMap[d.name]?.status === 'listed',
      pending: citationStatusMap[d.name]?.status === 'pending',
      notChecked: !citationStatusMap[d.name] || citationStatusMap[d.name]?.status === 'not_checked',
      listingUrl: citationStatusMap[d.name]?.url || null,
    }));
    const citationCount = directoryList.filter(d => d.listed).length;

    res.json({
      project: { id: project.id, name: project.name, business_name: project.business_name, domain: project.domain },
      summary: {
        suburbCount: suburbMatrix.length,
        serviceCount: serviceMatrix.filter(s => s.type === 'service').length,
        productCount: serviceMatrix.filter(s => s.type === 'product').length,
        gbpOnlyServiceCount: gbpOnlyServices.length,
        gbpSuburbCount: suburbMatrix.filter(s => s.inGbp).length,
        gbpServiceCount: serviceMatrix.filter(s => s.inGbp).length,
        servicesWithPage: serviceMatrix.filter(s => s.hasPage).length,
        servicesWithSuburbPages: serviceMatrix.filter(s => s.type === 'service' && s.suburbPageCount > 0).length,
        pagesWithSuburb: suburbMatrix.filter(s => s.pageCount > 0).length,
        pagesWithService: serviceMatrix.filter(s => s.pageCount > 0).length,
        trackedKeywords: rankKeywords.length,
        gridScans: Object.keys(gridMap).length,
        totalWebPages: websitePages.length,
        totalGscKeywords: gscKeywords.length,
        suburbCoverage,
        serviceCoverage,
        totalGaps,
        reviewStats,
        gbpCategories,
        gbpPostCount: gbpPosts.length,
        gbpPostsThisMonth,
        gbpProductCount: gbpProductNames.size,
        competitorCount: topCompetitors.length,
        totalCombos,
        coveredCombos,
        fullyCovered,
        indexingTotal,
        indexingIndexed,
        indexingNotIndexed,
        totalReviews: allReviews.length,
        suburbsWithReviews: suburbMatrix.filter(s => s.reviewMentions > 0).length,
      },
      suburbSource,
      hasLocationPages,
      suburbs: suburbMatrix,
      unmatchedGscSuburbs: (() => {
        // Find GSC keywords with suburb-like patterns NOT in our target list
        const matchedKws = new Set();
        for (const [kwLower] of Object.entries(gscMap)) {
          for (const n of allSuburbNames) {
            if (kwLower.includes(n)) matchedKws.add(kwLower);
          }
        }
        // Check all SUBURB_GPS names + common suburb patterns
        const allKnownSuburbs = Object.keys(SUBURB_GPS);
        const discovered = [];
        for (const [kwLower, gsc] of Object.entries(gscMap)) {
          if (matchedKws.has(kwLower)) continue;
          if ((gsc.impressions || 0) < 5) continue;
          for (const sub of allKnownSuburbs) {
            if (kwLower.includes(sub) && !allSuburbNames.has(sub)) {
              discovered.push({ keyword: gsc.keyword, suburb: sub, impressions: gsc.impressions, clicks: gsc.clicks, position: gsc.position });
              break;
            }
          }
        }
        return discovered.sort((a, b) => (b.impressions || 0) - (a.impressions || 0)).slice(0, 20);
      })(),
      services: serviceMatrix.filter(s => s.type === 'service'),
      products: serviceMatrix.filter(s => s.type === 'product'),
      definedServices,
      definedProducts,
      gbpOnlyServices,
      gbpOnlyLocations,
      competitors: topCompetitors,
      matrix: matrixRows,
      serviceNames: Array.from(allServiceNames).map(n => serviceSources[n].original),
      recommendations: recommendations.sort((a, b) => { const pri = { critical: 0, high: 1, medium: 2, low: 3 }; return (pri[a.priority] || 4) - (pri[b.priority] || 4); }),
      gbpCompleteness,
      gbpAuditChecks,
      competitorBenchmarks,
      citationCount,
      citationScanned,
      directoryList,
      gscQueries: gscKeywords
        .filter(g => (g.impressions || 0) > 0)
        .sort((a, b) => (b.impressions || 0) - (a.impressions || 0))
        .slice(0, 20)
        .map(g => ({ query: g.keyword, impressions: g.impressions || 0, clicks: g.clicks || 0, ctr: g.ctr || 0, position: g.position || 0 })),
    });
  } catch (e) {
    console.error('[local-intel] Error:', e.message, e.stack);
    res.status(500).json({ error: e.message });
  }
});

// ==================== LOCAL INTEL — BULK FIX GAPS ====================
app.post('/api/projects/:id/local-intel/fix-gaps', async (req, res) => {
  const projectId = req.params.id;
  const { action, keyword_limit } = req.body; // 'generate_keywords' | 'queue_pages' | 'all'
  const kwLimit = Math.min(Math.max(parseInt(keyword_limit) || 20, 5), 100);
  try {
    const projR = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    const project = projR.rows[0];

    // Get RC profile for services + suburbs
    const rcR = await pool.query("SELECT config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    const rc = rcR.rows[0]?.config ? (typeof rcR.rows[0].config === 'string' ? JSON.parse(rcR.rows[0].config) : rcR.rows[0].config) : null;
    const profile = rc?.profile || null;

    // Extract suburbs from GBP + project
    const suburbs = new Set();
    if (profile?.serviceArea?.places?.placeInfos) {
      for (const p of profile.serviceArea.places.placeInfos) {
        const name = (p.placeName || '').replace(/,?\s*(WA|Australia|VIC|NSW|QLD|SA|NT|TAS|ACT)\s*/gi, '').replace(/\d{4}/, '').trim();
        if (name) suburbs.add(name);
      }
    }
    if (project.service_areas) {
      const sa = typeof project.service_areas === 'string' ? JSON.parse(project.service_areas) : project.service_areas;
      if (Array.isArray(sa)) sa.forEach(s => { const n = (typeof s === 'string' ? s : s.name || '').trim(); if (n) suburbs.add(n); });
    }

    // Extract services from GBP
    const services = [];
    if (profile?.serviceItems) {
      for (const si of profile.serviceItems) {
        const label = si.freeFormServiceItem?.label?.displayName || '';
        if (label) services.push(label);
      }
    }

    // Get existing keywords to avoid duplicates
    const existingKw = await pool.query('SELECT keyword FROM rank_keywords WHERE project_id=$1', [projectId]);
    const existingSet = new Set(existingKw.rows.map(r => r.keyword.toLowerCase()));

    // Get existing content queue items to avoid duplicates
    const existingCq = await pool.query('SELECT page_title FROM content_queue WHERE project_id=$1', [projectId]);
    const existingCqSet = new Set(existingCq.rows.map(r => (r.page_title || '').toLowerCase()));

    const results = { keywords_added: 0, pages_queued: 0, keywords_skipped: 0, pages_skipped: 0 };

    // 1. Generate keywords: top 3 services × all suburbs
    if (action === 'generate_keywords' || action === 'all') {
      // Pick top service terms (short, generic ones work best as keyword roots)
      const keywordRoots = [];
      const industry = (project.industry || '').toLowerCase();

      // Use business-relevant short service names as keyword roots
      for (const svc of services) {
        const lower = svc.toLowerCase();
        // Skip long compound services, keep short actionable ones
        if (lower.split(/\s+/).length <= 4 && !lower.includes('&') && !lower.includes('and')) {
          keywordRoots.push(lower);
        }
      }
      // Also add industry/category as root
      if (profile?.categories?.primaryCategory?.displayName) {
        keywordRoots.unshift(profile.categories.primaryCategory.displayName.toLowerCase());
      }
      const roots = [...new Set(keywordRoots)].slice(0, 10);
      const location = (project.location || '').trim();
      const suburbArr = [...suburbs];

      // Generate combos prioritising: primary category first, then each root across suburbs
      const combos = [];
      for (const root of roots) {
        for (const suburb of suburbArr) {
          combos.push(`${root} ${suburb}`.trim());
        }
      }
      // Cap at kwLimit, skipping existing
      let added = 0;
      for (const keyword of combos) {
        if (added >= kwLimit) break;
        if (existingSet.has(keyword.toLowerCase())) {
          results.keywords_skipped++;
          continue;
        }
        try {
          await pool.query(
            'INSERT INTO rank_keywords (project_id, keyword, location) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING',
            [projectId, keyword, location || keyword.split(' ').pop()]
          );
          existingSet.add(keyword.toLowerCase());
          results.keywords_added++;
          added++;
        } catch (e) {
          console.log(`[fix-gaps] Skip keyword "${keyword}": ${e.message}`);
        }
      }
    }

    // 2. Queue suburb landing pages in content_queue
    if (action === 'queue_pages' || action === 'all') {
      // Check which suburbs already have pages
      const opR = await pool.query('SELECT results FROM onpage_audit_cache WHERE project_id=$1', [projectId]);
      const existingPages = [];
      if (opR.rows[0]?.results) {
        const results2 = typeof opR.rows[0].results === 'string' ? JSON.parse(opR.rows[0].results) : opR.rows[0].results;
        if (Array.isArray(results2)) {
          for (const p of results2) existingPages.push((p.url || p.slug || '').toLowerCase());
        }
      }

      const normalize = s => s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
      const primaryService = profile?.categories?.primaryCategory?.displayName || project.industry || 'services';

      for (const suburb of suburbs) {
        const n = normalize(suburb);
        const slugForm = n.replace(/\s+/g, '-');
        // Check if any existing page URL contains this suburb
        const hasPage = existingPages.some(url => url.includes(slugForm) || url.includes(n.replace(/\s+/g, '')));
        if (hasPage) {
          results.pages_skipped++;
          continue;
        }
        // Check if already in content queue
        const pageTitle = `${primaryService} ${suburb}`;
        if (existingCqSet.has(pageTitle.toLowerCase())) {
          results.pages_skipped++;
          continue;
        }
        try {
          await pool.query(
            `INSERT INTO content_queue (project_id, page_title, content_type, source, priority, brief, stage)
             VALUES ($1, $2, 'new_page', 'local-intel', 'medium', $3, 'queue')`,
            [projectId, pageTitle, `Create a suburb landing page for ${suburb}. Target keywords: ${primaryService.toLowerCase()} ${suburb.toLowerCase()}. Include local suburb info, service descriptions, and a clear CTA.`]
          );
          existingCqSet.add(pageTitle.toLowerCase());
          results.pages_queued++;
        } catch (e) {
          console.log(`[fix-gaps] Skip page "${pageTitle}": ${e.message}`);
        }
      }
    }

    console.log(`[fix-gaps] Project ${projectId}: +${results.keywords_added} keywords, +${results.pages_queued} pages queued`);
    res.json({ ok: true, ...results });
  } catch (e) {
    console.error('[fix-gaps] Error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// ==================== LOCAL INTEL — ADD/DELETE SUBURBS & SERVICES ====================
app.post('/api/projects/:id/local-intel/suburbs', async (req, res) => {
  const projectId = req.params.id;
  const { name } = req.body;
  if (!name || !name.trim()) return res.status(400).json({ error: 'Suburb name required' });
  try {
    const projR = await pool.query('SELECT service_areas FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    let sa = projR.rows[0].service_areas || [];
    if (typeof sa === 'string') sa = JSON.parse(sa);
    if (!Array.isArray(sa)) sa = [];
    const trimmed = name.trim();
    const exists = sa.some(s => (typeof s === 'string' ? s : s.name || '').toLowerCase() === trimmed.toLowerCase());
    if (exists) return res.status(409).json({ error: 'Suburb already exists' });
    sa.push(trimmed);
    await pool.query('UPDATE projects SET service_areas=$1 WHERE id=$2', [JSON.stringify(sa), projectId]);
    res.json({ ok: true, service_areas: sa });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

app.delete('/api/projects/:id/local-intel/suburbs/:name', async (req, res) => {
  const projectId = req.params.id;
  const suburbName = decodeURIComponent(req.params.name).trim().toLowerCase();
  try {
    const projR = await pool.query('SELECT service_areas FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    let sa = projR.rows[0].service_areas || [];
    if (typeof sa === 'string') sa = JSON.parse(sa);
    if (!Array.isArray(sa)) sa = [];
    const filtered = sa.filter(s => (typeof s === 'string' ? s : s.name || '').trim().toLowerCase() !== suburbName);
    await pool.query('UPDATE projects SET service_areas=$1 WHERE id=$2', [JSON.stringify(filtered), projectId]);
    res.json({ ok: true, service_areas: filtered });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Rename suburb
app.put('/api/projects/:id/local-intel/suburbs/:name', async (req, res) => {
  const projectId = req.params.id;
  const oldName = decodeURIComponent(req.params.name).trim().toLowerCase();
  const { name: newName } = req.body;
  if (!newName || !newName.trim()) return res.status(400).json({ error: 'New name required' });
  try {
    const projR = await pool.query('SELECT service_areas FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    let sa = projR.rows[0].service_areas || [];
    if (typeof sa === 'string') sa = JSON.parse(sa);
    if (!Array.isArray(sa)) sa = [];
    sa = sa.map(s => {
      const val = typeof s === 'string' ? s : s.name || '';
      return val.trim().toLowerCase() === oldName ? newName.trim() : val;
    });
    await pool.query('UPDATE projects SET service_areas=$1 WHERE id=$2', [JSON.stringify(sa), projectId]);
    res.json({ ok: true });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Add/remove/move service or product
app.post('/api/projects/:id/local-intel/offerings', async (req, res) => {
  const projectId = req.params.id;
  const { action, name, type, fromType } = req.body;
  // action: 'add' | 'remove' | 'move' (move = remove from fromType, add to type)
  if (!name || !type) return res.status(400).json({ error: 'name and type required' });
  try {
    const projR = await pool.query('SELECT defined_services, defined_products FROM projects WHERE id=$1', [projectId]);
    if (!projR.rows.length) return res.status(404).json({ error: 'Project not found' });
    let services = Array.isArray(projR.rows[0].defined_services) ? [...projR.rows[0].defined_services] : [];
    let products = Array.isArray(projR.rows[0].defined_products) ? [...projR.rows[0].defined_products] : [];

    if (action === 'add') {
      if (type === 'service' && !services.includes(name)) services.push(name);
      if (type === 'product' && !products.includes(name)) products.push(name);
    } else if (action === 'remove') {
      if (type === 'service') services = services.filter(s => s !== name);
      if (type === 'product') products = products.filter(s => s !== name);
    } else if (action === 'move') {
      // Move from one list to the other
      if (fromType === 'service') services = services.filter(s => s !== name);
      if (fromType === 'product') products = products.filter(s => s !== name);
      if (type === 'service' && !services.includes(name)) services.push(name);
      if (type === 'product' && !products.includes(name)) products.push(name);
    }

    await pool.query('UPDATE projects SET defined_services=$1, defined_products=$2 WHERE id=$3',
      [JSON.stringify(services), JSON.stringify(products), projectId]);
    res.json({ ok: true, defined_services: services, defined_products: products });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Rename service
app.put('/api/projects/:id/local-intel/services/:name', async (req, res) => {
  const projectId = req.params.id;
  const oldName = decodeURIComponent(req.params.name).trim().toLowerCase();
  const { name: newName } = req.body;
  if (!newName || !newName.trim()) return res.status(400).json({ error: 'New name required' });
  try {
    const rcR = await pool.query("SELECT id, config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    if (!rcR.rows.length) return res.status(404).json({ error: 'No RC profile found' });
    let config = rcR.rows[0].config;
    if (typeof config === 'string') config = JSON.parse(config);
    if (!config.custom_services) config.custom_services = [];
    config.custom_services = config.custom_services.map(s => s.toLowerCase() === oldName ? newName.trim() : s);
    await pool.query('UPDATE project_integrations SET config=$1 WHERE id=$2', [JSON.stringify(config), rcR.rows[0].id]);
    res.json({ ok: true });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/api/projects/:id/local-intel/services', async (req, res) => {
  const projectId = req.params.id;
  const { name } = req.body;
  if (!name || !name.trim()) return res.status(400).json({ error: 'Service name required' });
  try {
    // Services are stored in RC profile → serviceItems. We'll also store custom services in project_integrations config
    const rcR = await pool.query("SELECT id, config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    if (!rcR.rows.length) return res.status(404).json({ error: 'No RC profile found. Sync RC data first.' });
    let config = rcR.rows[0].config;
    if (typeof config === 'string') config = JSON.parse(config);
    if (!config.custom_services) config.custom_services = [];
    const trimmed = name.trim();
    const allServices = [];
    if (config.profile?.serviceItems) {
      for (const si of config.profile.serviceItems) {
        allServices.push((si.freeFormServiceItem?.label?.displayName || '').toLowerCase());
      }
    }
    allServices.push(...config.custom_services.map(s => s.toLowerCase()));
    if (allServices.includes(trimmed.toLowerCase())) return res.status(409).json({ error: 'Service already exists' });
    config.custom_services.push(trimmed);
    await pool.query('UPDATE project_integrations SET config=$1 WHERE id=$2', [JSON.stringify(config), rcR.rows[0].id]);
    res.json({ ok: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

app.delete('/api/projects/:id/local-intel/services/:name', async (req, res) => {
  const projectId = req.params.id;
  const serviceName = decodeURIComponent(req.params.name).trim().toLowerCase();
  try {
    const rcR = await pool.query("SELECT id, config FROM project_integrations WHERE project_id=$1 AND kind='rc_profile'", [projectId]);
    if (!rcR.rows.length) return res.status(404).json({ error: 'No RC profile found' });
    let config = rcR.rows[0].config;
    if (typeof config === 'string') config = JSON.parse(config);
    // Remove from custom_services if present
    if (config.custom_services) {
      config.custom_services = config.custom_services.filter(s => s.trim().toLowerCase() !== serviceName);
    }
    // Remove from GBP serviceItems if present
    if (config.profile?.serviceItems) {
      config.profile.serviceItems = config.profile.serviceItems.filter(si => {
        const label = (si.freeFormServiceItem?.label?.displayName || '').trim().toLowerCase();
        return label !== serviceName;
      });
    }
    await pool.query('UPDATE project_integrations SET config=$1 WHERE id=$2', [JSON.stringify(config), rcR.rows[0].id]);
    res.json({ ok: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});


