// ==================== 16. INTERNAL LINKING ====================

// Run internal link audit — crawl pages, build link graph, find orphans, generate AI suggestions
app.post('/api/projects/:projectId/internal-links/audit', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  const force = req.body?.force === true;
  try {
    const proj = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (!proj.rows.length) return res.status(404).json({ error: 'Project not found' });
    const project = proj.rows[0];
    if (!project.domain) return res.status(400).json({ error: 'Project domain is required' });

    // No rate limit — internal linking is low-cost

    // Guard: don't start if already running
    const existing = await pool.query('SELECT status, updated_at FROM internal_link_audit_cache WHERE project_id=$1', [projectId]);
    if (existing.rows.length && existing.rows[0].status === 'running') {
      const elapsed = Date.now() - new Date(existing.rows[0].updated_at).getTime();
      if (elapsed < 5 * 60 * 1000) {
        return res.json({ ok: true, status: 'running', message: 'Audit already in progress' });
      }
      // Stale — allow restart
    }

    // Mark running
    await pool.query(`
      INSERT INTO internal_link_audit_cache (project_id, status, updated_at)
      VALUES ($1, 'running', NOW())
      ON CONFLICT (project_id) DO UPDATE SET status='running', error_message=NULL, updated_at=NOW()
    `, [projectId]);

    res.json({ ok: true, status: 'running' });

    // Background processing
    (async () => {
      try {
        let baseUrl = project.domain.replace(/\/$/, '');
        if (!/^https?:\/\//i.test(baseUrl)) baseUrl = 'https://' + baseUrl;
        let wpUrl = project.wp_url || baseUrl;
        if (!/^https?:\/\//i.test(wpUrl)) wpUrl = 'https://' + wpUrl;

        // 0. Load plugin-pushed pages (collected locally inside WordPress — bypasses crawl blocking and
        //    carries the real rendered content, including Elementor). Used as the page list and as a
        //    per-page fallback when a server-side crawl is blocked.
        const pushedByUrl = new Map();
        try {
          const cc = await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='connector_cache'`, [projectId]);
          for (const pp of (cc.rows[0]?.config?.pages || [])) {
            const u = (pp.url || '').replace(/\/$/, '');
            if (u) pushedByUrl.set(u, pp);
          }
          if (pushedByUrl.size) console.log(`[internal-links] Loaded ${pushedByUrl.size} plugin-pushed pages`);
        } catch (e) {}

        // 1. Discover pages.
        // Prefer the plugin-pushed page list whenever we have it: it carries the real rendered content
        // and, crucially, lets us SKIP the server-side crawl that Cloudflare blocks (the blocked fetches
        // pile up at 10s each and hang the whole run). Only crawl live when there are no pushed pages.
        const authHeaders = getWpAuthHeaders(project);
        let pages;
        if (pushedByUrl.size) {
          pages = [...pushedByUrl.values()].map(pp => ({ url: pp.url, title: pp.title }));
          console.log(`[internal-links] Using ${pages.length} plugin-pushed pages (no crawl)`);
        } else {
          pages = await discoverPages(baseUrl, wpUrl, authHeaders);
          console.log(`[internal-links] No pushed pages — crawled discovery found ${pages.length}`);
        }
        console.log(`[internal-links] ${pages.length} pages for project ${projectId}`);
        if (!pages.length) {
          await pool.query(`UPDATE internal_link_audit_cache SET status='completed', total_pages=0, total_links=0, orphan_pages='[]', stats='{}', suggestions_count=0, audited_at=NOW(), updated_at=NOW() WHERE project_id=$1`, [projectId]);
          return;
        }

        // 2. Crawl each page and extract internal links
        const domain = new URL(baseUrl).hostname;
        const linkGraph = []; // {source_url, source_title, target_url, anchor_text, context_snippet}
        const pageData = []; // {url, title, wordCount, outbound[], inbound[]}
        const pageMap = new Map(); // url -> {title, outbound, inbound, wordCount}

        for (const page of pages) {
          const url = page.url;
          const urlNorm0 = url.replace(/\/$/, '');
          // Fast path: if we already have this page's rendered content from the plugin push, use it
          // directly and skip the live fetch entirely (avoids Cloudflare-blocked requests that hang).
          // On a forced re-run, ignore stale plugin-pushed content and crawl the live page, so newly
          // added in-content links (hubs, spokes) are actually picked up.
          const ppFast = force ? null : pushedByUrl.get(urlNorm0);
          if (ppFast && (ppFast.text || (ppFast.links && ppFast.links.length))) {
            const fullText = (ppFast.text || '').replace(/\s+/g, ' ').trim();
            const outbound = [];
            for (const l of (ppFast.links || [])) {
              let href = (l.href || '').trim();
              const anchor = (l.anchor || '').trim();
              if (!anchor || anchor.length > 200) continue;
              try { const rr = new URL(href, url); if (rr.hostname !== domain) continue; href = rr.href.replace(/\/$/, ''); } catch { continue; }
              if (href === urlNorm0) continue;
              outbound.push({ target_url: href, anchor_text: anchor, context_snippet: '' });
              linkGraph.push({ source_url: urlNorm0, source_title: ppFast.title || page.title, target_url: href, anchor_text: anchor, context_snippet: '' });
            }
            pageMap.set(urlNorm0, { title: ppFast.title || page.title, outbound, inbound: [], wordCount: ppFast.wordCount || fullText.split(/\s+/).length, textSnippet: fullText.substring(0, 1500), fullText });
            continue;
          }
          try {
            // Cache-bust on forced re-runs so we read the freshly-updated page, not a cached copy.
            const fetchUrl = force ? (url + (url.includes('?') ? '&' : '?') + 'sr=' + Date.now()) : url;
            const resp = await fetch(fetchUrl, { headers: { 'User-Agent': 'SEORoomBot/1.0', 'Cache-Control': 'no-cache, no-store, max-age=0', 'Pragma': 'no-cache' }, signal: AbortSignal.timeout(12000) });
            if (!resp.ok) throw new Error('HTTP ' + resp.status);
            const html = await resp.text();
            const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
            const title = titleMatch ? titleMatch[1].trim() : page.title;

            // Word count (strip HTML)
            const textContent = html.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
            const wordCount = textContent.split(/\s+/).length;

            // Extract internal links from content area
            const bodyMatch = html.match(/<body[\s\S]*?<\/body>/i);
            const body = bodyMatch ? bodyMatch[0] : html;
            // Remove nav, header, footer to focus on content links
            const content = body
              .replace(/<nav[\s\S]*?<\/nav>/gi, '')
              .replace(/<header[\s\S]*?<\/header>/gi, '')
              .replace(/<footer[\s\S]*?<\/footer>/gi, '');

            const linkRegex = /<a\s[^>]*href=["']([^"'#]+)["'][^>]*>([\s\S]*?)<\/a>/gi;
            let match;
            const outbound = [];
            while ((match = linkRegex.exec(content)) !== null) {
              let href = match[1].trim();
              const anchorHtml = match[2];
              const anchor = anchorHtml.replace(/<[^>]+>/g, '').trim();
              if (!anchor || anchor.length > 200) continue;

              // Resolve relative URLs
              try {
                const resolved = new URL(href, url);
                if (resolved.hostname !== domain) continue; // external
                href = resolved.href.replace(/\/$/, '');
              } catch { continue; }

              // Skip assets, anchors, etc
              if (href.match(/\.(jpg|jpeg|png|gif|svg|pdf|css|js|xml|zip)$/i)) continue;
              if (href === url.replace(/\/$/, '')) continue; // self-link

              // Get surrounding context (sentence containing the link)
              const plainContext = content.substring(Math.max(0, match.index - 100), match.index + match[0].length + 100)
                .replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

              outbound.push({ target_url: href, anchor_text: anchor, context_snippet: plainContext.substring(0, 250) });
              linkGraph.push({
                source_url: url.replace(/\/$/, ''),
                source_title: title,
                target_url: href,
                anchor_text: anchor,
                context_snippet: plainContext.substring(0, 250)
              });
            }

            pageMap.set(url.replace(/\/$/, ''), { title, outbound, inbound: [], wordCount, textSnippet: textContent.substring(0, 1500), fullText: textContent });
          } catch (crawlErr) {
            // Crawl blocked/failed — use the plugin-pushed content for this page if we have it
            const urlNorm = url.replace(/\/$/, '');
            const pp = pushedByUrl.get(urlNorm);
            if (pp && (pp.text || (pp.links && pp.links.length))) {
              const fullText = (pp.text || '').replace(/\s+/g, ' ').trim();
              const outbound = [];
              for (const l of (pp.links || [])) {
                let href = (l.href || '').trim();
                const anchor = (l.anchor || '').trim();
                if (!anchor || anchor.length > 200) continue;
                try { const rr = new URL(href, url); if (rr.hostname !== domain) continue; href = rr.href.replace(/\/$/, ''); } catch { continue; }
                if (href === urlNorm) continue;
                outbound.push({ target_url: href, anchor_text: anchor, context_snippet: '' });
                linkGraph.push({ source_url: urlNorm, source_title: pp.title || page.title, target_url: href, anchor_text: anchor, context_snippet: '' });
              }
              pageMap.set(urlNorm, { title: pp.title || page.title, outbound, inbound: [], wordCount: pp.wordCount || fullText.split(/\s+/).length, textSnippet: fullText.substring(0, 1500), fullText });
              console.log(`[internal-links] Used plugin-pushed content for ${url}`);
            } else {
              console.log(`[internal-links] Failed to crawl ${url}: ${crawlErr.message}`);
            }
          }
        }

        // 3. Build inbound links
        for (const link of linkGraph) {
          const target = pageMap.get(link.target_url);
          if (target) {
            target.inbound.push({ source_url: link.source_url, anchor_text: link.anchor_text });
          }
        }

        // 4. Find orphan pages (0 inbound internal links, excluding homepage)
        const orphanPages = [];
        const pageStats = [];
        for (const [url, data] of pageMap) {
          const isHome = url === baseUrl || url === baseUrl.replace(/\/$/, '') || url.replace(/https?:\/\//, '').replace(/\/$/, '') === domain;
          pageStats.push({
            url,
            title: data.title,
            outbound_count: data.outbound.length,
            inbound_count: data.inbound.length,
            word_count: data.wordCount,
            is_orphan: !isHome && data.inbound.length === 0
          });
          if (!isHome && data.inbound.length === 0) {
            orphanPages.push({ url, title: data.title, word_count: data.wordCount });
          }
        }

        // 5. Save link graph to DB (clear old, insert new)
        await pool.query('DELETE FROM internal_link_graph WHERE project_id=$1', [projectId]);
        for (const link of linkGraph) {
          await pool.query(`
            INSERT INTO internal_link_graph (project_id, source_url, source_title, target_url, anchor_text, context_snippet)
            VALUES ($1, $2, $3, $4, $5, $6)
            ON CONFLICT (project_id, source_url, target_url, anchor_text) DO NOTHING
          `, [projectId, link.source_url, link.source_title, link.target_url, link.anchor_text, link.context_snippet]);
        }

        // 6. Generate AI suggestions via Haiku (batched to avoid token limits)
        const suggestions = [];
        if (pageMap.size >= 2) {
          // Prioritize pages: orphans first, then low-inbound, then rest — limit text to 500 chars
          const allPages = [];
          for (const [url, data] of pageMap) {
            allPages.push({
              url,
              title: data.title,
              outbound: data.outbound.length,
              inbound: data.inbound.length,
              outbound_targets: data.outbound.map(l => l.target_url).slice(0, 10),
              word_count: data.wordCount,
              text_excerpt: (data.textSnippet || '').substring(0, 500)
            });
          }
          // Sort: orphans first, then by fewest inbound links
          allPages.sort((a, b) => {
            if (a.inbound === 0 && b.inbound !== 0) return -1;
            if (b.inbound === 0 && a.inbound !== 0) return 1;
            return a.inbound - b.inbound;
          });

          // Also build a compact page directory (url + title only) for all pages so AI knows link targets
          const pageDirectory = allPages.map(p => ({ url: p.url, title: p.title, inbound: p.inbound }));

          // Batch: send 40 source pages per AI call with the full directory of targets
          const BATCH_SIZE = 40;
          const batches = [];
          for (let i = 0; i < Math.min(allPages.length, 120); i += BATCH_SIZE) {
            batches.push(allPages.slice(i, i + BATCH_SIZE));
          }

          for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
            const batch = batches[batchIdx];
            try {
              console.log('[internal-links] AI batch ' + (batchIdx + 1) + '/' + batches.length + ' (' + batch.length + ' pages)');
              const aiResp = await anthropic.messages.create({
                model: 'claude-haiku-4-5-20251001',
                max_tokens: 4000,
                messages: [{
                  role: 'user',
                  content: 'You are an internal linking SEO expert. Suggest internal links for this website.\n\n' +
                    'Business: ' + (project.business_name || project.name) + '\n' +
                    'Industry: ' + (project.industry || 'unknown') + '\n' +
                    'Domain: ' + domain + '\n\n' +
                    'ALL PAGES ON SITE (potential link targets):\n' +
                    JSON.stringify(pageDirectory) + '\n\n' +
                    'SOURCE PAGES TO ANALYZE (suggest links FROM these pages):\n' +
                    JSON.stringify(batch, null, 1) + '\n\n' +
                    'Orphan pages (no inbound links): ' + JSON.stringify(orphanPages.map(p => p.url)) + '\n\n' +
                    'CRITICAL RULES:\n' +
                    '- The "suggested_anchor" MUST be an EXACT phrase (2-6 words) that appears verbatim in the source page text_excerpt. Copy it exactly.\n' +
                    '- Do NOT invent or rephrase anchor text. Only use words you can see in text_excerpt.\n' +
                    '- If you cannot find suitable anchor text in a page text_excerpt, skip that page.\n' +
                    '- Focus on linking related content together (topical relevance)\n' +
                    '- Prioritize orphan pages as targets — they need inbound links most\n' +
                    '- Do not suggest links that already exist (check outbound_targets)\n' +
                    '- Suggest 3-8 links per batch\n' +
                    '- Priority: high (orphan pages, cornerstone), medium (related topics), low (nice-to-have)\n\n' +
                    'Return ONLY valid JSON array:\n' +
                    '[{"source_url":"https://...","source_title":"Page title","target_url":"https://...","target_title":"Target page title","suggested_anchor":"exact phrase from text_excerpt","context_sentence":"The sentence containing the anchor","reason":"Why this helps SEO","priority":"high|medium|low"}]'
                }]
              });

              const aiText = aiResp.content[0]?.text || '[]';
              const jsonMatch = aiText.match(/\[[\s\S]*\]/);
              if (jsonMatch) {
                const parsed = JSON.parse(jsonMatch[0]);
                for (const s of parsed) {
                  if (s.source_url && s.target_url) {
                    suggestions.push(s);
                  }
                }
              }
            } catch (aiErr) {
              console.error('[internal-links] AI batch ' + (batchIdx + 1) + ' error: ' + aiErr.message);
            }
          }
          console.log('[internal-links] Total AI suggestions before validation: ' + suggestions.length);
        }

        // 7. Validate suggestions against the RENDERED page text (what the plugin's render-time injector acts on).
        //    This works on Elementor/page-builder sites too, because the rendered text contains the visible content —
        //    unlike WordPress post_content, which is empty on builder pages.
        await pool.query(`DELETE FROM internal_link_suggestions WHERE project_id=$1 AND status IN ('pending', 'dismissed', 'approved', 'failed')`, [projectId]);
        let validCount = 0, skippedCount = 0;

        for (const s of suggestions) {
          const anchor = (s.suggested_anchor || '').toLowerCase().trim();
          if (!anchor || anchor.length < 3) { skippedCount++; continue; }

          // Anchor must be PLACEABLE: present in the page's visible text AND have an unlinked occurrence the
          // injector can wrap (not already a link). This is what the render-time injector requires.
          const sourceData = pageMap.get((s.source_url || '').replace(/\/$/, ''));
          const renderedText = (sourceData?.fullText || '');
          const existingAnchors = (sourceData?.outbound || []).map(o => o.anchor_text);
          if (!anchorIsPlaceable(renderedText, anchor, existingAnchors)) {
            console.log('[internal-links] Skipped (not placeable): "' + s.suggested_anchor + '" on ' + s.source_url);
            skippedCount++;
            continue;
          }

          // Target must be a real page on the site, and not a self-link.
          const targetNorm = (s.target_url || '').replace(/\/$/, '');
          if (!pageMap.has(targetNorm) || targetNorm === (s.source_url || '').replace(/\/$/, '')) {
            console.log('[internal-links] Skipped: target ' + s.target_url + ' not a distinct crawled page');
            skippedCount++;
            continue;
          }

          await pool.query(`
            INSERT INTO internal_link_suggestions (project_id, source_url, source_title, target_url, target_title, suggested_anchor, context_sentence, reason, priority, status)
            VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, 'pending')
          `, [projectId, s.source_url, s.source_title || '', s.target_url, s.target_title || '', s.suggested_anchor || '', s.context_sentence || '', s.reason || '', s.priority || 'medium']);
          validCount++;
        }
        console.log('[internal-links] Suggestions: ' + validCount + ' valid, ' + skippedCount + ' skipped');

        // 8. Compute stats
        const stats = {
          total_pages: pageMap.size,
          total_internal_links: linkGraph.length,
          avg_outbound: pageMap.size ? (linkGraph.length / pageMap.size).toFixed(1) : 0,
          orphan_count: orphanPages.length,
          pages_with_few_links: pageStats.filter(p => p.outbound_count < 3 && !p.is_orphan).length,
          most_linked: [...pageMap.entries()]
            .map(([url, d]) => ({ url, title: d.title, inbound: d.inbound.length }))
            .sort((a, b) => b.inbound - a.inbound)
            .slice(0, 5),
          least_linked: [...pageMap.entries()]
            .map(([url, d]) => ({ url, title: d.title, inbound: d.inbound.length }))
            .sort((a, b) => a.inbound - b.inbound)
            .slice(0, 5),
          page_details: pageStats
        };

        // 9. Save audit record — report the count that ACTUALLY saved (validCount), not the pre-validation number,
        //    and record how many were dropped + why, so the UI can explain an empty list instead of lying.
        await pool.query(`
          INSERT INTO audits (project_id, pillar, status, audit_data, completed_at)
          VALUES ($1, 'internal_links', 'completed', $2, NOW())
        `, [projectId, JSON.stringify({ stats, orphan_pages: orphanPages, suggestions_count: validCount, suggestions_generated: suggestions.length, suggestions_skipped: skippedCount })]);

        // 10. Update cache
        await pool.query(`
          UPDATE internal_link_audit_cache
          SET status='completed', total_pages=$2, total_links=$3, orphan_pages=$4, stats=$5, suggestions_count=$6, audited_at=NOW(), updated_at=NOW()
          WHERE project_id=$1
        `, [projectId, pageMap.size, linkGraph.length, JSON.stringify(orphanPages), JSON.stringify(stats), validCount]);

        console.log(`[internal-links] Audit complete for project ${projectId}: ${pageMap.size} pages, ${linkGraph.length} links, ${orphanPages.length} orphans, ${validCount} saved (${suggestions.length} generated, ${skippedCount} skipped)`);

      } catch (bgErr) {
        console.error(`[internal-links] Background audit error: ${bgErr.message}`);
        await pool.query(`UPDATE internal_link_audit_cache SET status='error', error_message=$2, updated_at=NOW() WHERE project_id=$1`, [projectId, bgErr.message]);
      }
    })();

  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Get internal link audit status + results
app.get('/api/projects/:projectId/internal-links/audit', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const cache = await pool.query('SELECT * FROM internal_link_audit_cache WHERE project_id=$1', [projectId]);
    if (!cache.rows.length) return res.json({ status: 'idle', total_pages: 0, total_links: 0, orphan_pages: [], stats: {}, suggestions_count: 0 });
    const row = cache.rows[0];
    // Stale detection: if running for >5 minutes, auto-reset
    if (row.status === 'running' && row.updated_at) {
      const elapsed = Date.now() - new Date(row.updated_at).getTime();
      if (elapsed > 5 * 60 * 1000) {
        row.status = row.audited_at ? 'completed' : 'idle';
        await pool.query('UPDATE internal_link_audit_cache SET status=$2, updated_at=NOW() WHERE project_id=$1', [projectId, row.status]);
      }
    }
    res.json(row);
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Get link graph for a project
app.get('/api/projects/:projectId/internal-links/graph', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const links = await pool.query('SELECT * FROM internal_link_graph WHERE project_id=$1 ORDER BY source_url', [projectId]);
    res.json({ links: links.rows });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Get suggestions
app.get('/api/projects/:projectId/internal-links/suggestions', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  const status = req.query.status || 'pending';
  try {
    const q = status === 'all'
      ? await pool.query('SELECT * FROM internal_link_suggestions WHERE project_id=$1 ORDER BY priority DESC, created_at', [projectId])
      : await pool.query('SELECT * FROM internal_link_suggestions WHERE project_id=$1 AND status=$2 ORDER BY priority DESC, created_at', [projectId, status]);
    res.json({ suggestions: q.rows });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Approved links pull — the WordPress plugin fetches this and injects links at render time.
// No auth: contains no sensitive data (just internal anchor → target mappings) and the plugin needs open read.
app.get('/api/projects/:projectId/internal-links/approved', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const q = await pool.query(
      `SELECT source_url, target_url, target_title, suggested_anchor
         FROM internal_link_suggestions
        WHERE project_id=$1 AND status IN ('approved','applied','live')
        ORDER BY priority DESC, created_at`,
      [projectId]
    );
    // Group by source page so the plugin can match by current URL
    const byPage = {};
    for (const r of q.rows) {
      const src = (r.source_url || '').replace(/\/$/, '');
      if (!src) continue;
      (byPage[src] = byPage[src] || []).push({
        anchor: r.suggested_anchor,
        target: r.target_url,
        target_title: r.target_title || '',
      });
    }
    res.set('Cache-Control', 'public, max-age=300');
    res.json({ project_id: projectId, count: q.rows.length, links_by_page: byPage });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Plugin confirms which approved/queued links it actually placed on the live pages.
// No JWT (plugin reports outbound). Body: { confirmations: [{ source_url, target_url, live: true|false }] }
// live=true  -> status 'live'   (real link is on the page)
// live=false -> status 'failed' (anchor not present on the page, can't place)
app.post('/api/projects/:projectId/internal-links/confirm', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  const { confirmations } = req.body || {};
  if (!Array.isArray(confirmations)) return res.status(400).json({ error: 'confirmations array required' });
  try {
    let live = 0, failed = 0;
    for (const c of confirmations) {
      const src = (c.source_url || '').replace(/\/+$/, '');
      const tgt = (c.target_url || '').replace(/\/+$/, '');
      if (!src || !tgt) continue;
      if (c.live) {
        const r = await pool.query(
          `UPDATE internal_link_suggestions SET status='live'
             WHERE project_id=$1 AND rtrim(source_url,'/')=$2 AND rtrim(target_url,'/')=$3 AND status IN ('approved','applied','live')`,
          [projectId, src, tgt]);
        live += r.rowCount;
      } else {
        const r = await pool.query(
          `UPDATE internal_link_suggestions SET status='failed'
             WHERE project_id=$1 AND rtrim(source_url,'/')=$2 AND rtrim(target_url,'/')=$3 AND status IN ('approved','applied','live')`,
          [projectId, src, tgt]);
        failed += r.rowCount;
      }
    }
    res.json({ ok: true, live, failed });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Build Hubs — turn empty index/parent pages (e.g. /a-f, /services) into real hubs by injecting an
// in-content list of links to all their child pages (/a-f/*). Fixes orphaned model/area pages that are
// only linked from the nav menu. Reversible (plugin backs up the page).
app.post('/api/projects/:projectId/internal-links/build-hubs', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    if (!getWpAuthHeaders(project)) return res.status(400).json({ error: 'WordPress Application Password not configured in Project Settings.' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    const discovered = await discoverPages(`https://${domain}`, project.wordpress_url, getWpAuthHeaders(project));
    const pathOf = (u) => { try { return new URL(u).pathname.replace(/\/+$/, ''); } catch { return (u || '').replace(/\/+$/, ''); } };
    const slugTitle = (u) => { const seg = pathOf(u).split('/').pop() || ''; return seg.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()); };
    const pages = (discovered || []).map(d => ({ url: (d.url || '').replace(/\/+$/, ''), title: (d.title || '').trim() })).filter(p => p.url);

    // Index pages by their path; group children by parent path
    const byPath = new Map(pages.map(p => [pathOf(p.url), p]));
    const childrenByParent = {};
    for (const p of pages) {
      const pa = pathOf(p.url);
      const parent = pa.replace(/\/[^/]+$/, '');
      if (parent && parent !== pa) (childrenByParent[parent] = childrenByParent[parent] || []).push(p);
    }

    // Clean link label: page's own name only — drop any "Parent/" path prefix and " | brand" suffix.
    const label = (titleOrUrl, url) => { const t = (titleOrUrl || '').split('/').pop().replace(/\s*[\|\-–—].*$/, '').trim(); return t || slugTitle(url); };
    const rebuild = req.body && req.body.rebuild === true; // re-do existing hub blocks (e.g. to refresh labels)

    let built = 0; const results = [];
    for (const [parentPath, children] of Object.entries(childrenByParent)) {
      if (children.length < 3) continue;            // needs enough children to be a real hub
      const hub = byPath.get(parentPath);
      if (!hub) continue;                            // the parent must be an actual existing page
      const cleanName = label(hub.title, hub.url);
      const items = children
        .slice()
        .sort((a, b) => label(a.title, a.url).localeCompare(label(b.title, b.url)))
        .map(c => `<li><a href="${c.url}/">${label(c.title, c.url)}</a></li>`).join('');
      const intro = `Car Key Rescue provides fast, mobile car key replacement, cutting and programming across ${cleanName} and the wider Perth metro area. Whether you've lost your keys, need a spare, have a broken key, or you're locked out, our qualified technicians come directly to you with dealer-level equipment — without the dealer price. Choose the page that fits your situation below to learn more and get a free quote.`;
      const html = `<div class="seoroom-hub"><h2>Explore ${cleanName}</h2><p>${intro}</p><ul>${items}</ul></div>`;
      // Full clean page used only to RECOVER a page whose Elementor data is corrupt (replaces it).
      const fullHtml = `<h2>${cleanName}</h2><p>${intro}</p><div class="seoroom-hub"><ul>${items}</ul></div>`;
      try {
        if (rebuild) { try { await callPluginApi(project, '/restore-content-block', 'POST', { url: hub.url }); } catch (e) {} } // remove the old block first
        const r = await callPluginApi(project, '/insert-content-block', 'POST', { url: hub.url, html });
        if (r && r.ok && (r.inserted || r.already)) { built++; results.push({ hub: hub.url, children: children.length, already: !!r.already }); }
        else if (r && r.message && /parse/i.test(r.message)) {
          // The page's Elementor data is corrupted — recover it by writing a clean valid page (backs up current).
          try {
            const rb = await callPluginApi(project, '/rebuild-elementor', 'POST', { url: hub.url, html: fullHtml });
            if (rb && rb.ok) { built++; results.push({ hub: hub.url, children: children.length, rebuilt: true }); }
            else results.push({ hub: hub.url, error: (rb && rb.message) || 'rebuild failed' });
          } catch (e2) { results.push({ hub: hub.url, error: e2.message }); }
        }
        else results.push({ hub: hub.url, error: (r && r.message) || 'insert failed' });
      } catch (e) { results.push({ hub: hub.url, error: e.message }); }
    }

    try { const urls = results.filter(r => !r.error).map(r => r.hub); if (urls.length) await purgeCloudflareCache(project, urls.slice(0, 30)); } catch (e) {}
    res.json({ ok: true, built, hubs: results, message: built ? `${built} hub page(s) now link their child pages in body content.` : 'No hub pages found (need a parent page like /a-f with 3+ child pages).' });
  } catch (e) {
    console.error('[build-hubs] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Link Spokes — give each child page (model/suburb/service page) clean contextual links UP to its hub and
// ACROSS to the services page, completing the hub-and-spoke loop with descriptive anchors. Reversible.
app.post('/api/projects/:projectId/internal-links/link-spokes', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    if (!getWpAuthHeaders(project)) return res.status(400).json({ error: 'WordPress Application Password not configured in Project Settings.' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    const discovered = await discoverPages(`https://${domain}`, project.wordpress_url, getWpAuthHeaders(project));
    const pathOf = (u) => { try { return new URL(u).pathname.replace(/\/+$/, ''); } catch { return (u || '').replace(/\/+$/, ''); } };
    const slugTitle = (u) => { const seg = pathOf(u).split('/').pop() || ''; return seg.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()); };
    const pages = (discovered || []).map(d => ({ url: (d.url || '').replace(/\/+$/, ''), title: (d.title || '').trim() })).filter(p => p.url);
    const byPath = new Map(pages.map(p => [pathOf(p.url), p]));

    const servicesPage = byPath.get('/services') ? byPath.get('/services').url : `https://${domain}`;

    const childrenByParent = {};
    for (const p of pages) { const pa = pathOf(p.url); const parent = pa.replace(/\/[^/]+$/, ''); if (parent && parent !== pa) (childrenByParent[parent] = childrenByParent[parent] || []).push(p); }

    // Persisted "done" set so re-runs skip finished pages instantly (no plugin round-trip each time).
    const doneRow = await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='spoke_done'`, [projectId]);
    const doneSet = new Set((doneRow.rows[0]?.config?.urls) || []);

    const cap = parseInt(req.body && req.body.cap) || 25;
    let processed = 0, already = 0, remaining = 0; const errors = []; const purgeUrls = [];
    for (const [parentPath, children] of Object.entries(childrenByParent)) {
      if (children.length < 3) continue;
      const hub = byPath.get(parentPath);
      for (const child of children) {
        if (doneSet.has(child.url)) continue;                 // already handled in a previous run — skip, no call
        if (processed >= cap) { remaining++; continue; }
        const hubName = hub ? ((hub.title || slugTitle(hub.url)).replace(/\s*[\|\-–—].*$/, '').trim()) : '';
        const hubLink = hub ? `<a href="${hub.url}/">all ${hubName}</a>` : '';
        const block = `<div class="seoroom-spoke"><p>Looking for something else? ${hubLink ? ('Browse ' + hubLink + ', or see') : 'See'} our full range of <a href="${servicesPage}/">car key services</a>.</p></div>`;
        try {
          const r = await callPluginApi(project, '/insert-content-block', 'POST', { url: child.url, html: block, marker: 'seoroom-spoke' });
          if (r && r.ok) { doneSet.add(child.url); if (r.already) already++; else { processed++; purgeUrls.push(child.url); } }
          else errors.push(child.url);
        } catch (e) { errors.push(child.url); }
      }
    }
    // Save the done set
    try { await pool.query(`INSERT INTO project_integrations (project_id, kind, config) VALUES ($1,'spoke_done',$2) ON CONFLICT (project_id, kind) DO UPDATE SET config=$2`, [projectId, JSON.stringify({ urls: [...doneSet] })]); } catch (e) {}
    try { if (purgeUrls.length) await purgeCloudflareCache(project, purgeUrls.slice(0, 30)); } catch (e) {}
    res.json({ ok: true, processed, already, remaining, errors: errors.length, message: `${processed} spoke page(s) linked to their hub + services${remaining ? `; ${remaining} remaining — click again to continue` : ''}.${already ? ` ${already} already done.` : ''}` });
  } catch (e) {
    console.error('[link-spokes] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Link Remaining Orphans — for each leftover orphan, find its most relevant existing (non-orphan) page by
// distinctive keyword overlap (brand/model/suburb), and append a "Related pages" link block there. This
// gives the hard-to-reach orphans (top-level model+suburb pages) a genuine inbound link. Reversible.
app.post('/api/projects/:projectId/internal-links/link-remaining-orphans', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    if (!getWpAuthHeaders(project)) return res.status(400).json({ error: 'WordPress Application Password not configured.' });

    const cache = await pool.query(`SELECT orphan_pages FROM internal_link_audit_cache WHERE project_id=$1`, [projectId]);
    const orphanList = (cache.rows[0]?.orphan_pages) || [];
    if (!orphanList.length) return res.json({ ok: true, linked: 0, message: 'No orphans — run the audit first.' });

    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    const discovered = await discoverPages(`https://${domain}`, project.wordpress_url, getWpAuthHeaders(project));
    const norm = u => (u || '').replace(/\/+$/, '');
    const pathOf = (u) => { try { return new URL(u).pathname.replace(/\/+$/, ''); } catch { return (u || '').replace(/\/+$/, ''); } };
    const slugTitle = (u) => { const seg = pathOf(u).split('/').pop() || ''; return seg.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()); };
    const cleanLabel = (t, u) => { const x = (t || '').split('/').pop().replace(/\s*[\|\-–—].*$/, '').trim(); return x || slugTitle(u); };
    const pages = (discovered || []).map(d => ({ url: norm(d.url), title: (d.title || '').trim() })).filter(p => p.url);

    const orphanSet = new Set(orphanList.map(o => norm(o.url)));
    const STOP = new Set(['car','key','keys','replacement','replacements','perth','the','of','and','in','a','to','for','services','service','repair','repairs','programming','spares','from','lost','mobile','locksmith','rescue','your','our','professional','automotive','vehicle','best','need','how','what','guide','tips']);
    const distinctive = (title) => new Set((title || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length > 3 && !STOP.has(w)));

    // Candidate targets = pages that are NOT orphans (they already have authority to pass down)
    const targets = pages.filter(p => !orphanSet.has(p.url)).map(p => ({ ...p, words: distinctive(p.title) }));

    // Match each orphan to the best target by shared distinctive words
    const byTarget = {};
    let unmatched = 0;
    for (const orphan of orphanList) {
      const ow = distinctive(orphan.title);
      if (!ow.size) { unmatched++; continue; }
      let best = null, bestScore = 0;
      for (const t of targets) {
        if (t.url === norm(orphan.url)) continue;
        let s = 0; for (const w of ow) if (t.words.has(w)) s++;
        if (s > bestScore) { bestScore = s; best = t; }
      }
      if (best && bestScore >= 1) { (byTarget[best.url] = byTarget[best.url] || { target: best, orphans: [] }).orphans.push(orphan); }
      else unmatched++;
    }

    let linked = 0; const purgeUrls = []; const results = [];
    for (const key of Object.keys(byTarget)) {
      const { target, orphans } = byTarget[key];
      const items = orphans.slice(0, 10).map(o => `<li><a href="${norm(o.url)}/">${cleanLabel(o.title, o.url)}</a></li>`).join('');
      const html = `<div class="seoroom-related"><h3>Related car key services</h3><ul>${items}</ul></div>`;
      try {
        const r = await callPluginApi(project, '/insert-content-block', 'POST', { url: target.url, html, marker: 'seoroom-related' });
        if (r && r.ok && (r.inserted || r.already)) { linked += orphans.length; purgeUrls.push(target.url); results.push({ target: target.url, orphans: orphans.length }); }
        else results.push({ target: target.url, error: (r && r.message) || 'insert failed' });
      } catch (e) { results.push({ target: target.url, error: e.message }); }
    }
    try { if (purgeUrls.length) await purgeCloudflareCache(project, purgeUrls.slice(0, 30)); } catch (e) {}
    res.json({ ok: true, linked, unmatched, targets: results.length, message: `Linked ${linked} orphan(s) from ${results.length} relevant page(s).${unmatched ? ` ${unmatched} had no relevant page to link from.` : ''} Re-run the audit to confirm.` });
  } catch (e) {
    console.error('[link-remaining-orphans] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Clean Anchors — dismiss pending suggestions where one anchor is reused across 3+ different target pages
// (keeps the 2 best by priority). Stops the "same generic anchor to 15 pages" pattern.
app.post('/api/projects/:projectId/internal-links/clean-anchors', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const rows = (await pool.query(`SELECT id, suggested_anchor, target_url, priority FROM internal_link_suggestions WHERE project_id=$1 AND status='pending'`, [projectId])).rows;
    const norm = a => (a || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').replace(/\s+/g, ' ').trim();
    const byAnchor = {};
    for (const r of rows) { const a = norm(r.suggested_anchor); if (!a) continue; (byAnchor[a] = byAnchor[a] || []).push(r); }
    const prio = { high: 0, medium: 1, low: 2 };
    let dismissed = 0;
    for (const a of Object.keys(byAnchor)) {
      const group = byAnchor[a];
      const distinct = new Set(group.map(g => (g.target_url || '').replace(/\/+$/, '')));
      if (distinct.size >= 3) {
        group.sort((x, y) => (prio[x.priority] ?? 1) - (prio[y.priority] ?? 1));
        const keep = new Set(group.slice(0, 2).map(g => g.id));
        for (const g of group) if (!keep.has(g.id)) { await pool.query(`UPDATE internal_link_suggestions SET status='dismissed' WHERE id=$1`, [g.id]); dismissed++; }
      }
    }
    res.json({ ok: true, dismissed, message: `${dismissed} suggestion(s) dismissed — they reused one generic anchor across many different pages.` });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Insert Permanently — write approved/applied links INTO the page content via the plugin (survives all
// caching). Marks inserted links 'live', records rollback history, purges caches.
app.post('/api/projects/:projectId/internal-links/insert-permanent', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    if (!getWpAuthHeaders(project)) return res.status(400).json({ error: 'WordPress Application Password not configured in Project Settings.' });

    const ids = Array.isArray(req.body?.suggestion_ids) ? req.body.suggestion_ids : null;
    const includePending = req.body?.include_pending === true;
    const statusFilter = includePending ? `('pending','approved','applied','live')` : `('approved','applied','live')`;
    const rows = (await pool.query(
      ids && ids.length
        ? `SELECT id, source_url, target_url, target_title, suggested_anchor FROM internal_link_suggestions WHERE project_id=$1 AND id=ANY($2) AND status IN ('pending','approved','applied','live')`
        : `SELECT id, source_url, target_url, target_title, suggested_anchor FROM internal_link_suggestions WHERE project_id=$1 AND status IN ${statusFilter}`,
      ids && ids.length ? [projectId, ids] : [projectId])).rows;
    if (!rows.length) return res.json({ ok: true, inserted: 0, failed: 0, message: 'No approved links to insert.' });

    // Group by source page
    const byPage = {};
    for (const r of rows) { const s = (r.source_url || '').replace(/\/+$/, ''); if (s) (byPage[s] = byPage[s] || []).push(r); }

    let inserted = 0, failed = 0; const purgeUrls = [];
    for (const src of Object.keys(byPage)) {
      const linkList = byPage[src].map(r => ({ anchor: r.suggested_anchor, target: r.target_url }));
      let result = null;
      try {
        result = await callPluginApi(project, '/insert-links', 'POST', { url: src, links: linkList });
      } catch (e) {
        console.log('[insert-permanent] plugin call failed for', src, e.message);
        for (const r of byPage[src]) { await pool.query(`UPDATE internal_link_suggestions SET status='failed' WHERE id=$1`, [r.id]); failed++; }
        continue;
      }
      const okSet = new Set((result && result.inserted || []).map(a => (a || '').toLowerCase().trim()));
      for (const r of byPage[src]) {
        const a = (r.suggested_anchor || '').toLowerCase().trim();
        if (okSet.has(a)) {
          await pool.query(`UPDATE internal_link_suggestions SET status='live' WHERE id=$1`, [r.id]);
          inserted++;
          // Rollback history
          try {
            await pool.query(
              `INSERT INTO wp_change_history (project_id, page_id, page_url, page_title, change_type, field_name, original_value, new_value)
               VALUES ($1,$2,$3,$4,'internal_link','post_content', $5, $6)`,
              [projectId, result.page_id || 0, src, '', '[no link]', `<a href="${r.target_url}">${r.suggested_anchor}</a>`]
            );
          } catch (e) {}
        } else { await pool.query(`UPDATE internal_link_suggestions SET status='failed' WHERE id=$1`, [r.id]); failed++; }
      }
      purgeUrls.push(src);
    }

    // Purge edge cache for the modified pages
    try { if (purgeUrls.length) await purgeCloudflareCache(project, purgeUrls.slice(0, 30)); } catch (e) {}

    res.json({ ok: true, inserted, failed, message: `${inserted} link(s) written into page content (permanent), ${failed} could not be placed.` });
  } catch (e) {
    console.error('[insert-permanent] error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Fix Failed Anchors — for each FAILED link, fetch the source page and re-anchor to a phrase that
// actually exists in the page body (derived from the target's title), so the injector can place it.
app.post('/api/projects/:projectId/internal-links/reanchor-failed', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const rows = (await pool.query(
      `SELECT id, source_url, target_url, target_title, suggested_anchor FROM internal_link_suggestions
        WHERE project_id=$1 AND status='failed'`, [projectId])).rows;
    if (!rows.length) return res.json({ ok: true, reanchored: 0, skipped: 0, message: 'No failed links to fix.' });

    const STOP = new Set(['the','and','for','with','your','you','our','are','was','will','how','does','what','when','from','this','that','into','out','can','perth','services','service','guide','tips','need','know','about','your','have','get','a','an','in','on','of','to','is','it','do','my','at','be','or','as','if']);
    // Build candidate anchor phrases from a target title: longest meaningful n-grams first, then key words
    const candidates = (title) => {
      const words = (title || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(Boolean);
      const out = [];
      for (let n = 4; n >= 2; n--) for (let i = 0; i + n <= words.length; i++) {
        const g = words.slice(i, i + n);
        if (g.filter(w => !STOP.has(w) && w.length > 3).length >= 1) out.push(g.join(' '));
      }
      for (const w of words) if (!STOP.has(w) && w.length > 4) out.push(w);
      return [...new Set(out)];
    };

    const byPage = {};
    for (const r of rows) { const s = (r.source_url || '').replace(/\/+$/, ''); if (s) (byPage[s] = byPage[s] || []).push(r); }

    let reanchored = 0, skipped = 0;
    const pages = Object.keys(byPage);
    for (let b = 0; b < pages.length; b += 5) {
      const batch = pages.slice(b, b + 5);
      await Promise.all(batch.map(async (src) => {
        let html = '';
        try {
          const bust = (src.includes('?') ? '&' : '?') + 'seoroom_verify=' + Date.now();
          const resp = await fetch(src + bust, { headers: { 'User-Agent': 'SEORoomBot/1.0', 'Cache-Control': 'no-cache, no-store, max-age=0', 'Pragma': 'no-cache' }, signal: AbortSignal.timeout(20000) });
          if (resp.ok) html = await resp.text();
        } catch (e) {}
        if (!html) { skipped += byPage[src].length; return; }
        // Body text only — strip scripts/styles, headings and existing links (we won't anchor inside those)
        const body = html
          .replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ')
          .replace(/<h[1-6][\s\S]*?<\/h[1-6]>/gi, ' ').replace(/<a\b[\s\S]*?<\/a>/gi, ' ');
        const text = body.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').toLowerCase();
        for (const link of byPage[src]) {
          const cands = [(link.suggested_anchor || '').toLowerCase(), ...candidates(link.target_title)];
          let pick = null;
          for (const c of cands) { if (c && c.length >= 4 && text.includes(c)) { pick = c; break; } }
          if (pick) {
            await pool.query(`UPDATE internal_link_suggestions SET suggested_anchor=$1, status='approved' WHERE id=$2`, [pick, link.id]);
            reanchored++;
          } else { skipped++; }
        }
      }));
    }
    res.json({ ok: true, reanchored, skipped, message: `${reanchored} re-anchored to on-page phrases, ${skipped} had no usable phrase. Open SEO Room → Settings on the site (refreshes the plugin), then click Verify Now.` });
  } catch (e) {
    console.error('[internal-links] reanchor error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Verify Now — the dashboard fetches each source page (cache-busted) and checks whether the internal
// link to the target is actually present, then flips status to 'live' or 'failed'. Independent of the
// plugin's hourly WP-cron, so the user doesn't have to wait.
app.post('/api/projects/:projectId/internal-links/verify', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const rows = (await pool.query(
      `SELECT id, source_url, target_url FROM internal_link_suggestions
        WHERE project_id=$1 AND status IN ('approved','applied','live')`, [projectId]
    )).rows;
    if (!rows.length) return res.json({ ok: true, live: 0, failed: 0, checked: 0, message: 'No applied links to verify.' });

    // Purge Cloudflare first so the fetch sees the freshly-injected version
    try {
      const proj = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
      const srcUrls = [...new Set(rows.map(r => (r.source_url || '').replace(/\/+$/, '')))].filter(Boolean);
      if (proj && srcUrls.length) await purgeCloudflareCache(proj, srcUrls.slice(0, 30));
    } catch (e) {}

    // Group by source page
    const byPage = {};
    for (const r of rows) {
      const src = (r.source_url || '').replace(/\/+$/, '');
      if (!src) continue;
      (byPage[src] = byPage[src] || []).push(r);
    }

    let live = 0, failed = 0, checked = 0;
    const pages = Object.keys(byPage);
    // Fetch pages in small parallel batches
    for (let b = 0; b < pages.length; b += 5) {
      const batch = pages.slice(b, b + 5);
      await Promise.all(batch.map(async (src) => {
        let html = '';
        try {
          const bust = (src.includes('?') ? '&' : '?') + 'seoroom_verify=' + Date.now();
          const resp = await fetch(src + bust, {
            headers: { 'User-Agent': 'SEORoomBot/1.0', 'Cache-Control': 'no-cache, no-store, max-age=0', 'Pragma': 'no-cache' },
            signal: AbortSignal.timeout(20000)
          });
          if (resp.ok) html = await resp.text();
        } catch (e) {}
        // Collect all hrefs on the page → normalized path set
        const hrefs = [...html.matchAll(/<a\s[^>]*href=["']([^"']+)["']/gi)].map(m => m[1]);
        const paths = new Set(hrefs.map(h => { try { return new URL(h, src).pathname.replace(/\/+$/, ''); } catch { return (h || '').replace(/\/+$/, ''); } }));
        for (const link of byPage[src]) {
          checked++;
          let tpath = '';
          try { tpath = new URL(link.target_url).pathname.replace(/\/+$/, ''); } catch { tpath = (link.target_url || '').replace(/^https?:\/\/[^/]+/, '').replace(/\/+$/, ''); }
          const found = !!html && tpath && paths.has(tpath);
          if (found) { await pool.query(`UPDATE internal_link_suggestions SET status='live' WHERE id=$1`, [link.id]); live++; }
          else { await pool.query(`UPDATE internal_link_suggestions SET status='failed' WHERE id=$1`, [link.id]); failed++; }
        }
      }));
    }
    res.json({ ok: true, live, failed, checked, message: `${live} live, ${failed} not found, ${checked} checked.` });
  } catch (e) {
    console.error('[internal-links] verify error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Orphan rescue — give EVERY orphan page at least one contextual inbound link.
// Heuristic (no AI cost): for each orphan, find a page whose rendered text already contains a phrase
// matching the orphan's topic, and create a suggestion linking that phrase to the orphan. Anchor is
// guaranteed to exist on the source page (so the render-time injector can place it). Scales to hundreds.
app.post('/api/projects/:projectId/internal-links/rescue-orphans', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const cache = await pool.query(`SELECT orphan_pages FROM internal_link_audit_cache WHERE project_id=$1`, [projectId]);
    const orphanList = (cache.rows[0]?.orphan_pages) || [];
    if (!orphanList.length) return res.json({ ok: true, created: 0, message: 'No orphan pages — run the audit first.' });

    const norm = s => (s || '').replace(/\/$/, '');
    const domain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    const orphanUrlSet = new Set(orphanList.map(o => norm(o.url)));

    // Source pages = where we can place an inbound link. Prefer plugin-pushed content; if none, fetch the
    // site's pages LIVE (cache-busted) so this works without "Push Data Now".
    let sources = [];
    const cc = await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='connector_cache'`, [projectId]);
    const pushed = ((cc.rows[0]?.config?.pages) || []).filter(p => p.text && p.text.length > 50);
    if (pushed.length) {
      sources = pushed.map(p => ({ url: norm(p.url), title: p.title || '', text: (p.text || '').toLowerCase() }));
    } else {
      let urls = [];
      try {
        const authHeaders = getWpAuthHeaders(project);
        const discovered = await discoverPages(`https://${domain}`, project.wordpress_url, authHeaders);
        urls = (discovered || []).map(d => norm(d.url)).filter(Boolean);
      } catch (e) {}
      // Prefer non-orphan "hub" pages as link sources, then fall back to any page; cap to 30 fetches.
      const nonOrphans = urls.filter(u => !orphanUrlSet.has(u));
      const fetchList = [...new Set([`https://${domain}`, ...nonOrphans, ...urls])].slice(0, 30);
      for (let i = 0; i < fetchList.length; i += 8) {
        const batch = fetchList.slice(i, i + 8);
        await Promise.all(batch.map(async (u) => {
          try {
            const bust = (u.includes('?') ? '&' : '?') + 'seoroom_verify=' + Date.now();
            const r = await fetch(u + bust, { headers: { 'User-Agent': 'SEORoomBot/1.0', 'Cache-Control': 'no-cache, no-store, max-age=0', 'Pragma': 'no-cache' }, signal: AbortSignal.timeout(12000) });
            if (!r.ok) return;
            const h = await r.text();
            const body = h.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ')
              .replace(/<nav[\s\S]*?<\/nav>/gi, ' ').replace(/<header[\s\S]*?<\/header>/gi, ' ').replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
              .replace(/<a\b[\s\S]*?<\/a>/gi, ' ');
            const text = body.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').toLowerCase();
            if (text.length > 50) sources.push({ url: norm(u), title: '', text });
          } catch (e) {}
        }));
      }
    }
    if (!sources.length) return res.json({ ok: true, created: 0, message: 'Could not read any page content (the site may be blocking requests). Try again, or use Build Clusters instead.' });

    // Anchors must be distinctive — skip ultra-generic phrases that appear on every page.
    const GENERIC = new Set(['car key', 'car keys', 'key replacement', 'car key replacement', 'replacement', 'services', 'service', 'repair', 'repairs', 'perth', 'locksmith', 'mobile locksmith']);
    // Clear previous orphan-rescue suggestions that are still pending (so re-runs don't duplicate)
    await pool.query(`DELETE FROM internal_link_suggestions WHERE project_id=$1 AND status='pending' AND reason LIKE 'Orphan rescue%'`, [projectId]);

    let created = 0;
    const usedPerSource = {};
    const usedAnchor = {}; // anchor -> how many targets already use it (cap at 2 for diversity)
    for (const orphan of orphanList) {
      const ourl = norm(orphan.url);
      const cleanTitle = (orphan.title || '').replace(/\s*[\|\-–—].*$/, '').trim();
      const words = cleanTitle.toLowerCase().split(/\s+/).filter(w => w.length > 2);
      const candidates = [];
      if (cleanTitle.length >= 8 && !GENERIC.has(cleanTitle.toLowerCase())) candidates.push(cleanTitle.toLowerCase());
      for (let n = 4; n >= 2; n--) for (let i = 0; i + n <= words.length; i++) {
        const ph = words.slice(i, i + n).join(' ');
        if (ph.length >= 8 && !GENERIC.has(ph)) candidates.push(ph);
      }
      // Distinctive single words (suburb/model names like "armadale", "mitsubishi") — last resort
      for (const w of words) if (w.length >= 6 && !GENERIC.has(w)) candidates.push(w);
      const uniq = [...new Set(candidates)].sort((a, b) => b.length - a.length);

      let best = null;
      for (const cand of uniq) {
        if ((usedAnchor[cand] || 0) >= 2) continue; // diversity: don't reuse one anchor for 3+ targets
        for (const src of sources) {
          if (src.url === ourl) continue;
          if ((usedPerSource[src.url] || 0) >= 5) continue;
          if (src.text.includes(cand)) { best = { src, anchor: cand }; break; }
        }
        if (best) break;
      }
      if (!best) continue;
      usedAnchor[best.anchor] = (usedAnchor[best.anchor] || 0) + 1;
      await pool.query(`
        INSERT INTO internal_link_suggestions (project_id, source_url, source_title, target_url, target_title, suggested_anchor, context_sentence, reason, priority, status)
        VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,'pending')
      `, [projectId, best.src.url, best.src.title, orphan.url, orphan.title || '', best.anchor, '', 'Orphan rescue — gives this page an inbound internal link', 'high']);
      usedPerSource[best.src.url] = (usedPerSource[best.src.url] || 0) + 1;
      created++;
    }
    res.json({ ok: true, created, orphans: orphanList.length, message: `${created} orphan-rescue links created (of ${orphanList.length} orphans). Review and approve them in Suggestions.` });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

// Find an anchor for a link: a phrase from the target page's title that already exists in the source page's text.
// An anchor is "placeable" by the render-time injector only if it appears in the page's visible text AND
// has at least one occurrence that ISN'T already a link (so we never double-link or invent text).
function anchorIsPlaceable(text, anchor, existingAnchors) {
  const a = (anchor || '').toLowerCase().trim();
  const t = (text || '').toLowerCase();
  if (!a || a.length < 3 || !t.includes(a)) return false;
  let tc = 0, i = 0; while ((i = t.indexOf(a, i)) !== -1) { tc++; i += a.length; }
  const lc = (existingAnchors || []).filter(la => (la || '').toLowerCase().includes(a)).length;
  return tc > lc;
}

function sropt_findClusterAnchor(targetTitle, sourceTextLower) {
  const cleanTitle = (targetTitle || '').replace(/\s*[\|\-–—].*$/, '').trim();
  const words = cleanTitle.toLowerCase().split(/\s+/).filter(w => w.length > 2);
  const candidates = [];
  if (cleanTitle.length >= 6) candidates.push(cleanTitle.toLowerCase());
  for (let n = 4; n >= 2; n--) for (let i = 0; i + n <= words.length; i++) {
    const ph = words.slice(i, i + n).join(' ');
    if (ph.length >= 6) candidates.push(ph);
  }
  const uniq = [...new Set(candidates)].sort((a, b) => b.length - a.length);
  for (const c of uniq) if (sourceTextLower.includes(c)) return c;
  return null;
}

// Build topic clusters — AI groups pages into clusters (pillar service page + supporting spokes), then
// generate bidirectional pillar<->spoke internal links. Anchors are grounded in real page text, so the
// plugin's render-time injector can place them. This builds the hub-and-spoke structure that moves rankings.
app.post('/api/projects/:projectId/internal-links/build-clusters', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  if (!anthropic) return res.status(503).json({ error: 'ANTHROPIC_API_KEY not configured' });
  try {
    const cc = await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='connector_cache'`, [projectId]);
    const allPages = ((cc.rows[0]?.config?.pages) || []).filter(p => p.url && p.title);
    if (allPages.length < 4) return res.json({ ok: true, created: 0, message: 'Not enough page content — run Push Data Now on the site, then re-run the audit.' });

    const norm = s => (s || '').replace(/\/$/, '');
    const byUrl = {};
    for (const p of allPages) byUrl[norm(p.url)] = { url: norm(p.url), title: p.title, text: (p.text || '').toLowerCase(), linkAnchors: (p.links || []).map(l => (l.anchor || '').toLowerCase()) };

    // 1. AI clustering (one call) — titles + urls only
    const dir = allPages.slice(0, 220).map(p => ({ url: norm(p.url), title: p.title }));
    const aiResp = await anthropic.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 6000,
      messages: [{ role: 'user', content:
        'Group these website pages into SEO topic clusters. For each cluster pick ONE pillar (the main service/category page) and list its spoke pages (supporting articles, variants, sub-services that belong to that topic). Only group genuinely related pages; leave unrelated pages out. Use the EXACT urls given.\n\n' +
        'PAGES:\n' + JSON.stringify(dir) + '\n\n' +
        'Return ONLY JSON: {"clusters":[{"pillar":"https://...","spokes":["https://...","https://..."]}]}'
      }]
    });
    let clusters = [];
    try {
      const m = (aiResp.content[0]?.text || '').match(/\{[\s\S]*\}/);
      clusters = m ? (JSON.parse(m[0]).clusters || []) : [];
    } catch (e) { return res.status(500).json({ error: 'Could not parse AI clustering response' }); }

    // 2. Generate bidirectional links per cluster, anchor-grounded
    await pool.query(`DELETE FROM internal_link_suggestions WHERE project_id=$1 AND status IN ('pending','failed') AND reason LIKE 'Topic cluster%'`, [projectId]);
    let created = 0, clustersUsed = 0;
    for (const cl of clusters) {
      const pillar = byUrl[norm(cl.pillar)];
      const spokes = (cl.spokes || []).map(s => byUrl[norm(s)]).filter(Boolean).filter(s => s.url !== pillar?.url);
      if (!pillar || spokes.length === 0) continue;
      clustersUsed++;
      let pillarOut = 0;
      for (const spoke of spokes) {
        // spoke -> pillar (anchor about the pillar topic, found UNLINKED in the spoke's text)
        const upAnchor = sropt_findClusterAnchor(pillar.title, spoke.text);
        if (upAnchor && anchorIsPlaceable(spoke.text, upAnchor, spoke.linkAnchors)) {
          await pool.query(`INSERT INTO internal_link_suggestions (project_id, source_url, source_title, target_url, target_title, suggested_anchor, context_sentence, reason, priority, status) VALUES ($1,$2,$3,$4,$5,$6,'','Topic cluster — spoke links up to pillar','high','pending')`,
            [projectId, spoke.url, spoke.title, pillar.url, pillar.title, upAnchor]);
          created++;
        }
        // pillar -> spoke (cap to keep the pillar clean)
        if (pillarOut < 10) {
          const downAnchor = sropt_findClusterAnchor(spoke.title, pillar.text);
          if (downAnchor && anchorIsPlaceable(pillar.text, downAnchor, pillar.linkAnchors)) {
            await pool.query(`INSERT INTO internal_link_suggestions (project_id, source_url, source_title, target_url, target_title, suggested_anchor, context_sentence, reason, priority, status) VALUES ($1,$2,$3,$4,$5,$6,'','Topic cluster — pillar links down to spoke','medium','pending')`,
              [projectId, pillar.url, pillar.title, spoke.url, spoke.title, downAnchor]);
            created++; pillarOut++;
          }
        }
      }
    }
    res.json({ ok: true, created, clusters: clustersUsed, message: `${created} cluster links created across ${clustersUsed} topic clusters. Review and approve them in Suggestions.` });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

