// Backlink gap analysis
app.post('/api/projects/:projectId/backlinks/gap', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    const proj = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!proj) return res.status(404).json({ error: 'Project not found' });
    if (!DATAFORSEO_AUTH) return res.status(503).json({ error: 'DataForSEO not configured' });

    const domain = (proj.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    // Use provided/settings competitors, but only entries that look like domains (gap needs domains, not names).
    const provided = req.body.competitors || proj.competitors || [];
    let cleanCompetitors = provided
      .map(c => (c || '').replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/+$/, ''))
      .filter(c => /\./.test(c)).slice(0, 5);

    // If none usable, auto-discover — preferring organic SERP competitors (who we compete with in search,
    // and whose backlinks are the most relevant to win) over Maps local-pack competitors.
    let autoDiscovered = false;
    if (!cleanCompetitors.length) {
      const found = await discoverCompetitorDomains(projectId, proj, true, true);
      cleanCompetitors = found.slice(0, 5).map(c => c.domain);
      autoDiscovered = cleanCompetitors.length > 0;
    }
    if (!cleanCompetitors.length) {
      return res.status(400).json({ error: 'No competitor domains found. Run a Maps grid scan (or Players Handshake), or add competitor domains in project settings.' });
    }
    console.log(`[backlinks] Gap analysis: ${domain} vs ${cleanCompetitors.join(', ')}${autoDiscovered ? ' (auto-discovered)' : ''}`);

    const gapResult = await dataForSeoBacklinkGap(domain, cleanCompetitors, {
      intersection_mode: req.body.intersection_mode,
      exclude: req.body.exclude,
    });
    console.log(`[backlinks] Gap debug:`, JSON.stringify(gapResult.debug));

    // Enrich each opportunity with a composite score and a link-type classification, then sort best-first.
    gapResult.opportunities = (gapResult.opportunities || [])
      .map(o => {
        const dir = directoryInfo(o.domain);
        const junk = !dir && isJunkBacklinkDomain(o.domain);
        let score = scoreOpportunity(o.rank, o.competitors_count);
        if (junk) score = Math.round(score * 0.1); // bury SEO-tool/spam junk
        let type;
        if (dir) type = 'directory';            // verified directory (has pricing/difficulty)
        else if (junk) type = 'spam';
        else { type = classifyLinkType(o.domain); if (type === 'directory') type = 'resource'; } // only verified dirs get 'directory'
        return {
          ...o,
          link_type: type,
          is_spam: type === 'spam',
          score,
          directory: dir, // {name, free, price, difficulty, url} or null
        };
      })
      // Real opportunities first (junk buried), then best score (authority-led), then most competitors.
      .sort((a, b) => (a.is_spam - b.is_spam) || (b.score - a.score) || (b.competitors_count - a.competitors_count));

    // Persist the full enriched result so it survives navigation/reload (single cache row).
    const gapPayload = {
      domain, competitors: cleanCompetitors, auto_discovered: autoDiscovered,
      total: gapResult.total, opportunities: gapResult.opportunities, scanned_at: new Date().toISOString()
    };
    try {
      await pool.query(
        `INSERT INTO project_integrations (project_id, kind, config) VALUES ($1,'backlink_gap_cache',$2)
         ON CONFLICT (project_id, kind) DO UPDATE SET config=$2`,
        [projectId, JSON.stringify(gapPayload)]
      );
    } catch (e) {}

    // Log cost
    try {
      await pool.query('INSERT INTO api_costs (project_id, feature, provider, api_calls, cost, details) VALUES ($1, $2, $3, $4, $5, $6)',
        [projectId, 'backlink_gap', 'dataforseo', 1, gapResult.cost || 0, JSON.stringify({ domain, competitors: cleanCompetitors })]);
    } catch (e) { /* optional */ }

    res.json({
      domain,
      competitors: cleanCompetitors,
      auto_discovered: autoDiscovered,
      opportunities: gapResult.opportunities,
      total: gapResult.total,
      cost: gapResult.cost,
      debug: gapResult.debug
    });
  } catch (e) {
    console.error('[backlinks] Gap error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

