// AI analyser for one gap keyword: crawls the competitors' ranking pages and explains why they rank +
// a concrete plan to compete. Cached per keyword so re-opening is instant and free.
app.post('/api/projects/:projectId/serp-gap/analyze', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  const { keyword, competitors } = req.body || {};
  try {
    if (!anthropic) return res.status(503).json({ error: 'AI not configured (ANTHROPIC_API_KEY missing).' });
    if (!keyword) return res.status(400).json({ error: 'keyword required' });
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });

    // Return cached analysis if present.
    const cacheRow = (await pool.query(`SELECT config FROM project_integrations WHERE project_id=$1 AND kind='serp_gap_analysis'`, [projectId])).rows[0];
    const cache = cacheRow?.config?.map || {};
    if (cache[keyword.toLowerCase()] && !req.body.force) return res.json({ ...cache[keyword.toLowerCase()], cached: true });

    const bizDomain = (project.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    const industry = project.industry || 'local business';
    const location = project.location || '';

    // Crawl up to 3 competitor ranking pages for real signals.
    const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36';
    const pages = [];
    for (const c of (competitors || []).slice(0, 3)) {
      if (!c.url) continue;
      try {
        const resp = await fetch(c.url, { headers: { 'User-Agent': UA }, signal: AbortSignal.timeout(10000) });
        if (!resp.ok) { pages.push({ domain: c.domain, position: c.position, error: 'HTTP ' + resp.status }); continue; }
        const html = await resp.text();
        const grab = (tag) => { const m = html.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>', 'i')); return m ? m[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 180) : ''; };
        const h2s = [...html.matchAll(/<h2[^>]*>([\s\S]*?)<\/h2>/gi)].map(m => m[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim()).filter(Boolean).slice(0, 14);
        const text = html.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
        pages.push({ domain: c.domain, position: c.position, title: grab('title'), h1: grab('h1'), h2s, wordCount: text.split(/\s+/).length });
      } catch (e) { pages.push({ domain: c.domain, position: c.position, error: e.message }); }
    }

    const pagesText = pages.map(p => p.error
      ? `${p.domain} (#${p.position}): [page not fetchable: ${p.error}]`
      : `${p.domain} (#${p.position}): title="${p.title}" | H1="${p.h1}" | ~${p.wordCount} words | H2s: ${(p.h2s || []).join(' | ')}`
    ).join('\n') || '(competitor page content unavailable — base your plan on the keyword and intent)';

    const prompt = `You are a senior SEO strategist. The client ${bizDomain} (a ${industry}${location ? ' in ' + location : ''}) does NOT rank for "${keyword}", but these competitors do:

${pagesText}

Explain why the competitors rank and give a specific, practical plan for the client to compete and outrank them for "${keyword}". Tailor everything to this exact keyword and a local ${industry}. Return STRICT JSON only:
{
  "intent": "what the searcher actually wants (one sentence)",
  "why_they_rank": ["3-4 concrete reasons grounded in the competitor pages above"],
  "how_to_compete": {
    "page_type": "e.g. dedicated service page | in-depth guide | comparison page",
    "target_word_count": number,
    "recommended_headings": ["5-8 H2 headings for the client's page"],
    "must_cover": ["4-6 specific points/topics to include"],
    "angle": "the differentiator the client should lead with to stand out"
  },
  "difficulty": "Easy|Medium|Hard",
  "quick_win": "the single highest-leverage first action"
}`;

    const msg = await anthropic.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 1300, messages: [{ role: 'user', content: prompt }] });
    let txt = (msg.content?.[0]?.text || '').trim();
    const s = txt.indexOf('{'), e = txt.lastIndexOf('}'); if (s >= 0 && e > s) txt = txt.slice(s, e + 1);
    let analysis; try { analysis = JSON.parse(txt); } catch { analysis = { raw: txt }; }

    const result = { ok: true, keyword, pages, analysis };
    cache[keyword.toLowerCase()] = result;
    try {
      await pool.query(`INSERT INTO project_integrations (project_id, kind, config) VALUES ($1,'serp_gap_analysis',$2) ON CONFLICT (project_id, kind) DO UPDATE SET config=$2`, [projectId, JSON.stringify({ map: cache })]);
    } catch (e) {}
    res.json(result);
  } catch (e) { console.error('[serp-gap-analyze]', e.message); res.status(500).json({ error: e.message }); }
});

// ==================== AIO — AI SEARCH (Google AI Overview citation tracking) ====================
// For your tracked keywords, checks whether Google shows an AI Overview and which domains it cites —
// so you can see where you're cited vs your competitors, and where the citation opportunities are.
app.post('/api/projects/:projectId/aio/scan', async (req, res) => {
  const projectId = parseInt(req.params.projectId);
  try {
    if (!SERPAPI_KEY) return res.status(503).json({ error: 'SerpAPI not configured' });
    const project = (await pool.query('SELECT * FROM projects WHERE id=$1', [projectId])).rows[0];
    if (!project) return res.status(404).json({ error: 'Project not found' });
    const clientHost = (project.domain || '').replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '').toLowerCase();

    let competitors = [];
    try { competitors = (await discoverCompetitorDomains(projectId, project, false, true)).slice(0, 8).map(c => c.domain); } catch (e) {}

    const kwRows = (await pool.query(`SELECT DISTINCT keyword FROM rank_keywords WHERE project_id=$1 AND (location IS NULL OR location='') ORDER BY keyword`, [projectId])).rows;
    let keywords = kwRows.map(r => r.keyword).filter(Boolean);
    if (Array.isArray(req.body.keywords) && req.body.keywords.length) keywords = req.body.keywords;
    keywords = keywords.slice(0, 30);
    if (!keywords.length) return res.status(400).json({ error: 'No keywords to scan. Add keywords in SERP Rankings first.' });

    const hostOf = (u) => { try { return new URL(u).hostname.replace(/^www\./, '').toLowerCase(); } catch { return ''; } };
    const flattenOverview = (ov) => {
      const parts = [];
      const walk = (blocks) => { for (const b of (blocks || [])) { if (b.snippet) parts.push(b.snippet); if (b.title) parts.push(b.title); if (Array.isArray(b.list)) for (const li of b.list) { if (li.title) parts.push(li.title); if (li.snippet) parts.push(li.snippet); } if (b.text_blocks) walk(b.text_blocks); } };
      walk(ov.text_blocks);
      return parts.join(' ').replace(/\s+/g, ' ').trim().slice(0, 1800);
    };
    let cost = 0;
    const results = [];

    for (const kw of keywords) {
      let present = false, refs = [], err = null, overviewText = '';
      try {
        const data = await serpApiSearch({ engine: 'google', q: kw, google_domain: 'google.com.au', gl: 'au', hl: 'en' });
        cost += 0.012;
        let ov = data.ai_overview;
        // AI Overview sometimes returns only a page_token; fetch the full block in a 2nd call.
        if (ov && ov.page_token && !(ov.text_blocks || ov.references)) {
          try { const d2 = await serpApiSearch({ engine: 'google_ai_overview', page_token: ov.page_token }); cost += 0.012; ov = d2.ai_overview || ov; } catch (e) {}
        }
        if (ov && (ov.text_blocks || ov.references)) {
          present = true;
          overviewText = ov.text_blocks ? flattenOverview(ov) : '';
          refs = (ov.references || []).map(r => ({ domain: hostOf(r.link), title: r.title || r.source || '', link: r.link || '', index: r.index })).filter(r => r.domain);
        }
      } catch (e) { err = e.message; }
      const cited = refs.map(r => r.domain);
      const youCited = !!(clientHost && cited.includes(clientHost));
      const yourPos = youCited ? (refs.find(r => r.domain === clientHost)?.index ?? null) : null;
      const compsCited = competitors.filter(c => cited.includes(c));
      results.push({ keyword: kw, ai_overview: present, you_cited: youCited, your_position: yourPos, competitors_cited: compsCited, sources: refs, overview_text: overviewText, error: err });
    }

    const summary = {
      total: results.length,
      with_overview: results.filter(r => r.ai_overview).length,
      you_cited: results.filter(r => r.you_cited).length,
      competitor_cited: results.filter(r => r.competitors_cited.length > 0).length,
      opportunity: results.filter(r => r.ai_overview && !r.you_cited).length, // overview shows but you're not in it
    };
    const payload = { keywords: results, summary, competitors, scanned_at: new Date().toISOString() };
    await pool.query(`INSERT INTO project_integrations (project_id, kind, config) VALUES ($1,'aio_cache',$2) ON CONFLICT (project_id, kind) DO UPDATE SET config=$2`, [projectId, JSON.stringify(payload)]).catch(() => {});
    try { await pool.query('INSERT INTO api_costs (project_id, feature, provider, api_calls, cost, details) VALUES ($1,$2,$3,$4,$5,$6)', [projectId, 'aio_scan', 'serpapi', keywords.length, cost, JSON.stringify({ count: keywords.length })]); } catch (e) {}
    res.json({ ...payload, cost });
  } catch (e) { console.error('[aio]', e.message); res.status(500).json({ error: e.message }); }
});

